INSERT INTO `dr_1_anliguanli` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `alxqysbzt`, `alxqyzbspzs`, `alxqyzbspzsjj`, `cpxqyysbcs1`) VALUES
(232, 10, '        水电七局点赞豫工除雪滚：清扫效率高       ', '136', '', '冬季来临，中国水利水电第七工程局因工程需要，计划采购除雪滚刷，用于水电站地面冬季积雪清除。为了选到高品质的设备，项目方综合对比了多个厂家！经过1个月的综合对比，客户最终选择豫工作为供货方，是对产品经理专业服务和工厂生产实力的认可。为了提高清扫效率，客户选择豫工自带动力系列除雪滚刷，并选用工作宽度3米的机型，用以匹配项目工地的装载机。冬季来临，为应对冬季除雪设备的大量需求，豫工机械工厂未雨绸缪，提前', 1, 1, '创始人', 9, '/show-232.html', 0, 0, '39.96.59.7-41184', 1700812721, 1701055059, 0, '137', '', '', ''),
(233, 10, '        豫工除雪滚大批量登录湖北高速       ', '139', '', '冬季来临，湖北鄂州某标段市政高速公路因除雪需要，计划采购雪滚设备，经同一高速公路相邻标段负责人推荐，咨询豫工除雪滚刷。给客户推荐豫工雪滚的李总，跟客户承包同一高速公路的不同标段，2022年10月采购豫工马路吹扫机，根据工人反馈，设备风量大、吹扫效率高。因为设备性价比高，2022年12月李总又陆续批量采购豫工融雪撒布机、雪滚、雪铲设备，清雪除雪设备一站式配齐。去年高速公路大雪，李总承包的标段清雪除雪', 1, 1, '创始人', 9, '/show-233.html', 0, 0, '39.96.59.7-41192', 1700812721, 1701055333, 0, '138', '', '', ''),
(234, 10, '        18万隧道物资向中铁十二局圆满交付       ', '140', '', '中铁十二局深江铁路项目计划采购一批隧道物资。9月27日，负责人谭总咨询豫工小导管缩尖、冲孔设备，对比设备性能指标，了解工厂生产实力，审核公司经营资质。客户同时咨询了另外三个厂家，经过半个月的综合对比，最终选择豫工机械作为其设备供应商。10月16日，客户谭总与豫工签订合同！在定购小导管缩尖机、小导管冲孔机的同时，加购数控弯箍机、自动滚丝机、压弯机设备！作为18年隧道喷浆支护设备生产厂家，豫工机械通过', 1, 1, '创始人', 9, '/show-234.html', 0, 0, '39.96.59.7-41198', 1700812721, 1701055423, 0, '141', '', '', ''),
(235, 10, '        夏邑住建局点赞豫工永磁防汛泵车       ', '142', '', '5月20日，河南夏邑住建局计划采购防汛泵车，根据客户对设备流量和性能的要求，产品经理推荐300方、500方、1000方永磁防汛泵车。作为政府采购项目，客户对质量、细节要求严格，咨询多个厂家后，选定包括豫工在内的三个厂家，提交设备方案，做最后对比。产品经理提交的方案中，充分体现了豫工人对细节的追求，不仅对永磁防汛泵的结构做客观展示，对核心部件如发电机组品牌、永磁泵国家级检测认证、关键配件配置也一 一', 1, 1, '创始人', 9, '/show-235.html', 0, 0, '39.96.59.7-41204', 1700812721, 1701055706, 0, '143', '144', '', ''),
(236, 10, '        飞机售后，助力厦门地铁抢工期       ', '145', '', '豫工故事客户谭总长期从事混凝土护坡支护项目，一直租赁混凝土湿喷机施工，却因为设备陈旧，遭遇上水慢、压力低、流量小......等问题的困扰。2023年2月，客户咨询豫工液压湿喷机，因为工程量小，最终还是选择租赁设备施工。然而，合作虽然未成，沟通从未间断！豫工产品经理的专业过硬，服务耐心，给客户留下深刻的印象，赢得客户的信任。租赁设备施工中遇到问题，他总是向豫工咨询解决办法。作为深耕机械行业18年的厂', 1, 1, '创始人', 9, '/show-236.html', 0, 0, '39.96.59.7-41210', 1700812721, 1701056010, 0, '146', '147', '', ''),
(237, 10, '        混凝土输送泵泰国售后，助力一带一路建设       ', '148', '', '客户负责中泰高铁——超前支护工程项目。2021年9月，客户首次咨询豫工液压湿喷机，工字钢弯拱机等设备，同时咨询了河南、湖南至少5个生产厂家。2021年12月5日，客户到访公司总部——郑州运营中心，并考察了豫工机械隧道支护设备生产基地。客户看到豫工门类齐全的设备生产线，庞大的仓库备货，完全满足其隧道物资一站式采购的需求，非常满意，从而达成合作意向！2022年2月，客户第一次下单2台双喷头液压湿喷机，', 1, 1, '创始人', 9, '/show-237.html', 0, 0, '39.96.59.7-41216', 1700812721, 1701056348, 0, '149', '150', '', ''),
(238, 10, '        34万隧道物资圆满交付，获中铁六局点赞       ', '151', '', '四川客户承接中铁六局康新高速钢结构加工项目，按照甲方（中铁六局项目部）要求，批量采购一批隧道物资设备，共计六款7台。为了买到符合要求的设备，也为了节约成本，客户走访对比了多个生产厂家。产品经理结合客户钢筋加工尺寸、钢板切割厚度、工期进度，制定了合理的设备采购方案：300型数控型钢冷弯机、数控龙门等离子切割机、50型小导管缩尖机、50型数控小导管双头割孔机、220型全自动网片排焊接生产线等，并在众多', 1, 1, '创始人', 9, '/show-238.html', 0, 0, '39.96.59.7-41222', 1700812721, 1701056801, 0, '152', '153', '', ''),
(239, 10, '        一位豫工售后20天的工作日记       ', '127', '', '10月面对疫情压力，豫工人迎难而上，捷报频传，业绩一路飘红。  然而，成交只是开始，服务永无止境！10月10日，为解决因疫情售后人员出行不便的问题，公司特发起服务动员令，从无疫情地区的本部工厂一线，抽调8位技术工程师，组建应急技术服务小组，代替售后部门职能，赴各地客户工地，提供技术服务。  我们截取了一名工程师20天（10.10-11.1）的工作日志，来记录这次意义非凡的行动。下面跟随王工的脚步，', 1, 1, '创始人', 9, '/show-239.html', 0, 0, '39.96.59.7-41228', 1700812722, 1701054137, 0, '128', '129', '', ''),
(240, 10, '        6万平边坡绿化，喷播机租还是买？       ', '130', '', '客户好评因为朋友三年前订购豫工的30型筛土机，设备一直运转良好，对豫工品牌比较认可！他一直在微信朋友圈关注豫工的发展动态，了解到近几年，豫工喷播机一直在出货。特意向我推荐，现在看来，施工效果确实不错，与产品经理介绍的效果差不多，完全满足施工需求，选择豫工，就是放心。施工现场', 1, 1, '创始人', 9, '/show-240.html', 0, 0, '39.96.59.7-41234', 1700812722, 1701054324, 0, '132', '131', '湖北十堰喷播机客户，负责郧西县土质边坡绿化项目，施工面积6万平，绿化山坡高度30米。经朋友（豫工机械30型筛土机老客户）介绍，来咨询豫工液压喷播机、筛土机，为了节约成本，对于喷播机，客户倾向于租赁使用。6月20日，客户来厂考察，现代化的生产车间、专业化技术团队、种类齐全的系列设备，彻底打消心中疑虑，当天即爽快下单，并追加一台20型筛土机。安装培训过程中，乔工从喷播机使用前的准备工作，基本操作，基材配比，设备日常保养到常见故障处理，一点点指导工人。由于喷播机配备360°旋转万向喷头，作业面调换方便，轻松实现多方向喷播，工人很快即掌握操作方法。施工现场，6方液力喷播机搭配30米引管，喷播高度轻松达到30米，施工效率1000方/天，完全满足客户施工要求，搭配的20型筛土机高效筛分，密切配合，完美解决筛土问题。', ''),
(241, 10, '        豫工钢筋网片排焊机助力雄安新区建设       ', '133', '', '客户好评必须为豫工的专业服务点赞，提供的施工方案，实用性强，施工成本低，真是省心、省力、省钱！据现场工人反馈，此次购买的全气动钢筋网片焊机不仅焊点牢固，自动落料，焊接速度快，而且定位精准，网格尺寸标准。另外，设备在运行过程中没有出现任何故障，减少了维修时间和费用，这对提高生产效率，保证工期至关重要。案例现场', 1, 1, '创始人', 9, '/show-241.html', 0, 0, '39.96.59.7-41240', 1700812722, 1701054983, 0, '134', '135', '中铁十一局雄安新区容西市政工程建设项目，客户需要制作宽2米，长6米，钢丝直径6-8mm，20个焊点的钢筋网片，用于批量的建筑用钢筋网片焊接。客户精心筛选了4个厂家，提供设备方案，最终选择豫工，是对我们专业能力和高性价比施工方案的高度认可。针对客户的施工要求，产品经理并没有推荐最高配置的排焊设备，而是提供了最适合客户需求的高性价比设备方案：半自动气动钢筋网片排焊机+2立方左右空压机+豫工17年经验的专业服务，因为这份想客户之所想的合作诚意，最终赢得客户青睐。试机过程中，设备通过气动下压的焊接方式，焊接压力均匀，焊点牢固、稳定，焊接速度快，可以达到40排/分钟。', ''),
(242, 10, '        中建五局点赞豫工液压湿喷机       ', '106', '', '客户好评喷浆速度很快，操作很简单！这是设备给我最大的印象！感谢技术人员的辛勤付出，很专业也很有责任心，总是耐心指导工人操作步骤，听工人说他们现在可以熟练掌握设备的安装、拆卸、操作、保养步骤。选择豫工，我很放心。施工现场', 1, 1, '创始人', 9, '/show-242.html', 0, 0, '39.96.59.7-41268', 1700812726, 1701051514, 0, '108', '107', '湖南长沙地铁站项目，由中国建筑五局承建，订购液压湿喷机主要用于基坑支护，总施工面积100000平，为保证工期，客户要求单日喷浆面积达到1000平方，水平输送距离达到50米。根据客户工程需求，产品经理为客户推荐YG-90型单喷头液压湿喷机，配套豫工电动16立方空气压缩机。液压湿喷机采用骨料粒径15mm的浆料，在16立方电动空压机的完美配合下，高效喷浆，每小时喷浆量达到7m³，输送距离轻松达到50米，完全满足客户施工需求。', ''),
(243, 10, '        豫工湿喷台车助力中铁隧道局开工大吉!       ', '109', '', '施工现场', 1, 1, '创始人', 9, '/show-243.html', 0, 0, '39.96.59.7-41276', 1700812726, 1701052243, 0, '110', '111', '宜兴铁路ZQ-3标项目，由中铁隧道局承建，计划采购液压湿喷机用于铁路隧道喷浆支护施工。客户在实地考察公司的生产规模后，对公司的生产能力很放心，为保证工期不误，客户决定采购生产效率更高的湿喷台车机械手（生产效率30㎥/h），并且一次采购两台。这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程度高，遥控操作，全自动喷浆无盲区，广泛应用于高铁、隧道、边坡、地铁、基坑等喷浆支护项目。施工现场，操作人员使用无线遥控进行喷射作业，远离作业面，不仅操作方便，更增加了工人的安全性。客户对设备高效的生产能力很满意，表示：根据工程需要，下次再上一台。', ''),
(244, 10, '        豫工液压湿喷机助力中铁18局地铁站建设       ', '112', '', '客户好评客户盛赞豫工液压湿喷机湿喷效果杠杠滴，现场操作工人说：这设备陡起（徐州方言：太厉害的意思），很好！到目前为止，没有听到工人反馈任何故障问题，这也减少了维修时间和费用，提高了生产效率。案例现场', 1, 1, '创始人', 9, '/show-244.html', 0, 0, '39.96.59.7-41282', 1700812726, 1701052475, 0, '114', '113', '徐州奥体中心地铁站项目，由中铁十八局承建，此次订购的液压湿喷机主要用于地铁基坑支护施工。客户之前订购的转子式喷浆机，因为工人反馈一直有堵管现象，影响工期，不得已重新订购！为保证客户工期不误，工厂安排物流发专车连夜为客户送货。在与发货部确认设备到达的时间后，豫工售后与技术支持部工程师乔工乘高铁从郑州出发，在设备送抵工地的第一时间赶到客户工地——徐州中铁十八局奥体中心地铁站施工现场。作为对风量、混凝土浆料要求很高的设备，试机过程中，液压湿喷机采用骨料粒径15mm，混凝土塌落度150-180的混凝土浆料，配合16/10型空压机，设备水平输送距离轻松达到80米，垂直喷射距离达到50米，生产能力每小时7立方。', ''),
(245, 10, '        设备3年0故障，客户返单抛丸机       ', '115', '', '客户评价因为之前的合作，一直在朋友圈关注豫工的发展动态，了解到客户对于抛丸机使用反馈一直很好，此次工地需要该设备，就直接下单了，现在看来，施工效果果然不错，完全满足防水施工需求，选择豫工，就是放心。施工现场展示     河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。', 1, 1, '创始人', 9, '/show-245.html', 0, 0, '39.96.59.7-41288', 1700812726, 1701052656, 0, '116', '117', '乌鲁木齐文启程3万平车库顶板防水施工，选择豫工路面抛丸机，用于防水喷涂前打毛！多年前，客户曾定购豫工熔胶机、脱桶器，使用3年0故障，此次防水施工，工期紧急，为提高施工效率，客户指定购买豫工550型路面抛丸机。 为保证客户假期正常施工，4月30日，售后张工，逆行五一出行高峰，订高价往返机票，赶赴客户施工现场。 值得一提的是，豫工另一新疆客户，乌鲁木齐公园尚景车库顶板防水施工方，计划采购豫工抛丸机打毛地面，因没有见过真机，对设备不放心，又担心河南与新疆相距太远，售后跟不上，一直在犹豫中！在工作人员的协调下，客户赶到施工现场考察。 试机过程中，抛丸机自动行走，无尘环保，打毛速度300㎡/h,处理面粗糙度均匀，无损伤，整个过程不漏砂！效果理想，客户当场下单。', ''),
(246, 10, '        中铁大桥局2.3米大桩，高效破拆       ', '120', '', '客户好评破桩过程中，赶上中铁大桥局领导视察现场！在全程观看破桩机施工后，将苏工找到身边，交流破桩心得！领导表示：项目上，曾经使用过其他厂家的破桩机，因为速度、效率、破桩程度不太理想，目前已不再使用。现在这款设备破桩效果，与之前相比，效果不错。“在同一场地，同等地质条件下，豫工破桩机比之前那款相比，破桩速度更快，效率更高！”另一负责施工的领导介绍说。施工现场', 1, 1, '创始人', 9, '/show-246.html', 0, 0, '39.96.59.7-41294', 1700812726, 1701052770, 0, '118', '119', '客户所在项目位于山西运城，中铁大桥局 黄河大桥建造工程，桩径2.3米，桩高3-4米，共700多根桩。客户订购破桩机特别谨慎，在咨询多个破桩机厂家后，终锁定豫工机械。客户选择的是17个破桩模块，30KW液压泵站全套设备。 施工旺季，刚刚结束广西百色中交四公局巴马-凭祥公路2-2.2米桩径安装调试的苏工，来不及休息，即马不停蹄赶赴客户施工现场。 凭借多年服务经验，在工人配合下，苏工很快完成破桩机的安装调试！ 试机过程中，17个模块，6吨重破桩机，在30KW泵站配合下，由55吨位吊车吊起，在苏工的指挥下缓缓套入桩身，每30公分截取一次，单次截桩时间2-3分钟，3米高桩柱，30分钟破除。', ''),
(247, 10, '        雄安高铁站负一层环氧树脂涂装前打毛       ', '121', '', '客户评价听朋友介绍，才开始了解豫工的抛丸机，工期紧，仓促下单，没想到效率、速度都这么棒！按照这个速度， 4天即可保质保量完工，不错！图片展示', 1, 1, '创始人', 9, '/show-247.html', 0, 0, '39.96.59.7-41300', 1700812726, 1701053548, 0, '122', '123', '国家级工程，雄安新区高铁站房建设，中铁建工二局项目，环氧树脂涂装前地面基层打毛，施工面积20000平，工期紧急，豫工550型路面抛丸机担纲重任，日处理地面5000平方，效果、速度，客户双重满意。豫工路面抛丸机作为豫工的经典机型，功能稳定、技术成熟、环保高效。从刚刚推向市场时，老客户仗义订购，到后迅速打开市场，需求量暴增，成为越来越多的客户，地面防水打毛、桥面糙化处理、钢板除锈的首选设备，我们仅仅用了3年。就像抖音一样，时时刻刻从用户的需求出发，不火爆都难。 值得一提的是，今年9月份，云南大理客户，钢板除锈施工，第一次用磨光机，有粉尘，环保局不通过。改用湿喷机，排出的污水污染下水道，村委会不让用，后选择豫工路面抛丸机，高效、无尘、环保，客户满意，甲方点赞。', ''),
(248, 10, '        浙江台州破桩机房建桩破除       ', '124', '', '客户好评客户为豫工破桩机的工作效率点赞，是人工的数十倍！客户对调整模块数量的工作专业度表示高度认可，感谢豫工售后服务团队的热情服务和耐心指导。图片展示', 1, 1, '创始人', 9, '/show-248.html', 0, 0, '39.96.59.7-41306', 1700812726, 1701053793, 0, '125', '126', '中铁建工集团下属浙江台州火车站房建工程项目工地直径850-1100mm的圆柱形灌注桩，高约2-3米，施工方为了提高施工效率，摒弃老旧的人工破除法，改用豫工破桩机进行机械破除。 本次施工采用挖掘机吊取破桩机，并以它为移动载具，同时作为动力源提供破桩动力。由施工人员指挥辅助将破桩机套入桩身，在截第一段时，在距离桩上端面400mm左右处截，以后往下每隔距离不大于300mm左右截一次。在截后一段时先清除掉落在桩体周围的碎混凝土，再对准标高线截后一次。 截完后，由一名施工人员将碎混凝土清除，使用工具将标高线灌注桩表面处理平整。 试机过程中，豫工破桩机被客户誉为工地破桩提速神器，直径850-1100mm，高约2-3米的圆柱形灌注桩，每5分钟破除！', ''),
(249, 10, '        驻马店某别墅车库顶板防水处理       ', '97', '', '客户好评客户表示:总包对防水效果的认可，让我对豫工设备很放心。购买成套设备，售后很方便，听工人反馈设备很好用，操作简单、维护方便，让我很省心。天气炎热，工人室外作业很辛苦，设备高效作业，大大减轻工人的工作量，工作效率提高了，这对如期完工很重要！图片展示', 1, 1, '创始人', 9, '/show-249.html', 0, 0, '39.96.59.7-41312', 1700812727, 1701051124, 0, '98', '99', '驻马店崇文府小区地下车库顶板防水项目。工期紧急，崔先生特订购豫工防水施工成套设备，高效完成防水作业。 为确保验收顺利，客户特请来项目总包确认防水效果，总包点评：不错，这个效果可以。 客户崔先生负责崇文府小区地下车库顶棚防水项目，订购豫工550型路面抛丸机主要用于去除水泥表面浮浆并打毛地面，以利于防水层吸附。因为客户请来的甲方对豫工抛丸机效果高度肯定，当即复购豫工非固化喷涂机一台，用于接下来防水层喷涂。 客户崔先生表示：路面抛丸机在去除水泥浮浆打毛地面方面与铣刨机相比优势明显，抛丸机效率高，操作过程干净整洁，无任何污染，不需要二次处理；抛铣机在去除浮浆时灰尘污染大、效率慢，路面打完后还需要进一步处理灰尘！', ''),
(250, 10, '        中国二冶中学建设项目防水施工       ', '100', '', '客户好评豫工非固化喷涂机太棒了！与租用的设备相比，综合施工效率提高了4-5倍，非常好！今年天已经冷了，明年开春再来，继续购买。图片展示', 1, 1, '创始人', 9, '/show-250.html', 0, 0, '39.96.59.7-41318', 1700812727, 1701051214, 0, '102', '101', '客户负责某中学楼顶防水项目，施工面积76000平。 2020年4月，罗先生第一次咨询豫工非固化喷涂机，经过4个月的询价和厂家对比，8月，罗先生提出想看现场施工效果，工作人员安排罗先生到驻马店，豫工防水施工客户工地，就近考察。 8月26日，客户动身到豫工防水施工设备套装客户驻马店泌阳工地考察。在那里，客户看到了非固化喷涂机在路面抛丸机的协同配合下，高效施工，方便快捷，了解到豫工设备操作简便、品质稳定，听到了豫工服务专业周到、用心负责，心里更加踏实。罗先生考察回来的第二天，即爽快地与公司签订购买合同 试机过程中，施工效果与驻马店工地效果一模一样，非固化喷涂机在溶胶机和拖桶器的配合下，高效均匀喷涂，所有设备密切配合，火力全开，预计一天可完成防水施工面积2000平。', ''),
(251, 10, '        张家口中泰城车库顶板防水前打毛       ', '103', '', '客户好评结束客户服务第5天，张工电话回访客户设备使用情况。客户表示：喷涂机效率挺高，溶胶速度也可以，工人用起来很顺手。因抛丸机退换货拉下的工期有望补回来，项目不出意外，可以如期完工，交付甲方。图片展示', 1, 1, '创始人', 9, '/show-251.html', 0, 0, '39.96.59.7-41324', 1700812727, 1701051362, 0, '105', '104', '客户陈先生从事桥面防水工程，选择豫工抛丸机，是因为2019年，看到鄂尔多斯朋友在用豫工凿毛机，听朋友反馈效果不错，就一直关注豫工机械。端午前夕，陈先生开始桥面防水工程施工，工期紧急，为提高效率，陈先生放弃灰尘污染大、效率慢的铣刨机，选择豫工抛丸机，去除表面浮浆并打毛桥面！ 由于桥面施工工艺不同，客户对抛丸机抛丸深度要求比较高，需要深度抛丸，去除表面浮浆并打毛桥面，以利于防水层吸附。经过售后毛工的专业调试，很快达到施工要求。客户对抛丸机终的试机效果很满意！ 试机过程中，毛工为工人细心演示使用过程，手把手教工人操作步骤和注意事项，经过一个小时的细心指导，工人与设备默契配合。', ''),
(252, 10, '        西安兴平食品工业钢板除锈       ', '94', '', '客户评价钢板除锈施工，第一次用磨光机，有粉尘，环保局不通过，改用湿喷机，排出的污水污染下水道，村委会不让用，后选择豫工路面抛丸机，无尘环保，客户满意，甲方点赞图片展示', 1, 1, '创始人', 9, '/show-252.html', 0, 0, '39.96.59.7-41368', 1700812730, 1701050909, 0, '96', '95', '客户订购850型路面抛丸机属于二次返单，一个月内两次下单。 2020年5月9日曾订购公司550型路面抛丸机一台。因除锈干净平整，达到SA3级，效果远超预期。6月3日，客户复购850型路面抛丸机。 设备达到客户工地后！工程师张工即风尘仆仆赶赴客户工地，未及休息即投入到紧张的调试工作中去！工期就是金钱！为减少客户工期等待，工程师赶时间，挣进度，工作至天黑，争取设备早一刻投入使用。整个调试过程非常顺利。张工现场手把手教客户工人操作步骤和注意事项，经过一个小时的专业培训，施工人员熟练掌握操作要领，人机默契配合。试机过程中，850型抛丸机钢板高效施工，处理过的表面干净平整，无需再做任何处理。自带的除尘装置，将抛丸后的灰尘自动回收，整个除锈过程环保无污染，效果远超预期。', ''),
(253, 10, '        山西重点建设项目祁离高速破桩       ', '85', '', '客户评价破桩之前，客户反复强调完好保留桥梁桩竖向钢筋。试机结果完美达成客户要求。豫工破桩机被客户称为“破除桥梁桩专用神器”。客户表示：豫工破桩机截桩不留芯，避免二次人工处理，大大减少破桩工程人工投入，为确保工期意义重大！图片展示', 1, 1, '创始人', 9, '/show-253.html', 0, 0, '39.96.59.7-41376', 1700812731, 1701049964, 0, '86', '87', '中铁三局百亿工程——祁离高速建设项目，客户抢工期、保质量，机械破除吕梁段桥梁桩，根据工程需要，要求彻底破碎桩身混凝土的同时，必须完好保留竖向钢筋！经多方考察，施工方确定由豫工破桩机执行破除任务。吕梁段桥梁桩桩径1.5-1.8米，C30混凝土结构，需要17个模块，为给破桩机提供足够的破桩动力，又选择豫工22KW专用液压泵站。 张工到达工地后，第一时间投入安装调试工作，在工地工人和吊车师傅的协同配合下，3个小时完成破桩机17个模块的安装工作，当天下午6点左右完成调试! 试机过程中，张工指挥工人辅助将破桩机套入桩身,微调破桩机的位置和松紧度，直至紧紧锁定桩面。调节液压泵站压力向破桩机加压，混凝土桩身在破桩机的强压下缓缓碎裂，直至彻底断裂，竖向钢筋完好保留。', ''),
(254, 10, '        长春碧桂园地下车库顶板防水施工       ', '88', '', '客户好评在结束服务第五天，乔工回访客户设备施工情况，对方表示：防水施工速度和防水施工效果，项目部都非常满意，已成功签订合同，明年5月份开工，完成9万平地下车库顶板防水施工。图片展示', 1, 1, '创始人', 9, '/show-254.html', 0, 0, '39.96.59.7-41384', 1700812731, 1701050120, 0, '90', '89', '长春市碧桂园车库顶棚防水施工，面积8万平方， 天气转冷，白天施工时间缩短，工期临近，客户放弃人工刮涂，改为机器施工，之前租了一台喷涂设备，租金一天3000元！然而远远不能满足工期需要。客户经老客户转介绍，选择购买豫工非固化喷涂机，计划两台喷涂机同时施工，提高工作效率，保证工期不误。 豫工YGF-2000非固化喷涂机试机过程中，施工效果使客户有种如获至宝的感觉。不管工作效率、喷涂宽度还是喷涂效果，都远超客户预期，客户表示：与租用设备相比，豫工非固化喷涂设备使施工效率提高了4-5倍。 张工表示：豫工非固化，配备6.1L定制钢泵，容量大，动力强，雾化扇形可达80cm，施工更高效，一天轻松帮客户喷涂2000多平方。配合豫工为非固化喷涂机专门研发的溶胶机，全程高效、均匀加热，可使设备喷涂更均匀，效果更好。', ''),
(255, 10, '        空军某部队军用机场跑道打毛项目       ', '91', '', '客户好评部队领导对豫工550型路面抛丸机施工效果很满意，并称赞豫工机械贴心的售后服务远超预期！图片展示', 1, 1, '创始人', 9, '/show-255.html', 0, 0, '39.96.59.7-41392', 1700812731, 1701050575, 0, '93', '92', '客户属于中国人民解放军某部队，购买豫工550型路面抛丸机，主要用于军用机场道路施工。 由于部队非常注重产品质量，在采购之前，部队慎重筛选了三个厂家供评审小组选择。豫工机械终能通过审核，源于豫工机械对客户严格的质保承诺，和豫工550型路面抛丸机自身过硬的产品质量，经过多次合同修订后，终于签订合同。 调试当天，张工早早来到部队门口，几乎与送货物流车同时抵达。上午8点，带设备交付后，张工第一时间投入设备的安装调试工作，由于之前沟通到位，安装调试用的工具、电线准备齐全，并配有发电设备，在兵哥的配合下，整个安装调试过程非常顺利。 张工现场认真教兵哥操作步骤和注意事项，并与兵哥互加微信，方便后期设备的操作和维护！', ''),
(256, 10, '        保定市政工程混凝土地面打毛       ', '82', '', '客户反馈客户刘先生高度称赞营销顾问的专业推荐，对调试路面抛丸机配发的切丸非常满意，效果明显，完全满足施工要求。非常认可豫工550型路面抛丸机，不仅工作效率满足要求，而且操作简便，在毛工的耐心指导下，工人虽年过六旬，但上手很快，完全不影响施工进度。图片展示', 1, 1, '创始人', 9, '/show-256.html', 0, 0, '39.96.59.7-41398', 1700812731, 1701048071, 0, '83', '84', '河北市政水泥道路抛丸工程，因为工期紧急，对路面抛丸机工作效率和能否满足施工要求非常重视。客户工人大多年过六旬，沟通有一定难度，豫工售后人员凭借专业技术水平，使工人尽快熟练操作设备操作步骤，解决客户后顾之忧。2020年6月21日星期日，正在休息的毛工接到豫工售后与技术支持部的工作通知，河北保定客户购买550型路面抛丸机，因为工期紧急，必须尽快赶赴客户工地安装调试。到达工地后，毛工第一时间投入设备的安装调试工作中去。 因为客户工地工人大多年过六旬，增加了工作沟通和设备培训的难度。毛工耐心指导，不断重复培训工人操作步骤和注意事项，直到工人熟练掌握，才放心离开！', ''),
(361, 10, '价值40万除雪滚圆满交付', '545', '', '历时16天，辗转3个项目现场，价值40万除雪滚圆满交付！', 1, 1, '创始人', 9, '/show-361.html', 0, 0, '1.192.0.71-39025', 1702280100, 1702368534, 0, '629', '630', '', ''),
(362, 10, '15台除雪设备“亮剑”高速除雪', '546', '', '强！15台除雪设备“亮剑”高速除雪，为道路畅通保驾护航！', 1, 1, '创始人', 9, '/show-362.html', 0, 0, '1.192.0.71-10915', 1702280806, 1702368373, 0, '627', '628', '', ''),
(363, 10, '湖北高速上线豫工除雪滚', '631', '', '强！湖北高速上线豫工除雪滚，“刷”过的地方安全感拉满！', 1, 1, '创始人', 9, '/show-363.html', 0, 0, '1.192.0.71-10915', 1702280866, 1702368828, 0, '640', '626', '', ''),
(364, 10, '价值18万隧道物资圆满交付', '548', '隧道物资,小导管缩尖冲孔机', '强！价值18万隧道物资圆满交付，获中铁十二局点赞！', 1, 1, '创始人', 9, '/show-364.html', 0, 0, '1.192.0.71-10915', 1702280922, 1702367109, 0, '612', '613', '', ''),
(365, 10, '水电七局点赞豫工除雪滚', '549', '除雪滚,豫工除雪滚', '水电七局点赞豫工除雪滚：操作方便 清扫效率高！', 1, 1, '创始人', 9, '/show-365.html', 0, 0, '1.192.0.71-27932', 1702281073, 1702366561, 0, '606', '605', '', ''),
(386, 10, '豫工机械助力济宁地铁高效施工', '962', '液压湿喷机,混凝土湿喷机', '客户瞿总负责济宁地铁7号线基坑湿喷建设，项目施工面积80000平，喷浆距离50-100米。为了选到合适的设备，客户订购过程特别谨慎，确定合作之前，同时咨询了多个厂家，并对企业的售后服务和生产实力进行了谨慎评估。3月29日，瞿总咨询豫工液压湿喷机，产品经理根据客户发来的现场图片，结合工期进度、工程量以及喷浆距离，优先为客户推荐了90型液压湿喷机、16/8电动移动空压机和配套的速凝剂管喷浆管。经过近半', 1, 2, '豫工机械', 9, '/show-386.html', 0, 0, '123.160.240.219-53377', 1717234361, 1717234971, 0, '963', '969', '通宵达旦 昼夜不停，豫工机械助力济宁地铁高效施工！', ''),
(389, 10, '豫工技术员紧急支援 黑龙江五常水灾！', '983', '防汛泵,水泵,排涝,应急防汛,移动防汛泵,移动泵车,暴雨,车库排水', '防汛应急相关部门采购豫工6台1000方大流量防汛泵车，勇战暴雨洪涝灾害。客户此次订购的防汛泵车，流量100', 1, 2, '豫工机械', 9, '/show-389.html', 0, 0, '171.15.11.139-56262', 1720407025, 1720409060, 0, '980', '981', '受强降雨影响，黑龙江五常市牤牛河、拉林河等河流沿岸大量村屯被淹，包括龙凤山镇、志广乡、民乐朝鲜族乡、向阳镇、沙河子镇等地出现不同程度洪涝灾害。截至8月7日，五常市累计转移受灾群众五万多人。相关部门正在加紧抢修道路、电力、通信等相关设施，保证救援抢修任务能够顺利进行。\r\n为了更快完成抢险、恢复工作，防汛应急相关部门采购豫工6台1000方大流量防汛泵车，勇战暴雨洪涝灾害。\r\n客户此次订购的防汛泵车，流量1000方，扬程12米， 吸程6米，配套84KW的6缸潍柴柴油机，进口直径300mm  出口直径300mm。\r\n为保证设备早日投入防汛工作，豫工机械售后服务部张工乘飞机，从北京防汛泵售后现场出发，赶赴客户指定地点，技术支援黑龙江防洪救援工作。\r\n设备试机，6台防汛泵运行稳定，高效吸水，具备强大的抽排能力和灵活性，与救援救灾形成工作合力，成为防汛抗洪好帮手。', ''),
(390, 10, '豫工技术员千里奔赴防汛一线', '984', '防汛泵,防汛排涝,水泵,应急防汛', '作为防汛泵行业18年生产厂家，豫工机械在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业，累计服务防汛泵客户5000+！豫工机械工厂内景展示汛期来临叠加台风强降雨天气，豫工防汛泵需求量暴增，为了让客户订购的防汛泵早日投入应急救灾，工厂严格质量检测，加班加点出货。紧急支援  “逆”水而行风雨同舟 众志成城，豫工机械', 1, 2, '豫工机械', 9, '/show-390.html', 0, 0, '171.15.11.139-54366', 1720412042, 1720412042, 0, '993', '994', '受强降雨影响，黑龙江五常市牤牛河、拉林河等河流沿岸大量村屯被淹，包括龙凤山镇、志广乡、民乐朝鲜族乡、向阳镇、沙河子镇等地出现不同程度洪涝灾害。截至8月7日，五常市累计转移受灾群众五万多人。相关部门正在加紧抢修道路、电力、通信等相关设施，保证救援抢修任务能够顺利进行。\r\n为了更快完成抢险、恢复工作，防汛应急相关部门采购豫工6台1000方大流量防汛泵车，勇战暴雨洪涝灾害。\r\n客户此次订购的防汛泵车，流量1000方，扬程12米， 吸程6米，配套84KW的6缸潍柴柴油机，进口直径300mm  出口直径300mm。\r\n防汛泵车配套的离心式中开泵，又称为双吸离心泵，自吸能力强，输送流量大、扬程高、输送距离长，稳定性好，能够在不同的负载下，保持稳定工作状态，不易产生振动和噪音，完全满足高负荷防汛应急需要。', '1500型拖车防汛泵'),
(391, 10, '豫工工程师奔赴涿州技术支援', '1015', '防汛水泵,水泵,抗洪排涝,抽水', '作为防汛泵行业18年生产厂家，公司在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业。豫工质造，值得信赖！豫工机械工厂内景展示严格检测 如期交货汛情如火、昼夜奋战。汛期以来，豫工防汛泵需求量暴增，为了早日让客户拿到设备，抗洪救灾，工厂严格质量检测，加班加点出货。在设备即将达到客户指定地点，豫工机械售后服务部毛工，', 1, 2, '豫工机械', 9, '/show-391.html', 0, 0, '171.15.11.139-19259', 1720424781, 1720427863, 0, '1012', '1014', '受冷暖空气和台风“杜苏芮”共同影响，涿州市河道行洪和城市内涝风险加剧，防汛形势十分严峻。境内北拒马河、小清河、白沟河等多条河流流量较大，小清河分洪区、兰沟洼蓄滞洪区已相继启用。\r\n据统计，截至8月1日10时，涿州受灾人数133913人，受灾村居146个，面积225.38平方公里。8月2日6时，河北省启用永定河泛区，这是海河流域应对洪水启用的第8处蓄滞洪区。\r\n为提高防汛效率，产品经理推荐客户订购三进三出1500型大流量防汛泵车。该设备搭载潍柴动力，采用柴油机自吸水泵，流量可达2000立方每小时，最高扬程可以达到25米，吸程7.5米。\r\n防汛泵车布局合理，搭载智能设备，可手动和自动控制，实时监控和数据测量，工作效率高。整机移动便捷、操作智能、运行稳定、管件快速拆装，满足复杂条件下防汛排涝需要。', '流量：1500立方/每小时'),
(392, 10, '夏邑住建局点赞豫工永磁防汛泵车', '1016', '永磁泵,防汛水泵,抗洪,排水,暴雨,抽水', '此次客户选择豫工，不仅与产品经理专业细致的方案密不可分，更与公司对设备的细节打造密切相关。作为18年防汛泵生产厂家，做细节一直是豫工人的专长，发展至今，公司在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业。  客户定购的永磁防汛泵系列，除了硬核配置，在细节方面也堪称完美，比如：设备特添加照明灯结构，功率35W，', 1, 2, '豫工机械', 9, '/show-392.html', 0, 0, '171.15.11.139-19914', 1720428761, 1720429621, 0, '1025', '1026', '5月20日，河南夏邑住建局计划采购防汛泵车，根据客户对设备流量和性能的要求，产品经理推荐300方、500方、1000方永磁防汛泵车。作为政府采购项目，客户对质量、细节要求严格，咨询多个厂家后，选定包括豫工在内的三个厂家，提交设备方案，做最后对比。产品经理提交的方案中，充分体现了豫工人对细节的追求，不仅对永磁防汛泵的结构做客观展示，对核心部件如发电机组品牌、永磁泵国家级检测认证、关键配件配置也一 一标注，方便客户直观了解。\r\n经过2个月的慎重对比，客户最终选定豫工作为本次防汛泵政府采购的供货厂家，并于7月10日，签订定货合同。客户最终选定的设备型号为300方永磁防汛泵车和500方永磁防汛泵车。其中，300方防汛泵车，配18kw 常柴发电机组。500方永磁防汛泵车配30kw潍柴发电机组。', '型号：500方永磁防汛泵车'),
(396, 10, '豫工4台除雪滚  助力怀仁市政道路除雪作业', '1091', '除雪,撒布机,雪滚,雪铲', '12月18日，怀仁市政因道路除雪需要，咨询豫工除雪滚，客户对设备首先提出三点要求：好用、质量过关、2天内到货', 1, 1, '创始人', 9, '/show-396.html', 0, 0, '1.192.2.178-58180', 1769580446, 1770195606, 0, '1110', '1123', '设备试机，在车速30km/h的状态下，模拟降雪路段进行除雪作业测试和载重转弯测试，发动机运行良好，滚刷转动平稳，无异响抖动，调节滚刷角度和离地高度，实现清雪作业，设备连续运行1小时状态正常。', '环卫清扫车重型3m除雪滚');
INSERT INTO `dr_1_anliguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(232, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;冬季来临，中国水利水电第七工程局因工程需要，计划采购除雪滚刷，用于水电站地面冬季积雪清除。为了选到高品质的设备，项目方综合对比了多个厂家！经过1个月的综合对比，客户最终选择豫工作为供货方，是对产品经理专业服务和工厂生产实力的认可。为了提高清扫效率，客户选择豫工自带动力系列除雪滚刷，并选用工作宽度3米的机型，用以匹配项目工地的装载机。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-23111615214b96.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;冬季来临，为应对冬季除雪设备的大量需求，豫工机械工厂未雨绸缪，提前生产大量现货，库存充足，客户无需等待。在公司与水电七局签订合同后，工厂迅速响应，对设备做出厂前功能测试后，闪电发货！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116152212919.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;/&gt;&lt;br/&gt;刚刚结束湖南娄底雪滚调试的张工，在确定设备到达时间后，马不停蹄赶赴客户工地——河南洛宁水电站，与设备同时间到达。凭借多年工作经验，张工很快完成设备的安装调试。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-23111615223J18.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;设备试机，搭配液压动力站 200W直流电机 37KW潍坊柴油动力，除雪滚双向角度调节，左右摆角30度，雪滚最高转速2400r/min，清扫效率高，完全达到工作指标，客户非常满意！&lt;br/&gt;张工表示：客户订购的除雪滚刷，为公司带动力系列扫雪滚，效率高、安装方便！刷片直径800mm,有效清理积雪宽度3000mm,尼龙钢丝混合刷片，除雪效率高，清雪速度20kg/h。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-23111615245Y51.jpg&quot; style=&quot;width: 900px; height: 579px;&quot;/&gt;&lt;br/&gt;试机期间，张工给客户讲解设备的操作要领，指导客户遥控控制及手动控制除雪滚，在确认客户完全掌握操作步骤和日常保养方法后，结束本次技术服务！&lt;br/&gt;客户表示：订购前，考察了多个厂家，综合对比后，还是觉得豫工的雪滚性价比更高！感谢张技术的辛苦服务，项目领导对设备的试机效果很满意，操作方便，清扫效率高！&lt;/span&gt;&lt;/p&gt;'),
(233, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;冬季来临，湖北鄂州某标段市政高速公路因除雪需要，计划采购雪滚设备，经同一高速公路相邻标段负责人推荐，咨询豫工除雪滚刷。给客户推荐豫工雪滚的李总，跟客户承包同一高速公路的不同标段，2022年10月采购豫工马路吹扫机，根据工人反馈，设备风量大、吹扫效率高。因为设备性价比高，2022年12月李总又陆续批量采购豫工融雪撒布机、雪滚、雪铲设备，清雪除雪设备一站式配齐。去年高速公路大雪，李总承包的标段清雪除雪效率很高，工人有条不紊地工作，效率提升了一倍。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116153203434.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;因为有老客户使用证明，客户采购过程很顺利，在了解了设备的性能和参数后，即签订合同，一次下单两台，全款成交！整个合作如德芙般丝滑。客户采购的是3米自带动力除雪滚，转速280-300r/min。液压独立动力单元驱动雪滚上下左右摆动，左右摆角30度，潍坊37kw柴油机，尼龙钢丝混合刷片材质，动力强劲除雪效率高，全遥控和手动操作两种方式，使用方便。冬季来临，豫工机械急客户之所急，结合以往生产服务经验，提前生产储备大量雪滚、雪铲、融雪撒布机等设备，确保客户签订合同后，当日发货！工厂从技术部抽调技术研发人员，补充安装调试的售后人员，确保货到，服务到！因为工厂大量现货，在客户签订合同当日，即闪电发货。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116153220929.png&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;11月10日，在设备到达客户工地的同时，豫工技术支持部刘工一早到达客户工地。由于客户订购的是自带动力的雪滚系列，安装调试相对比较简单，拆下保险杠 安装支架 连接电源线，即完成调试工作。刘工表示：豫工的雪滚分为自动动力系列和不带动力系列！对于不带动力的雪滚，客户在订购的时候，可以给工厂提供车型照片、变速箱型号、取力器型号和安装取力器窗口图片以及安装位置等，工厂在雪滚出货时，成套配备相应的螺栓、支架等安装配件，提高效率，免除客户安装时的麻烦。如果你不想从车底盘取力，可以选择自带动力系列，只需要提供安装位置信息即可！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116153250V7.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116153310317.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;设备试机，除雪滚稳定高速旋转，动力强劲！全遥控控制雪滚，上下左右摆动，操作简单！厚厚的积雪瞬间被清扫，雪滚经过的地方，安全感拉满！客户表示：听李总的推荐，定了豫工的除雪滚，今天看试机效果，确实好！还要感谢豫工刘技术员的专业指导，设备很快就调试好了！听工人说：有了这两台扫雪滚，今年的高速道路除雪工期可以缩短不少！&lt;/span&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;'),
(234, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;中铁十二局深江铁路项目计划采购一批隧道物资。9月27日，负责人谭总咨询豫工小导管缩尖、冲孔设备，对比设备性能指标，了解工厂生产实力，审核公司经营资质。客户同时咨询了另外三个厂家，经过半个月的综合对比，最终选择豫工机械作为其设备供应商。10月16日，客户谭总与豫工签订合同！在定购小导管缩尖机、小导管冲孔机的同时，加购数控弯箍机、自动滚丝机、压弯机设备！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-2311161540342E.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;作为18年隧道喷浆支护设备生产厂家，豫工机械通过上万个隧道施工项目的使用检测，性能稳定，作业高效，特别是小导管加工系列、钢筋加工系列、钢板切割系列，门类齐全，型号多样、可满足隧道支护设备一站式采购，省心省力省钱！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154050B3.jpg&quot; style=&quot;width: 900px; height: 505px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154104Q9.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-23111615411YT.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;10月18日，客户定购的50型小导管缩尖机&amp;nbsp; 50型小导管冲孔机&amp;nbsp; WG12数控弯箍机&amp;nbsp; &amp;nbsp;50型自动套丝机 20型八字筋压弯机，完成出厂前检测调试，专车发货，送抵客户工地！10月24日，设备到达深圳市平栾山客户项目工地——深江铁路钢结构加工厂！豫工售后乔工同期到达，开始4天的技术服务！凭借丰富经验，乔工高效完成前期的安装调试工作。通电试机，设备高效工作，完全满足施工需要，顺利通过客户验收！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154136119.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154205241.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154219616.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;培训期间，乔工恪守满意100的服务原则，针对工人操作0基础的情况，细心讲解、耐心指导，确保工人完全掌握操作要领。即使结构复杂的数控弯箍机，乔工表示：作为智能设备，数控弯箍机操作很简单，对于没有任何经验的工人来说，也很容易上手，只要认识数学，就能操作。这个设备劲大，效率高，可以完美地帮工人解放双手！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-23111615423JO.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/231116/2-231116154250R8.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;客户表示：豫工的设备就是牛！现在加工车间里，5台设备高效工作，保证项目上工程需要！就是辛苦乔工了，来到工地这几天，他一直在忙着调试设备，培训工人，如今工人对每台设备都能熟练操作了！选择豫工真的很省心！&lt;/span&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;'),
(235, 1, 10, '&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5月20日，河南夏邑住建局计划采购防汛泵车，根据客户对设备流量和性能的要求，产品经理推荐300方、500方、1000方永磁防汛泵车。作为政府采购项目，客户对质量、细节要求严格，咨询多个厂家后，选定包括豫工在内的三个厂家，提交设备方案，做最后对比。产品经理提交的方案中，充分体现了豫工人对细节的追求，不仅对永磁防汛泵的结构做客观展示，对核心部件如发电机组品牌、永磁泵国家级检测认证、关键配件配置也一 一标注，方便客户直观了解。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51010141.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;经过2个月的慎重对比，客户最终选定豫工作为本次防汛泵政府采购的供货厂家，并于7月10日，签订定货合同。客户最终选定的设备型号为300方永磁防汛泵车和500方永磁防汛泵车。其中，300方防汛泵车，配18kw 常柴发电机组。500方永磁防汛泵车配30kw潍柴发电机组。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51149492.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;此次客户选择豫工，不仅与产品经理专业细致的方案密不可分，更与公司对设备的细节打造密切相关。作为18年防汛泵生产厂家，做细节一直是豫工人的专长，发展至今，公司在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51239207.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51302292.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 客户定购的永磁防汛泵系列，除了硬核配置，在细节方面也堪称完美，比如：设备特添加照明灯结构，功率35W，光通量10001m，上下角度可做100度调整，提高野外作业的便利性！从整体上看，该系列永磁泵车整体美观大方，布局合理，搭载智能设备，可手机端和电脑端远程控制，工作效率高。可视化操作面板，操作简便，每一处细节都为应急抢险而来。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ514133N.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 夏季汛期来临，超强级台风“杜苏芮”靠近，豫工防汛泵需求量暴增，原本300方永磁泵搭载的2轮拖挂，仓库刚好用完。恰逢河南多日细雨连绵，为保证如期交货，工厂与客户沟通后，免费为客户升级为4轮拖车。7月17日，永磁防汛泵车通过严格质量检测，从工厂发货，18日到达客户指定位置，距离合同约定到货日期，提前4天！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51501520.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 与设备一起到达的，还有豫工机械售后与技术支持部乔工，凭借丰富的服务经验，乔工很快完成设备安装调试。500方泵车试机，出水口水量足，排水量每小时可达600m3，扬程达到9米以上，可同时满足每小时排水量500方，扬程11米的防汛要求。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ51G64S.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 培训过程中，借助智能化操作面板，快速接头，工作人员很快掌握使用方法！经客户最终确认，设备顺利交接。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230808/2-230PQ5160C02.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;厂家服务非常用心，设备到货比预定时间提前了4天，感谢豫工对我们工作的支持！刚见到设备时，让我们眼前一亮，外壳喷漆细腻光滑，饱满均匀，明亮如镜，对于经常接触水的设备，有助于防水防潮，对保养至关重要！设备出水口水量足，流量大！操作也简单，真的是设备好，服务棒，很满意！&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(236, 1, 10, '&lt;h3&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;豫工故事&lt;/span&gt;&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;客户谭总长期从事混凝土护坡支护项目，一直租赁混凝土湿喷机施工，却因为设备陈旧，遭遇上水慢、压力低、流量小......等问题的困扰。2023年2月，客户咨询豫工液压湿喷机，因为工程量小，最终还是选择租赁设备施工。然而，合作虽然未成，沟通从未间断！豫工产品经理的专业过硬，服务耐心，给客户留下深刻的印象，赢得客户的信任。租赁设备施工中遇到问题，他总是向豫工咨询解决办法。作为深耕机械行业18年的厂家，豫工人常年与工程人打交道，深知做工程的不易，更理解施工中设备出现问题，工程人对工期的焦虑。所以，对于客户的咨询，产品经理总是有问必答，无论时间早晚、不分上班周末。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531140949253.jpg&quot; style=&quot;width: 341px; height: 489px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141004217.png&quot; style=&quot;width: 375px; height: 489px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;今年五月，客户开始负责厦门轨道交通某地铁站喷浆支护工程，喷浆面积30000平方，按照甲方要求，客户工期压力很大，考虑到之前租赁湿喷机遇到的问题，客户决定采购新设备，提高施工效率，确保工期不误。长期租赁设备的经验，让客户清楚：售后服务是与设备品质同等重要的存在，厂家长期的维护保养支持是设备高效运转的关键，湿喷机也不例外！为了买到心仪的设备，客户咨询对比了多个厂家，并到当地的湿喷机工厂实地考察。综合对比下来，客户发现各个厂家的湿喷机外观大致相似，内部结构却大不一样！为此，客户详细对比设备参数，系统学习内部结构，对电机、速凝剂泵等部件进行多家对比。最终选择豫工，据产品经理解释，是豫工湿喷机的内部结构优势决定的。豫工湿喷机采用先机的液压系统，优质的速凝剂泵，一级能效电机和双泵动力系统。更重要的是豫工一年质保，终身维护的服务承诺，彻底解除客户的后顾之忧。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-23053114114KS.jpg&quot; style=&quot;width: 900px; height: 418px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141203133.png&quot; style=&quot;width: 900px; height: 670px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;根据客户的工程情况，产品经理为客户推荐豫工90型液压湿喷机，喷浆效率8立方/h,喷浆骨料直径5-10mm，搭配110kw20立方空压机,确保混凝土浆料输送距离达到100米。5月9日，客户签订合同，并当天发货。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141252H2.jpg&quot; style=&quot;width: 900px; height: 676px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141311623.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5月14日下午，液压湿喷机到达客户工地后，5月15日一早，豫工机械售后与技术支持部乔工，凌晨出发前往新郑机场，乘坐早上6：30的飞机，奔赴客户工地。上午9:30左右，乔工到达客户工地，开始液压湿喷机的技术服务，安装设备、布置电源、接风管、喷浆管、水、电等，凭借多年服务经验，有条不紊开展试机前的准备工作。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141402495.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-23053114142B63.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;设备试机，90型液压湿喷机在双泵加持下，喷浆压力高，工作效率高。骨料粒径8-10mm的混凝土料快速喷出，一小时喷浆8立方左右。喷射出的混凝土浆料与护坡壁密切服帖、喷浆面密实、均匀、平整，无裂缝、漏喷现象。试机期间，乔工给工人讲解设备的操作要领、注意事项，并重点强调凝剂泵、喷浆管、S管、料斗及料缸等的日常保养细节。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-23053114163cP.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230531/2-230531141622649.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/p&gt;&lt;h3&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;客户反馈&lt;/span&gt;&lt;/h3&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;据工人反馈，设备挺好用的，操作简单，喷浆也稳定。出浆口压力大，比之前租赁的老旧设备，效率提升很多。感谢豫工对我们的鼎力支持！感谢技术员的用心指导，设备试机时，他一直在现场盯着，根据工况反复调整设备，直到处于最佳工作状态！对于工人提出的问题总是耐心解答，一一回复。真的是很有责任心的企业，感谢豫工。&lt;/span&gt;&lt;/div&gt;'),
(237, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;客户负责中泰高铁——超前支护工程项目。2021年9月，客户首次咨询豫工液压湿喷机，工字钢弯拱机等设备，同时咨询了河南、湖南至少5个生产厂家。2021年12月5日，客户到访公司总部——郑州运营中心，并考察了豫工机械隧道支护设备生产基地。客户看到豫工门类齐全的设备生产线，庞大的仓库备货，完全满足其隧道物资一站式采购的需求，非常满意，从而达成合作意向！&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-23032414562b95.png&quot; style=&quot;width: 900px; height: 899px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2022年2月，客户第一次下单2台双喷头液压湿喷机，并在之后的时间里持续复购，截至2022年底，客户已订购设备6次，总货款达千万以上。目前中泰铁路Muak LeK隧道四个站口，有三个站口都在使用豫工的设备。作为2022年的明星客户，中泰高铁Muak LeK隧道以其使用设备数量和使用时长，成为豫工2023春季巡检的第一站，检修对象包括液压湿喷机、混凝土输送泵、工字钢弯拱机、混凝土搅拌站等隧道工程设备！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324144325F3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;“豫工机械春季检修”是公司为助力客户高效施工而发起！每逢年后施工旺季，售后部门会评估重点设备的使用情况和时间节点，进行“大体检”、“大检修”，提升工作效率，延长使用寿命，为客户工程保驾护航，真正做到终身维护的承诺！到今天，豫工已坚持了18年。2023.2.3，春季检修按下启动键，豫工机械技术与售后服务部张工乘飞机，从郑州出发，飞往泰国曼谷，赶赴客户工地——中泰高铁项目Muak LeK隧道3-2出口，为客户在用的豫工隧道支护设备做检修保养。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-23032414441X30.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;font-size:16px;&quot;&gt;经过三个小时飞机+三个小时汽车的奔波，张工顺利到达客户工地，稍作休整后，带领工人开始全面检修工作！张工仔细听取工人反馈，带领工人对设备停机检修，大到湿喷机的速凝剂泵、眼镜板，小到切割环、小端，开展地毯式排查体检，并进行恢复性整修工作。经过紧锣密鼓的系统检修，工地设备“满血复活”，高效运转，为中泰高铁隧道支护建设开足马力，大展身手！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324144514457.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;font-size:16px;&quot;&gt;感谢豫工对我们技术支持，派过来的工作人员很专业，很负责，带领工人对设备进行了全方位“体检”，以后我们用着就更放心了！听工人反映：检修之后，设备比之前更好用了！感谢豫工，免除了我的后顾之忧！近十年来，豫工机械以其“高性价比”的设备得到越来越多国外客户的认可，来司访问、工厂考察的客户络绎不绝，遍布全球100多个国家和地区，豫工质造，值得信赖！&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324144624953.png&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(238, 1, 10, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;四川客户承接中铁六局康新高速钢结构加工项目，按照甲方（中铁六局项目部）要求，批量采购一批隧道物资设备，共计六款7台。&lt;br/&gt;为了买到符合要求的设备，也为了节约成本，客户走访对比了多个生产厂家。产品经理结合客户钢筋加工尺寸、钢板切割厚度、工期进度，制定了合理的设备采购方案：&lt;span style=&quot;color:#000000;&quot;&gt;&lt;strong&gt;300型数控型钢冷弯机、数控龙门等离子切割机、50型小导管缩尖机、50型数控小导管双头割孔机、220型全自动网片排焊接生产线&lt;/strong&gt;&lt;/span&gt;等，并在众多厂家中脱颖而出，最终赢得客户认可！&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301A250W5.png&quot; style=&quot;width: 900px; height: 901px;&quot; title=&quot;隧道物资部分设备展示&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;客户为什么选择豫工？&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工机械——隧道物资一站式采购最优选择！&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;此次客户采购设备数量庞大，虽同属隧道物资，却涉及多个品类。豫工机械作为18年隧道物资生产企业，品类齐全，型号多样，完全满足客户一站式采购需求。因设备同出一个工厂，公司通过整合物流、售后资源，尽量减少客户支出，从而给到客户一个更具竞争力的价格。另外，豫工常年从事隧道喷浆支护设备售后服务，轻车熟路，对于隧道设备，没有搞不定的，为后期设备维护提供强有力的技术支持，放心省心。&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301A544456.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;豫工机械钢筋网片排焊机生产车间&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;加班加点 如期交货&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;12月以来，伴随疫情政策优化调整，各地工程有序复工，&lt;strong&gt;隧道物资&lt;/strong&gt;设备需求剧增，工厂每天订单爆满；为保证客户工期不误，生产车间加班加点，确保按期交货！12月26日，价值34万的7台隧道支护设备，通过严格质检，专车发货，送往客户工地！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301AFL91.png&quot; style=&quot;width: 900px; height: 501px;&quot; title=&quot;豫工机械钢筋网片排焊机发货现场&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size:16px;&quot;&gt;1月2日，在与发货部确认到货日期后，豫工售后技术部王工辗转1500多公里，风尘仆仆，到达海拔3000多米的四川甘孜康定客户工地，带领工人紧锣密鼓开展设备安装调试工作！&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301AK02T.jpg&quot; style=&quot;width: 900px; height: 585px;&quot; title=&quot;豫工机械客户中铁六局施工工地&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301APD57.jpg&quot; style=&quot;width: 900px; height: 674px;&quot; title=&quot;豫工机械售后带领工人调试安装设备&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301AR1926.jpg&quot; style=&quot;width: 900px; height: 674px;&quot; title=&quot;豫工机械售后带领工人调试安装设备&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size:16px;&quot;&gt;就在王工一心扑在工作上时，猝不及防，遭遇了严重的高原反应，连续三天头晕恶心吃不下饭，感谢客户送来了爱心药品，方解了燃眉之急！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301ATW59.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size:16px;&quot;&gt;王工凭借丰富经验，统筹安排，以最快速度完成调试工作！通电试机，每台设备稳定运行，钢筋标准件被高效生产，流畅输出。甲方（中铁六局康信高速项目部）现场视察，对设备的性能、生产能力很满意，确定了与客户的后续合作顺利进行！&lt;/span&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301A422E2.jpg&quot; style=&quot;width: 900px; height: 674px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;font-size:16px;&quot;&gt;培训过程中，对于常年操作机械型设备的工人来说，初次接触数控型设备，难免有些吃力！王工手把手教工人操作步骤，带领工人反复练习，直到熟练掌握操作要领。&lt;/span&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301A95W13.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;豫工机械售后带领工人操作设备&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301F020T7.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;豫工机械售后带领工人操作设备&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color:#000000;&quot;&gt;客户反馈&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;设备工作状态很好，工人正在车间熟练操作他们！感谢王工的用心指导，设备到货后，他一直在车间盯着，很负责，对工人很耐心，7台设备，他对每台设备都很了解，大家都很信任他！&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;感谢豫工对我们的全力支持，前两天工地停电，技术员一直在这里耐心等待，没有催促，没有给我们压力！下次定设备，还要找他们！&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301F124128.jpg&quot; style=&quot;width: 900px; height: 1947px;&quot;/&gt;&lt;/div&gt;'),
(239, 1, 10, '&lt;div&gt;10月面对疫情压力，豫工人迎难而上，捷报频传，业绩一路飘红。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q13S3Q3.jpg&quot; style=&quot;width: 1024px; height: 768px;&quot;/&gt;&lt;br/&gt;\r\n 然而，成交只是开始，服务永无止境！10月10日，为解决因疫情售后人员出行不便的问题，公司特发起服务动员令，从无疫情地区的本部工厂一线，抽调8位技术工程师，组建应急技术服务小组，代替售后部门职能，赴各地客户工地，提供技术服务。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q13954G3.jpg&quot; style=&quot;width: 900px; height: 214px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;我们截取了一名工程师20天（10.10-11.1）的工作日志，来记录这次意义非凡的行动。下面跟随王工的脚步，一起见证豫工人的极致服务！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q14042536.jpg&quot; style=&quot;width: 1024px; height: 768px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;10月10日，应急服务小组王工从本部工厂出发，前往浙江杭州，开启新一轮的客户服务。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q14151H3.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;strong&gt;服务第一站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;浙江杭州泥浆分离器安装调试&lt;br/&gt;&lt;div&gt;服务时间：10.13&lt;/div&gt;&lt;div&gt;设备型号：250型泥浆分离器&lt;/div&gt;&lt;div&gt;服务项目：中铁14局水面路桥立桩泥沙净化&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q14231C3.jpg&quot; style=&quot;width: 900px; height: 495px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;服务第二站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;江西赣州小导管缩尖、冲孔机安装调试&lt;/div&gt;&lt;div&gt;&lt;div&gt;服务时间：10月16日&lt;/div&gt;&lt;div&gt;服务项目：中铁十八局文昌隧道进口钢筋加工&lt;/div&gt;&lt;div&gt;设备型号：42♯小导管尖头机、42♯小导管冲孔机&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q14413263.jpg&quot; style=&quot;width: 900px; height: 494px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;strong&gt;服务第三站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;浙江玉环市泥浆分离器调试&lt;/div&gt;&lt;/div&gt;&lt;div&gt;服务时间：10月19日&lt;/div&gt;&lt;div&gt;设备型号：150型泥浆分离器&lt;/div&gt;&lt;div&gt;服务项目：中铁24局打桩机泥浆处理&lt;/div&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q1445bM.jpg&quot; style=&quot;width: 900px; height: 497px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;服务第四站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;广西白色喷播机安装调试&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;div&gt;服务时间：10月22日&amp;nbsp;&lt;/div&gt;&lt;div&gt;设备型号：88kw液力喷播机&lt;/div&gt;&lt;div&gt;服务项目：国道边防工程绿化项目&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q15055246.jpg&quot; style=&quot;width: 900px; height: 503px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;strong&gt;服务第五站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;浙江台州泥浆分离器安装调试&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;服务时间：10月24日&lt;/div&gt;&lt;div&gt;设备型号:150型泥浆分离器&lt;/div&gt;&lt;div&gt;服务项目：高铁桥墩泥浆处理&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q1522S63.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/strong&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;服务第六站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;海南临高县喷播机安装调试&lt;/div&gt;&lt;/div&gt;&lt;div&gt;服务时间：10月29日&lt;/div&gt;&lt;div&gt;设备型号：4方液力喷播机&amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/div&gt;&lt;div&gt;服务项目：边坡绿化项目&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q153393M.jpg&quot; style=&quot;width: 900px; height: 499px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;服务第七站&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;昆明市曲靖洗沙生产线安装调试&lt;/div&gt;&lt;/div&gt;&lt;div&gt;服务时间：11月1日&lt;/div&gt;&lt;div&gt;设备型号：洗沙生产线&lt;/div&gt;&lt;div&gt;服务项目：制砂厂圆锥破破碎生产线&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221118/2-22111Q154335L.jpg&quot; style=&quot;width: 900px; height: 674px;&quot;/&gt;&lt;br/&gt;\r\n 结束洗沙生产线售后服务后，王工已与近日返回本部工厂，修整后，投入新一批客户服务中去。这就是豫工对客户负责的态度，为每一份信赖，兑现百分百的承诺；也是豫工应对突发事件的处置能力，永远有替补方案，planB planC ......&lt;/div&gt;&lt;div&gt;目前，豫工机械正值双11黄金周，超低价，超省钱，超实惠！你值得拥有！&lt;br/&gt;\r\n 是的，你永远可以相信豫工机械，这个拥有18年服务经验的企业，始终把售后服务与产品质量，置于战略性地位，为广大客户提供专业、及时、无忧的售后服务，为客户工程保驾护航。&lt;/div&gt;'),
(240, 1, 10, '&lt;h1&gt;客户好评&lt;/h1&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;因为朋友三年前订购豫工的30型筛土机，设备一直运转良好，对豫工品牌比较认可！他一直在微信朋友圈关注豫工的发展动态，了解到近几年，豫工喷播机一直在出货。特意向我推荐，现在看来，施工效果确实不错，与产品经理介绍的效果差不多，完全满足施工需求，选择豫工，就是放心。&lt;/span&gt;&lt;/p&gt;&lt;h1&gt;施工现场&lt;/h1&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011112612533.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011112PUF.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011112R1U8.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011112S4216.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;'),
(241, 1, 10, '&lt;h1&gt;客户好评&lt;/h1&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;必须为豫工的专业服务点赞，提供的施工方案，实用性强，施工成本低，真是省心、省力、省钱！据现场工人反馈，此次购买的全气动钢筋网片焊机不仅焊点牢固，自动落料，焊接速度快，而且定位精准，网格尺寸标准。另外，设备在运行过程中没有出现任何故障，减少了维修时间和费用，这对提高生产效率，保证工期至关重要。&lt;/span&gt;&lt;/p&gt;&lt;h1&gt;案例现场&lt;/h1&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011101003358.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011101031461.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-221011101100527.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221011/2-2210111011422F.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;'),
(242, 1, 10, '&lt;h1&gt;客户好评&lt;/h1&gt;&lt;p&gt;&lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;喷浆速度很快，操作很简单！这是设备给我最大的印象！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;感谢技术人员的辛勤付出，很专业也很有责任心，总是耐心指导工人操作步骤，听工人说他们现在可以熟练掌握设备的安装、拆卸、操作、保养步骤。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;选择豫工，我很放心。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;h1&gt;施工现场&lt;/h1&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K544B2.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K61YG.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K63K93.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101KF22a.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;'),
(243, 1, 10, '&lt;h1&gt;&lt;span style=&quot;color:#0000cd;&quot;&gt;施工现场&lt;/span&gt;&lt;/h1&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101IP53G.jpg&quot; style=&quot;width: 900px; height: 405px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101J232611.jpg&quot; style=&quot;width: 900px; height: 505px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101ISAI.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101IZG45.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;'),
(244, 1, 10, '&lt;h1&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;&lt;span style=&quot;font-size:36px;&quot;&gt;&lt;strong&gt;客户好评&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/h1&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;客户盛赞豫工液压湿喷机湿喷效果杠杠滴，现场操作工人说：这设备陡起（徐州方言：太厉害的意思），很好！到目前为止，没有听到工人反馈任何故障问题，这也减少了维修时间和费用，提高了生产效率。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;h1&gt;&lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 255);&quot;&gt;&lt;span style=&quot;font-size: 36px;&quot;&gt;案例现场&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h1&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010160125Y8.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010160150T0.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-22101016020IQ.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010160225X0.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;'),
(245, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户评价&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;因为之前的合作，一直在朋友圈关注豫工的发展动态，了解到客户对于抛丸机使用反馈一直很好，此次工地需要该设备，就直接下单了，现在看来，施工效果果然不错，完全满足防水施工需求，选择豫工，就是放心。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;施工现场展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210517/2-21051G55539514.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210517/2-21051G55F2501.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210517/2-21051G55600521.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210517/2-21051G55639346.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210517/2-21051G55H3360.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt; &lt;strong style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px; text-indent: 32px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(246, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;破桩过程中，赶上中铁大桥局领导视察现场！在全程观看破桩机施工后，将苏工找到身边，交流破桩心得！&lt;/div&gt;&lt;div&gt;领导表示：项目上，曾经使用过其他厂家的破桩机，因为速度、效率、破桩程度不太理想，目前已不再使用。现在这款设备破桩效果，与之前相比，效果不错。&lt;/div&gt;&lt;div&gt;“在同一场地，同等地质条件下，豫工破桩机比之前那款相比，破桩速度更快，效率更高！”另一负责施工的领导介绍说。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;施工现场&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G604335G.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6045B06.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6051Gb.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G60530622.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6061U38.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(247, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户评价&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;听朋友介绍，才开始了解豫工的抛丸机，工期紧，仓促下单，没想到效率、速度都这么棒！按照这个速度，&lt;br/&gt; 4天即可保质保量完工，不错！&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162120910.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162134F2.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162144J3.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162154P6.jpg&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032616220BT.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(248, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;客户为豫工破桩机的工作效率点赞，是人工的数十倍！&lt;/div&gt;&lt;div&gt;客户对调整模块数量的工作专业度表示高度认可，感谢豫工售后服务团队的热情服务和耐心指导。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326144K5619.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326144PbT.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326143R2359.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326143U23R.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(249, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;客户表示:总包对防水效果的认可，让我对豫工设备很放心。购买成套设备，售后很方便，听工人反馈设备很好用，操作简单、维护方便，让我很省心。&lt;/div&gt;&lt;div&gt;天气炎热，工人室外作业很辛苦，设备高效作业，大大减轻工人的工作量，工作效率提高了，这对如期完工很重要！&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326151424a9.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032615143NM.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326151450608.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261515033X.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032615151QB.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(250, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;豫工非固化喷涂机太棒了！与租用的设备相比，综合施工效率提高了4-5倍，非常好！今年天已经冷了，明年开春再来，继续购买。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154T2Q7.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154UXM.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261549113W.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261549245K.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154935108.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154944420.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(251, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;结束客户服务第5天，张工电话回访客户设备使用情况。客户表示：喷涂机效率挺高，溶胶速度也可以，工人用起来很顺手。因抛丸机退换货拉下的工期有望补回来，项目不出意外，可以如期完工，交付甲方。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326152I1355.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326152J5550.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326152KA47.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326152PV24.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(252, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户评价&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;钢板除锈施工，第一次用磨光机，有粉尘，环保局不通过，改用湿喷机，排出的污水污染下水道，村委会不让用，后选择豫工路面抛丸机，无尘环保，客户满意，甲方点赞&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162620649.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162632Z0.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162642605.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162AR48.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;');
INSERT INTO `dr_1_anliguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(253, 1, 10, '&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户评价&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/case_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;破桩之前，客户反复强调完好保留桥梁桩竖向钢筋。试机结果完美达成客户要求。豫工破桩机被客户称为“破除桥梁桩专用神器”。&lt;/div&gt;&lt;div&gt;客户表示：豫工破桩机截桩不留芯，避免二次人工处理，大大减少破桩工程人工投入，为确保工期意义重大！&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/case_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032616321b29.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326163230145.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326163240E7.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032616325U58.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326163310505.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(254, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;在结束服务第五天，乔工回访客户设备施工情况，对方表示：防水施工速度和防水施工效果，项目部都非常满意，已成功签订合同，明年5月份开工，完成9万平地下车库顶板防水施工。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326153953642.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154012393.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154023294.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326154041111.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261541001P.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(255, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户好评&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;部队领导对豫工550型路面抛丸机施工效果很满意，并称赞豫工机械贴心的售后服务远超预期！&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326160135M7.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326160152B2.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326160203596.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261602163B.png&quot; style=&quot;height: 415px; width: 691px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(256, 1, 10, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;客户反馈&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;客户刘先生高度称赞营销顾问的专业推荐，对调试路面抛丸机配发的切丸非常满意，效果明显，完全满足施工要求。&lt;/div&gt;&lt;div&gt;非常认可豫工550型路面抛丸机，不仅工作效率满足要求，而且操作简便，在毛工的耐心指导下，工人虽年过六旬，但上手很快，完全不影响施工进度。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032616112A61.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326161140524.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032616115R31.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326161221F5.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261612314A.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(361, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户在新疆从事除雪设备经营多年，对雪滚非常懂行！2023年10月中旬，客户咨询豫工除雪滚，因为采购数量大，客户同时咨询并现场考察了多个雪滚厂家。经过近1个月的综合对比，豫工雪滚以超高的性价比赢得客户信赖，并最终达成采购合同！客户此次共采购除雪设备14台，其中包括3米液压雪滚8台，3.5米自带动力除雪滚一台，3米自带动力除雪滚3台，3米轻型雪铲1台，10立方融雪剂撒布机1台。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276244b635bb.jpg&quot; title=&quot;5b2eb23d036ea6fe1dc753dad25f142&quot; alt=&quot;5b2eb23d036ea6fe1dc753dad25f142&quot; width=&quot;900&quot; height=&quot;600&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276268273a32.jpg&quot; title=&quot;雪铲&quot; alt=&quot;雪铲&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;11月13日，14台除雪设备完成出厂检测，连夜物流发货，并于11月20日到达客户指定位置。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17022763328515e5.jpg&quot; title=&quot;735037c5bd3f4695300665ace36a014&quot; alt=&quot;735037c5bd3f4695300665ace36a014&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;11月20日，豫工售后技术支持部张工乘飞机抵达新疆，按照客户要求，张工第一时间赶到客户要求的指定位置——新疆伊犁环卫部门，对第一批次雪滚设备安装调试！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276377b6ca38.jpg&quot; title=&quot;1702015871454&quot; alt=&quot;1702015871454&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;调试现场，张工遭遇连日冷雨，为了早日完成雪滚调试，他克服时差不适，与现场工作人员共战一线，争分夺秒，风雨无阻！经过四天加班加点的努力，三台雪滚安装完毕，设备试机，雪滚工作一切顺利，待环卫部门工作人员掌握设备的操作步骤，张工完成此次技术服务第一阶段的工作任务。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170227643505d90a.jpg&quot; title=&quot;微信图片_20231130145015&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276435e29fe0.jpg&quot; title=&quot;微信图片_20231130145035&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;11月25日，来不及休息的张工，马不停蹄来到另一指定位置，开始5台雪滚、1台10立方融雪剂撒布机、1台雪铲的安装调试。为了提高工作效率，客户调来2名电气焊工协助。在大家齐心协力的努力下，5天完成6台设备的安装调试。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170227647765e392.jpg&quot; title=&quot;微信图片_20231130144929&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276477ab9f1c.jpg&quot; title=&quot;微信图片_20231130144950&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;12月1日，张工一行来到某景区管理中心，为剩余的4台雪滚做安装调试，凭借丰富经验，在管理中心工作人员的配合下，雪滚调试任务很快完成。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276524f18be8.jpg&quot; title=&quot;安装过程 (7)_副本&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170227652417d851.jpg&quot; title=&quot;安装过程 (15)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17022765242c9cd9.jpg&quot; title=&quot;安装过程 (26)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;12月6日，14台除雪设备已全部完成最后的验收工作，运行稳定，即将开赴一线进行除雪作业！张工同时乘飞机返回郑州。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17022766127d1702.jpg&quot; title=&quot;@TD@76IW_~B(X09MOFW{AHH&quot; alt=&quot;@TD@76IW_~B(X09MOFW{AHH&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170227665897eebb.jpg&quot; title=&quot;$GJ2BADNU0[89INF%5BH4(Q&quot; alt=&quot;$GJ2BADNU0[89INF%5BH4(Q&quot; width=&quot;800&quot; height=&quot;670&quot; border=&quot;0&quot; vspace=&quot;0&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作为道路环卫清洁设备制造的主力军，豫工机械18年奋战除雪保通设备、抗洪救灾设备研发生产的路上，关键时刻，以极强的战斗力、执行力为客户提供专业技术方案和售后保障服务。&lt;/span&gt;&lt;/p&gt;'),
(362, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;为落实高速公路除雪保通工作部署，黑龙江高速计划采购一批除雪设备，2023年10月，负责人宋总咨询豫工除雪滚，客户同时咨询了多个厂家。11月6日，宋总与项目技术员来豫工工厂考察，在了解了工厂的生产规模、设备的性能指标，售后的技术支持后，与豫工机械签订采购合同！本次合作，客户共采购15台除雪设备，除了原定的10台3.5米除雪滚，又追加4台雪铲，1台液压融雪撒布机。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702276962c57ead.jpg&quot; title=&quot;微信图片_20231122160132&quot; alt=&quot;微信图片_20231122160132&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;自合同签订开始，在工厂领导的统一指挥下，技术部安排高效的出厂检测以及交付计划，售后部门制定完善的安装调试方案，发货部门全力以赴投入到保质、保量、保工期的工作中，业务经理积极对接客户，沟通交流意见，确保设备按照合同要求如期交付。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;2023年11月8日，15台冬季除雪设备完成最后的出厂检测，专车发货！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/17022769860695b3.jpg&quot; title=&quot;微信图片_20231122160114&quot; alt=&quot;微信图片_20231122160114&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;11月15日上午，载着15台除雪设备的拖车缓缓驶入黑龙江绕城高速养护中心，同期抵达的还有豫工的售后技术人员。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;交付现场，豫工技术员韩工指导养护中心的工作人员、汽修技术人员完成对雪滚、雪铲等设备的安装调试，并进行现场培训。韩工详细介绍了设备的操作特点、注意事项，并现场演示操作流程，专业尽责的服务态度赢得高速公路领导的一致认可及好评。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702277083ae159d.jpg&quot; title=&quot;33C@3Z7ADXC1%Y_C{MV$5Q6&quot; alt=&quot;33C@3Z7ADXC1%Y_C{MV$5Q6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702277111e18645.jpg&quot; title=&quot;IMG_20221221_162450833_original&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/1702277111cfb5f2.jpg&quot; title=&quot;IMG_20221222_113551574_original&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;5天的售后服务，调试的最后一天，恰逢客户所在地突降大雪，雪滚现场试机，整车作业最大速度可达30km/h，运行过程中，道路积雪被高速抛起至路边，完全实现除雪任务，满足客户对高速公路作业速度的要求，这也标志着本项目的完美交付。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://lantianxunrui.hnyugong.com/uploadfile/ueditor/image/202312/170227715596541d.jpg&quot; title=&quot;微信图片_20231122160220&quot; alt=&quot;微信图片_20231122160220&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;今冬以来，豫工第八代除雪滚以安装简单 价格实惠的高性价比，受到广大客户朋友的欢迎，出货量大！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;它装卸方便、操作便捷、自动平衡、安全耐用，成为豫工除雪系列设备的销量之最！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;该款设备可以根据路况进行匹配定制，不挑车型，保护路面，除雪效率高，彻底干净，辅以豫工专业团队技术指导培训及24小时售后服务，受到广大客户的青睐。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(363, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;冬季来临，湖北鄂州某标段市政高速公路因除雪需要，计划采购雪滚设备，经同一高速公路相邻标段负责人推荐，咨询豫工除雪滚刷。给客户推荐豫工雪滚的李总，跟客户承包同一高速公路的不同标段，2022年10月采购豫工马路吹扫机，根据工人反馈，设备风量大、吹扫效率高。因为设备性价比高，2022年12月李总又陆续批量采购豫工融雪撒布机、雪滚、雪铲设备，清雪除雪设备一站式配齐。去年高速公路大雪，李总承包的标段清雪除雪效率很高，工人有条不紊地工作，效率提升了一倍。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;因为有老客户使用证明，客户采购过程很顺利，在了解了设备的性能和参数后，即签订合同，一次下单两台，全款成交！整个合作如德芙般丝滑。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023686521e347b.jpg&quot; title=&quot;640&quot; alt=&quot;640&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户采购的是3米自带动力除雪滚，转速280-300r/min。液压独立动力单元驱动雪滚上下左右摆动，左右摆角30度，潍坊37kw柴油机，尼龙钢丝混合刷片材质，动力强劲除雪效率高，全遥控和手动操作两种方式，使用方便。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368665f6b7a3.jpg&quot; title=&quot;640 (1)&quot; alt=&quot;640 (1)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;冬季来临，豫工机械急客户之所急，结合以往生产服务经验，提前生产储备大量雪滚、雪铲、融雪撒布机等设备，确保客户签订合同后，当日发货！工厂从技术部抽调技术研发人员，补充安装调试的售后人员，确保货到，服务到！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368683c65cfb.jpg&quot; title=&quot;640 (2)&quot; alt=&quot;640 (2)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;因为工厂大量现货，在客户签订合同当日，即闪电发货。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368697b067ba.jpg&quot; title=&quot;640 (3)&quot; alt=&quot;640 (3)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;11月10日，在设备到达客户工地的同时，豫工技术支持部刘工一早到达客户工地。由于客户订购的是自带动力的雪滚系列，安装调试相对比较简单，拆下保险杠 安装支架 连接电源线，即完成调试工作。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368713c350d5.jpg&quot; title=&quot;640 (4)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368713db13ba.jpg&quot; title=&quot;640 (5)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;刘工表示：豫工的雪滚分为自动动力系列和不带动力系列！对于不带动力的雪滚，客户在订购的时候，可以给工厂提供车型照片、变速箱型号、取力器型号和安装取力器窗口图片以及安装位置等，工厂在雪滚出货时，成套配备相应的螺栓、支架等安装配件，提高效率，免除客户安装时的麻烦。如果你不想从车底盘取力，可以选择自带动力系列，只需要提供安装位置信息即可！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368731ea62f5.jpg&quot; title=&quot;640 (6)&quot; alt=&quot;640 (6)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备试机，除雪滚稳定高速旋转，动力强劲！全遥控控制雪滚，上下左右摆动，操作简单！厚厚的积雪瞬间被清扫，雪滚经过的地方，安全感拉满！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702368743de7e8a.jpg&quot; title=&quot;640 (7)&quot; alt=&quot;640 (7)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户表示：听从李总的推荐，定了豫工的除雪滚，今天看试机效果，确实好！还要感谢豫工刘技术员的专业指导，设备很快就调试好了！听工人说：有了这两台扫雪滚，今年的高速道路除雪工期可以缩短不少！&lt;/span&gt;&lt;/p&gt;'),
(364, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;中铁十二局深江铁路项目计划采购一批隧道物资。9月27日，负责人谭总咨询豫工小导管缩尖、冲孔设备，对比设备性能指标，了解工厂生产实力，审核公司经营资质。客户同时咨询了另外三个厂家，经过半个月的综合对比，最终选择豫工机械作为其设备供应商。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;10月16日，客户谭总与豫工签订合同！在定购小导管缩尖机、小导管冲孔机的同时，加购数控弯箍机、自动滚丝机、压弯机设备！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作为18年隧道喷浆支护设备生产厂家，豫工机械通过上万个隧道施工项目的使用检测，性能稳定，作业高效，特别是小导管加工系列、钢筋加工系列、钢板切割系列，门类齐全，型号多样、可满足隧道支护设备一站式采购，省心省力省钱！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367097bb323e.jpg&quot; title=&quot;32f8b141d2d63e5bf8bc78305e9772d&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367097a7e7f6.jpg&quot; title=&quot;531428164fe489800b974410e19d8b7&quot; width=&quot;818&quot; height=&quot;460&quot; border=&quot;0&quot; vspace=&quot;0&quot; alt=&quot;531428164fe489800b974410e19d8b7&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367163b937ad.jpg&quot; title=&quot;IMG_20201205_183351&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367163bb0c47.jpg&quot; title=&quot;微信图片_20181025115008&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;10月18日，客户定购的50型小导管缩尖机&amp;nbsp; 50型小导管冲孔机&amp;nbsp; WG12数控弯箍机&amp;nbsp; &amp;nbsp;50型自动套丝机 20型八字筋压弯机，完成出厂前检测调试，专车发货，送抵客户工地！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367465f9f374.jpg&quot; title=&quot;640 (1)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367465c1a35b.jpg&quot; title=&quot;640 (2)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367465fba1ad.jpg&quot; title=&quot;640 (3)&quot;/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;10月24日，设备到达深圳市平栾山客户项目工地——深江铁路钢结构加工厂！豫工售后乔工同期到达，开始4天的技术服务！培训期间，乔工恪守满意100的服务原则，针对工人操作0基础的情况，细心讲解、耐心指导，确保工人完全掌握操作要领。凭借丰富经验，乔工高效完成前期的安装调试工作。通电试机，设备高效工作，完全满足施工需要，顺利通过客户验收！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367524c4835f.jpg&quot; title=&quot;640 (4)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023675248fcb59.jpg&quot; title=&quot;640 (5)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702367524e69d58.jpg&quot; title=&quot;640 (6)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;即使结构复杂的数控弯箍机，乔工表示：作为智能设备，数控弯箍机操作很简单，对于没有任何经验的工人来说，也很容易上手，只要认识数学，就能操作。这个设备劲大，效率高，可以完美地帮工人解放双手！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;'),
(365, 1, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;冬季来临，中国水利水电第七工程局因工程需要，计划采购除雪滚刷，用于水电站地面冬季积雪清除。为了选到高品质的设备，项目方综合对比了多个厂家！经过1个月的综合对比，客户最终选择豫工作为供货方，是对产品经理专业服务和工厂生产实力的认可。为了提高清扫效率，客户选择豫工自带动力系列除雪滚刷，并选用工作宽度3米的机型，用以匹配项目工地的装载机。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/170236630863ab44.jpg&quot; title=&quot;IMG_20230105_143235887_original&quot; alt=&quot;IMG_20230105_143235887_original&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;冬季来临，为应对冬季除雪设备的大量需求，豫工机械工厂未雨绸缪，提前生产大量现货，库存充足，客户无需等待。在公司与水电七局签订合同后，工厂迅速响应，对设备做出厂前功能测试后，闪电发货！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023664995df410.jpg&quot; title=&quot;59a299b417d8650506bc9f061b17abd&quot; alt=&quot;59a299b417d8650506bc9f061b17abd&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;刚刚结束湖南娄底雪滚调试的张工，在确定设备到达时间后，马不停蹄赶赴客户工地——河南洛宁水电站，与设备同时间到达。凭借多年工作经验，张工很快完成设备的安装调试。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702366548d243b0.jpg&quot; title=&quot;IMG_20230105_143224348_original&quot; alt=&quot;IMG_20230105_143224348_original&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/170236665390f355.jpg&quot; title=&quot;A[UJ$K9ZUV3V0(U]03WCIJD&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023666530228fb.jpg&quot; title=&quot;IMG_20230106_093034838_original&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备试机，搭配液压动力站 200W直流电机 37KW潍坊柴油动力，除雪滚双向角度调节，左右摆角30度，雪滚最高转速2400r/min，清扫效率高，完全达到工作指标，客户非常满意！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702366676cd209d.jpg&quot; title=&quot;A[UJ$K9ZUV3V0(U]03WCIJD&quot; alt=&quot;A[UJ$K9ZUV3V0(U]03WCIJD&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;张工表示：客户订购的除雪滚刷，为公司带动力系列扫雪滚，效率高、安装方便！刷片直径800mm,有效清理积雪宽度3000mm,尼龙钢丝混合刷片，除雪效率高，清雪速度20kg/h。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;试机期间，张工给客户讲解设备的操作要领，指导客户遥控控制及手动控制除雪滚，在确认客户完全掌握操作步骤和日常保养方法后，结束本次技术服务！&lt;/span&gt;&lt;/p&gt;'),
(386, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;客户瞿总负责济宁地铁7号线基坑湿喷建设，项目施工面积80000平，喷浆距离50-100米。为了选到合适的设备，客户订购过程特别谨慎，确定合作之前，同时咨询了多个厂家，并对企业的售后服务和生产实力进行了谨慎评估。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;3月29日，瞿总咨询豫工液压湿喷机，产品经理根据客户发来的现场图片，结合工期进度、工程量以及喷浆距离，优先为客户推荐了90型液压湿喷机、16/8电动移动空压机和配套的速凝剂管喷浆管。经过近半个月的综合对比，4月12日，客户最终选定豫工机械为供货合作方。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202406/1717234741657627.jpg&quot; title=&quot;现场照片19&quot; alt=&quot;现场照片19&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;因为项目工期紧急，豫工机械急客户之所急，工厂快速响应，设备当天装车发货，奔赴施工现场。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;4月13日，在设备到达客户工地的同一天，豫工售后与技术支持部韩工乘高铁从郑州出发，当然下午2点到达项目指定位置。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202406/171723475983de34.jpg&quot; title=&quot;现场照片23&quot; alt=&quot;现场照片23&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;由于客户所在施工现场情况特殊，作业面有限，为了赶工期，项目上采用交替施工的模式，白天挖基坑，晚上喷浆加固。所以客户的喷浆作业安排在晚上进行。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;到达现场后，韩工全力配合客户工程进度，第一时间投入到设备的安装调试工作中。指导设备位置固定，接电源线，接风管，接喷浆管，接速凝剂管......在现场工人的配合下，韩工凭借专业技术，6点前完成设备的安装调试指导工作，确保晚上施工不误。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202406/1717234778305873.jpg&quot; title=&quot;现场照片13&quot; alt=&quot;现场照片13&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;晚上9点，施工开始，液压湿喷机动力强劲，平稳喷浆！粒度0.5厘米，使用塌落度180-210度的混凝土浆料，轻松完成50-100米的浆料输送，每小时喷浆5立方。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;韩工表示：液压湿喷机的喷浆量与喷浆距离有关。对于短距离喷浆，喷浆的速度可以调快到6方甚至7方；距离远时，为了避免造成堵管，喷浆速度要稍微降低一些，5方是最优状态。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202406/171723479330b224.jpg&quot; title=&quot;现场照片9&quot; alt=&quot;现场照片9&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;为了保证工程进度，韩工跟随客户的施工进度，昼夜不停，直到凌晨4点，天空微亮方才休息。为了加强工人操作设备的熟练度，第二天，韩工再次到现场指导，直至凌晨2点，工人能熟练操作设备为止。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(51, 51, 51); letter-spacing: 0.544px; background-color: rgb(250, 250, 239); font-family: system-ui, system-ui, system-ui, system-ui; font-size: 24px;&quot;&gt;客户好评&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-family: system-ui, system-ui, system-ui, system-ui; font-size: 12pt;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; background-color: rgb(250, 250, 239);&quot;&gt;第一次合作，为豫工的发货速度和售后服务点赞！感谢他们的鼎力支持，工程进展很顺利！工作人员很尽心，虽然工作到凌晨，却一直耐心地指导工人！真的很放心，下次有需要还选他们。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;'),
(389, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;受强降雨影响，黑龙江五常市牤牛河、拉林河等河流沿岸大量村屯被淹，包括龙凤山镇、志广乡、民乐朝鲜族乡、向阳镇、沙河子镇等地出现不同程度洪涝灾害。截至8月7日，五常市累计转移受灾群众五万多人。相关部门正在加紧抢修道路、电力、通信等相关设施，保证救援抢修任务能够顺利进行。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408294011399.png&quot; title=&quot;D549SBR~T~Q$I6((O25D%$N&quot; alt=&quot;D549SBR~T~Q$I6((O25D%$N&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;为了更快完成抢险、恢复工作，防汛应急相关部门采购豫工6台1000方大流量防汛泵车，勇战暴雨洪涝灾害。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;客户此次订购的防汛泵车，流量1000方，扬程12米， 吸程6米，配套84KW的6缸潍柴柴油机，进口直径300mm&amp;nbsp; 出口直径300mm。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408392038649.jpg&quot; title=&quot;2021_07_28_14_02_IMG_2716&quot; alt=&quot;2021_07_28_14_02_IMG_2716&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;防汛泵配套无堵塞自吸式排污泵，集自吸和无堵塞排污于一体，可用于输送含有悬浮颗粒及纤维杂质的液体。采用叶轮防堵设计，排污能力强，高效无堵塞。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;自吸式排污泵采用水力模型设计，效率比一般自吸泵高3倍左右，自吸性能好，自吸时间短。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408423be216d.jpg&quot; title=&quot;2021_07_28_10_19_IMG_2704&quot; alt=&quot;2021_07_28_10_19_IMG_2704&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;作为防汛泵行业18年生产厂家，豫工机械在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业，累计服务防汛泵客户30000+！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;豫工机械工厂内景展示&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408452aa85aa.jpg&quot; title=&quot;1e93820b-f8d1-4dfb-91cf-26f13c9df0e9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408452ed976b.jpg&quot; title=&quot;95a66f6b-8220-45e1-9847-310725ade97c&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;争分夺秒 火速交货&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;台风频繁登录，防汛形势严峻，豫工机械紧急启动应急预案，全体豫工人急客户之所急，严阵以待，迅速响应、加班加点，保质量 保供货，尽早将防汛泵送到应急救灾前沿。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408474ac396a.jpg&quot; title=&quot;1 (16)&quot; alt=&quot;1 (16)&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;飞机售后&amp;nbsp; 向险而行&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;为保证设备早日投入防汛工作，豫工机械售后服务部张工乘飞机，从北京防汛泵售后现场出发，赶赴客户指定地点，技术支援黑龙江防洪救援工作。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;调试现场，突遭暴雨来袭，张工与技术人员坚守一线，从上午到晚上，从多云到暴雨，奋战8小时，保证6台防汛泵车正常工作，力争设备第一时间执行防汛救援任务。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/172040849889a909.jpg&quot; title=&quot;2021_07_27_23_01_IMG_2700&quot; alt=&quot;2021_07_27_23_01_IMG_2700&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;设备试机，6台防汛泵运行稳定，高效吸水，具备强大的抽排能力和灵活性，与救援救灾形成工作合力，成为防汛抗洪好帮手。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720408520f07bab.jpg&quot; title=&quot;2021_07_28_10_19_IMG_2710&quot; alt=&quot;2021_07_28_10_19_IMG_2710&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;客户好评&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;感谢豫工的全力支持，防汛泵吸水量大。&lt;/span&gt;&lt;/p&gt;'),
(390, 2, 10, '&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作为防汛泵行业18年生产厂家，豫工机械在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业，累计服务防汛泵客户5000+！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械工厂内景展示&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/172042444343d990.jpg&quot; title=&quot;柴油移动防汛泵车 (13)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/172042444372d797.jpg&quot; title=&quot;防汛排涝泵&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;汛期来临叠加台风强降雨天气，豫工防汛泵需求量暴增，为了让客户订购的防汛泵早日投入应急救灾，工厂严格质量检测，加班加点出货。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720424500c0c8ba.jpg&quot; title=&quot;1 (30)&quot; alt=&quot;1 (30)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;紧急支援&amp;nbsp; “逆”水而行&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;风雨同舟 众志成城，豫工机械售后服务部乔工乘飞机，从商丘永城防汛泵售后现场出发，奔赴2000里，技术支援黑龙江省防洪设备安装调试。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720424530d3e064.jpg&quot; title=&quot;0C_4OWD]8~UN7M~N9@DA6[H&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204245300693d9.jpg&quot; title=&quot;3ETNPWDI93{W6ICUBC0@PKR&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;安装调试一直持续到晚上，遭遇暴雨来袭，豫工技术员坚守一线，与抗洪人员一道，全力以赴，通宵奋战，保证5台防汛泵车全部投入工作，第一时间开始执行防汛吸水任务！&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720424585f7d1b1.jpg&quot; title=&quot;1691481590786&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720424585ff35bd.jpg&quot; title=&quot;1691482970606&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备试机，防汛泵出水口流量大，完全满足客户防汛要求。晚上暴雨如柱，五台防汛泵同时上阵，控制住河水快速上涨的局面。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204245695d63e5.jpg&quot; title=&quot;K)J637MW]@114FNM@2G$MFO&quot; alt=&quot;K)J637MW]@114FNM@2G$MFO&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 20px;&quot;&gt;客户好评&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;感谢豫工对我们防汛工作的支持，设备提前到货，技术员及时到场，为我们争取了宝贵的时间，对防汛救援意义重大！技术员一直忙的晚上，虽然遭遇暴雨，依然坚持岗位，为豫工点赞，有担当有责任！&lt;/span&gt;&lt;/p&gt;'),
(391, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;作为防汛泵行业18年生产厂家，公司在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业。豫工质造，值得信赖！&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720425332557114.jpg&quot; title=&quot;_1e098538dfe006f018eeadf5ca000216_-1183076637_mmexport1690342319799&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720425332e0dac9.jpg&quot; title=&quot;_574c9f4f76c89d2ebacd2e7899326b5e_-1265425898_mmexport1690342381847&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204253327b3d53.jpg&quot; title=&quot;b7373dd392e091f9ae889766d3066c85&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em; text-align: center;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;豫工机械工厂内景展示&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;严格检测 如期交货&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;汛情如火、昼夜奋战。汛期以来，豫工防汛泵需求量暴增，为了早日让客户拿到设备，抗洪救灾，工厂严格质量检测，加班加点出货。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428430109535.jpg&quot; title=&quot;IMG_20230726_103749973_original&quot; alt=&quot;IMG_20230726_103749973_original&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;在设备即将达到客户指定地点，豫工机械售后服务部毛工，乘飞机从四川中江防汛泵调试现场出发，乘飞机赶赴河北抗洪现场，紧急驰援，技术支持！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备试机，在真空辅助系统的加持下，出水口水量足，排水量每小时达到1850m3，扬程达到15米以上，可同时满足每小时排水量2000方，扬程15米的防汛要求&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204284940601a2.jpg&quot; title=&quot;IMG_20230726_110704734_original&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428494a2f6fb.jpg&quot; title=&quot;IMG_20230726_110743945_original&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;培训过程中，借助智能化操作系统，快速接头，工作人员很快掌握使用要领！经客户最终确认，设备即可投入防汛抢险中。&lt;/span&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428520143133.jpg&quot; title=&quot;IMG_20230726_144549800_original&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204285203952d5.jpg&quot; title=&quot;IMG_20230726_144955605_original&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户好评&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;设备出水口水量足，操作也简单，感谢技术员的用心指导，工作人员很快掌握操作步骤，感谢豫工为防汛抗洪竭尽全力！&lt;/span&gt;&lt;/p&gt;'),
(392, 2, 10, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;此次客户选择豫工，不仅与产品经理专业细致的方案密不可分，更与公司对设备的细节打造密切相关。作为18年防汛泵生产厂家，做细节一直是豫工人的专长，发展至今，公司在防汛、应急、消防、抢险设备生产上经验丰富，强大的研发能力，专业现代化工厂，通过ISO9001国际质量认证，是质量、诚信、服务AAA企业。&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428918b902a1.jpg&quot; title=&quot;_1e098538dfe006f018eeadf5ca000216_-1183076637_mmexport1690342319799&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428918afe8d1.jpg&quot; title=&quot;_574c9f4f76c89d2ebacd2e7899326b5e_-1265425898_mmexport1690342381847&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428918cac151.jpg&quot; title=&quot;QQ图片20230731141253&quot;/&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;客户定购的永磁防汛泵系列，除了硬核配置，在细节方面也堪称完美，比如：设备特添加照明灯结构，功率35W，光通量10001m，上下角度可做100度调整，提高野外作业的便利性！从整体上看，该系列永磁泵车整体美观大方，布局合理，搭载智能设备，可手机端和电脑端远程控制，工作效率高。可视化操作面板，操作简便，每一处细节都为应急抢险而来。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720428986d51f3e.jpg&quot; title=&quot;_dab15ec5a73a79c736ac7eb4d7e9a096_342343020_mmexport1690342361113&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204289861099ef.jpg&quot; title=&quot;QQ图片20230731141406_副本&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;夏季汛期来临，超强级台风“杜苏芮”靠近，豫工防汛泵需求量暴增，原本300方永磁泵搭载的2轮拖挂，仓库刚好用完。恰逢河南多日细雨连绵，为保证如期交货，工厂与客户沟通后，免费为客户升级为4轮拖车。7月17日，永磁防汛泵车通过严格质量检测，从工厂发货，18日到达客户指定位置，距离合同约定到货日期，提前4天！&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/172042915778c2ad.jpg&quot; title=&quot;abbc9f5c757c21239efbaacde424b5e4&quot; alt=&quot;abbc9f5c757c21239efbaacde424b5e4&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;与设备一起到达的，还有豫工机械售后与技术支持部乔工，凭借丰富的服务经验，乔工很快完成设备安装调试。500方泵车试机，出水口水量足，排水量每小时可达600m3，扬程达到9米以上，可同时满足每小时排水量500方，扬程11米的防汛要求。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/1720429220d318d1.jpg&quot; title=&quot;IMG_20230719_104503185&quot; alt=&quot;IMG_20230719_104503185&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;培训过程中，借助智能化操作面板，快速接头，工作人员很快掌握使用方法！经客户最终确认，设备顺利交接。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202407/17204292785177ed.jpg&quot; title=&quot;IMG_20230719_113240889&quot; alt=&quot;IMG_20230719_113240889&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&amp;nbsp;客户好评&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&amp;nbsp;厂家服务非常用心，设备到货比预定时间提前了4天，感谢豫工对我们工作的支持！刚见到设备时，让我们眼前一亮，外壳喷漆细腻光滑，饱满均匀，明亮如镜，对于经常接触水的设备，有助于防水防潮，对保养至关重要！设备出水口水量足，流量大！操作也简单，真的是设备好，服务棒，很满意！&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_anliguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(396, 1, 10, '&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580655d6c1c6.jpg&quot; title=&quot;到达 (2)&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;color: rgb(62, 62, 62); font-family: &amp;quot;PingFang SC&amp;quot;, system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 0.544px; text-align: justify; text-wrap-mode: wrap; background-color: rgb(255, 255, 255);&quot;&gt;产品经理根据客户需要推荐豫工3米自带动力除雪滚，该设备有效工作宽度3米，搭载柴油发动机，最大除雪厚度100mm,工作时长4小时，工作速度30km/h，配置聚丙乙烯与钢丝混合材质滚刷，耐磨抗寒，适应低温作业环境。&amp;nbsp;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/17695807960433f6.jpg&quot; title=&quot;AECA29E5F77BDEB22511548F44FDA1E9&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/176958079621fe85.jpg&quot; title=&quot;IMG_20251016_081704&quot;/&gt;&lt;/p&gt;&lt;p&gt;客户谨慎评估除雪效率，详细考察工厂实力，于当天下午签订合作协议。&lt;/p&gt;&lt;p&gt;12月19日，4台3000型自带动力除雪滚经严格质量检测后，从工厂仓库发货，由专线物流运送。&amp;nbsp;&lt;/p&gt;&lt;p&gt;值得一提的是，2025年入冬以来，为解决客户对除雪设备的紧急需求，豫工工厂根据近几年客户需求大数据，对需求量最大的型号储备了充足的现货，包括而不限于3米除雪滚、0.3方融雪剂撒布机、3米除雪铲，其他设备根据仓库余量变化，及时组织生产和补充，以保证随时发货！&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/17695806553f1c54.jpg&quot; title=&quot;到达客户指定位置 (2)&quot;/&gt;&lt;/p&gt;&lt;p&gt;12月20日，除雪滚准时抵达怀仁市，按照客户要求，设备送到怀仁市政合作的汽修厂，以备接下来的安装调试。&lt;/p&gt;&lt;p&gt;12月22日，豫工售后与技术支持部江工到达指定现场，提供技术支持服务。&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580655d6eda2.jpg&quot; title=&quot;焊接 (2)&quot;/&gt;&lt;/p&gt;&lt;p&gt;根据客户安排，除雪滚将安装在环卫专用洒水车上。江工清点配件后，指导焊接工人对除雪滚的固定挂件进行定位焊接。&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/176958065605f7d3.jpg&quot; title=&quot;焊接 (6)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656b52515.jpg&quot; title=&quot;焊接 (8)&quot;/&gt;&lt;/p&gt;&lt;p&gt;挂件定位焊接精度要求较高，江工全程跟进指导，确保挂件与车辆大梁能牢固对接。&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/176958065630f8b8.jpg&quot; title=&quot;焊接 (10)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656c2d3d7.jpg&quot; title=&quot;清除障碍 (2)&quot;/&gt;&lt;/p&gt;&lt;p&gt;在此过程中，现场操作人员同步接受使用培训，掌握启停流程、日常维护及常见故障应对方法。&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656c8fe87.jpg&quot; title=&quot;设备摆放 (2)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656fd03e6.jpg&quot; title=&quot;完成 (3)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656f590d2.jpg&quot; title=&quot;完成 (6)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202601/1769580656b7f428.jpg&quot; title=&quot;完成&quot;/&gt;&lt;/p&gt;&lt;p&gt;江工表示：该款系列除雪滚拆卸方便，冬季过后，存放仓库时，只需要把固定螺栓拆掉即可取下，存储保养方便！&lt;/p&gt;&lt;p&gt;怀仁市政对除雪滚的工作效果与专业服务给予高度认可！&lt;/p&gt;&lt;p&gt;此次交付再次证明：作为20年除雪设备生产厂家，豫工机械在除雪设备的生产实力和服务保障方面，有能力帮助客户解决多种场景下除雪作业。&lt;/p&gt;');
