INSERT INTO `dr_1_anliguanli_recycle` (`id`, `cid`, `uid`, `catid`, `content`, `result`, `inputtime`) VALUES
(1, 10, 1, 10, '{\"1_anliguanli\":{\"id\":\"10\",\"catid\":\"10\",\"title\":\"案例管理测试4\",\"thumb\":\"10\",\"keywords\":\"案例管理测试4\",\"description\":\"案例管理测试4\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-10.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"127.0.0.1-56466\",\"inputtime\":\"1698982539\",\"updatetime\":\"1698995532\",\"displayorder\":\"0\",\"alxqysbzt\":\"11\",\"alxqyzbspzs\":\"12\",\"alxqyzbspzsjj\":\"案例管理测试4\",\"cpxqyysbcs1\":null},\"1_anliguanli_data_0\":{\"id\":\"10\",\"uid\":\"1\",\"catid\":\"10\",\"content\":\"&lt;p&gt;案例管理测试4&lt;br&gt;&lt;/p&gt;\"},\"1_anliguanli_category_data\":null}', '', 1701055293),
(2, 9, 1, 10, '{\"1_anliguanli\":{\"id\":\"9\",\"catid\":\"10\",\"title\":\"案例管理测试3\",\"thumb\":\"9\",\"keywords\":\"案例管理测试3\",\"description\":\"案例管理测试3\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-9.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"127.0.0.1-56186\",\"inputtime\":\"1698982420\",\"updatetime\":\"1698982420\",\"displayorder\":\"0\",\"alxqysbzt\":null,\"alxqyzbspzs\":null,\"alxqyzbspzsjj\":null,\"cpxqyysbcs1\":null},\"1_anliguanli_data_0\":{\"id\":\"9\",\"uid\":\"1\",\"catid\":\"10\",\"content\":\"&lt;p&gt;案例管理测试3&lt;br&gt;&lt;/p&gt;\"},\"1_anliguanli_category_data\":null}', '', 1701055293),
(3, 8, 1, 10, '{\"1_anliguanli\":{\"id\":\"8\",\"catid\":\"10\",\"title\":\"案例管理测试2\",\"thumb\":\"8\",\"keywords\":\"案例管理测试2\",\"description\":\"案例管理测试2\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-8.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"127.0.0.1-56186\",\"inputtime\":\"1698982377\",\"updatetime\":\"1698982377\",\"displayorder\":\"0\",\"alxqysbzt\":null,\"alxqyzbspzs\":null,\"alxqyzbspzsjj\":null,\"cpxqyysbcs1\":null},\"1_anliguanli_data_0\":{\"id\":\"8\",\"uid\":\"1\",\"catid\":\"10\",\"content\":\"&lt;p&gt;案例管理测试2&lt;br&gt;&lt;/p&gt;\"},\"1_anliguanli_category_data\":null}', '', 1701055293),
(4, 7, 1, 10, '{\"1_anliguanli\":{\"id\":\"7\",\"catid\":\"10\",\"title\":\"案例管理测试1\",\"thumb\":\"7\",\"keywords\":\"案例管理测试1\",\"description\":\"案例管理测试1\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-7.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"127.0.0.1-55911\",\"inputtime\":\"1698982185\",\"updatetime\":\"1698982185\",\"displayorder\":\"0\",\"alxqysbzt\":null,\"alxqyzbspzs\":null,\"alxqyzbspzsjj\":null,\"cpxqyysbcs1\":null},\"1_anliguanli_data_0\":{\"id\":\"7\",\"uid\":\"1\",\"catid\":\"10\",\"content\":\"&lt;p&gt;案例管理测试1&lt;br&gt;&lt;/p&gt;\"},\"1_anliguanli_category_data\":null}', '', 1701055293);
INSERT INTO `dr_1_chanpinguanli` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `cplbysbzt`, `cplbysbft`, `cpxqyzsbzt`, `cpxqyysbcs1`, `cpxqyysbcs2`, `cpxqyysbsyfw`, `cpxqyzbspjj`, `cpxqyzbzsp`) VALUES
(278, 11, '乳化沥青撒布机', '214', '', '沥青洒布机是一种黑色路面机械。沥青灌入式路面在碎石层摊铺碾压密实、平整均匀后，在清扫干净、保证干燥的基层上用沥青洒布机喷洒第一遍沥青，在趁热撒布嵌缝料均匀覆盖后，再由沥青洒布机喷洒第二遍沥青，直至喷洒罩面沥青形成路面。突出优势1：携带方便，操作简单，提高工作效率。2：可直接从方罐圆罐子等各种容器中抽取材料直接进行散布作业3：车台上可携带各类的开关材料容器及清洗器（10L）4：使用接着式散', 1, 1, '创始人', 9, '/show-278.html', 0, 0, '39.96.59.7-54672', 1701071212, 1701074660, 0, '216', '[\"217\",\"218\",\"219\"]', '', '洒布能力（流量）：15L/min', '汽油机:本田160', '\r\n专门用于高速公路、国省道、县乡道、城市道路以及机场等路面的预防性养护施工，适用普通沥青路面、碎石封层路面的早期养护处理', '', '215'),
(279, 11, '沥青搅拌机', '220', '', '沥青搅拌站主要用于废旧沥青混合料加热搅拌，再生利用，变废为宝，也可按比例进行少量新的沥青混合料加热搅拌。不受气温和边缘山区的影响，不受大型沥青搅拌站的制约，随时随地及时快捷地，进行沥青路面坑槽修补，确保道路安全畅通，也可用于摊铺彩色沥青路面和小面积庭院摊铺沥青混凝土。突出优势一、加热搅拌滚筒（一）节能环保：加热搅拌滚筒外有保温层，装有除尘设备。（二）质量可靠：轻油燃烧器的火焰是把搅拌滚筒', 1, 1, '创始人', 9, '/show-279.html', 0, 0, '39.96.59.7-54680', 1701071212, 1701076563, 0, '222', '[\"223\",\"224\",\"225\"]', '', '搅和量T/次：0.4-1.1m³', '所需时间min：10-15min', '\r\n不受气温和地域影响，不受大型沥青搅拌站的制约，随时就地、及时快捷', '', '221'),
(280, 11, '融雪剂撒布机', '226', '', '后挂式小型融雪剂撒布机安装于工程车、皮卡车、小型客货车后部，适用于公路、小区、机场等冬季冰雪路面防滑沙料和融雪剂的撒布。选用聚乙烯材质耐腐蚀。12V旋转马达，采用螺旋输送式出料，转速越高抛程越远。有效避免了融雪剂的浪费，保证融雪剂的均匀撒布，单位面积可节约融雪剂40%以上。产品特点小巧轻便 便于拆装：体积小、重量轻，与同类设备相比突显了它的灵活和方便性。冬季过后可方便的将设备卸下另行保存', 1, 1, '创始人', 9, '/show-280.html', 0, 0, '39.96.59.7-54686', 1701071212, 1701076741, 0, '228', '[\"229\"]', '', '容积：0.3m³/365kg', '撒布宽度：1-9M', '适合于各等级公路、城市道路、机场、广场、景区道路融雪使用。', '', '227'),
(281, 11, '冷喷划线机', '196', '', '本设备是平整地面划规定限制标志的路面施工机械，以快速、高效、准确等优点在城市规划和公路建设方面发挥了巨大作用，大程度的节省了路面施工的工期和经济投入。突出优势寿命长：泵体采用全油侵入式润滑方式，液压助力，减小磨损。使用寿命可达四万小时以上。耐酸碱耐磨：密封垫精心设计，超耐磨，冬季/夏季使用自如，耐酸碱，耐疲劳，更换简单方便。操作简单：立式车身，吸液管容易打理清洗，一人可独立移动操作方便。', 1, 1, '创始人', 9, '/show-281.html', 0, 0, '39.96.59.7-54692', 1701071213, 1701073815, 0, '198', '[\"199\",\"200\",\"201\"]', '', ' 卸荷流量：单枪 6L/min 双枪 8L/min', '大喷宽度：单枪：20cm 双枪 45L/min', '\r\n主要用于城市道路、高速公路、厂房、停车场、车库、广场和机场跑道的标线', '', '197'),
(282, 11, '热熔划线机', '206', '', 'YG380高级手推热熔划线机，是热熔标线施工的关键设备，通过与热熔釜配合使用，完成标线施工。该机采用特殊制造的高精密度铸铁划线斗，确保所划标线对齐、头齐、厚薄均匀，线型美观。可调节玻璃珠微珠撒播器，设有调速换挡装置，可调节撒播宽度。具有标线施工质量高，施工速度快，操作灵活，维护简单等特点设备结构1.涂料桶：双层不锈钢保温加热桶，容量100kg插入式手动搅拌装置，可拆卸装置。2.玻璃微珠贮存箱：25', 1, 1, '创始人', 9, '/show-282.html', 0, 0, '39.96.59.7-54698', 1701071213, 1701074030, 0, '202', '[\"204\",\"203\",\"205\"]', '', '行走速度：1-8km/h', ' 标线宽度：50/100/150/200/350mm', '\r\n公路，马路等路面交通安全标志如斑马线，人行道，车道，等路面指示、标志', '', '207'),
(283, 11, '550路面抛丸机', '208', '', '6532名客户一致选择它高效清理地面   突出优势效率高 省人工：一次性施工，即可得到干净整洁，粗糙度均匀的表面，工作效率高。混凝土地面打毛清理成本低：钢丸损失小，易损件更换方便，有效降低施工成本粗糙度可调：地面清理粗糙度可调，深可抛3-4mm，符合不同的清理要求。深度抛丸效果展示较浅抛丸效果展示暴露地面裂纹 防患于未然：清理表面干净整洁，粗糙度均匀，没有损伤，同时将混凝土地面的裂纹充分暴露出来，', 1, 1, '创始人', 9, '/show-283.html', 0, 0, '39.96.59.7-54704', 1701071213, 1749432141, 0, '209', '[\"210\",\"211\",\"212\"]', '', ' 工作宽度：550/600mm', ' 混凝土表面清理效率：≥400㎡/h', '广泛应用于混凝土桥面防水打毛、沥青路面的清理和打毛，以增加表面粗糙度；路面、隧道及桥粱的抗滑性能恢复；沥青路面泛油的清理、标志线清理；钢桥面除锈防腐涂装处理；机场', '', '213'),
(284, 11, '沥青路面灌缝机', '195', '', '通过压力注射式灌缝，使材料和缝壁紧密结合转向灵活的万向轮跟踪裂缝，使灌缝效果美观。由于灌缝材料使用沥青或灌缝胶，在温度较低时容易凝固，灌缝机配有汽油发电机提供电力，灌缝机在出料管部位采用恒温控制系统，避免材料烧焦老化，保证出料的顺畅。突出优势自主研发汽电一体化混合动力，电驱动技术，低排放、低耗能、节能环保先进的智能点火、检测控温技术独特的油套热熔釜设计，导热油处于釜内部四周及底部，使得加热均衡，胶', 1, 1, '创始人', 9, '/show-284.html', 0, 0, '39.96.59.7-54710', 1701071214, 1701073162, 0, '190', '[\"191\",\"192\",\"193\"]', '', '料斗容量：100L', '电力配置：本田2kw发电机', '\r\n适用于高速公路、市政、机场、广场、工业园区沥青、水泥路面的伸缩缝灌缝、复杂路面、不规则路面的灌缝，填补裂缝。', '', '194'),
(285, 11, '300型自行走铣刨机', '181', '', '路面铣刨机通俗说就是把损坏的旧路面刮一层，再铺上新面层。一般是为了消除旧路面破坏松散部分，或为了新旧面的结合良好，起拉毛作用。突出优势1、有吸尘器连接装置，提供无尘工作环境 2、可以长时间工作，功率大，强劲有力3、可以调节地面铣刨深度，铣刨深度达8mm4、直径60mm钨钢铣刀片，良好的耐用性5、刹车装置操纵灵活，有效调节行走速度6、特别适用于大范围的地面处理，速度快，效率高7、硬质合金大', 1, 1, '创始人', 9, '/show-285.html', 0, 0, '39.96.59.7-54722', 1701071215, 1701072656, 0, '186', '[\"187\",\"188\",\"189\"]', '180', '一次铣刨深度：5-20mm(混凝土) 5-30mm(沥青)', ' 工作宽度：300mm 工作效率：30-40㎡/', '桥面铺装，桥面拉毛，旧路面刨除，以及机场跑道、城市广场、大型工厂，物流仓储、车库、停车场等混凝土地面施工作业。', '路面铣刨机通俗说就是把损坏的旧路面刮一层，再铺上新面层。一般是为了消除旧路面破坏松散部分，或为了新旧面的结合良好，起拉毛作用。', '179'),
(286, 13, '客土喷播机', '256', '', '豫工客土喷播机，可以加土喷播机，可以添加适量的稻壳、锯末增加泥浆的附着力；采用常柴单缸柴油机，可以根据施工工地海拔高度选定不同马力的柴油机；可私人订制。设备适合30米以上边坡、陡边坡、缓边坡、石质边，喷播厚度一次大约在2-3cm，可挂铁丝网，配86-247kw的四缸或者六缸柴油机.具有出口压力大 扬程远 喷播效率高的特点突出优势豫工客土喷播机分为两大机型：机械搅拌系统、液压搅拌系统；搅拌', 1, 1, '创始人', 9, '/show-286.html', 0, 0, '39.96.59.7-58456', 1701077066, 1749431524, 0, '257', '[\"258\",\"259\",\"260\"]', '', ' 柴油机功率：华东132 东方红125 玉柴130', ' 扬程：水平 50m-210m 垂直：40m-75m', '高速公(铁)路边坡绿化、创面山体复绿、垃圾填埋场无土覆盖、矿山复绿、荒漠治理、河堤防护、养护洒水、大规模绿地重建等绿化工程', '', '261'),
(287, 13, '催化燃烧设备', '250', '', '催化燃烧装置是指在催化剂作用下燃烧的装置或设备。借助催化剂使有机废气在较低的起燃温度下进行无焰燃烧,使有机废气分解为无毒的二氧化碳和水蒸汽。广泛应用于线材加工、机械、电机、化工、设备、汽车、发动机、塑料、电器、石油、化工、印染等行业。工作原理低浓度废气经过活性炭吸附后达标排放，此时活性炭逐步饱和后切换炭箱继续吸附。该饱和炭箱则吸附阀门关闭，脱附阀门打开经催化燃烧内加热的温度并通过换热器送', 1, 1, '创始人', 9, '/show-287.html', 0, 0, '39.96.59.7-58462', 1701077066, 1701142770, 0, '251', '[\"252\",\"253\",\"254\"]', '', '风量：10000-40000m³/h 废气浓度:400mg/m³', ' 催化剂活性温度：230-300℃', '\r\n广泛应用于线材加工、机械、电机、化工、设备、汽车、发动机、塑料、电器、石油、化工、印染等行业。', '', '255'),
(288, 13, '水面割草船', '244', '', '割草船产品介绍按照船型设计规范采用链轴式增强尼龙输送带或不锈钢输送带,具有滤水性好、高耐磨、寿命长易维护等优点。收集舱进料端搭载切割沉水植物的L形切割系统、打散打碎作用的机械滚轮装置实现水体水面层不同深度各类水草垃圾的收集打捞。 割草船设备参数小型半自动中型全自动大型全自动收割面积：2000㎡/h收割面积：3000㎡/h收割面积：5000㎡/h储草量：5-8m³储草量：10-1', 1, 1, '创始人', 9, '/show-288.html', 0, 0, '39.96.59.7-58468', 1701077066, 1701142601, 0, '245', '[\"248\",\"246\",\"247\"]', '', ' 收割面积：2000-5000㎡/h', '储草量：5-20m³', '\r\n自动收集各类沉水、浮水水生植物,打捞毛竹、树枝、秸杆及各类水面漂浮垃圾。适用于各类城乡河道.水库、富营养化水域等。 集割草、打捞漂浮垃圾于一体，解决多种河道问题！', '', '249'),
(289, 13, '抽沙船', '243', '', '射吸式抽沙船简介射流式抽沙船也可叫作抽沙平台,是指利用水力的作用,将高压水枪出的水柱冲起的淤泥(或细沙、海沙等)在吸沙泵的作用下有管道输送到目的地，设计新颖，操作简便，效率高，适用于河道疏浚、湖泊水库清淤、围海造田、港口码头清理、抽砂等。该设备由船体、输送系统、进水系统、排空系统等组成，输送系统包括动力、离合器、泥浆泵等，排空系统包括高压水泵、抽真空装置等。射吸式抽沙船基本参数', 1, 1, '创始人', 9, '/show-289.html', 0, 0, '39.96.59.7-58474', 1701077066, 1701142389, 0, '238', '[\"239\",\"240\",\"241\"]', '', '18寸泵抽沙船', '产量：500方/h', '适用于河道、水库、浅海作业，沙子比较好抽，石头含量少的地形，输送距离可由近及远。', '', '242'),
(290, 13, '双轴撕碎机', '230', '', '双轴撕碎机产品简介双轴撕碎机又名剪切式撕碎机：通过剪切、撕裂和挤压达到减小物料尺寸，这种撕碎机广泛应用于废塑料、废橡胶、易拉罐、木材和其它大体积废弃物，我公司将欧美制造该类设备三十多年的经验引进中国，并根据国内实际情况进行改进，研发，推出技术成熟和设计先进的双轴撕碎机系列，为我国的废物回收利用前期的破碎，减容处理提供质量可靠的设备。撕碎机设备参数型号主轴功率主轴转速产量(t/h', 1, 1, '创始人', 9, '/show-290.html', 0, 0, '39.96.59.7-58480', 1701077066, 1701141364, 0, '232', '[\"234\",\"233\",\"235\"]', '', ' 粉碎程度:30-200mm', '生产能力：5-8t', '\r\n撕碎较难破碎的塑料、橡胶、纤维、纸张、木材、电器件、电缆等实心物料', '', '236'),
(291, 13, '工业压滤机', '286', '', '厢式压滤机是由多块滤板排列组成滤室。滤板的表面有凸点，用以支撑滤布。滤板的中心和边角上有液体通过孔，滤板排列后构成完整的通道，能通入悬浮液、洗涤水和引出滤液。滤板  厢式压滤机具有过滤压力大、过滤速度快、含水率低、滤板不易损坏等优点，聚丙烯厢式滤板填充玻璃纤维后可耐120度高温物料过滤，厢式压滤机容易实现自动化控制。适用于物料浓度比较大，处理重大的各种行业使用。 机械压紧压滤机是由电动机带动减速机', 1, 1, '创始人', 9, '/show-291.html', 0, 0, '39.96.59.7-58486', 1701077067, 1727252928, 0, '287', '[\"288\",\"289\",\"290\"]', '', '类型：厢式压滤机 板框式压滤机', ' 过滤面积：1-2600㎡', '设备适用于石油、化工、制药、制糖、冶金、食品、陶瓷、淀粉、污水处理等行业', '', '291'),
(292, 13, '30型筛土机', '280', '', '筛土机是对土进行筛选的振动筛，包括带点粘性的土，除去土（包括带粘性的土）中石块、碎石块、腐叶烂叶等杂质以及对土（包括带粘性的土）进行分级，筛选出粒径更小的细土等等。对于有粘性的土，可加大振动频率，用可选机型有直线振动筛，要求处理量特别大的可选用圆振筛。突出优势安装基础简易：因整个设备为箱形框架结构，只需有一平整地面即可。地面硬化便于清扫。高度整体性：除成品料堆料皮带机外，所有系统都集成于', 1, 1, '创始人', 9, '/show-292.html', 0, 0, '39.96.59.7-58492', 1701077067, 1701143900, 0, '281', '[\"282\",\"283\",\"284\"]', '', ' 滚筒直径：3*0.8m', ' 工作效率:60-80㎥/h', '\r\n筛沙机又名旱地筛沙船，砂石分离机，适用河道，水库，煤场的沙石分离设备。', '', '285'),
(293, 13, '泥浆分离器', '274', '', '泥浆净化机，也称为建筑工程泥浆处理设备，整机一体化程度高，占地面积小，结构合理，便于移动，设备自带变频调节电控柜对效果及电机可实现控制保护，泥沙回收效率高，脱水干堆效果理想，该设备在管道及出砂口均做了高标准密封，降低施工中对周边飞溅泥浆。设备优势泥浆充分净化，有效控制泥浆的性能指标，减少卡钻事故，提高造孔质量。 泥浆循环使用，节约造浆材料，减少废浆外运成本和造浆费用。 对土渣有效分离，提', 1, 1, '创始人', 9, '/show-293.html', 0, 0, '39.96.59.7-58498', 1701077067, 1701143704, 0, '275', '[\"276\",\"277\",\"278\"]', '', '液体处理能力：50㎥/h-500㎥/h', '渣料筛分能力：10-250t/h', '\r\n适用于水电、城建、桥梁桩基等正反循环成孔 (槽、泥水平衡盾构施工中的泥浆净化回收在钻孔灌注桩基工程、地下连续墙、隧道泥水盾构、地下非开挖等建筑工程领域', '', '279'),
(294, 16, '移动防汛水泵', '268', '', 'ZW型自吸式无堵塞排污泵适用于化工、石油、制药、采矿、造纸、纤维、浆料、纺织、食品、电厂及市政排污工程、公共设施排污、河塘养殖等行业。突出优势1、排污能力强：特殊的叶轮防堵设计，确保了泵高效且无堵塞。2、高效节能：采用优秀水力模型，效率比一般自吸泵高3～5%。3、自吸性能好：自吸高度比一般自吸泵高1米，且自吸时间更短。 4、防汛泵规格型号齐全，从普通款到自吸泵、拖车式图片展示', 1, 1, '创始人', 9, '/show-294.html', 0, 0, '39.96.59.7-58506', 1701077067, 1749432350, 0, '269', '[\"270\",\"271\",\"272\"]', '', ' 流量：200-1000m3/h', '扬程：9-20m 吸程：9m', '防汛排涝专用，既可防汛排涝，又可抽吸一切工程污水物和胶质液体', '', '273'),
(295, 13, '砂浆喷涂机', '262', '', '室内外墙体喷涂、水泥砂浆灌浆、桥梁灌浆及防水表面喷涂、防火喷涂、天花顶喷涂、墙壁喷涂、涂料喷涂、园林喷涂、浮雕效果涂料喷涂、吸音材料喷涂、防水堵漏、防水补漏专用设备产品特点1. 调节流量大小，调出蕞佳喷涂效果。2. 除在电控箱上可以开关外，还配备遥控开关喷涂。3. 喷枪与送料管的连接可以旋转，便于操作。4. 施工效率高，质量好。5. 体积小巧，便于现场搬运，而且配件费用低, 维修简单。6', 1, 1, '创始人', 9, '/show-295.html', 0, 0, '39.96.59.7-58512', 1701077067, 1701143382, 0, '263', '[\"265\",\"264\",\"266\"]', '', ' 输送高度：6-25m 输送距离：30-50米', '输送流量：3-5㎥/h', '\r\n广泛适用于桥梁、水坝、山坡、地下室、隧道、房屋厂厦的喷涂施工', '', '267'),
(296, 13, '喷砂机', '292', '', '喷砂技术广泛用于船舶、桥梁、水利工程、矿山机械制造、石油、化冶金、港口建设、轻工、飞机制造、机车车辆、仪器仪表、精密制造、电子工业等领域；是金属表面涂覆前大面积清理理想的方法；对非涂覆表面可达到表面强化、光饰和雕刻作用。产品特点操作简单，普工30min熟练操作，自动控制系统防工人误操作 生产效率高，一台喷砂机=50-80名熟练工人 喷砂精度高，去除微小、隐蔽飞边，不受形状限制，合格率高。', 1, 1, '创始人', 9, '/show-296.html', 0, 0, '39.96.59.7-58538', 1701077076, 1701144237, 0, '293', '[\"294\",\"295\",\"296\"]', '', '容量：0.15-1㎥/h', ' 效率：5-30㎡/h', '\r\n船舶、桥梁、水利工程、矿山机械制造、石油、化工冶金、港口建设、轻工、飞机制造、机车车辆、仪器仪表、精密制造、电子工业等领域', '', '297'),
(297, 14, '桥梁智能喷淋养护设备', '316', '', '箱梁、T梁砼在硬化的过程中，对温度湿度的变化非常敏感，如果养护工作不当或不及时，混凝土表面水分散失太快，混凝土在拆模前、甚至终凝前箱梁、T梁就会产生裂缝。采用智能喷淋养生系统只需设定好养护时间及循环范围并进行全天候、全湿润的养护效果显著。抛丸机配套吸尘器本机可随意调节工作时间、间隔时间及工作次数，手机远程操作，远程电脑监控，手动自动可随意切换，可以达到全天候、全湿润的养护质量标准，养护效', 1, 1, '创始人', 9, '/show-297.html', 0, 0, '39.96.59.7-59282', 1701144566, 1701145373, 0, '317', '[\"319\",\"318\",\"320\"]', '', '台座数量：12-60个', ' 台座长度：32m-40m', '可适用于高速高铁箱梁、T梁等；', '', '321'),
(298, 14, '智能压浆系统', '322', '', '预应力智能压浆设备由于集高速制浆机、自动称重系统、储浆桶、进浆/出浆检测设备、压浆泵于一体，现场使用只须将进浆管和返浆管与预应力管道对接，即可进行压浆施工，操作简单，使用方便，受到广大桥梁，公路等施工人员的喜爱。突出优势预应力智能压浆设备特点：自动配料，高精度的称重传感器( 称重精度', 1, 1, '创始人', 9, '/show-298.html', 0, 0, '39.96.59.7-59290', 1701144566, 1701153495, 0, '323', '[\"324\",\"325\",\"326\"]', '', '单次搅拌量：200kg', ' 称重精度&lt;0.2%', '\r\n适用于桥梁，公路等孔道预应力压浆施工', '', '327'),
(299, 14, '智能张拉系统', '328', '', '预应力智能张拉是指不依靠工人手动控制，而是利用计算机智能控制技术，通过仪器自动操作，完成钢绞线的张拉施工。由于智能系统的高精度和稳定性，能完全排除人为因素干扰，有效确保预应力张拉施工质量，是目前国内预应力张拉领域较先 进的张拉设备。突出优势设备实现了远程监控的功能，可以在操作室对整个操作过程进行查看，还能够观察数据分析，随时进行调整。在安全性方面进行了很大的改进，机器操作过程出现断电情况', 1, 1, '创始人', 9, '/show-299.html', 0, 0, '39.96.59.7-59296', 1701144566, 1701153594, 0, '329', '[\"330\",\"331\",\"332\"]', '', ' 千斤顶大压力：50Mpa', '位移测量精度：&lt;0.20%', '\r\n可完成预制空心板、预制T梁、预制箱梁、现浇连续梁、现浇盖梁和现浇钢构桥梁等后张预应力的张拉施工。', '', '333'),
(300, 14, '防撞墙模板台车', '334', '', '豫工机械防撞台车与以往的防撞墙施工相比，进一步提高了桥梁防撞墙施工进度和施工质量，也确保了桥梁防撞墙施工高处作业安全，为优质、高效、安全的完成桥梁防撞墙施工创造了良好条件。设备特点豫工防撞墙模板台车适应于桥梁防撞墙模板的吊装，运输，安装，拆卸，能够满足小半径弯桥、各种桥梁要求。同样，在平桥，直桥施工条件好的地方更加方便。本产品使用于-20~40℃，无火灾、无爆炸和无腐蚀性介质的环境中工作', 1, 1, '创始人', 9, '/show-300.html', 0, 0, '39.96.59.7-59302', 1701144566, 1701153692, 0, '335', '[\"336\",\"337\",\"338\"]', '', '设备型号：1t 2t', '起升高度：3.8米', '广泛适应于桥梁防撞墙模板的吊装，运输，安装，拆卸，能够满足小半径弯桥、各种桥梁要求。同样，在平桥，直桥施工条件好的地方更加方便。', '', '339'),
(301, 14, '钢绞线穿束机', '340', '', '豫工钢绞线穿束机为机械传动，通过电机带动主动轮转动，钢绞线从一端进线口插入，压轮压住钢绞线向前移动沿导管传入预留孔道，直到从孔道另一端传出，达到张拉用尺寸。该设备集放线和穿线为一体，质量可靠，设计合理，可进，可退，可连续传送，也可点动传送，传达钢绞线速度无极调速，体积小，重量轻，操作方便，性能可靠，应用广泛，是建造桥梁和大型建筑物采用有预应力工作中为孔道穿钢绞线的主要工具。突出优势1、', 1, 1, '创始人', 9, '/show-301.html', 0, 0, '39.96.59.7-59308', 1701144566, 1701153800, 0, '341', '[\"342\",\"343\",\"344\"]', '', ' 串线轮：2-10个', ' 串线距离：50-500米 产品简介', '\r\n广泛应用于预制桥梁、现浇桥梁的孔道穿钢绞线', '', '345'),
(302, 14, '高速搅拌机', '346', '', '用于灰浆搅拌，可连续搅拌水泥灰浆、砂浆，是注浆泵的佳配套设备突出优势设备具有体积小,重量轻,易于安装搬运等特点 双层制浆,出浆率高！灰浆经第一次搅拌后进入搅拌桶，不会沉淀离析，第二次搅拌出料通畅，避免堵浆。图片展示   180L立式款快速制浆机  180L卧式款快速制浆机  200L款高速制浆机  900型高速制浆机 制浆机施工现场', 1, 1, '创始人', 9, '/show-302.html', 0, 0, '39.96.59.7-59314', 1701144566, 1701153944, 0, '347', '[\"348\",\"349\",\"350\"]', '', ' 容量：900L', '搅拌量：6m³/h 电机功率3KW', '\r\n广泛应用于水电、铁路、公路、建筑、矿山邓行业的施工中', '', '351'),
(303, 14, '高铁螺旋筋成型机', '298', '', '螺旋筋成型机采用微电脑全自动PLC编码数控控制系统，用户只需在数控编码显示器上输入螺旋筋间距，米数，切断长度，误差为5mm以内，即可实现螺旋筋自动加工切断，大大提高了工程精度效率，加工速度20-40米/分钟。该机型可设置批次，可全自动加工一捆钢筋。突出优势1. 智能数控 提高效率 全自动螺旋筋成型机采用单片机集成控制，任意调节参数，多种参数储存功能、数字显示、节省时间，方便管理，提高生产', 1, 1, '创始人', 9, '/show-303.html', 0, 0, '39.96.59.7-59320', 1701144567, 1701144945, 0, '299', '[\"300\",\"301\",\"302\"]', '', '钢筋直径：6mm-22mm', ' 成型内径：100mm-500mm', '\r\n适用光伏电站地桩施工，高铁地铁，高架桥梁，管桩施工等预应力螺旋筋卷圈。', '', '303'),
(304, 14, '预应力压浆机', '304', '', '单双缸活塞泵，可输送水泥浆、黄泥浆、水玻璃、油、水等多种介质。具有结构紧凑、工作可靠、故障率低、清理及维修方便及泵送压力高等优点。适用范围广泛用于隧道、矿井采掘工作面注浆堵水，岩巷及混凝土井壁注浆堵漏水，隧道裂痕、破碎岩体、疏散岩石的加固补强，锚固注浆，回填注浆和防止地表下沉，防止滑坡，纠正建筑物偏斜所进行的注浆等。    突出优势 双缸注浆，大流量、高压力，输出量大，双缸注浆', 1, 1, '创始人', 9, '/show-304.html', 0, 0, '39.96.59.7-59326', 1701144567, 1701145145, 0, '305', '[\"306\",\"307\",\"308\"]', '', ' 灰浆泵输送量：3m³/h 6m³/h', '扬程：水平20-50m 垂直≤20m', '\r\n适用于矿井、隧道、水利、地铁、建筑、桥梁等施工地点的注浆堵漏水、填充空隙、裂缝补强注浆、加固破碎岩层、锚固注浆等工程', '', '309'),
(305, 14, '波纹管制管机', '310', '', '豫工机械波纹管制管机是生产预应力混凝土预留孔道金属波纹管的设备,采用镀锌或冷轧钢带(黑带)卷制成双波形经咬边扣压而成波纹管。产品优势体积小、效率高，维护简单，易学易懂可随意更换模具，适合各种型号的波纹管。齿轮传动，噪音低，传送稳定。省料、出管率高,与国内同机型相比,同规格的钢带,产管多。速度快,无级调速电机,制管速度可达 5000米/日省电。加工Ф70mm波纹管，百米耗电0.7度质量三包', 1, 1, '创始人', 9, '/show-305.html', 0, 0, '39.96.59.7-59334', 1701144567, 1701145236, 0, '311', '[\"313\",\"312\",\"314\"]', '', '', '', '\r\n体积小、效率高、操作维护简单。 可随意更换模具，适合各种型号的波纹管。 齿轮传动噪音低，传送稳定', '', '315'),
(306, 15, '钢筋网片排焊机', '370', '', '本设备采用直条钢筋送料生产方式，操作简单，效率高，主要用于焊接钢筋直径3.0-14.0mm，网片宽度3000mm以内网片，焊接长度在12米以内的生产加工。该设备在吸收国内外先进的机电控制电阻焊技术的基础上，自行研制成功的一种自动钢筋网片焊接设备。突出优势自动化 省人工：机器加装调直筒和调直排，直接盘丝入料，实现自动化，省去预先调直切断和人工摆放，节省时间设备和人工。 精度高 焊点牢固：钢', 1, 1, '创始人', 9, '/show-306.html', 0, 0, '39.96.59.7-35500', 1701154294, 1701154846, 0, '371', '[\"373\",\"372\",\"374\"]', '', ' 焊接丝径 3.0-14.0mm', ' 焊网宽度 0.5-3米', '\r\n广泛应用在工业与民用房屋的梁柱楼板、屋盖、墙体、混凝土路面、桥面铺装、机场跑道、隧道衬砌、箱涵、码头地坪、预制构件等', '', '375'),
(307, 15, '中空注浆锚杆', '376', '', '中空注浆锚杆的组成：1.普通式中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞 +塑料锚头2.自进式中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞+合金钻头3.组合式中空注浆锚杆由：0.5m32*5mm中空锚杆体+垫板+螺母+止浆塞+22mm/25mm钢筋+锚头+排气管+连接套4.涨壳中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞+涨壳锚头设备优势中空设计，实现了注浆的功能。注浆饱满，并可实现压力注浆', 1, 1, '创始人', 9, '/show-307.html', 0, 0, '39.96.59.7-35506', 1701154294, 1701154939, 0, '377', '[\"378\",\"379\",\"380\"]', '', ' 壁厚：3-8mm', '锚杆孔直径：4-80mm', '\r\n\r\n主要应用于公路、铁路、隧道的超前支护、边坡支护、基坑支护等地质条件中等良好的围岩进行系统支护', '', '381'),
(308, 15, '工字钢弯拱机', '382', '', '数控弯管机比普通冷弯机多一套数字编码控制系统，一套自动控制系统，液压智能控制阀，光电控制传感器，编码式电子尺，电子计米器。突出优势液压锁设计,一次成型  弯曲过程，不会出现油缸后退，保证弯曲精度 加厚加粗顶辊  配备强劲动力，顶弯型钢更有力 自动棍防滑处理  行进自如不打滑，效率高 更大减速机，弯拱更有力  国标纯铜电机 运行更稳定 液压控制屏  PLC程序控制器，弯曲精度高 液压驱动系', 1, 1, '创始人', 9, '/show-308.html', 0, 0, '39.96.59.7-35512', 1701154294, 1701155024, 0, '383', '[\"384\",\"385\",\"386\"]', '', ' 油缸推进速度：3-3.5mm/s', ' 小弯曲半径：1.8m', '\r\n主要应用于隧道，地铁，水电站，地下洞室等', '', '387'),
(309, 15, '湿喷台车机械手', '352', '', '隧道机械手整机高度低，回转半径小，能够使用于施工场地受限的工程；同时底盘采用刚性底盘，内燃-静液压传动，四轮驱动，配合四轮同向转向和可旋转驾驶室；四个斜撑式液压支腿保证底盘在承受喷射机械手施工及料斗进料的动作负荷时具有足够的稳定性。突出优势1、混凝土输送系统A、先进的无阻尼液压系统和长达1.2米的抽吸泵送行程，使泵送压力强劲而平稳，同时降低能耗和零件磨损。B、可根据客户需要将泵送调节达到', 1, 1, '创始人', 9, '/show-309.html', 0, 0, '39.96.59.7-35518', 1701154295, 1701154469, 0, '353', '[\"354\",\"355\",\"356\"]', '', '大喷射高度：16米', '大行走速度：15Km/h', '广泛适用于隧道、涵洞、地铁、边坡等工程！', '', '357'),
(310, 15, '液压湿喷机', '358', '', '液压湿喷机是泵送式混凝土湿喷机，系 统可靠性高，输送量稳定。喷射量连续调节：主油 泵采用变量柱塞泵，喷射速度可自由调节。速凝剂 添加量连续可调：可根据喷浆量无级调节。突出优势1、结构简单，适应性强。2、泵送压力高，输送距离远。3、高效率：输送排量大，综合工效高。4、高性能：喷射混凝土性能高，密实、匀质、高强度。5、高可靠性：关键件采用国内知名品牌，保证设备高可靠性。6、速凝剂添加与控制技术：采用知', 1, 1, '创始人', 9, '/show-310.html', 0, 0, '39.96.59.7-35524', 1701154295, 1701154662, 0, '359', '[\"360\",\"361\",\"362\"]', '', '生产能力：7-16㎡/h', ' 输送距离：100米', '\r\n隧道、边坡支护', '', '363'),
(311, 15, '混凝土喷浆车', '364', '', '吊装式喷浆机组可广泛适用于大垮度遂道施工，具有高效、人性化的特点，取代了传统的人工上料施工模式，大限度的节省了劳动力，避免了人工上料杨尘对施工人员的伤害，同时避免了人工上料时未硬化工作面上物料残留造成的浪费。突出优势1、双斗设计 24h连续工作 采用双斗设计，前斗下料，后斗上料，保证喷浆机连续不断24小时工作！上料斗设计容量6方，无爬梯设计，适应各种施工车辆卸料！ 2、液压升降 运行稳定', 1, 1, '创始人', 9, '/show-311.html', 0, 0, '39.96.59.7-35530', 1701154295, 1701154755, 0, '365', '[\"366\",\"367\",\"368\"]', '', ' 生产能力：7-14m³/h', '大输送距离：100m', '\r\n应用于铁路公路隧道、水利水电、地铁、矿山巷道、各种地下建筑建设和抢险等领域的喷浆坡施工。', '', '369'),
(312, 16, '二次构造泵', '394', '', '新型二次构造柱浇筑泵适用于超高层的细石混凝土输送，建筑楼层群体构造柱浇注，是目前国内小的混凝土输送泵，主要是针对一些特殊的施工工况或者狭窄空间施工条件受设备大小的局限而造成施工不便或难以完成施工进度而精心设计高科技产品。设备优势采用S管形式分配阀，满足小骨料混凝土、砂浆的泵送主油泵采用变形柱塞泵，使用效率高，压力强。液压系统采用独立的三回路控制、可靠性高的眼镜板、切割环采用硬质合金、耐磨', 1, 1, '创始人', 9, '/show-312.html', 0, 0, '39.96.59.7-36200', 1701155300, 1701155507, 0, '395', '[\"396\",\"397\",\"398\"]', '', ' 设备型号：10—50型 二次构筑泵', ' 工作效率：6-35m³/h', '\r\n各类工程建设的混凝土垢输送，高层建筑灰砂浆及细石混凝土输送、二次构造柱填充，压力注浆', '', '399'),
(313, 16, '新型软管泵', '400', '', '豫工软管蠕动泵，全新一代 国外技术 多功能多用途，核心部件 知名品牌 客户使用好评度达99%，无密封、无泄漏、自吸能力强、结构简单、操作维护方便。突出优势1、安装方便，运行简单，可长时间运转； 2、自吸力强，吸程8米，扬程100米，水平输送1000米 3、易损件少，更换方便。 4、允许干转、正反转。正转，无回流、虹吸现象，并具备截止阀功能；反转流体可送出并吸回。 5、泵送流体和转速成正比', 1, 1, '创始人', 9, '/show-313.html', 0, 0, '39.96.59.7-36208', 1701155300, 1701155602, 0, '401', '[\"403\",\"402\",\"404\"]', '', ' 吸程 8米 扬程 100米', '水平输送1000米', '\r\n使用温度≤100℃，可定制温度120℃以上软管泵产品，适用于化工行业 污水处理 煤矿冶金 医药生产 水泥砂浆 造纸涂料等行业', '', '405'),
(314, 16, '液压双缸注浆泵', '406', '', '本设备可输送水泥浆、黄泥浆、水玻璃、油、水等多种介质，既可以实现双液注浆,也可以实现单液注浆,也可作为清水泵、污水泵、泥浆泵使用，双液注浆机性能稳定，工作可靠，操作简单，是目前国内质量可靠的一种注浆设备。突出优势全液压传动，体积小，重量轻，注浆输送稳定可靠 工作压力自主调节，超过设置峰值，溢流阀开启，系统自动泄压，安全高效 电动机、风冷器更换防爆部件后，可用于煤矿等易燃易爆场所 在液压系', 1, 1, '创始人', 9, '/show-314.html', 0, 0, '39.96.59.7-36214', 1701155300, 1701155689, 0, '407', '[\"409\",\"408\",\"410\"]', '', '排浆量5-10㎥/h', '大输送距离300/80m(水平/垂直)', '\r\n广泛应用于隧道开凿与维护,道路、桥梁、水坝、矿山建设、高层建筑的基础工程及各类注浆施工', '', '411'),
(315, 16, '拱顶带模注浆一体机', '412', '', '该设备搅拌系统分为上下双层搅拌，搅拌灰/砂浆一次多可搅拌350L 浆料，上部搅拌制浆完成后，浆液可排放至下部搅拌。通过上下部二次搅拌桶配合，可实现向压浆设备不间断供料。配备安装的双缸活塞式砂浆注浆泵，注浆为缸体交互连续式工作方式，压力稳定，泵送浆体无气泡，工作效率8m³/h。抛丸机配套吸尘器泵送压力大：本设备配套双缸活塞式砂浆注浆泵，注浆为缸体交互连续式工作方式，压力稳定，泵送浆体无气泡', 1, 1, '创始人', 9, '/show-315.html', 0, 0, '39.96.59.7-36220', 1701155300, 1701155768, 0, '413', '[\"415\",\"414\",\"416\"]', '', '工作压力8MPa', '工作效率8m³/h', '\r\n\r\n铁路、公路注浆施工、隧道防水注砂浆、部分化工企业生产', '', '417'),
(316, 16, 'BW系列泥浆泵', '388', '', '该泵为卧式三缸往复单作用活塞泵。采用电机、柴油机,流量均匀，压力波动小,效率高，节约能源。突出优势可运送高浓度高粘度', 1, 1, '创始人', 9, '/show-316.html', 0, 0, '39.96.59.7-36226', 1701155301, 1701155392, 0, '389', '[\"390\",\"391\",\"392\"]', '', '大流量：150-320L/min', '大压力：7-10mpa', '\r\n1.煤矿、基坑支护注浆，锚固灌浆 2.抽稀泥浆，污水，混水 3.钻机输送清洗液', '', '393'),
(317, 17, '钢筋笼绕筋机', '436', '', '新型链条式钢筋笼绕筋机，直径误差可控制在1cm内，一米长度的钢筋笼盘筋间距误差可控制在5mm以内，生产效率是人工制作钢筋笼的3-4倍，设备操作工人只需要3-5个人，生产出来的成品钢筋笼主筋、盘筋间距均匀，焊点饱满、牢固。突出优势速度快省人工：待工状态2人可全程生产，正常工况3-6人一天可生产10-20多节钢筋笼。产品达标，间距均匀，完全可达到规范要求。 运转稳定：新型链条式设计，不用外加', 1, 1, '创始人', 9, '/show-317.html', 0, 0, '39.96.59.7-36908', 1701156008, 1701156534, 0, '437', '[\"439\",\"438\",\"440\"]', '', '基本规格：12米单筋、12米双筋', ' 滚笼直径范围：60-3000mm', '\r\n高铁桩（直径0.8-1.2米） 桥梁基础桩（直径1.2-2.5米常用 2.6-3米很少） 房建围桩（0.6-1.2米） 高速高架(直径1.2-2.5米常用)', '', '441'),
(318, 17, '小导管缩尖机', '418', '', '本设备低噪音、高效率缩尖，以及特殊结构设计，缩尖模具耐久度大大提高、简化操作流程，通过更换模具即可达到加工不同 型材的要求，达到一机两用甚至多用，工人仅需简单培训即可上岗操 作。突出优势高频加热，5秒缩尖成型，缩尖长度自由调节，加工面光滑，工件无伤痕 自动化加工，噪音小、易操作、产量高、性能稳定，可代替4-5个人工 独有闭路润滑循环系统，确保机器长时间正常运行 快速更换模具,在相应模具配', 1, 1, '创始人', 9, '/show-318.html', 0, 0, '39.96.59.7-36916', 1701156009, 1701156108, 0, '419', '[\"421\",\"420\",\"422\"]', '', ' 钢筋直径：小6-8mm大32mm', ' 钢管直径：32mm、42mm、50mm', '\r\n主要是针对隧道，地铁工地加工，新型钢材加工，隧道超前小导管缩尖等各种领域的型材缩径加工', '', '423'),
(319, 17, '小导管冲孔机', '424', '', '本机经过多年的优化和改进现已经具备了数控化控制孔位保证精准无误差、特殊结构设计冲针模具耐久度大大提高、简化操作流程，通过更换模具即可达到加工不同型材的要求，达到一机两用甚至多用、工人仅需简单培训即可上岗操作，该设备一经推出便受到广大用户的认可，现已被中铁、中建及中交各大公司及项目部广泛采用。突出优势1、智能数控系统，精准定位，操作简单，效率是人工10倍以上 2、气动夹紧、液压冲孔，数控控', 1, 1, '创始人', 9, '/show-319.html', 0, 0, '39.96.59.7-36922', 1701156009, 1701156191, 0, '425', '[\"426\",\"427\",\"428\"]', '', '360°自动旋转控制', ' 可冲三排孔、四排孔', '\r\n隧道超前小导管冲孔，建筑钢支撑圆管冲孔，吊篮方管冲孔，钢模板角铁冲孔，展示架冲孔，防护栏冲孔等各种领域的型材冲孔加工', '', '429'),
(320, 17, '全自动钢筋镦粗机', '430', '', '该设备用于钢筋连接工程中，它主要功能是把建筑用螺纹钢筋头部挤压墩粗，达到增加钢筋头部直径的目的，增大抗拉强度。本机操作简单、速度快、加工质量高，主要用于适用于建筑，路桥，高铁，地铁，隧道，电站要求较高的工程等国家重点工程，突出优势1、自动开模 模具卡槽全新设计，更换模具方便 2、全自动数控面板，一键启动，循环作业，单人可操作 3、压力表，精准显示压力，确保油压稳定，镦粗更标准 4、夹紧、', 1, 1, '创始人', 9, '/show-320.html', 0, 0, '39.96.59.7-36928', 1701156009, 1701156447, 0, '431', '[\"432\",\"433\",\"434\"]', '', '钢筋直径12-32Ⅱ-Ⅲ级建筑钢筋', ' 镦 粗 长 度： 3.5cm以上', '广泛应用于建筑、路桥、高铁、地铁、隧道、电站要求较高的工程等国家重点工程', '', '435'),
(321, 18, '液压劈裂棒', '442', '', '液压分裂棒主要由高液压泵站和分裂棒两大部分组成。140-180MP超高压油泵站输出的作用力作用于被分裂体孔壁，岩石在巨大的作用力下按预定方向裂开。突出优势1.可控制性 该设备不会像和其它冲击性拆除、凿岩设备那样，产生一些危险隐患；无需采取复杂的措施。 2.环保性 工作时，不会产生震动、冲击、噪音、粉尘、飞屑等。周围不会受到影响，即使在人口稠密地区或室内，以及精密设备旁，都可以无地工作。', 1, 1, '创始人', 9, '/show-321.html', 0, 0, '39.96.59.7-37636', 1701157315, 1701157388, 0, '443', '[\"445\",\"444\",\"446\"]', '', '劈裂力：800吨', '钻孔直径：90/110/130/150mm 钻孔深度≥500mm', '\r\n于各种坚硬岩石的无声开采，花岗岩，火山岩，石英岩、玄武岩，石英斑岩、硅质片岩，砂岩、石灰岩、大理岩、白云岩、黄铁矿等。大方量石方无声开采', '', '447'),
(322, 18, '液压破桩机', '448', '', '破桩机通过动力源给截桩机多个油缸提供压力，油缸直接驱动钎杆，同时挤压桩身，使桩头截除。破桩机施工过程中，操作简单，高效率，低噪音，低成本，适用于桩群施工工程中。破桩机采用高度模块化组合，通过销轴联接模块，可以通过不同模块数量组合，截除一定范围内直径桩头。突出优势通用性：动力来源多元化，根据工地条件可配挖机或者液压系统；链接方式自由灵活，可与多种工程机械自由链接，真正实现产品的通用性和经济', 1, 1, '创始人', 9, '/show-322.html', 0, 0, '39.96.59.7-37644', 1701157315, 1727252978, 0, '449', '[\"451\",\"450\",\"452\"]', '', '圆形截桩机截桩直径：250mm-2500mm', '方形截桩机截桩桩边长：250-650mm', '高铁桥梁，工民建筑桩基工程中得到广泛应用', '', '453'),
(323, 18, '液压绳锯机', '454', '', '液压绳锯机，单人可操作，便携式立式全铝，对较厚的混凝土实现各种切割，是混凝土墙，桥梁和支柱等切割、拆除、修缮适用的切割施工设备，对密排钢筋混凝土结构物，水下30米至50米的切割作业都能胜任，可满足墙锯不及的切割深度。突出优势结合多年施工经验，自行研发 全新一代，全自动钢筋混凝土切割设备，非常适合切复杂截面。 进口动力站 高速切割 意大利进口泵站，国内合资电机厂特别定做的特种电机，动力强劲', 1, 1, '创始人', 9, '/show-323.html', 0, 0, '39.96.59.7-37650', 1701157315, 1701157595, 0, '455', '[\"457\",\"456\",\"458\"]', '', '小输出功率：33HP', ' 给进方式：全自动液压', '\r\n适用钢筋混凝土，桥墩桥梁、支柱，房屋建筑，码头港口，水下切割等领域', '', '459'),
(324, 18, '10型等离子切割机', '460', '', 'YG-10 型是一种用电脑控制、精密机械传动、等离子切割三者技术相结合的高效率、高精度、高可靠性的热切割设备。该系列数控切割机整体外形美观，结构合理。横梁机架采用箱式焊接结构，经振动失效处理以消除焊接过程中产生的应力，具有刚性好、精度高、惯性小、工作平稳的特点。设备特点该设备模块化设计，机器零部件互换性强，设备的功能扩展更为简便。用户可根据对工艺需求配置不同的切割方式如火焰单割炬、火焰双', 1, 1, '创始人', 9, '/show-324.html', 0, 0, '39.96.59.7-37656', 1701157315, 1701157686, 0, '461', '[\"463\",\"462\",\"464\"]', '', ' 设备型号：YG-10', '切割厚度：25mm 以内', '可用于各种异形碳钢、锰钢、不锈钢等金属材料的大、中、小型板材下料。可完成异型板材的多种切割方式，另可选配等离子自动调高系统。', '', '465'),
(325, 18, '矿山绳锯机', '466', '', '豫工新型矿山绳锯机广泛应用于花岗岩开采和大理石开采等设备生产效率高、荒料规整无内伤、可开采大规格石料、开采成本低、符合环保要求、操作更安全。突出优势功能强 效率高：开采深度10-20米。切割速度快，根据石材的硬软可达2.5-12平方米/小时。多角度切割：机体360°旋转，垂直，水平，斜面等多方向切割，可水下切割。成材率高：成本低，切面平整光滑无内伤，锯缝小，不会造成浪费。荒料出材率比传统', 1, 1, '创始人', 9, '/show-325.html', 0, 0, '39.96.59.7-37662', 1701157315, 1701157769, 0, '467', '[\"468\",\"469\",\"470\"]', '', ' 开采深度10-20米', ' 切割速度：2.5-12㎥/h', '\r\n广泛应用于花岗岩开采和大理石开采等', '', '471'),
(326, 19, '非开挖定向钻', '497', '', '水平定向钻是指在不开挖地表表面的条件下，铺设多种地下公用设施（管道、电缆等）一种施工机械。设备优势滑架推进机构快慢速两档，提高空载作业效率；矿山钻机动力头，更适于干/湿式钻进，提高湿式钻进使用寿命；三缸大排量泥浆泵，钻机拉管施工可靠性高双液压夹持器接卸钻杆，提高作业效率；动力头自动浮移机构，有效延缓钻杆丝扣寿命国内知名电动机、液压元件，为钻机提供可靠的工作保障施工现场', 1, 1, '创始人', 9, '/show-326.html', 0, 0, '39.96.59.7-38298', 1701158007, 1701158657, 0, '499', '[\"500\",\"501\",\"502\"]', '', '导向钻头:直径100mm', '注水系统:三缸泥浆泵', '\r\n穿越公路、铁路、建筑物、河流，以及在闹市区、文物保护区、农作物和植被保护区等不易开挖的条件下，进行供水、煤气、电力、电讯、天然气、石油、污水排放等管线的铺设或更', '', '503'),
(327, 19, '水井钻机', '504', '', '按滑架、动力头配置来看是潜孔钻机，按水井钻机来分类，则归属为小型气动水井钻机，按锚固钻机来分类，则与40锚固钻机功能类似。突出优势一款综合多重钻机优点的改进型钻机，既可以农村打水井，也可以装上轮胎，通过其他设备牵引，适合在各种复杂地形施工。图片展示', 1, 1, '创始人', 9, '/show-327.html', 0, 0, '39.96.59.7-38306', 1701158007, 1701158769, 0, '505', '[\"507\",\"506\",\"508\"]', '', '钻孔直径（mm） 100-254', '钻孔深度（m） 200', '适用于工业钻井，民用钻井，地温钻井，具有钻孔直径大，钻孔深，进尺快，移动灵活，适用地域广等优点。', '', '509'),
(328, 19, '工程履带锚固钻机', '478', '', '豫工履带式锚固钻车，22kw电动回转动力头，结构简单、操作容易无需空压机，连接电源即可钻孔配备90-200mm麻花钻杆，硬质合金钻头，推进速度快升举高度高，拆卸钻杆方便突出优势掘进速度快：适应岩土掺杂工程。对硬质岩石，配合豫工分层式合金钻头，快速推进；新设计双轴联动支臂：实现低位孔、水平孔和高位孔钻进，可升至高3.6米钻凿，实现0-90度自由操作，满足各种复杂工况需求。同步升降平台，用于', 1, 1, '创始人', 9, '/show-328.html', 0, 0, '39.96.59.7-38312', 1701158008, 1701158340, 0, '479', '[\"481\",\"480\",\"482\"]', '', ' 液压升降 高3.6-5米', '钻孔深度 30-50m 钻孔直径 Ф90-ф300mm', '\r\n1.土层：三翼钻头钻进，泥浆排渣，适用于土层等地层高速钻进 2.岩层：空气潜孔锤钻进，空气排渣，适用于岩层，破碎层施工 3.含水量大地层：孔底液动锤钻进，泥浆排渣，适用', '', '483'),
(329, 19, '高举升锚固钻机', '484', '', '该钻机采用履带式底盘，行走方便，配套使用麻花钻杆，三叶合金钻头，优点是钻臂的行程高度可达到5.5-20米，日钻孔效率可达400-600米，大大节约了人工成本。该钻机结构新颖，稳定可靠，具有效率高，移动方便，低能耗，投资成本低等优点，成为边坡锚固工程的 产品。突出优势1、全液压控制，操作方便灵活，移位方便，机动性好，2、钻机回转器采用双液压马达驱动，输出扭矩大，提高了钻机钻进平稳性。3、可', 1, 1, '创始人', 9, '/show-329.html', 0, 0, '39.96.59.7-38318', 1701158008, 1701158429, 0, '485', '[\"486\",\"487\",\"488\"]', '', ' 举臂高度：9-30m', '钻孔直径：0-300mm 深度:0-70m', '\r\n建筑、水利、勘探、深基坑支护，边坡加固等工程，尤其适用于基坑锚杆孔、建筑工地钻探', '', '489'),
(330, 19, '潜孔钻机', '490', '', '本设备主要钻进方法：  1. 三翼钻头+螺旋钻杆  钻进，适用于土层等地层高速钻进；2. 钻杆+冲击器+金刚石钻头 钻进，空气排渣：适用于岩层，破    碎层施工；3. 钻杆、套管复合钻进；(配偏心钻头，自由钳，官靴，拔管机)突出优势大优势：满足大孔、深孔、狭窄空间作业打孔直径：90-260打孔深度：60米左右本设备还适用于施工城市深基坑支护、抗浮锚杆及地基灌浆加固工程孔、爆破工程的爆破', 1, 1, '创始人', 9, '/show-330.html', 0, 0, '39.96.59.7-38324', 1701158008, 1701158537, 0, '491', '[\"493\",\"492\",\"494\"]', '', ' 打孔直径：90-260', '打孔深度：60米左右', '\r\n水电站/铁路/公路边坡加固，以及各类地质灾害防治中的滑坡及危岩体锚固工程，特别适合高边坡岩体锚固工程，用于打锚固孔', '', '496'),
(332, 11, '非固化喷涂机', '510', '', '豫工非固化喷涂机高效喷涂，一机=4-5个人工配合配套设备非固化溶胶机、非固化拖桶器，日喷涂面积2000平。6.1L大流量泵，大容量，不憋泵；大流量，不漏料，不浪费雾化扇形高可达80cm，喷涂速度200㎡/h；自动内循环系统，特添加滤网设计，正确操作，不堵管，不堵头快速均匀加热，全程加热免清理，预热时间短。材料成形均匀，厚度从0.5mm到2mm可控专用定制钢泵，经久耐用！公司自主研发、生产加热喷涂软', 1, 1, '创始人', 9, '/show-332.html', 0, 0, '123.160.154.64-57272', 1701160628, 1701160796, 0, '511', '[\"512\",\"513\",\"514\"]', '', ' 胶管耐压：4Mpa', '加热管标配：10米', '可用于坡屋面、隧道、地铁、高铁、管廊、地下室、地下车库等工程的喷涂施工', '', '515'),
(366, 11, '除雪滚', '558', '除雪滚,除雪滚刷', '豫工机械18年市政环卫设备生产厂家，5万平生产车间，型号齐全，产品线丰富，主营：除雪滚刷，除雪铲，融雪撒布机，护栏清洗机等。', 1, 2, '豫工机械', 9, '/show-366.html', 0, 0, '1.192.0.71-50243', 1702280066, 1749431401, 0, '570', '[\"561\",\"560\",\"562\"]', '571', '左右调节:30°', '清扫宽度:2m-3.5m', '适用环卫车、自卸车、皮卡、装载机等', '', '550'),
(367, 11, '除雪铲', '572', '雪铲,除雪铲', '自动避障 移动方便', 1, 2, '豫工机械', 9, '/show-367.html', 0, 0, '1.192.0.71-34147', 1702286555, 1749431373, 0, '575', '[\"552\",\"553\",\"554\"]', '574', '除雪宽度：2m-3.5m', '左右转角：≥30°', '雪滚、雪铲可互相使用，可匹配皮卡、装载机、洗扫车、洒水车等', '', '551'),
(368, 11, '融雪撒布机', '580', '融雪撒布机,融雪剂撒布机', '无级变速 三级防腐 加厚加固 低耗环保', 1, 2, '豫工机械', 9, '/show-368.html', 0, 0, '1.192.3.174-1246', 1702363981, 1702363981, 0, '585', '[\"587\",\"586\",\"588\"]', '589', '料斗容积：0.3-5m³', '撒布宽度：0.6-12米', '粗盐 细盐 除冰剂 细沙 融雪剂', '', '590'),
(369, 11, '工程电热毯', '591', '大型加热毯厂家,电热保温毯', '混凝土保温防冻电热毯可拆卸，可折叠，可直接混凝土表面加热，恒温，均衡加热。', 1, 2, '豫工机械', 9, '/show-369.html', 0, 0, '1.192.3.174-2195', 1702364750, 1744946726, 0, '599', '[\"601\",\"600\",\"602\"]', '598', '保温层厚度：5mm~50mm', '温度控制方式：自动恒温或外置温控装置控制', '主要用于混凝土养护，路面养护防冻，融雪等', '', '603'),
(371, 11, '车载破冰除雪一体机', '642', '车载破冰除雪一体机', '车载破冰除雪机是专为车辆设计的装置，用于清除道路上的冰雪，以保障交通安全。这些除雪机通常安装在车辆的前部，如卡车、拖拉机或特殊的除雪车辆，并通过车辆的动力来驱动。', 1, 1, '创始人', 9, '/show-371.html', 0, 0, '123.160.152.92-37456', 1702871620, 1744946535, 0, '643', '[\"645\",\"644\",\"646\"]', '647', '外形尺寸 3*1.6*1.3m', '破冰厚度 5-200mm', '适用环卫车、自卸车、皮卡、装载机等', '', '648'),
(372, 11, '桥梁蒸汽养护器', '668', '桥梁蒸汽养护器', '桥梁蒸汽养护器是一种桥梁养护设备,通过利用燃油产生蒸汽来进行桥梁的养护工作。这种设备具有便捷、环保等优点,被广泛应用于桥梁的日常养护和维修中。', 1, 1, '创始人', 9, '/show-372.html', 0, 0, '123.52.23.133-1527', 1702954157, 1744946712, 0, '662', '[\"664\",\"663\",\"665\"]', '666', '外形尺寸 600*300*1200mm', '额定功率 3600W', '主要用于钢筋水泥制桥梁的养护工作。', '', '667'),
(373, 11, '机载式凿毛机', '680', '机载式凿毛机', '凿毛机是一种把已经完成的主体结构面进行处理，使两个施工阶段的施工面粘结牢固的类似于斩斧的工具。通常凿毛机是应用在在现浇混凝土结构中，在现浇板浇注完毕后，要凿毛，进行下一层的浇注，让混凝土粘结牢固。所以“凿毛机”一般也被称为“混凝土凿毛机”', 1, 1, '创始人', 9, '/show-373.html', 0, 0, '123.52.23.133-26442', 1702969861, 1702974522, 0, '683', '[\"685\",\"684\",\"686\"]', '682', '重量 330kg/h', '效率 100方/h', '主要用于隧道和桥梁的混凝土路面的凿毛工作', '', '681'),
(374, 11, '路面吹扫机', '701', '路面吹扫机', '车载路面吹风机针对目前高速公路路边角清扫困难而生产的路面清扫设备,具有快速、高效、低工作强度等优点,的解决了高速公路边角清扫困难等问题。', 1, 1, '创始人', 9, '/show-374.html', 0, 0, '123.52.23.133-19239', 1702975536, 1749431511, 0, '703', '[\"705\",\"704\",\"706\"]', '702', '尺寸 1800×1200×1350mm', '吹扫距离 0---12米', '路面吹扫机主要适用于路面的吹扫等作业工作', '', '707'),
(375, 11, '液压铣刨机', '724', '液压铣刨机', '铣刨机液压规格的不仅可以自动行走，而且还是柴油，集合了两种规格的特点。适用也额比较广泛，多种场景都可以尽显它的身影，路面拉毛、地面铣刨、路标清除等，就连冬季的路面除冰都是可以的。', 1, 1, '创始人', 9, '/show-375.html', 0, 0, '123.52.23.133-17968', 1702977265, 1702977769, 0, '726', '[\"727\",\"728\",\"729\"]', '725', '铣刨深度 0-500mm', '行驶速度 40米每MIn', '液压铣刨机主要用于室内或者室外水泥地面的抛锚工作', '', '722'),
(376, 11, '混凝土输送泵', '739', '混凝土输送泵', '混凝土输送泵采用电动机或柴油机驱动泵送系统，通过液压系统恒功率控制自动调节混凝土输送泵的输送量，也可用手动控制来选择混凝土输送量。混凝土输送泵主要有泵送体系、液压和电控体系、主动力体系构成。', 1, 1, '创始人', 9, '/show-376.html', 0, 0, '123.52.23.133-8014', 1702978529, 1702979199, 0, '742', '[\"743\",\"744\",\"745\"]', '741', '外形尺寸 1800*700*1200mm', '水平输送距离 50m', '主要用于工地上的混凝土的搅拌和远距离输送', '', '740'),
(377, 11, '防撞缓冲包', '759', '防撞缓冲包', '防撞缓冲包主要用于高速公路施工，隧道施工，公路施工。最大限度地降低了城市道路和高速公路养护施工中，施工车辆、养护人员和事故处理交警的安全风险问题。', 1, 1, '创始人', 9, '/show-377.html', 0, 0, '123.160.240.5-58931', 1703037304, 1703041107, 0, '762', '[\"763\",\"764\",\"765\"]', '761', '离地间隙   200-300mm', '缓冲垫的厚度   680mm', '防撞缓冲包主要用于普通公路和高速工作的路面施工人员及交警的防撞和安全工作。', '', '758'),
(378, 11, '移动照明车', '777', '移动照明车', '移动照明车适用于各种室内、外场工作场所。中国煤炭行业、中石油、中石化、中海油、电力、冶金、铁路、钢铁、船舶、航空航天、公安消防、化工、政府部门及大型企业照明的使用需要。', 1, 1, '创始人', 9, '/show-378.html', 0, 0, '123.160.240.5-17193', 1703052996, 1744947280, 0, '779', '[\"781\",\"780\",\"782\"]', '778', '电压: 100V-240V', '应急时间: ≥180min', '移动照明车适用于各种室内、外场工作场所的照明使用。', '', '783'),
(379, 11, '隧道风机', '797', '隧道风机', '隧道风机也叫隧道射流风机、隧道风机、射流风机，广泛应用于水利大坝工程、公路、铁路、地铁等隧道的实际使用。', 1, 1, '创始人', 9, '/show-379.html', 0, 0, '123.160.240.5-17193', 1703053020, 1703063327, 0, '799', '[\"801\",\"800\",\"802\"]', '798', '风压（pa） 3500-5500', '风量（m³/min） 1250-2000', '主要应用于水利大坝工程、公路、铁路、地铁等隧道的通风作业。', '', '803'),
(380, 11, '陶瓷柱塞泵', '815', '陶瓷柱塞泵', '陶瓷柱塞泵是一种应用于工业领域的高效、耐磨的泵类设备。它具有许多优良的特性，如使用寿命长、耐腐蚀、高温抗磨损等。', 1, 1, '创始人', 9, '/show-380.html', 0, 0, '123.160.240.5-17193', 1703053043, 1749432265, 0, '817', '[\"819\",\"818\",\"820\"]', '816', '驱动方式 液压驱动', '尺寸 1.6米*1.2米*1.6米', '陶瓷柱塞泵主要是把泥水混合的液体输送到压滤机的前置设备。', '', '821'),
(381, 11, '无轴滚筒筛', '836', '无轴滚筒筛', '无轴滚筒筛又叫无轴滚筒筛沙机，它采用了无轴设计，避免大件软质物料缠绕，可以用于对带状、缠绕性物料进行分级处理，在整个生产运转过程中，滚筒在不停的运转，筛孔不易堵塞，无轴滚筒筛筛分筒可封闭，避免在生产过程中造成尘土飞扬现象。筛分的过大物料小于100mm，中间10-50mm，较细物料可以达到3mm以下。', 1, 1, '创始人', 9, '/show-381.html', 0, 0, '123.160.240.5-12102', 1703053153, 1703123565, 0, '838', '[\"840\",\"839\",\"841\"]', '837', '工作方法 转筒', '重量 1200kg', '主要适用于生活垃圾、建筑垃圾、河沙、黄沙、烘干沙、有机肥、煤粉、锯末等。', '', '842'),
(382, 11, '永磁防汛泵', '849', '永磁防汛泵', '便携式永磁防汛排涝潜水泵重量轻体积小、移动方便。流量大、适用场景广泛、可根据用户要求定做。采用不锈钢制作而成，性能强。主要用于排涝、抗旱、应急抽排水等。', 1, 1, '创始人', 9, '/show-382.html', 0, 0, '123.160.240.5-12102', 1703053177, 1749432181, 0, '851', '[\"852\",\"853\",\"854\"]', '850', '材质: 不锈钢', '驱动方式: 电磁', '永磁防汛泵主要用于防汛工作中的抽水和排水作业。', '', '855'),
(383, 11, '轮式洗砂机', '876', '轮式洗砂机', '轮式洗砂机是天然沙以及人工砂的洗选设备,是配合制砂机使用的一种水洗式制砂的洗砂设备。广泛应用于矿山、冶金、建材、水泥、道路建设、水利水电等领域。', 1, 1, '创始人', 9, '/show-383.html', 0, 0, '123.160.240.5-27458', 1703053252, 1703139709, 0, '871', '[\"873\",\"874\",\"875\"]', '870', '规格 三槽', '生产能力 200吨/小时', '主要用于河沙、人工砂等物料的洗选。', '', '868'),
(384, 11, '绿篱修剪机', '892', '绿篱修剪机', '绿篱修剪机，修剪绿篱和绿墙的机械。通过修剪控制灌木的高度和藤本植物的厚度,并进行造型,使绿篱和绿墙成为理想的景观。可由汽油机、电动机或液压马达带动。工作部件为切割刀片,按其运动方式,分为往复式和旋转式。根据整机结构,分为便携式和悬挂式。', 1, 1, '创始人', 9, '/show-384.html', 0, 0, '123.160.240.5-27458', 1703053293, 1749431520, 0, '894', '[\"895\",\"896\",\"897\"]', '893', '适用对象 边坡、中分带、高枝', '材质 定制钛钢', '绿篱修剪机，主要是车载绿篱修剪机主要用于高速公路和普通公路的高处数木和灌木丛的修剪。', '', '891'),
(385, 13, '水下清淤机器人', '951', '排污机器人,水下清淤履带机器人', '水下清淤机器人操作简单、安全可靠、高效环保、机动灵活、能实现有限空间淤泥一站式处理。', 1, 2, '豫工机械', 9, '/show-385.html', 0, 0, '123.52.22.83-56825', 1717125160, 1722500345, 0, '952', '[\"954\",\"953\",\"955\"]', '', '扬程：5-20米', '遥控距离：300-400米', '适合城市内大小河道、湖库、公园景观水、污水管道、箱涵、隧道、暗涵、雨污分流管道等多种场景的清污', '水下清淤机器人操作简单、安全可靠、高效环保、机动灵活、能实现有限空间淤泥一站式处理。', '956'),
(394, 16, '排水机器人', '1060', '排水机器人,履带式排水机器人,防汛排涝,抗洪排水', '履带式遥控排水机器人具备显著的排水能力，其扬程高且可通过遥控进行操作。该设备能够直接拖拽水带，深入积水区域进行排涝，并将水输送至500米以外的地点。整机重量为1295千克，比同类产品轻20%，具有高机动性和能源效率。接地比压小，低于人行走时的地面压力，可在软地面安全行走。轻量化设计提高了机动性，同时降低了运输和部署成本。', 1, 2, '豫工机械', 9, '/show-394.html', 0, 0, '171.15.10.148-65273', 1749622861, 1749624324, 0, '1061', '[\"1062\"]', '1063', '流量：3000立方米/小时', '扬程：15米', '主要用于暴雨洪涝灾害导致的城市下沉隧道、地下商场、社区地下室、能源物流管廊等地下空间紧急抽排水。', '履带式遥控排水机器人具备显著的排水能力，其扬程高且可通过遥控进行操作。该设备能够直接拖拽水带，深入积水区域进行排涝，并将水输送至500米以外的地点。整机重量为1295千克，比同类产品轻20%，具有高机动性和能源效率。接地比压小，低于人行走时的地面压力，可在软地面安全行走。轻量化设计提高了机动性，同时降低了运输和部署成本。', '1064'),
(395, 16, '手抬消防泵', '1071', '消防泵,细水雾消防泵,手抬式消防泵,应急消防,消防救援,应急救援,森林灭火', '手抬机动消防泵采用品牌国产汽油机与本公司研制的单级离心泵组组成。它集中了国内外同类产品的先进结构和优良性能，具有体积小、重量轻、结构紧凑、起动迅速、使用可靠、维护方便等特点，并且引用了现代先进的滑片泵引水装置，具有引水深度深、速度快等特点，是目前国内较轻便的一种消防泵。移动式手抬消防泵的优势便携性强：由于体积小、重量轻，移动式手抬消防泵可以轻松搬运到偏远地区或复杂地形，确保及时到达火灾现场。操作简', 1, 2, '豫工机械', 9, '/show-395.html', 0, 0, '171.15.10.148-52179', 1749626403, 1750067526, 0, '1089', '[\"1083\"]', '1082', '最大流量：55T/h', '扬程：58m', '无论是城市还是乡村，无论是工厂还是住宅区，移动式手抬消防泵都能发挥出重要作用。特别是在偏远山区、森林草原等难以到达的地方，它更是不可或缺的灭火利器。', '移动式手抬消防泵是一种便携式消防设备，主要由发动机、水泵、吸水管、水带及水枪等组成。它的最大特点是轻便、灵活，可以快速移动到火灾现场进行灭火作业。', '1086');
INSERT INTO `dr_1_chanpinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(278, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(0, 0, 0); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;沥青洒布机是一种黑色路面机械。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(0, 0, 0); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;沥青灌入式路面在碎石层摊铺碾压密实、平整均匀后，在清扫干净、保证干燥的基层上用沥青洒布机喷洒第一遍沥青，在趁热撒布嵌缝料均匀覆盖后，再由沥青洒布机喷洒第二遍沥青，直至喷洒罩面沥青形成路面。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1：携带方便，操作简单，提高工作效率。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2：可直接从方罐圆罐子等各种容器中抽取材料直接进行散布作业&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3：车台上可携带各类的开关材料容器及清洗器（10L）&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4：使用接着式散布装置，可选择的使用种类散布喷头，适用于切削表面乳液的散布及路肩施工等线状散布作业。&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G4523Kb.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G45252M4.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G45324T8.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G4533O10.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G4534TN.jpg&quot; style=&quot;width: 691px; height: 460px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(279, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;沥青搅拌站主要用于废旧沥青混合料加热搅拌，再生利用，变废为宝，也可按比例进行少量新的沥青混合料加热搅拌。不受气温和边缘山区的影响，不受大型沥青搅拌站的制约，随时随地及时快捷地，进行沥青路面坑槽修补，确保道路安全畅通，也可用于摊铺彩色沥青路面和小面积庭院摊铺沥青混凝土。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;一、加热搅拌滚筒&lt;/div&gt;&lt;div&gt;（一）节能环保：加热搅拌滚筒外有保温层，装有除尘设备。&lt;/div&gt;&lt;div&gt;（二）质量可靠：轻油燃烧器的火焰是把搅拌滚筒内的空气加热。&lt;/div&gt;&lt;div&gt;（三）加热时间短：内部叶片螺旋状排列，受热面积大。&lt;/div&gt;&lt;div&gt;（四）劳动强度低：采用底卸式自动提升上料。&lt;/div&gt;&lt;div&gt;二、发电机组&lt;/div&gt;&lt;div&gt;（一）性能可靠：柴油机与发电机直连或三角带传动。&lt;/div&gt;&lt;div&gt;（二）防震效果好：橡胶减震机构，主机架工作时十分平稳。&lt;/div&gt;&lt;div&gt;三、控制系统&lt;/div&gt;&lt;div&gt;&amp;nbsp;具备自整定（AT）功能的AI人工智能控制。&lt;/div&gt;&lt;div&gt;四、使用方便&lt;/div&gt;&lt;div&gt;&amp;nbsp;有车载式；拖拉式；固定式。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-210622120100321.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-210622122435Y4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-210622140244513.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-21062212024I21.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-210622120322939.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-210622120203D0.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210622/2-21062212022V54.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(280, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;后挂式小型融雪剂撒布机安装于工程车、皮卡车、小型客货车后部，适用于公路、小区、机场等冬季冰雪路面防滑沙料和融雪剂的撒布。&lt;br/&gt;选用聚乙烯材质耐腐蚀。12V旋转马达，采用螺旋输送式出料，转速越高抛程越远。有效避免了融雪剂的浪费，保证融雪剂的均匀撒布，单位面积可节约融雪剂40%以上。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;产品特点&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;strong&gt;小巧轻便&lt;/strong&gt;&lt;strong&gt;&amp;nbsp;便于&lt;/strong&gt;&lt;strong&gt;拆&lt;/strong&gt;&lt;strong&gt;装&lt;/strong&gt;：体积小、重量轻，与同类设备相比突显了它的灵活和方便性。冬季过后可方便的将设备卸下另行保存，不占用车辆。&lt;br/&gt; &lt;strong&gt;配合多种轻型汽车使用&lt;/strong&gt;&amp;nbsp;可与多种轻型汽车配合使用，尤其适用皮卡、客货车等小型车辆，便于在市政道路、停车场、狭窄道路抛洒融雪剂清除积雪。&lt;br/&gt; &lt;strong&gt;V型设计 螺旋下料&lt;/strong&gt;：下料斗倒V型垂直设计，料仓内配备12V旋转马达，采用螺旋输送式出料。&lt;br/&gt; &lt;strong&gt;无级变速&lt;/strong&gt;&lt;strong&gt;&amp;nbsp;过载保护&lt;/strong&gt;：控制器无级变速，撒布量、撒布宽度自由选择，大宽度12米，带过载保护功能。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291I043a9.png&quot; style=&quot;width: 695px; height: 384px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291I100324.png&quot; style=&quot;width: 695px; height: 385px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291I111M4.png&quot; style=&quot;width: 695px; height: 388px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291I12B20.png&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(281, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;本设备是平整地面划规定限制标志的路面施工机械，以快速、高效、准确等优点在城市规划和公路建设方面发挥了巨大作用，大程度的节省了路面施工的工期和经济投入。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;寿命长：泵体采用全油侵入式润滑方式，液压助力，减小磨损。使用寿命可达四万小时以上。&lt;/div&gt;&lt;div&gt;耐酸碱耐磨：密封垫精心设计，超耐磨，冬季/夏季使用自如，耐酸碱，耐疲劳，更换简单方便。&lt;/div&gt;&lt;div&gt;操作简单：立式车身，吸液管容易打理清洗，一人可独立移动操作方便。&lt;br/&gt; 不堵塞：&amp;nbsp;吸料管网，不锈钢加工抗腐蚀，内壁不脱落无堵塞。吸液滤网解决了进液面小，易堵塞的问题，增加进液面积，空间缩小。内置加大滤网。&lt;/div&gt;&lt;div&gt;阀体:进液阀和出液阀采用球式体瓷珠超耐磨，比传统钢球超出几十倍寿命。不断面，不碎坐。&lt;/div&gt;&lt;div&gt;维护简单:采用立式设计紧凑实用移动方便，可拆卸，车架可轻松缠绕30米高压软管，整体设备易打理。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326102622362.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032610263K21.jpg&quot;/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326102A2512.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326102F4292.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326102GA55.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326102HTZ.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(282, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;YG380高级手推热熔划线机，是热熔标线施工的关键设备，通过与热熔釜配合使用，完成标线施工。&lt;/div&gt;&lt;div&gt;该机采用特殊制造的高精密度铸铁划线斗，确保所划标线对齐、头齐、厚薄均匀，线型美观。可调节玻璃珠微珠撒播器，设有调速换挡装置，可调节撒播宽度。具有标线施工质量高，施工速度快，操作灵活，维护简单等特点&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备结构&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;1.&lt;strong&gt;涂料桶&lt;/strong&gt;：双层不锈钢保温加热桶，容量100kg插入式手动搅拌装置，可拆卸装置。&lt;/div&gt;&lt;div&gt;2.&lt;strong&gt;玻璃微珠贮存箱&lt;/strong&gt;：25kg/箱&amp;nbsp;&lt;/div&gt;&lt;div&gt;3.&lt;strong&gt;玻璃珠微珠撒播器&lt;/strong&gt;：同步离合撒播，设有调速换档装&lt;/div&gt;&lt;div&gt;4.&lt;strong&gt;划线斗&lt;/strong&gt;：高精度超薄材质制造，刮板式结构，标准配置150mm&lt;/div&gt;&lt;div&gt;5.&lt;strong&gt;落地刀&lt;/strong&gt;：硬质合金，设有偏心套装置，能够调整标线厚度范围：1-2.5mm&lt;/div&gt;&lt;div&gt;6.&lt;strong&gt;胶轮&lt;/strong&gt;：铝合金轮股，耐热橡胶特制，后尾轮设有定位器，使车体沿直线方向前行&lt;/div&gt;&lt;div&gt;7.&lt;strong&gt;标线宽度&lt;/strong&gt;：根据工程要求更换不同规格划线斗&amp;nbsp; &amp;nbsp;&lt;/div&gt;&lt;div&gt;8.&lt;strong&gt;加热方式&lt;/strong&gt;：石油液化气，携带液化气罐；分别供给涂料桶、划线斗前后喷火嘴，三个调节阀门分别控制火力大小。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G20644611.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G20AbE.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G20H94L.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G20JL10.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G20KL11.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(283, 1, 11, '&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;6532名客户一致选择它高效清理地面&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402145322316.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/strong&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;strong&gt;&lt;span style=&quot;font-size:18px;&quot;&gt;突出优势&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;效率高 省人工：&lt;/strong&gt;一次性施工，即可得到干净整洁，粗糙度均匀的表面，工作效率高。&lt;br/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032610360GX.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;混凝土地面打毛&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103622451.png&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;清理成本低&lt;/strong&gt;：钢丸损失小，易损件更换方便，有效降低施工成本&lt;br/&gt;&lt;strong&gt;粗糙度可调&lt;/strong&gt;：地面清理粗糙度可调，深可抛3-4mm，符合不同的清理要求。&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103632591.png&quot;/&gt;&lt;br/&gt;深度抛丸效果展示&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032610364M20.png&quot;/&gt;&lt;br/&gt;较浅抛丸效果展示&lt;br/&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;暴露地面裂纹 防患于未然&lt;/strong&gt;：清理表面干净整洁，粗糙度均匀，没有损伤，同时将混凝土地面的裂纹充分暴露出来，防患于未然。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103A9227.png&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;抛丸前地面展示&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103G0392.png&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(284, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;通过压力注射式灌缝，使材料和缝壁紧密结合&lt;br/&gt;转向灵活的万向轮跟踪裂缝，使灌缝效果美观。&lt;br/&gt;由于灌缝材料使用沥青或灌缝胶，在温度较低时容易凝固，灌缝机配有汽油发电机提供电力，灌缝机在出料管部位采用恒温控制系统，避免材料烧焦老化，保证出料的顺畅。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;自主研发汽电一体化混合动力，电驱动技术，低排放、低耗能、节能环保&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;先进的智能点火、检测控温技术&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;独特的油套热熔釜设计，&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;导热油处于釜内部四周及底部，使得加热均衡，胶料不容易碳化，&lt;/span&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;并配置安全阀全循环，加热更快、更均匀.&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;唯一的热循环加热系统设计，进口意大利利雅路445T1柴油燃烧器，油耗低。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;高效的出料系统设计&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;整机安全低重心设计&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;电动搅拌&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;热熔釜防堵塞设计&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103053254.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103104255.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210330/2-210330092ULE.jpg&quot; style=&quot;width: 691px; height: 691px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326103114U9.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(285, 1, 11, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;1、有吸尘器连接装置，提供无尘工作环境&lt;br/&gt; 2、可以长时间工作，功率大，强劲有力&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;3、可以调节地面铣刨深度，铣刨深度达8mm&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;4、直径60mm钨钢铣刀片，良好的耐用性&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;5、刹车装置操纵灵活，有效调节行走速度&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;6、特别适用于大范围的地面处理，速度快，效率高&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;7、硬质合金大刀片，八星强劲大刀片，刀片是金刚石硬度，刀头先镶嵌，后焊接，更为结实耐用&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;8、深度是可以调节的，有深度调节轮，旋转即可&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;9、刀鼓采用涨紧套连接，扭矩大抗冲击&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G4320V10.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G4322K24.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G43239B4.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G43251B9.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G43302533.jpg&quot; style=&quot;width: 691px; height: 319px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G43313626.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032G433561L.jpg&quot; style=&quot;width: 691px; height: 371px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(286, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工客土喷播机，可以加土喷播机，可以添加适量的稻壳、锯末增加泥浆的附着力；采用常柴单缸柴油机，可以根据施工工地海拔高度选定不同马力的柴油机；可私人订制。&lt;br/&gt;设备适合30米以上边坡、陡边坡、缓边坡、石质边，喷播厚度一次大约在2-3cm，可挂铁丝网，配86-247kw的四缸或者六缸柴油机.具有出口压力大 扬程远 喷播效率高的特点&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工客土喷播机分为两大机型：机械搅拌系统、液压搅拌系统；&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;搅拌采用螺旋叶片搅拌与回流冲刷搅拌相结合的模式，形成立体搅拌；&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;采用单台柴油机驱动，油耗低，操作易维护，降低使用成本和工作成本；&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;360°旋转万向喷头，配有组合喷头及引管阀门，方便作业面进行调换；&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;现拥有客土喷播机核心泵特制加压的单级泵、多级泵，客户可选择性大，可以将粘稠物料从喷嘴处高速喷出，直接射程20-90m。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326110211603.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326110223Z5.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261102333D.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326110244612.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(287, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;催化燃烧装置是指在催化剂作用下燃烧的装置或设备。借助催化剂使有机废气在较低的起燃温度下进行无焰燃烧,使有机废气分解为无毒的二氧化碳和水蒸汽。广泛应用于线材加工、机械、电机、化工、设备、汽车、发动机、塑料、电器、石油、化工、印染等行业。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;工作原理&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;低浓度废气经过活性炭吸附后达标排放，此时活性炭逐步饱和后切换炭箱继续吸附。该饱和炭箱则吸附阀门关闭，脱附阀门打开经催化燃烧内加热的温度并通过换热器送入饱和炭箱进行底温（70℃-100℃）及温度产生的压力使活性炭内堆积的有机溶剂脱附下来并由脱附风机送入催化燃烧内的催化室在200℃—400℃无焰低温环境下与催化剂产生反应变成二氧化碳和水达标排放。被脱附后的炭恢复了活性后继续切换下个炭箱进行脱附炭再生，以此循环&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161131605.jpg&quot; style=&quot;width: 590px; height: 302px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161K2E6.jpg&quot; style=&quot;width: 524px; height: 168px;&quot;/&gt;&lt;br/&gt; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;催化燃烧工艺流程示意图&amp;nbsp;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;br/&gt; &lt;div&gt;近十多年的研究表明，催化燃烧技术完全可能解决可燃气体燃烧不充分，二次污染的问题，使燃气燃烧达到低排放的标准，近于零排放，同时可以有效提高炉膛内热效率。&lt;/div&gt;豫工机械催化燃烧设备可燃组分浓度和热值限制较小；起燃温度低，大部分有机物和CO在200℃~400℃即可完成反应，故辅助燃料消耗少，而且大量地减少了NOx的产生,可用来消除恶臭。&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-21033116120Y35.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-21033116121a12.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161243K0.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161253518.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161304552.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331161314c3.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(288, 1, 13, '&lt;h2&gt;割草船产品介绍&lt;/h2&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;按照船型设计规范采用链轴式增强尼龙输送带或不锈钢输送带,具有滤水性好、高耐磨、寿命长易维护等优点。收集舱进料端搭载切割沉水植物的L形切割系统、打散打碎作用的机械滚轮装置实现水体水面层不同深度各类水草垃圾的收集打捞。&amp;nbsp;&lt;/span&gt;&lt;/div&gt;&lt;h2&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;割草船设备参数&lt;/span&gt;&lt;/h2&gt;&lt;table border=&quot;1&quot; cellspacing=&quot;0&quot;&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;小型半自动&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;中型全自动&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;大型全自动&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割面积：2000㎡/h&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割面积：3000㎡/h&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割面积：5000㎡/h&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;储草量：5-8m³&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;储草量：10-15m³&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;储草量：15-20m³&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割深度：0.6-1m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割深度：0.6-1m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;收割深度：0.6-1m&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;驱动方式：明轮&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;驱动方式：明轮&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;驱动方式：明轮&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;柴油机功率：24kw&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;柴油机功率：40kw&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;柴油机功率：56-85kw&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作航速：2-4km/h&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作航速：2-4km/h&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作航速：2-4km/h&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;卸载高度：0-3m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;卸载高度：0-3m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;卸载高度：0-3m&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;整船吃水深度：0.5m-0.6m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;整船吃水深度：0.5m-0.6m&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:189px;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;整船吃水深度：0.5m-0.6m&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;h2&gt;割草船设备优势&lt;/h2&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、单组或多组明轮推进,液压驱动控制明轮无级调速实现设备前进后退和转向,具备狭窄水域原地调头和不缠绕水体水草杂物的优点。&amp;nbsp;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2、前收后卸作业形式,工作舱衔接处交错层叠布置有效增加装载量,卸料作业时卸载舱自动开启门档。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230210/2-230210161546309.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;/span&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3、工艺精良 抗腐蚀，加厚钢槽 稳固耐用，整机运行稳定，寿命长。&lt;br/&gt;\r\n 4、处理效率高，18年生产技术，设计合理，维修方便，处理量大，功率消耗小，洗净度高。&lt;br/&gt;\r\n 5、自动化程度高，通过严格检测，保质保量，智能化控制，效率高，容易操作！稳定耐用，型号齐全，种类多，质量好，按照客户需求，支持定制加工。&lt;/span&gt;&lt;/p&gt;&lt;h2&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;割草船工作现场&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230210/2-230210154K5316.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230210/2-230210154Q2S5.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230210/2-230210154RC61.png&quot;/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_chanpinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(289, 1, 13, '&lt;h2&gt;射吸式抽沙船简介&lt;/h2&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;射流式抽沙船也可叫作抽沙平台,是指利用水力的作用,将高压水枪出的水柱冲起的淤泥(或细沙、海沙等)在吸沙泵的作用下有管道输送到目的地，设计新颖，操作简便，效率高，适用于河道疏浚、湖泊水库清淤、围海造田、港口码头清理、抽砂等。该设备由船体、输送系统、进水系统、排空系统等组成，输送系统包括动力、离合器、泥浆泵等，排空系统包括高压水泵、抽真空装置等。&lt;/span&gt;&lt;/div&gt;&lt;h2&gt;射吸式抽沙船基本参数&lt;/h2&gt;&lt;h3&gt;&amp;nbsp;&lt;/h3&gt;&lt;p style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none; font-variant-numeric: normal; font-variant-east-asian: normal; font-stretch: normal; line-height: 1.4; font-family: &amp;quot;Hiragino Sans GB&amp;quot;, Tahoma, Arial, 宋体, sans-serif; color: rgb(51, 51, 51);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none; font-family: simsun; font-size: 14pt; color: rgb(0, 51, 0);&quot;&gt;&lt;span data-spm-anchor-id=&quot;a261y.25179003.137725730131935.i1.2ec36b6dh3j366&quot; style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none;&quot;&gt;下抽13米，输送距离500米，扬程38米&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none; border-collapse: collapse; border-spacing: 0px; color: rgb(51, 51, 51); font-family: &amp;quot;Hiragino Sans GB&amp;quot;, Tahoma, Arial, 宋体, sans-serif;&quot;&gt;&lt;tbody style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none;&quot;&gt;&lt;tr style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none;&quot;&gt;&lt;td style=&quot;box-sizing: border-box; text-size-adjust: 100