100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none; font-family: simsun; font-size: 14pt; color: rgb(0, 51, 0);&quot;&gt;&lt;span style=&quot;box-sizing: border-box; text-size-adjust: 100%; -webkit-tap-highlight-color: transparent; margin: 0px; padding: 0px; outline: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;h2&gt;射吸式抽沙船设备优势&lt;/h2&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;抽沙/清淤连续作业&lt;/strong&gt;：抽取、输送、排出和处理各工序一次性完成。&lt;br/&gt;&lt;strong&gt;操作简单&lt;/strong&gt;：相对绞吸式抽沙船，射吸式抽沙船成本造价低，操作简单，设计新颖。&lt;br/&gt;&lt;strong&gt;输送距离远&lt;/strong&gt;：根据沙质情况不同，单泵输送可达2公里以上，抽沙浓度可达40%。&lt;br/&gt;&lt;strong&gt;满足多种需求&lt;/strong&gt;：根据需求产量及工矿环境，配套相应泵型，满足不同需求。&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;h2&gt;射吸式抽沙船施工现场&lt;/h2&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-2302091P002623.jpg&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-2302091P033T2.jpg&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-2302091P105Q2.jpg&quot; style=&quot;width: 800px; height: 800px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-2302091P132c9.jpg&quot; style=&quot;width: 800px; height: 800px;&quot;/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(290, 1, 13, '&lt;h3&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;双轴撕碎机产品简介&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;双轴撕碎机又名剪切式撕碎机：通过剪切、撕裂和挤压达到减小物料尺寸，这种撕碎机广泛应用于废塑料、废橡胶、易拉罐、木材和其它大体积废弃物，我公司将欧美制造该类设备三十多年的经验引进中国，并根据国内实际情况进行改进，研发，推出技术成熟和设计先进的双轴撕碎机系列，为我国的废物回收利用前期的破碎，减容处理提供质量可靠的设备。&lt;/span&gt;&lt;/p&gt;&lt;h3&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;撕碎机设备参数&lt;/span&gt;&lt;/h3&gt;&lt;table align=&quot;center&quot; border=&quot;1&quot; cellspacing=&quot;0&quot;&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;型号&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;主轴功率&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;主轴转速&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;产量&lt;/strong&gt;&lt;strong&gt;(t/h)&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;刀盘数量&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;刀盘直径&lt;/strong&gt;&lt;strong&gt;mm&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;破碎粒度&lt;/strong&gt;&lt;strong&gt;cm&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;料仓尺寸&lt;/strong&gt;&lt;strong&gt;mm&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-600&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;18.5kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;23&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;0.5-0.8&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;260&lt;/span&gt;&lt;/td&gt;&lt;td rowspan=&quot;7&quot; style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong&gt;3-10&lt;/strong&gt;&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;820*900&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-800&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;22kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;1-2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;350&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;1000*1000&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-1000&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;30kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;18&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;2.5-3.5&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;25&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;400&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;1200*1000&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-1200&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;45kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;18&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;5-8&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;30&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;500&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;1400*1000&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-1500&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;55kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;16&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;8-12&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;32&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;550&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;2000*1200&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-1800&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;75kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;16&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;10-18&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;36&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;600&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;2300*1200&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td style=&quot;width:66px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;YG-2000&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:78px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;90kw*2&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:74px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;14&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:72px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;15-25&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:71px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;40&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:75px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;650&lt;/span&gt;&lt;/td&gt;&lt;td style=&quot;width:85px;&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;2425*1400&lt;/span&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;h3&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;实力大厂 品质保证&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;大料块粉碎&lt;/strong&gt;：特厚钢结构,强力旋转轴,抗高扭矩，大口径投料斗。&lt;br/&gt;&lt;strong&gt;撕碎力强&lt;/strong&gt;：独特回转刀设计，剪切力强、刀刃锋利，强力破碎。&lt;br/&gt;&lt;strong&gt;PLC控制&lt;/strong&gt;：处理物过大、过多时，设正逆运转和停机保护。&lt;br/&gt;&lt;strong&gt;寿命长&lt;/strong&gt;：特殊合金动刀及定刀，坚固耐用,切削能力强，产能高&lt;br/&gt;&lt;strong&gt;售后完善&lt;/strong&gt;：产品三包，一年质保，终身维护，18年经验服务全国。&lt;/span&gt;&lt;/p&gt;&lt;h3&gt;双轴撕碎机适用物料&lt;/h3&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;废旧家电壳：拆下洗衣机壳，冰箱壳，彩电壳等&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;废弃木制品：建筑工地模板、方木、木板、树枝、树根、木箱、床垫、橱柜、旧家具等&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;废旧家居用品(如棉胎、地毯、旧衣服鞋帽)&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;铜丝电线电缆(单条不能超过￠2cm,整扎不能超过￠4cm)&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;各种废旧金属：铜，铝，铅以及厚度在5mm以下的钢板&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;餐厨垃圾、生活垃圾、动物尸体、RDF衍生物、医疗垃圾、生物桔杆、园林垃圾&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;胶头料、纸厂绞绳&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;木托盘，塑料托盘树根、树桩、树干和树枝&lt;/span&gt;&lt;/div&gt;&lt;h3&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;双轴撕碎机工厂实拍&lt;/span&gt;&lt;/h3&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-230209152UB07.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-2302091529194F.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-230209152940H5.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230209/2-230209153001U1.png&quot; style=&quot;width: 750px; height: 750px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(291, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;厢式压滤机是由多块滤板排列组成滤室。滤板的表面有凸点，用以支撑滤布。滤板的中心和边角上有液体通过孔，滤板排列后构成完整的通道，能通入悬浮液、洗涤水和引出滤液。滤板&amp;nbsp;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;厢式压滤机具有过滤压力大、过滤速度快、含水率低、滤板不易损坏等优点，聚丙烯厢式滤板填充玻璃纤维后可耐120度高温物料过滤，厢式压滤机容易实现自动化控制。适用于物料浓度比较大，处理重大的各种行业使用。&lt;br/&gt; 机械压紧压滤机是由电动机带动减速机，经齿轮带动丝杠推动压紧板压紧滤板。大齿轮采用滚珠运动能保证压紧时的可靠性和稳定性。用继电器控制电流实现压紧后自动停止，可对电机实现过热和过载保护。具有性能稳定、结构简单、操作方便、安全、省力，易维修，经久耐用。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104JE31.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104KT20.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104Q01Q.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104R2949.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104S22R.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104T3Y1.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104U34X.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326104Z3145.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(292, 1, 13, '&lt;p&gt;&amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;筛土机是对土进行筛选的振动筛，包括带点粘性的土，除去土（包括带粘性的土）中石块、碎石块、腐叶烂叶等杂质以及对土（包括带粘性的土）进行分级，筛选出粒径更小的细土等等。&lt;br/&gt;对于有粘性的土，可加大振动频率，用可选机型有直线振动筛，要求处理量特别大的可选用圆振筛。&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;安装基础简易：因整个设备为箱形框架结构，只需有一平整地面即可。地面硬化便于清扫。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;高度整体性：除成品料堆料皮带机外，所有系统都集成于一个整体框架内，既保证了设备的整体性又留有适度的维修保养和巡视空间。便利和安全。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;拆装转场简便：设备的高度整体性便于施工现场存放或转场运输，拆装部件只有成品堆料皮带机，松开底部固定螺栓和吊挂钢丝绳，将成品皮带机塞入主框架底面即可。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作可靠性：其核心的筛分系统采用搅拌机的搅拌原理，原料在搅拌筒内受连续螺旋叶片翻滚、推挤及物料间相互磨擦作用，作用强烈可靠性高。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;滚筛筒平置，料流在筛筒螺旋叶片间滚筛五圈以上，使砂料反复翻滚而充分离散、筛分。不同于斜置滚筛或斜置振动筛所引起的大小料相互冲挤或大料托小料振跳而引起的筛分不彻底、混料现象。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105632362.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105643249.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105A3921.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105Fc91.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105G92D.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105HY55.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(293, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;泥浆净化机，也称为建筑工程泥浆处理设备，整机一体化程度高，占地面积小，结构合理，便于移动，设备自带变频调节电控柜对效果及电机可实现控制保护，泥沙回收效率高，脱水干堆效果理想，该设备在管道及出砂口均做了高标准密封，降低施工中对周边飞溅泥浆。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;泥浆充分净化，有效控制泥浆的性能指标，减少卡钻事故，提高造孔质量。&lt;br/&gt; 泥浆循环使用，节约造浆材料，减少废浆外运成本和造浆费用。&lt;br/&gt; 对土渣有效分离，提高造孔效率&lt;br/&gt; 泥浆闭路循环净化方式以及较低的渣料含水率减少对环境的影响&lt;br/&gt; 双层筛网，净化效果比单层筛网提高近50%以上，操作安全方便，维护简单，运行稳定。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261052033I.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105219119.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105230139.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032610524HK.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261053001K.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105309517.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326105322K4.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(294, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;ZW型自吸式无堵塞排污泵适用于化工、石油、制药、采矿、造纸、纤维、浆料、纺织、食品、电厂及市政排污工程、公共设施排污、河塘养殖等行业。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;1、排污能力强：特殊的叶轮防堵设计，确保了泵高效且无堵塞。&lt;/div&gt;&lt;div&gt;2、高效节能：采用优秀水力模型，效率比一般自吸泵高3～5%。&lt;/div&gt;&lt;div&gt;3、自吸性能好：自吸高度比一般自吸泵高1米，且自吸时间更短。&lt;br/&gt; 4、防汛泵规格型号齐全，从普通款到自吸泵、拖车式&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331142TU23.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331142Z11V.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331142920246.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-21033114293N07.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-2103311429531a.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_chanpinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(295, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;室内外墙体喷涂、水泥砂浆灌浆、桥梁灌浆及防水表面喷涂、防火喷涂、天花顶喷涂、墙壁喷涂、涂料喷涂、园林喷涂、浮雕效果涂料喷涂、吸音材料喷涂、防水堵漏、防水补漏专用设备&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;产品特点&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;1. 调节流量大小，调出蕞佳喷涂效果。&lt;/div&gt;&lt;div&gt;2. 除在电控箱上可以开关外，还配备遥控开关喷涂。&lt;/div&gt;&lt;div&gt;3. 喷枪与送料管的连接可以旋转，便于操作。&lt;/div&gt;&lt;div&gt;4. 施工效率高，质量好。&lt;/div&gt;&lt;div&gt;5. 体积小巧，便于现场搬运，而且配件费用低, 维修简单。&lt;/div&gt;&lt;div&gt;6. 使用方便、速度快、省材料、省人工、更省钱,一台机器只配三个人, 150平方 /小时（厚度2cm）。&lt;/div&gt;&lt;div&gt;7. 材料比例（水泥）0.7：3砂浆。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331111Q0L3.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331111T4517.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331111Z3194.jpg&quot; style=&quot;width: 800px; height: 400px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-21033111191X16.jpg&quot; style=&quot;width: 800px; height: 400px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331111930924.jpg&quot; style=&quot;width: 800px; height: 451px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210331/2-210331111956438.jpg&quot; style=&quot;width: 800px; height: 451px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(296, 1, 13, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;喷砂技术广泛用于船舶、桥梁、水利工程、矿山机械制造、石油、化冶金、港口建设、轻工、飞机制造、机车车辆、仪器仪表、精密制造、电子工业等领域；是金属表面涂覆前大面积清理理想的方法；对非涂覆表面可达到表面强化、光饰和雕刻作用。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;产品特点&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;strong&gt;操作简单&lt;/strong&gt;，普工30min熟练操作，自动控制系统防工人误操作&lt;br/&gt; &lt;strong&gt;生产效率高&lt;/strong&gt;，一台喷砂机=50-80名熟练工人&lt;br/&gt; &lt;strong&gt;喷砂精度高&lt;/strong&gt;，去除微小、隐蔽飞边，不受形状限制，合格率高。&lt;br/&gt; &lt;strong&gt;可除结构复杂&lt;/strong&gt;，可除任何形状小型橡塑合金制品、脆性塑料制品、镁/锌/铝合金铸件飞边&lt;br/&gt; &lt;strong&gt;不伤制品表面&lt;/strong&gt;，提高产品外观质量，增加产品使用寿命。&lt;br/&gt; &lt;strong&gt;占地少&lt;/strong&gt;，一台喷砂机加上附属设备只需10平方米&lt;br/&gt; &lt;strong&gt;技术先进&lt;/strong&gt;：日本先进技术，效率提高30%，磨料和能耗损失降低20%；安全、可靠、结构简单，易于操作与维修。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291K454O8.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291K513C7.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291K523223.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-2103291K540F7.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(297, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;箱梁、T梁砼在硬化的过程中，对温度湿度的变化非常敏感，如果养护工作不当或不及时，混凝土表面水分散失太快，混凝土在拆模前、甚至终凝前箱梁、T梁就会产生裂缝。采用智能喷淋养生系统只需设定好养护时间及循环范围并进行全天候、全湿润的养护效果显著。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;抛丸机配套吸尘器&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;本机可随意调节工作时间、间隔时间及工作次数，手机远程操作，远程电脑监控，手动自动可随意切换，可以达到全天候、全湿润的养护质量标准，养护效果极为显著。同时喷淋系统从供水到工作完毕，基本实现了过程全自动智能化控制，大大降低劳动强度，提高劳动生产率，具有成本低，安装、维修方便，节约用水等显著优点。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;冬季蒸汽养生和夏季喷淋养生可共用此系统&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326110923H1.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040215355AY.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326110935414.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326111003647.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(298, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;预应力智能压浆设备由于集高速制浆机、自动称重系统、储浆桶、进浆/出浆检测设备、压浆泵于一体，现场使用只须将进浆管和返浆管与预应力管道对接，即可进行压浆施工，操作简单，使用方便，受到广大桥梁，公路等施工人员的喜爱。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;预应力智能压浆设备特点：自动配料，高精度的称重传感器( 称重精度&amp;lt;0.2% ) ,准确的控制了水灰比。高速制浆系统自动控制搅拌时间、规范搅拌过程,大大提高了浆液质量。循环压浆从管道 低点压入,从出浆口导流到低速搅拌桶,浆液在孔道内循环,通过压力将孔道内空气从出浆口和钢绞线缝隙完全排出,关闭出浆口后继续加压,在持荷时间内保持不低FO.5MPa的压力。精 确的压力测控装置能精 确的控制压力,保证了孔道压浆的密实性。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040215462A39.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154F4509.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154H2Z1.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154I5405.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(299, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;预应力智能张拉是指不依靠工人手动控制，而是利用计算机智能控制技术，通过仪器自动操作，完成钢绞线的张拉施工。&lt;br/&gt;&lt;div&gt;由于智能系统的高精度和稳定性，能完全排除人为因素干扰，有效确保预应力张拉施工质量，是目前国内预应力张拉领域较先 进的张拉设备。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;设备实现了远程监控的功能，可以在操作室对整个操作过程进行查看，还能够观察数据分析，随时进行调整。&lt;/div&gt;&lt;div&gt;在安全性方面进行了很大的改进，机器操作过程出现断电情况，设备将会立即停止工作来确保安全性。&amp;nbsp;&amp;nbsp;&lt;/div&gt;&lt;div&gt;设备上的电脑具有自动计算的功能，而且精度非常高，产生的误差小。能够根据频率来判定需要的油压，能够实现对张力值的正确控制，而且随着设备的移动，可以精 确的测量出需要的伸长量。&amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/div&gt;&lt;div&gt;设备自动化的操作，使其受外界环境的影响较小，在任何的环境下，设备都可以进行操作，即使在雨天等恶劣环节，设备也可以进行操作。&amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/div&gt;&lt;div&gt;设备操作简单，设备的电脑界面没有太复杂的程序，也没有太多的技术含量，操作人员经过简单的培训就能够掌握要领。&amp;nbsp; &amp;nbsp;&amp;nbsp;&lt;/div&gt;&lt;div&gt;设备建立了报警系统，在实际操作的过程中，出现任何故障或者说张拉结果不符合要求等等，系统会自动报警，以保证设备运行的安全性。 　　&lt;/div&gt;&lt;div&gt;另外，这种张拉设备还有多重安全防护功能，卸载保护等等， 大限度的提高设备的安全性，减少设备运行过程中产生的事故隐患&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040215432W07.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154313557.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154420B0.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402154436340.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040215424Tc.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(300, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工机械&lt;/span&gt;&lt;/span&gt;&lt;/a&gt;防撞台车与以往的防撞墙施工相比，进一步提高了桥梁防撞墙施工进度和施工质量，也确保了桥梁防撞墙施工高处作业安全，为优质、高效、安全的完成桥梁防撞墙施工创造了良好条件。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备特点&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;豫工防撞墙模板台车适应于桥梁防撞墙模板的吊装，运输，安装，拆卸，能够满足小半径弯桥、各种桥梁要求。同样，在平桥，直桥施工条件好的地方更加方便。&lt;/div&gt;&lt;div&gt;本产品使用于-20~40℃，无火灾、无爆炸和无腐蚀性介质的环境中工作。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;施工现场&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P232460.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P245246.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P259104.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P313a0.jpg&quot; style=&quot;width: 695px; height: 588px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P32X54.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051P344602.jpg&quot; style=&quot;width: 695px; height: 500px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(301, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;豫工钢绞线穿束机为机械传动，通过电机带动主动轮转动，钢绞线从一端进线口插入，压轮压住钢绞线向前移动沿导管传入预留孔道，直到从孔道另一端传出，达到张拉用尺寸。&lt;br/&gt;该设备集放线和穿线为一体，质量可靠，设计合理，可进，可退，可连续传送，也可点动传送，传达钢绞线速度无极调速，体积小，重量轻，操作方便，性能可靠，应用广泛，是建造桥梁和大型建筑物采用有预应力工作中为孔道穿钢绞线的主要工具。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;1、 节约大量人力，只需上下两人，大大减轻劳动强度，节省了人员管理。&lt;/div&gt;&lt;div&gt;2、 操作易学，维修方便，无任何浪费，大大节约了材料费用。&lt;/div&gt;&lt;div&gt;3、 钢绞线不用提前切割存放，提高生产效率，保证材料质量。&lt;/div&gt;&lt;div&gt;4、 每分钟穿线70-80米，两人日穿钢绞线18-20吨，15000-18000米，32M高速铁路箱梁两跨，成本低，高效快速准确。&lt;/div&gt;&lt;div&gt;5、 设备轻便，易于拆卸、安装、运输。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430121J3637.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430121P23R.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430121R2G5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430121S5504.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430121U1540.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(302, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;用于灰浆搅拌，可连续搅拌水泥灰浆、砂浆，是注浆泵的佳配套设备&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;设备具有体积小,重量轻,易于安装搬运等特点&lt;br/&gt; 双层制浆,出浆率高！灰浆经第一次搅拌后进入搅拌桶，不会沉淀离析，第二次搅拌出料通畅，避免堵浆。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&amp;nbsp;&lt;/div&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&amp;nbsp;&lt;/div&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-210419151022N4.jpg&quot; style=&quot;width: 695px; height: 727px;&quot;/&gt;&lt;br/&gt; 180L立式款快速制浆机&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-2104191510332N.jpg&quot; style=&quot;width: 695px; height: 714px;&quot;/&gt;&lt;br/&gt; 180L卧式款快速制浆机&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-210419151044D6.jpg&quot; style=&quot;width: 695px; height: 834px;&quot;/&gt;&lt;br/&gt; 200L款高速制浆机&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-210419151101Z2.jpg&quot; style=&quot;width: 695px; height: 838px;&quot;/&gt;&lt;br/&gt; 900型高速制浆机&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041915111IJ.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;制浆机施工现场\r\n &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(303, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;螺旋筋成型机采用微电脑全自动PLC编码数控控制系统，用户只需在数控编码显示器上输入螺旋筋间距，米数，切断长度，误差为5mm以内，即可实现螺旋筋自动加工切断，大大提高了工程精度效率，加工速度20-40米/分钟。&lt;br/&gt;该机型可设置批次，可全自动加工一捆钢筋。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;1.&amp;nbsp;&lt;strong&gt;智能数控&lt;/strong&gt;&lt;strong&gt;&amp;nbsp;提高效率&lt;/strong&gt;&lt;br/&gt; 全自动螺旋筋成型机采用单片机集成控制，任意调节参数，多种参数储存功能、数字显示、节省时间，方便管理，提高生产效率。&lt;br/&gt; &lt;strong&gt;2.进口核心器件，延长使用寿命&lt;/strong&gt;&lt;br/&gt; 关键部分采用进口器件，确保本机的使用寿命，采用编码器计米误差极小，准确定位。&lt;br/&gt; &lt;strong&gt;3.平稳、快速、准确&lt;/strong&gt;&lt;br/&gt; 本机具有平稳、快速、准确的特点，可快速、慢速、倒顺料施工。&lt;br/&gt; 平稳：全部具有液压传动，摆线马达，无需齿轮助力，可减少齿轮间隙&lt;br/&gt; 快速：每分钟20-40米&lt;br/&gt; 准确：打圆误差±0.50MM&lt;br/&gt; &lt;strong&gt;4.箱型结构 传动灵活可靠&lt;/strong&gt;&lt;br/&gt; 本机为箱型结构，刚性好，液压传动部分灵活可靠。&lt;br/&gt; &lt;strong&gt;5.快速送料 自动启停&lt;/strong&gt;&lt;br/&gt; 控制箱设有：快速送料、自动切断、手动切断、自动停止、在启动等功能。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326091G1507.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326091H33B.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326091IM16.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326091K01W.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(304, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;单双缸活塞泵，可输送水泥浆、黄泥浆、水玻璃、油、水等多种介质。&lt;br/&gt;具有结构紧凑、工作可靠、故障率低、清理及维修方便及泵送压力高等优点。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;适用范围&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;广泛用于隧道、矿井采掘工作面注浆堵水，岩巷及混凝土井壁注浆堵漏水，隧道裂痕、破碎岩体、疏散岩石的加固补强，锚固注浆，回填注浆和防止地表下沉，防止滑坡，纠正建筑物偏斜所进行的注浆等。&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-210419120140445.png&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-2104191201525A.png&quot; style=&quot;width: 695px; height: 545px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041912020DE.png&quot; style=&quot;width: 695px; height: 441px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041912021U96.jpg&quot; style=&quot;width: 695px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;br/&gt; 双缸注浆，大流量、高压力，输出量大，双缸注浆，效率更好&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041912000C43.png&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;br/&gt; BY-1型抗震压力表 ，自动调压，降低事故率&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-210419120023415.png&quot; style=&quot;width: 695px; height: 462px;&quot;/&gt;&lt;br/&gt; 结构紧凑，造型美观 ，可拆性好，便于拆装和搬迁&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041912003O57.png&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&amp;nbsp;&lt;/div&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&amp;nbsp;&lt;/div&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;国标纯铜电机 动力强劲 性能可靠 故障率低，生产效率高&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210419/2-21041912011XK.png&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(305, 1, 14, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;波纹管制管机是生产预应力混凝土预留孔道金属波纹管的设备,采用镀锌或冷轧钢带(黑带)卷制成双波形经咬边扣压而成波纹管。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;产品优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;体积小、效率高，维护简单，易学易懂&lt;/div&gt;&lt;div&gt;可随意更换模具，适合各种型号的波纹管。&lt;/div&gt;&lt;div&gt;齿轮传动，噪音低，传送稳定。&lt;/div&gt;&lt;div&gt;省料、出管率高,与国内同机型相比,同规格的钢带,产管多。&lt;/div&gt;&lt;div&gt;速度快,无级调速电机,制管速度可达 5000米/日&lt;/div&gt;&lt;div&gt;省电。加工Ф70mm波纹管，百米耗电0.7度&lt;/div&gt;&lt;div&gt;质量三包,经久耐用，20万米以内不需大修&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-21041609225I29.jpg&quot; style=&quot;width: 695px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-210416092310I9.png&quot; style=&quot;width: 695px; height: 341px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-21041609232TN.png&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-210416092344Z1.png&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-21041609240aL.png&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;发货现场&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-2104160925195W.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210416/2-2104160925312c.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;豫工机械&lt;/span&gt;&lt;/a&gt;是&lt;/strong&gt;国内大型预应力设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(306, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;本设备采用直条钢筋送料生产方式，操作简单，效率高，主要用于焊接钢筋直径3.0-14.0mm，网片宽度3000mm以内网片，焊接长度在12米以内的生产加工。该设备在吸收国内外先进的机电控制电阻焊技术的基础上，自行研制成功的一种自动钢筋网片焊接设备。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;自动化 省人工：&lt;/strong&gt;机器加装调直筒和调直排，直接盘丝入料，实现自动化，省去预先调直切断和人工摆放，节省时间设备和人工。&lt;br/&gt; &lt;strong&gt;精度高 焊点牢固：&lt;/strong&gt;钢筋网排焊机焊接主机采用同步控制技术,系统稳定，工作效率高，使用寿命长,精度高,焊点焊接牢固。&lt;br/&gt; &lt;strong&gt;新型焊接 丝径范围大&lt;/strong&gt;：焊接变压器采用了新型水冷却高效焊网变压器,焊接电流任意可调,扩大了焊接丝径范围；焊接铜头采用焊接专用铬锆铜块，并采用水循环冷却，很大程度的降低了损耗率,并可多面使用。&lt;br/&gt; &lt;strong&gt;智能拉网 轻松改变孔距&lt;/strong&gt;：钢筋网片排焊机拉网系统使用计算机编程控制,横筋间距可通过控制柜的显示器任意调整,改变孔距方便简单,，在同一张网片上可以实现多达30多种不同的间距。&lt;br/&gt; &lt;strong&gt;PLC控制 操作简单&lt;/strong&gt;：触控屏操作，简单易学，加入自停报警功能，机器异常会自动停止，机器自带剪片机，网片达到设定长度自动剪断，自动落网，机器不用停止，提升效率。&lt;br/&gt; &lt;strong&gt;自动落丝 提高人效&lt;/strong&gt;&amp;nbsp;PLC控制电机自动落丝,不须人工摆放。（配备有横丝落料检测系统）&amp;nbsp;全程操作只需1一2人。&lt;br/&gt; &lt;strong&gt;核心部件 防腐耐用&lt;/strong&gt;&amp;nbsp;关键零部件全部采用合金材料，并经过反夏的高温热处理 从而达到非常高的硬度。并且表面通过特殊的防腐处理。在防腐的同时保证零部件顺畅运行。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;图片展示&lt;/span&gt;&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040215503S59.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402155150J8.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040216003W22.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402160054942.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(307, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;中空注浆锚杆的组成：&lt;br/&gt;1.普通式中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞 +塑料锚头&lt;/div&gt;&lt;div&gt;2.自进式中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞+合金钻头&lt;/div&gt;&lt;div&gt;3.组合式中空注浆锚杆由：0.5m32*5mm中空锚杆体+垫板+螺母+止浆塞+22mm/25mm钢筋+锚头+排气管+连接套&lt;/div&gt;&lt;div&gt;4.涨壳中空注浆锚杆由：锚杆体+垫板+螺母+止浆塞+涨壳锚头&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;中空设计，实现了注浆的功能。&lt;/div&gt;&lt;div&gt;注浆饱满，并可实现压力注浆。&lt;/div&gt;&lt;div&gt;杆体的居中性好，砂浆可以将锚杆体全长包裹 ，避免了锈蚀的可能性，达到长期支护的目的。&lt;/div&gt;&lt;div&gt;安装方便，不需现场加工螺纹，就可方便的安装垫板、螺母。&lt;/div&gt;&lt;div&gt;采用向上排气锚头，彻底解决了水平线以上中空锚杆排气问题。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image1&quot;&gt;&lt;div class=&quot;body_image_center1&quot;&gt;&lt;div class=&quot;body_image_block1&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备参数&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content1&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q21142461.png&quot; style=&quot;width: 695px; height: 392px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备资质&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q204591K.jpg&quot; style=&quot;width: 695px; height: 500px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q20515H3.jpg&quot; style=&quot;width: 695px; height: 995px;&quot;/&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;工厂及发货现场&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q20610537.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q206392A.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q20A62P.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210628/2-21062Q20R3644.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(308, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;数控弯管机比普通冷弯机多一套数字编码控制系统，一套自动控制系统，液压智能控制阀，光电控制传感器，编码式电子尺，电子计米器。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;strong&gt;液压锁设计,一次成型&amp;nbsp;&amp;nbsp;&lt;/strong&gt;弯曲过程，不会出现油缸后退，保证弯曲精度&lt;br/&gt; &lt;strong&gt;加厚加粗顶辊&amp;nbsp;&amp;nbsp;&lt;/strong&gt;配备强劲动力，顶弯型钢更有力&lt;br/&gt; &lt;strong&gt;自动棍防滑处理&amp;nbsp;&amp;nbsp;&lt;/strong&gt;行进自如不打滑，效率高&lt;br/&gt; &lt;strong&gt;更大减速机，弯拱更有力&amp;nbsp;&amp;nbsp;&lt;/strong&gt;国标纯铜电机&amp;nbsp;运行更稳定&lt;br/&gt; &lt;strong&gt;液压控制屏&amp;nbsp;&amp;nbsp;&lt;/strong&gt;PLC程序控制器，弯曲精度高&lt;br/&gt; &lt;strong&gt;液压驱动系统&amp;nbsp;&amp;nbsp;&lt;/strong&gt;大压力，动力更强，操作更精确&lt;br/&gt; &lt;strong&gt;高品质液压油缸&amp;nbsp;&amp;nbsp;&lt;/strong&gt;加大油缸&amp;nbsp;弯拱更有力&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032611250I06.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032611251Y63.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326112530J9.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326112541b9.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326112F9135.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(309, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;隧道机械手整机高度低，回转半径小，能够使用于施工场地受限的工程；同时底盘采用刚性底盘，内燃-静液压传动，四轮驱动，配合四轮同向转向和可旋转驾驶室；四个斜撑式液压支腿保证底盘在承受喷射机械手施工及料斗进料的动作负荷时具有足够的稳定性。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;1、混凝土输送系统&lt;/div&gt;&lt;div&gt;A、先进的无阻尼液压系统和长达1.2米的抽吸泵送行程，使泵送压力强劲而平稳，同时降低能耗和零件磨损。&lt;/div&gt;&lt;div&gt;B、可根据客户需要将泵送调节达到0~60立方米的宽范围。利于完成复杂工况的喷浆工作。（推荐泵送调节范围为5--20立方米）&lt;/div&gt;&lt;div&gt;2、电控系统&lt;/div&gt;&lt;div&gt;A、完备的本机操作和遥控操作系统，配备过电压和低电压保护，双重应急停机安全保护。&lt;/div&gt;&lt;div&gt;B、电脑人机对话: 施喷数据输入和记录储存；显示即时运转工况和运转数据；故障报告；PLC控制液压系统；混凝土泵和计量泵同步程控。&lt;/div&gt;&lt;div&gt;C、高质量的无线遥控器，可遥控所有喷浆动作。&lt;/div&gt;&lt;div&gt;3、速凝剂添加系统&lt;/div&gt;&lt;div&gt;先进可靠的变频变速技术，结合PLC和电脑控制，根据混凝土输出量和设定添加比率，自动调节变频器输出，实现电机变速和自动按混凝土输送量调整添加剂添加量。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;br/&gt; &lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/1-210611151302425.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/1-21061115133C14.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/1-210611151349319.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/1-210611151401J9.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(310, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;液压湿喷机是泵送式混凝土湿喷机，系 统可靠性高，输送量稳定。喷射量连续调节：主油 泵采用变量柱塞泵，喷射速度可自由调节。速凝剂 添加量连续可调：可根据喷浆量无级调节。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、结构简单，适应性强。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2、泵送压力高，输送距离远。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3、高效率：输送排量大，综合工效高。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4、高性能：喷射混凝土性能高，密实、匀质、高强度。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5、高可靠性：关键件采用国内知名品牌，保证设备高可靠性。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;6、速凝剂添加与控制技术：采用知名品牌计量泵，计量准确，雾化射流与喷嘴料流 混合使得速凝剂与混凝土混合均匀。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;7、降低了机旁和喷嘴外的粉尘浓度，消除了对工人健康的危害。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;8、回弹度低。干喷时，混凝土回弹度达15%-50%,采用湿喷技术，回弹率甚至可降 低到10%以下，有效节约成本。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;9、采用风冷却方式冷却液压油，简单环保。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;10、一机多用，既可作为湿喷机用，也可作为混凝土输送泵用。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-21040216231W58.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402162332140.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402162544U2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021626053U.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402162649355.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(311, 1, 15, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;吊装式喷浆机组可广泛适用于大垮度遂道施工，具有高效、人性化的特点，取代了传统的人工上料施工模式，大限度的节省了劳动力，避免了人工上料杨尘对施工人员的伤害，同时避免了人工上料时未硬化工作面上物料残留造成的浪费。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、&lt;strong&gt;双斗设计 24h连续工作&lt;/strong&gt;&amp;nbsp;采用双斗设计，前斗下料，后斗上料，保证喷浆机连续不断24小时工作！上料斗设计容量6方，无爬梯设计，适应各种施工车辆卸料！&lt;br/&gt; &lt;strong&gt;2、液压升降 运行稳定 &lt;/strong&gt;料斗升降、支腿全部采用液压动力，力量大，运行稳，操作手柄方便快捷！&lt;br/&gt; &lt;strong&gt;3、加厚钢材 永不变形&lt;/strong&gt;&amp;nbsp;喷浆车机架采用加厚钢材，承载能力大，保证机体刚性，不易变形，安全结实。主梁从尾到头均采用国标矩型钢，一通到底。&lt;br/&gt; &lt;strong&gt;4、专利设计 节省物料&lt;/strong&gt;&amp;nbsp;速凝剂添加采用震动式，出料可控，速凝剂可定量添加。后料斗采取单独振动方式，在喷浆料潮湿卸料不畅情况下，启动振动下料。&lt;br/&gt; &lt;strong&gt;5、操作简单 维修方便 &lt;/strong&gt;两台7型喷浆机控制按钮位于机体两侧，方便各喷浆机操作人员操作。&lt;br/&gt; 前料斗可翻转。在前料斗翻转情况下，可拆卸维修喷浆机。&lt;br/&gt; &lt;strong&gt;6、支持定制 全国发货&lt;/strong&gt;&lt;br/&gt; 整机尺寸、料斗大小、设备配置，根据需要量身定制，全国发货&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402155623b5.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326113442553.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402155H3C0.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402155J9200.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_chanpinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(312, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;新型二次构造柱浇筑泵适用于超高层的细石混凝土输送，建筑楼层群体构造柱浇注，是目前国内小的混凝土输送泵，主要是针对一些特殊的施工工况或者狭窄空间施工条件受设备大小的局限而造成施工不便或难以完成施工进度而精心设计高科技产品。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;采用S管形式分配阀，满足小骨料混凝土、砂浆的泵送&lt;/div&gt;&lt;div&gt;主油泵采用变形柱塞泵，使用效率高，压力强。&lt;/div&gt;&lt;div&gt;液压系统采用独立的三回路控制、可靠性高的眼镜板、切割环采用硬质合金、耐磨、寿命长&lt;/div&gt;&lt;div&gt;泵送机构采用双缸活塞式，性能先进，连续性好&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;整机展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916122305501.jpg&quot; style=&quot;width: 800px; height: 400px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916122349493.jpg&quot; style=&quot;width: 800px; height: 400px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916122411H5.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091612243ET.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916122504963.jpg&quot; style=&quot;width: 800px; height: 400px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(313, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;豫工软管蠕动泵，全新一代&amp;nbsp;国外技术&amp;nbsp;多功能多用途，核心部件&amp;nbsp;知名品牌&amp;nbsp;客户使用好评度达99%，无密封、无泄漏、自吸能力强、结构简单、操作维护方便。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;1、安装方便，运行简单，可长时间运转；&lt;br/&gt; 2、自吸力强，吸程8米，扬程100米，水平输送1000米&lt;br/&gt; 3、易损件少，更换方便。&lt;br/&gt; 4、允许干转、正反转。正转，无回流、虹吸现象，并具备截止阀功能；反转流体可送出并吸回。&lt;br/&gt; 5、泵送流体和转速成正比，计量准确&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120331213.jpg&quot; style=&quot;width: 691px; height: 516px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120345525.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032612035K45.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032612040Qa.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032612041Q59.jpg&quot; style=&quot;width: 691px; height: 388px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021632429B.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(314, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;本设备可输送水泥浆、黄泥浆、水玻璃、油、水等多种介质，既可以实现双液注浆,也可以实现单液注浆,也可作为清水泵、污水泵、泥浆泵使用，双液注浆机性能稳定，工作可靠，操作简单，是目前国内质量可靠的一种注浆设备。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;全液压传动，体积小，重量轻，注浆输送稳定可靠&lt;br/&gt; 工作压力自主调节，超过设置峰值，溢流阀开启，系统自动泄压，安全高效&lt;br/&gt; 电动机、风冷器更换防爆部件后，可用于煤矿等易燃易爆场所&lt;br/&gt; 在液压系统中设有耐震压力表，抗震性能好&lt;br/&gt; 新型散热系统，散热面积大，散热效果好，使液压系统运行更稳定&lt;br/&gt; 吸浆口、出浆口双进双出设置，口径可调，流量可调&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120921428.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120930551.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120941S6.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120950506.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(315, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;该设备搅拌系统分为上下双层搅拌，搅拌灰/砂浆一次多可搅拌350L 浆料，上部搅拌制浆完成后，浆液可排放至下部搅拌。通过上下部二次搅拌桶配合，可实现向压浆设备不间断供料。&lt;br/&gt;配备安装的双缸活塞式砂浆注浆泵，注浆为缸体交互连续式工作方式，压力稳定，泵送浆体无气泡，工作效率8m³/h。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;抛丸机配套吸尘器&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;strong&gt;泵送压力大&lt;/strong&gt;：本设备配套双缸活塞式砂浆注浆泵，注浆为缸体交互连续式工作方式，压力稳定，泵送浆体无气泡，高可达8MPa&lt;br/&gt; &lt;strong&gt;施工效率高&lt;/strong&gt;：结构设计合理，上下两层搅拌，可实现不间断供料，生产效率高，工作效率8m³/h。&lt;br/&gt; &lt;strong&gt;安全可靠&lt;/strong&gt;：压力稳定，拥有三道压力检测表，施工更安全。标配20米38高压砂浆专用注浆管&lt;br/&gt; &lt;strong&gt;计量精确&lt;/strong&gt;：小分度置为0.IMpa,计量更为精确&lt;br/&gt; &lt;strong&gt;操作简单&lt;/strong&gt;：自动化程度高，集PLC智能数显、自动记录流量、压力、搅拌、泵送浆为一体的集成砂浆注浆设备&lt;br/&gt; &lt;strong&gt;移动方便&lt;/strong&gt;：本台车设计为移动式，一人即可移动设备&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251P23bN.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251P2553L.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251P311646.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(316, 1, 16, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;该泵为卧式三缸往复单作用活塞泵。采用电机、柴油机,流量均匀，压力波动小,效率高，节约能源。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;可运送高浓度高粘度&amp;lt;10000PaS及富含颗粒的悬浮浆液&lt;br/&gt; 输送液流平稳、无过流、脉动及拌和、剪切浆液表象&lt;br/&gt; 排出压力与转速无关，低流量也可持续排出高压力&lt;br/&gt; 流量与转速成正比，经过调速可完成流量调节&lt;br/&gt; 自吸力强，可直接抽吸液体；泵可反转，适用管道正反向冲刷&lt;br/&gt; 运转平稳、无振荡、噪音小，可拆性好，便于维修和搬迁&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120040218.jpg&quot; style=&quot;width: 691px; height: 691px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120050D6.jpg&quot; style=&quot;width: 691px; height: 691px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120101325.jpg&quot; style=&quot;width: 691px; height: 512px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326120111c3.jpg&quot; style=&quot;width: 691px; height: 388px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(317, 1, 17, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;新型链条式钢筋笼绕筋机，直径误差可控制在1cm内，一米长度的钢筋笼盘筋间距误差可控制在5mm以内，生产效率是人工制作钢筋笼的3-4倍，设备操作工人只需要3-5个人，生产出来的成品钢筋笼主筋、盘筋间距均匀，焊点饱满、牢固。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;strong&gt;速度快&lt;/strong&gt;&lt;strong&gt;省人工&lt;/strong&gt;：待工状态2人可全程生产，正常工况3-6人一天可生产10-20多节钢筋笼。产品达标，间距均匀，完全可达到规范要求。&lt;br/&gt; &lt;strong&gt;运转&lt;/strong&gt;&lt;strong&gt;稳定&lt;/strong&gt;：新型链条式设计，不用外加辅助圈，节省时间，绕筋速度快，运营稳定噪音小。机械化作业不受人为因素影响，长时间工作可稳定质量不变。&lt;br/&gt; &lt;strong&gt;适合&lt;/strong&gt;&lt;strong&gt;不同钢筋：&lt;/strong&gt;针对不同箍筋数量，形式、型号、大小、长度的设计要求，不会因设备功能而影响钢筋笼设计或不能上机生产。&lt;br/&gt; &lt;strong&gt;转运便捷&lt;/strong&gt;：组合式设计使搬运、安装、生产等过程不依赖起重设备，适应工厂化大批量固定生产和施工现场分散的机动作业。&lt;br/&gt; &lt;strong&gt;流水线形式&lt;/strong&gt;：独立施工不受各工序影响，不间断完成主筋箍筋焊接成型，绕筋过程施焊等全部过程。&lt;br/&gt; &lt;strong&gt;精准定位 安装更快&lt;/strong&gt;：采用螺纹连接技术可精准定位，帮助提高钢筋笼分解、安装速度。&lt;br/&gt; &lt;strong&gt;按需定制 上门服务&lt;/strong&gt;：包教会，免费上门安装调试！单双筋，自由切换，根据您的需要为您定制。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326115614G1.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021A32D54.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-2103261156433S.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021AGLD.jpg&quot; style=&quot;width: 691px; height: 565px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(318, 1, 17, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;本设备低噪音、高效率缩尖，以及特殊结构设计，缩尖模具耐久度大大提高、简化操作流程，通过更换模具即可达到加工不同 型材的要求，达到一机两用甚至多用，工人仅需简单培训即可上岗操 作。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;高频加热，5秒缩尖成型，缩尖长度自由调节，加工面光滑，工件无伤痕&lt;br/&gt; 自动化加工，噪音小、易操作、产量高、性能稳定，可代替4-5个人工&lt;br/&gt; 独有闭路润滑循环系统，确保机器长时间正常运行&lt;br/&gt; 快速更换模具,在相应模具配合下，可轻松加工不同形状金属管，满足不同需求。&lt;br/&gt; 气动加紧装置，力度大，不跑偏，加工精密稳定&amp;nbsp;&lt;br/&gt; 伺服电机 加工精度高&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021A93H17.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021A95JI.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F202G7.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F044630.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(319, 1, 17, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;本机经过多年的优化和改进现已经具备了数控化控制孔位保证精准无误差、特殊结构设计冲针模具耐久度大大提高、简化操作流程，通过更换模具即可达到加工不同型材的要求，达到一机两用甚至多用、工人仅需简单培训即可上岗操作，该设备一经推出便受到广大用户的认可，现已被中铁、中建及中交各大公司及项目部广泛采用。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;1、智能数控系统，精准定位，操作简单，效率是人工10倍以上&lt;br/&gt; 2、气动夹紧、液压冲孔，数控控制，精度高，工件快速成型&lt;br/&gt; 3、送料系统360°精准旋转，双排对穿孔，可冲3、4排孔，孔径6-12mm&lt;br/&gt; 4、设备标准件数控加工，精度高，大限度延长设备使用寿命&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F456223.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F512Z3.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F6064O.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021F620343.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(320, 1, 17, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;该设备用于钢筋连接工程中，它主要功能是把建筑用螺纹钢筋头部挤压墩粗，达到增加钢筋头部直径的目的，增大抗拉强度。本机操作简单、速度快、加工质量高，主要用于适用于建筑，路桥，高铁，地铁，隧道，电站要求较高的工程等国家重点工程，&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;1、自动开模 模具卡槽全新设计，更换模具方便&lt;br/&gt; 2、全自动数控面板，一键启动，循环作业，单人可操作&lt;br/&gt; 3、压力表，精准显示压力，确保油压稳定，镦粗更标准&lt;br/&gt; 4、夹紧、镦粗双液压缸，性能稳定，效率高&lt;br/&gt; 5、13-32mm钢筋镦粗，不用更换撞头。模具高强度淬火处理，耐用，寿命长。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021A01a03.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402163550351.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021A035491.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-210402163604245.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(321, 1, 18, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;液压分裂棒主要由高液压泵站和分裂棒两大部分组成。140-180MP超高压油泵站输出的作用力作用于被分裂体孔壁，岩石在巨大的作用力下按预定方向裂开。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;1.&lt;strong&gt;可控制&lt;/strong&gt;&lt;strong&gt;性&lt;/strong&gt;&amp;nbsp;该设备不会像和其它冲击性拆除、凿岩设备那样，产生一些危险隐患；无需采取复杂的措施。&lt;br/&gt; 2.&lt;strong&gt;环保性&lt;/strong&gt;&amp;nbsp;工作时，不会产生震动、冲击、噪音、粉尘、飞屑等。周围不会受到影响，即使在人口稠密地区或室内，以及精密设备旁，都可以无地工作。&lt;br/&gt; 3.&lt;strong&gt;经济性&lt;/strong&gt;&amp;nbsp;&amp;nbsp;1分钟可完成劈裂，并且可连续无间断地工作（即使下雨天等恶劣天气），效率高，运行及成本很低，无需像作业那样采取隔离或其它耗时和昂贵的审批措施。&lt;br/&gt; 4.&lt;strong&gt;精准&lt;/strong&gt;&lt;strong&gt;性&lt;/strong&gt;&amp;nbsp;与大多数的拆除设备不同， 劈裂棒可以预先的确定劈裂方向，劈裂形状，劈裂精度高。&lt;br/&gt; 5.&lt;strong&gt;适用性&lt;/strong&gt;&amp;nbsp;人性化的外形设计和耐用性结构设计，确保了其使用简单易学，仅需两人操作，便捷，使用寿命长；液压泵站80公斤，搬运相当方便。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251HJ9601.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251HPQ05.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251HR5459.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210329/2-210329151956121.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(322, 1, 18, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;破桩机通过动力源给截桩机多个油缸提供压力，油缸直接驱动钎杆，同时挤压桩身，使桩头截除。&lt;br/&gt;破桩机施工过程中，操作简单，高效率，低噪音，低成本，适用于桩群施工工程中。&lt;br/&gt;破桩机采用高度模块化组合，通过销轴联接模块，可以通过不同模块数量组合，截除一定范围内直径桩头。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;通用性：动力来源多元化，根据工地条件可配挖机或者液压系统；链接方式自由灵活，可与多种工程机械自由链接，真正实现产品的通用性和经济性；可伸缩吊链式设计，满足多地形施工作业要求&lt;br/&gt; 安全性：施工人员不接触施工，适合复杂地形安全施工要求&lt;br/&gt; 环保性：全液压驱动，实现桩头施工的低噪音作业，施工时，不影响周边环境，静液压径向施工，对母桩及设备无影响。&lt;br/&gt; 低成本：操作系统简单便捷，人员配备较少，降低人工成本、机器维护等施工成本&lt;br/&gt; 多功能：圆桩机和方桩机实现模块通用，变换模块组合实现圆桩、方桩皆能破除，一机双用&lt;br/&gt; 便捷性：体积小、重量轻，运输便捷；简易的模块拆换设计，通过变换模块数量，满足不同桩径的施工，模块重组是拆装简单快捷&lt;br/&gt; 寿命长：质量可靠，使用寿命更长&lt;br/&gt; &lt;strong&gt;承载设备&lt;/strong&gt;&lt;br/&gt; 挖掘机：挖机同时提供动力和提升力&lt;br/&gt; 液压系统+吊车：液压系统提供动力，吊车提供提升力&lt;br/&gt; 液压系统+装载机：液压系统提供动力，装载机提供提升力&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H334B4.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H34VV.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H403Y5.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H416360.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H42UW.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(323, 1, 18, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;液压绳锯机，单人可操作，便携式立式全铝，对较厚的混凝土实现各种切割，是混凝土墙，桥梁和支柱等切割、拆除、修缮适用的切割施工设备，对密排钢筋混凝土结构物，水下30米至50米的切割作业都能胜任，可满足墙锯不及的切割深度。&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;结合多年施工经验，自行研发 全新一代，全自动钢筋混凝土切割设备，非常适合切复杂截面。&lt;br/&gt; &lt;strong&gt;进口动力站 高速切割 &lt;/strong&gt;意大利进口泵站，国内合资电机厂特别定做的特种电机，动力强劲，高速切割；静态破拆 无震动拆除，不破坏被拆除物体周边构造。&lt;br/&gt; &lt;strong&gt;航空材质 轻便抗摔&lt;/strong&gt;&amp;nbsp;航空机架铝合金型材，强度高，轻便抗摔、不怕水，不怕灰尘，抗压抗撞击。&lt;br/&gt; 便携式立式结构，单人可操作，可自由拆卸，多角度切割，安全省力。&lt;br/&gt; &lt;strong&gt;高效切割 平直整齐 &lt;/strong&gt;液压绳锯工作时无振动、低噪音、定位准。&lt;br/&gt; 施工时保证切口平直，整齐，无需修边处理，并可以在钢筋混凝土，陶瓷，玻璃上切割。远程手柄操控，重量轻，体积小&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021K515N9.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021K53C20.png&quot; style=&quot;width: 695px; height: 496px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021K556194.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021K60OF.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021P100J9.jpg&quot; style=&quot;width: 695px; height: 465px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(324, 1, 18, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;YG-10 型是一种用电脑控制、精密机械传动、等离子切割三者技术相结合的高效率、高精度、高可靠性的热切割设备。该系列数控切割机整体外形美观，结构合理。横梁机架采用箱式焊接结构，经振动失效处理以消除焊接过程中产生的应力，具有刚性好、精度高、惯性小、工作平稳的特点。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备特点&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;该设备模块化设计，机器零部件互换性强，设备的功能扩展更为简便。用户可根据对工艺需求配置不同的切割方式如火焰单割炬、火焰双割炬、火焰直线三割炬、火焰单割炬+抽条机、火焰双割炬+抽条机和各种规格的等离子割炬等等。&lt;/div&gt;&lt;div&gt;机械传动系统采用精密滚动轴承和 7 级精度的齿轮齿条传动。齿轮箱采用精密行星齿轮减速器，机械结构增设了自动补偿齿隙装置，使之能做到无齿隙传动，保证了切割机良好的使用性能和精度。整机定位精度、重复精度达到 JB/T5102-1999 标准，切割质量达到 JB/T10045.3-1999、JB/T10045.4-1999 标准.&lt;/div&gt;&lt;div&gt;YG-10 型可用于各种异形碳钢、锰钢、不锈钢等金属材料的大、中、小型板材下料。可完成异型板材的多种切割方式，另可选配等离子自动调高系统。&lt;/div&gt;&lt;div&gt;目前YG-10 型是一种高精度钢板热切割的新型自动化设备，该设备已在造船工业、重型机械、化工设备、锅炉制造、机车车辆、石油化工等制造行业得到广泛应用。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505154P0V5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505154T0911.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505154911F3.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050515495c22.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050515501a47.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(325, 1, 18, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;豫工新型矿山绳锯机广泛应用于花岗岩开采和大理石开采等&lt;br/&gt;设备生产效率高、荒料规整无内伤、可开采大规格石料、开采成本低、符合环保要求、操作更安全。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;功能强 效率高：开采深度10-20米。切割速度快，根据石材的硬软可达2.5-12平方米/小时。&lt;/div&gt;&lt;div&gt;多角度切割：机体360°旋转，垂直，水平，斜面等多方向切割，可水下切割。&lt;/div&gt;&lt;div&gt;成材率高：成本低，切面平整光滑无内伤，锯缝小，不会造成浪费。荒料出材率比传统工艺出材率可提高50%以上。&lt;/div&gt;&lt;div&gt;操作安全环保：无噪音，无粉尘，分离式操控，劳动强度低，安全性高&lt;/div&gt;&lt;div&gt;自动化程度高:操作界面简单直观，显示主机设定电流、主电机转速等参数，中央电脑控制，操作简单，容易掌握，切割工艺自动控制。&lt;/div&gt;&lt;div&gt;一人操作多台：具备自动与手动功能，在设备自动运行时可完全实现无人操作，一人操作多台设备&lt;/div&gt;&lt;div&gt;石料开采专用：花岗岩、大理石、青石、石灰石等各种矿山及大型桥梁和高层建筑的分离拆迁。&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021HH6237.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021HJ6292.jpg&quot; style=&quot;width: 691px; height: 319px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021HP2493.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021H915536.jpg&quot; style=&quot;width: 691px; height: 460px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210402/2-2104021HU9120.jpg&quot; style=&quot;width: 691px; height: 457px;&quot;/&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(326, 1, 19, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;水平定向钻是指在不开挖地表表面的条件下，铺设多种地下公用设施（管道、电缆等）一种施工机械。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;设备优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;滑架推进机构快慢速两档，提高空载作业效率；&lt;/div&gt;&lt;div&gt;矿山钻机动力头，更适于干/湿式钻进，提高湿式钻进使用寿命；&lt;/div&gt;&lt;div&gt;三缸大排量泥浆泵，钻机拉管施工可靠性高&lt;/div&gt;&lt;div&gt;双液压夹持器接卸钻杆，提高作业效率；&lt;/div&gt;&lt;div&gt;动力头自动浮移机构，有效延缓钻杆丝扣寿命&lt;/div&gt;&lt;div&gt;国内知名电动机、液压元件，为钻机提供可靠的工作保障&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;施工现场&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210901/2-210Z1093124c6.png&quot; style=&quot;width: 754px; height: 667px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210901/2-210Z1093321X4.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210901/2-210Z1093416463.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210901/2-210Z1093515235.png&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210901/2-210Z1093619100.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(327, 1, 19, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;按滑架、动力头配置来看是潜孔钻机，按水井钻机来分类，则归属为小型气动水井钻机，按锚固钻机来分类，则与40锚固钻机功能类似。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;一款综合多重钻机优点的改进型钻机，既可以农村打水井，也可以装上轮胎，通过其他设备牵引，适合在各种复杂地形施工。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img3&quot;&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251K319341.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251K350233.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251K40K49.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251K420K6.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(328, 1, 19, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工履带式锚固钻车，22kw电动回转动力头，结构简单、操作容易&lt;br/&gt;无需空压机，连接电源即可钻孔&lt;br/&gt;配备90-200mm麻花钻杆，硬质合金钻头，推进速度快&lt;br/&gt;升举高度高，拆卸钻杆方便&lt;/span&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;span style=&quot;color:#000000;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;掘进速度快：适应岩土掺杂工程。对硬质岩石，配合豫工分层式合金钻头，快速推进；&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;color:#000000;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;新设计双轴联动支臂：实现低位孔、水平孔和高位孔钻进，可升至高3.6米钻凿，实现0-90度自由操作，满足各种复杂工况需求。&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;color:#000000;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;同步升降平台，用于钻凿高水平位孔，解决拆卸钻杆时人员操作区域问题&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;color:#000000;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;省油耐用，加大液压油箱，合理液压管分配，省油耗；新型油管衔接，不渗油&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;color:#000000;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;电力驱动，噪音小，不需要空压机，操作简单，适合城市施工深坑支护、地铁、机场边坡稳固工程&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;p class=&quot;p&quot; style=&quot;margin-top: 0pt; margin-right: 0pt; margin-bottom: 0pt; padding: 0pt; line-height: 150%; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&lt;span class=&quot;15&quot; style=&quot;font-family: 宋体; color: rgb(0, 0, 0); letter-spacing: 0pt; font-size: 12pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img2&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251I200310.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251I213512.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251I22X39.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251I241958.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251I25D36.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;'),
(329, 1, 19, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;该钻机采用履带式底盘，行走方便，配套使用麻花钻杆，三叶合金钻头，优点是钻臂的行程高度可达到5.5-20米，日钻孔效率可达400-600米，大大节约了人工成本。&lt;/p&gt;&lt;p style=&quot;-webkit-tap-highlight-color: rgba(0, 0, 0, 0); box-sizing: border-box; margin: 0px; padding: 0px; color: rgb(0, 0, 0); font-family: &amp;quot;Helvetica Neue&amp;quot;, Helvetica, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, &amp;quot;\\\\5FAE软雅黑&amp;quot;, Arial, sans-serif; font-size: 16px;&quot;&gt;该钻机结构新颖，稳定可靠，具有效率高，移动方便，低能耗，投资成本低等优点，成为边坡锚固工程的 产品。&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1、全液压控制，操作方便灵活，移位方便，机动性好，&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2、钻机回转器采用双液压马达驱动，输出扭矩大，提高了钻机钻进平稳性。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3、可配备新型的变角机构使对孔更加方便，调节范围变大，可以降低对工作面的要求。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4、对散热系统进行了优化，确保液压系统的工作温度在45～70°之间。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5、配有专用的跟管钻进钻具，在不稳定地层用套管护壁开孔，常规球齿钻头终孔。钻进效率高，成孔质量好。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;6、钻机除了履带底盘、夹持卸扣器和转盘外，可以选配旋喷模块叠加，使钻机更加适合工程施工。&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;7、主要钻进方法：潜孔锤常规钻进 螺旋钻进、钻杆钻进、套管钻进、钻杆套管复合钻进。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H02TJ.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H124527.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H135256.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H14V07.jpg&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H159316.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210325/2-2103251H209143.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_chanpinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(330, 1, 19, '&lt;div class=&quot;body_paragraph&quot;&gt;&lt;div class=&quot;body_paragraph_center&quot;&gt;&lt;div class=&quot;body_paragraph_block&quot;&gt;&lt;div&gt;本设备主要钻进方法：&amp;nbsp;&amp;nbsp;&lt;/div&gt;&lt;div&gt;1. 三翼钻头+螺旋钻杆&amp;nbsp; 钻进，适用于土层等地层高速钻进；&lt;/div&gt;&lt;div&gt;2. 钻杆+冲击器+金刚石钻头 钻进，空气排渣：适用于岩层，破&amp;nbsp; &amp;nbsp; 碎层施工；&lt;/div&gt;&lt;div&gt;3. 钻杆、套管复合钻进；(配偏心钻头，自由钳，官靴，拔管机)&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match&quot;&gt;&lt;div class=&quot;body_match_center&quot;&gt;&lt;div class=&quot;body_match_block&quot;&gt;&lt;div class=&quot;body_match_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;突出优势&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_match_block_content&quot;&gt;&lt;div&gt;&lt;div&gt;大优势：满足大孔、深孔、狭窄空间作业&lt;/div&gt;&lt;div&gt;打孔直径：90-260&lt;/div&gt;&lt;div&gt;打孔深度：60米左右&lt;/div&gt;本设备还适用于施工城市深基坑支护、抗浮锚杆及地基灌浆加固工程孔、爆破工程的爆破孔、高压旋喷桩、隧道管棚支护孔等，将其动力头略微变动，即可方便地全方位施工。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image&quot;&gt;&lt;div class=&quot;body_image_center&quot;&gt;&lt;div class=&quot;body_image_block&quot;&gt;&lt;div class=&quot;body_image_block_title&quot;&gt;&lt;div&gt;&lt;h2&gt;图片展示&lt;/h2&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&quot;body_image_block_content&quot;&gt;&lt;div class=&quot;body_image_block_content_img1&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326141255111.jpg&quot; style=&quot;width: 691px; height: 557px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326141240B0.jpg&quot; style=&quot;width: 691px; height: 921px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326141312521.jpg&quot; style=&quot;width: 691px; height: 921px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-21032614132B62.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326141341a2.jpg&quot; style=&quot;width: 691px; height: 516px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; \r\n &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(332, 1, 11, '&lt;div style=&quot;width: 880px;min-height: 2400px;overflow: hidden;box-sizing: border-box;padding-left: 36px;float: left;&quot;&gt;\r\n    &lt;div class=&quot;body_paragraph&quot;&gt;\r\n        &lt;div class=&quot;body_paragraph_center&quot;&gt;\r\n            &lt;div class=&quot;body_paragraph_block&quot;&gt;\r\n                &lt;p&gt;\r\n                    &lt;span style=&quot;font-size:16px;&quot;&gt;豫工非固化喷涂机高效喷涂，一机=4-5个人工配合配套设备非固化溶胶机、非固化拖桶器，日喷涂面积2000平。6.1L大流量泵，大容量，不憋泵；大流量，不漏料，不浪费雾化扇形高可达80cm，喷涂速度200㎡/h；自动内循环系统，特添加滤网设计，正确操作，不堵管，不堵头快速均匀加热，全程加热免清理，预热时间短。材料成形均匀，厚度从0.5mm到2mm可控专用定制钢泵，经久耐用！&lt;/span&gt;\r\n                &lt;/p&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n    &lt;div class=&quot;body_match&quot;&gt;\r\n        &lt;div class=&quot;body_match_center&quot;&gt;\r\n            &lt;div class=&quot;body_match_block&quot;&gt;\r\n                &lt;div class=&quot;body_match_block_title&quot;&gt;\r\n                    &lt;div&gt;\r\n                        &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;/&gt;\r\n                    &lt;/div&gt;\r\n                &lt;/div&gt;\r\n            &lt;/div&gt;\r\n        &lt;/div&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;公司自主研发、生产加热喷涂软管，隔热效果好，耐高压、耐高温、耐腐蚀，性能稳定&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;国内较先使用非固化定制专用钢泵，经久耐用，压力稳定，寿命是普通泵的三倍以上。&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;一键智能施工，简单易学，智控数字显示，带故障自检功能&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;人性化设计，保护装置比较全面，尽量避免误操作损坏设备。&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;全程高效、均匀加热，预热时间国内领先，用后不需要清洗，温度智能可控&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;过滤系统完善，喷涂不会堵嘴，结构设计合理，设备维护简单&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;span style=&quot;font-size:16px;&quot;&gt;非固化喷涂、灌浆两用，经济实用&lt;/span&gt;\r\n    &lt;/div&gt;\r\n    &lt;div&gt;\r\n        &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221109/2-22110Z94349407.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221109/2-22110Z94414948.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221109/2-22110Z9443EB.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221109/2-22110Z94515X4.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;\r\n    &lt;/div&gt;\r\n&lt;/div&gt;'),
(366, 2, 11, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;装卸简单&lt;/strong&gt;：载重汽车前部悬挂、驶入式连接。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;操作简便&lt;/strong&gt;：所有作业指令在驾驶室操控，自动离合无极切换直接驱动，离合操作&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;自动平衡&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;发动机位于设备中部，保护车辆主梁具有自动找平功能&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;雪辊离地高度可自动调节、自动平衡、安全稳定&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;独立液压动力站，可定向转动。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;安全耐用&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;加装防雪橡胶板，有效防止溅雪阻挡驾驶员视线&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;雪辊左右偏转±30°，无极可调，遇障碍浮动保护避让&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;strong&gt;高质量刷毛&lt;/strong&gt;：全塑刷毛与弹性钢丝混合，耐磨度是同类产品 2.5 倍以上。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702361830aa9890.png&quot; title=&quot;1&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/170236183074bdec.png&quot; title=&quot;6&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702361830713584.png&quot; title=&quot;ba23c0dc9a32bafe350569b56aad5d8b&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702361830ecd5aa.png&quot; title=&quot;LB[T9T1]SVV%%(HW]5M5P{T&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;'),
(367, 2, 11, ''),
(368, 2, 11, '&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布宽度连续可调&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;撒布均匀 稳定可靠&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;聚乙烯材质 抗腐蚀 使用寿命长&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;接电方便 搭载多种轻型汽车&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702364277e9cdc0.png&quot; title=&quot;_]$YZXN262JGV7}`{I3ONZG&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702364278c4158b.png&quot; title=&quot;8064a9e14f18b5cafc4e1a61f23349aa&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023642775f0330.png&quot; title=&quot;AHJ1[`2NEI(2@D~8$62)4GD&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023642781f5350.png&quot; title=&quot;EG)%E7[Z%FY3L9NOTV0J%N3&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;line-height: 3em;&quot;&gt;&lt;br/&gt;&lt;/p&gt;'),
(369, 2, 11, '&lt;p style=&quot;line-height: 2em;&quot;&gt;&lt;span style=&quot;font-size: 18px;&quot;&gt;混凝土保温防冻电热毯是一款采用发热线，防水，阻燃绝缘面料为原料，针对混凝土养护为主要设计目标的柔性，可拆卸，可折叠的加热毯 。混凝土养护电热毯可直接混凝土表面加热。混凝土养护电热毯恒温，均衡加热。&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702364925d3b028.png&quot; title=&quot;$YSUU{)MU(X8[M9U($~6X8B&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/17023649252c9ffc.png&quot; title=&quot;62dfe578d11f812abc45f4a064845eb8&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702364925a00b5b.png&quot; title=&quot;Q{T7BBGEFHMJ@1H{F5]GC~A&quot;/&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202312/1702364955011443.png&quot; title=&quot;JRNM33[TLV)]_`J`N02QQLH&quot; alt=&quot;JRNM33[TLV)]_`J`N02QQLH&quot;/&gt;&lt;/p&gt;'),
