(1, 38, 1, 17, '{\"1_chanpinguanli\":{\"id\":\"38\",\"catid\":\"17\",\"title\":\" 钢筋钢管加工机械测试4\",\"thumb\":\"41\",\"keywords\":\"钢筋钢管加工机械测试4\",\"description\":\"钢筋钢管加工机械测试4\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/index.php?c=show&id=38\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"127.0.0.1-59635\",\"inputtime\":\"1699062454\",\"updatetime\":\"1699062454\",\"displayorder\":\"0\"},\"1_chanpinguanli_data_0\":{\"id\":\"38\",\"uid\":\"1\",\"catid\":\"17\",\"content\":\"&lt;p&gt;&amp;nbsp;钢筋钢管加工机械测试4&lt;br&gt;&lt;/p&gt;\"},\"1_chanpinguanli_category_data\":null}', '', 1699062502),
