INSERT INTO `dr_1_shipinguanli` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`, `spxqysbzsp`, `spxqyzbspjs`) VALUES
(258, 6, '抛丸机混凝土地面打毛', '176', '', '地面打毛效果展示', 1, 1, '创始人', 9, '/show-258.html', 0, 0, '39.96.59.7-44570', 1700819591, 1701068283, 0, '177', '南京润华建设地下车库顶棚混凝土地面防水打毛项目 设备型号：YG-850路面抛丸机 处理速度：≥600㎡/h 工作宽度：800mm'),
(259, 6, '液压破桩机破800圆桩', '172', '', '', 1, 1, '创始人', 9, '/show-259.html', 0, 0, '39.96.59.7-48082', 1701058120, 1701068146, 0, '173', '液压破桩机 桩径：直径800的圆柱形灌注桩，高约2-3米 破桩速度：3米高灌注桩，5分钟破除完毕'),
(260, 6, '液压破桩机破方桩', '174', '', '', 1, 1, '创始人', 9, '/show-260.html', 0, 0, '39.96.59.7-48088', 1701058120, 1701068198, 0, '175', ''),
(261, 6, '钢筋网片排焊机施工', '164', '', '工作人员测试：焊点均匀 焊接牢固', 1, 1, '创始人', 9, '/show-261.html', 0, 0, '39.96.59.7-48186', 1701058182, 1701067949, 0, '165', ''),
(262, 6, '非固化喷涂机防水喷涂', '166', '', '', 1, 1, '创始人', 9, '/show-262.html', 0, 0, '39.96.59.7-48194', 1701058182, 1701067992, 0, '167', '丹东某别墅车库顶板防水喷涂 设备型号：YG2000非固化喷涂机（经典版）非固化溶胶机 非固化拖桶器 喷涂速度：2000㎡/天'),
(263, 6, '破桩机破1.5米圆桩', '168', '', '', 1, 1, '创始人', 9, '/show-263.html', 0, 0, '39.96.59.7-48202', 1701058182, 1701068029, 0, '169', '萧宏建设桥梁桩桩径1米 C30混凝土结构 需要10个模块 2米高灌注桩 5分钟破除'),
(264, 6, '江苏混凝土桥面打毛', '170', '', '', 1, 1, '创始人', 9, '/show-264.html', 0, 0, '39.96.59.7-48208', 1701058182, 1701068083, 0, '171', '江苏泰兴桥面混凝土地面打毛项目 设备型号：YG-850路面抛丸机 处理速度：≥600㎡/h 工作宽度：550-600mm'),
(265, 6, '喷播机高速公路绿化', '154', '', '', 1, 1, '创始人', 9, '/show-265.html', 0, 0, '39.96.59.7-48214', 1701058183, 1701067393, 0, '155', '西藏高速公路绿化现场 设备型号： YKP-132 传动方式： 机械传动 柴油机功率 ： 玉柴130 罐体容积： 8立方 (8000L)'),
(266, 6, '非固化喷涂机防水喷涂', '156', '', '', 1, 1, '创始人', 9, '/show-266.html', 0, 0, '39.96.59.7-48220', 1701058183, 1701067746, 0, '157', '上海天铂小区楼顶非固化喷涂防水施工 设备型号：YG2000非固化喷涂机（经典款） 喷涂速度：2000㎡/天'),
(267, 6, '泥浆分离器处理现场', '158', '', '', 1, 1, '创始人', 9, '/show-267.html', 0, 0, '39.96.59.7-48228', 1701058183, 1701067810, 0, '159', '郑万高铁桩基施工泥浆处理现场 设备型号：YG-500型泥浆分离器 液体处理能力：500m3/h 渣料筛分能力：75-250t/h 分离粒度d50：60µm'),
(268, 6, '液压湿喷机隧道支护', '160', '', '', 1, 1, '创始人', 9, '/show-268.html', 0, 0, '39.96.59.7-48234', 1701058183, 1701067858, 0, '161', '型号：90型单喷头液压湿喷机 优势：泵送压力大、输送距离远、回弹率低、施工效率高等优势 生产能力：7㎥/h, 喷射距离100米 垂直扬尘60米'),
(269, 6, '抛丸机钢板除锈', '162', '', '', 1, 1, '创始人', 9, '/show-269.html', 0, 0, '39.96.59.7-48240', 1701058183, 1701067898, 0, '163', '云南大理钢板除锈 设备型号：YG-550路面抛丸机 处理速度：75-100㎡/h 工作宽度：550-600mm'),
(397, 6, '豫工车载除雪滚刷 全型号参数及产品详解', '1114', '豫工,雪滚,雪铲,撒布机,除雪设备', '一、豫工车载除雪滚刷 主流型号及规格 豫工车载除雪滚刷按工作宽度划分，覆盖2.0m-3.6m全尺寸区间，核心分为自带动力（独立发动机）与取力式（车辆取力/液压驱动）两大系列，各型号适配不同车型与作业场景，其中3.0m型号为市场主力款，现货充足、性价比突出，可满足多数规模化除雪需求，具体型号参数如下：型号有效工作宽度刷片直径适配车型动力类型核心适配场景YG-XG20002000mm600/800mm', 1, 1, '创始人', 9, '/show-397.html', 0, 0, '123.160.243.73-54322', 1770189912, 1770254698, 0, '1127', '豫工作为河南本土实力机械企业，其车载除雪滚刷主打高适配、强耐磨、高效作业，涵盖多尺寸型号，支持自带动力与车辆取力双模式，广泛应用于市政道路、高速公路、机场厂区、小区广场等各类场景，适配轻卡、重卡、装载机、洗扫车等多种车型，兼顾精细化除雪与批量作业需求，是冬季道路清雪的核心设备之⼀，凭借扎实做工与高性价比，多次为市政清雪保障提供支持，可快速响应紧急除雪需求，2天内即可完成发货交付。'),
(398, 6, '豫工喷砂机_空压机全型号参数 ', '1128', '喷砂机,豫工,空压机,表面处理,钢板除锈', '河南豫工作为工业机械实力制造商，专注表面处理与气源设备研发生产，其喷砂机与空压机主打高效耐用、适配性强、配套性佳，覆盖小型便携到大型工业级全规格，可精准匹配钢结构除锈、船舶桥梁翻新、矿山机械维护、石油管道处理、市政工程施工等多场景需求，形成“气源供给+表面处理”一体化解决方案。产品现货充足，河南郑州工厂直发，2天内快速发货，支持定制化参数与批量采购，兼顾性价比与实用性，是工业生产、工程施工中表面处', 1, 1, '创始人', 9, '/show-398.html', 0, 0, '123.160.243.73-13648', 1770256297, 1770369636, 0, '1129', '选型核心原则：空压机排气量≥喷砂机需求气量的1.2倍，压力与喷砂机工作压力匹配（优先0.8MPa），同时结合作业场景、作业规模、是否有供电条件选择合适机型。\r\n钢板喷砂除锈视频。'),
(399, 6, '豫工双绞龙抛雪机 型号_参数_结构_', '1137', '抛雪机,豫工,双绞龙抛雪机,扬雪机,扫雪机', '豫工双绞龙抛雪机是冬季高效除雪的核心设备，凭借左右螺旋绞龙的协同作业，实现积雪的切削、集中、输送与抛投一体化，适配多种积雪场景，广泛应用于市政、公路、机场等领域。以下整合市面上主流型号、核心参数、结构特性及适配场景，助力精准选型与高效除雪作业。', 1, 1, '创始人', 9, '/show-399.html', 0, 0, '123.160.243.73-8843', 1770344740, 1770369616, 0, '1138', '选型需结合作业场景面积、积雪厚度、适配主机及作业需求，小型场地优先选择滑移适配款，兼顾灵活性；中大型场地及厚雪场景，优先选择独立发动机驱动的中大型机型，侧重抛雪能力与连续作业能力；同时关注设备防护性能、维护便捷性及环保标准，匹配实际除雪工况，实现高效、低成本除雪。'),
(400, 6, '豫工清淤机器人 型号_参数_结构_适配场景全解析', '1143', '清淤机器人,清淤设备,清淤泥机器,智能清淤', '豫工清淤机器人 型号_参数_结构_适配场景全解析豫工清淤机器人是豫工机械核心智能环保设备，依托19年智能清淤设备研发经验，专为解决狭小空间、水下危险区域清淤难题设计，实现“不排水、不停工、人员不下水”的安全高效清淤作业，可一站式完成淤泥搅散、揽收、输送、后处理全流程，大幅替代人工，降低作业风险与人工成本，适配市政、矿山、环保等多领域清淤需求。以下整合豫工清淤机器人主流型号、核心参数、专属结构及适配', 1, 1, '创始人', 9, '/show-400.html', 0, 0, '123.52.22.14-11024', 1773456841, 1773459988, 0, '1144', ''),
(401, 6, '豫工板框压滤机 型号_参数_结构_适配场景全解析', '1154', '', '豫工板框压滤机是豫工机械核心固液分离设备，依托20年水利环保设备研发生产经验，主打“高效过滤、坚固耐用、智能便捷、适配广泛”核心优势，整合豫工定制滤板、高压液压系统、智能控制系统及密封防护结构，区别于普通板框压滤机，实现“快速脱水、滤饼干度高、能耗低、易运维”的作业效果，适配市政污水、矿山尾矿、化工废水、食品加工、建筑污泥等多领域固液分离场景，可连续稳定运行，大幅提升固液分离效率，降低污泥处置成本', 1, 1, '创始人', 9, '/show-401.html', 0, 0, '123.52.22.14-13102', 1773460512, 1773460787, 0, '1148', ''),
(402, 6, '豫工路面抛丸机 型号_参数_结构_适配场景全解析', '1155', '抛丸机,钢板除锈,抛丸设备,桥梁抛丸,路面抛丸', '豫工路面抛丸机是豫工机械依托20年水利市政及路面工程设备研发生产经验，专为路面养护、桥面处理、工业地面加工等场景研发的核心设备，主打“高效除锈、均匀抛丸、无尘环保、适配多元路面”核心优势，核心部件采用豫工定制耐磨抛丸轮、密封除尘系统及智能操控模块，区别于普通路面抛丸机，实现“抛丸强度可调、无尘作业、高效节能”的作业效果，适配市政道路、高速公路、桥梁隧道、工业厂房、机场跑道等多领域路面处理需求，可高', 1, 1, '创始人', 9, '/show-402.html', 0, 0, '123.52.22.14-11108', 1773817055, 1773817055, 0, '1159', ''),
(403, 6, '豫工激光超声波桥梁摊铺机 型号_参数_结构_适配场景全解析', '1161', '激光摊铺机,超声波摊铺机,激光整平,桥梁摊铺机', '豫工激光超声波桥梁摊铺机是豫工机械核心桥梁铺装智能化设备，依托激光+超声波双控找平核心技术，摆脱人工经验依赖，专为公路桥梁、市政桥梁、高铁桥梁等铺装工程设计，可一站式完成桥面混凝土的精准布料、摊铺、整平、提浆、振捣一体化作业，大幅提升铺装平整度、高程精度与施工效率，降低人工成本，适配直线段、曲线段、匝道等多种桥梁结构，兼顾施工质量与环保性。', 1, 1, '创始人', 9, '/show-403.html', 0, 0, '123.52.22.14-13108', 1773818031, 1773818031, 0, '1163', '');
INSERT INTO `dr_1_shipinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
