INSERT INTO `dr_1_shipinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(397, 1, 6, '&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:21px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;一、豫工车载除雪滚刷&lt;/span&gt; &lt;span style=&quot;font-family:等线&quot;&gt;主流型号及规格&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;豫工车载除雪滚刷按工作宽度划分，覆盖&lt;/span&gt;2.0m-3.6m&lt;span style=&quot;font-family:等线&quot;&gt;全尺寸区间，核心分为自带动力（独立发动机）与取力式（车辆取力&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;液压驱动）两大系列，各型号适配不同车型与作业场景，其中&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3.0m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;型号为市场主力款，现货充足、性价比突出，可满足多数规模化除雪需求，具体型号参数如下：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;table cellspacing=&quot;0&quot;&gt;&lt;tbody&gt;&lt;tr class=&quot;firstRow&quot;&gt;&lt;td width=&quot;92&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-style: solid; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;型号&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;92&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-style: solid; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family: