:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:21px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202602/1770190756efd7ee.jpg&quot; title=&quot;3米除雪滚.jpg&quot; alt=&quot;3米除雪滚.jpg&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:21px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;&lt;br/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:21px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;二、核心技术参数（通用&lt;/span&gt;+&lt;span style=&quot;font-family:等线&quot;&gt;主力型号详解）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:20px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;1. &lt;span style=&quot;font-family:等线&quot;&gt;通用核心参数&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;滚刷转速：&lt;/span&gt;230–310r/min&lt;span style=&quot;font-family:等线&quot;&gt;，自带动力型转速优化为&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;280–300r/min&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，扭矩充足，可高效剥离压实积雪与薄冰，避免扫雪无力问题，搭配液压油风冷散热装置，防止高速作业时高温停摆。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;作业速度：&lt;/span&gt;5–30km/h&lt;span style=&quot;font-family:等线&quot;&gt;，市政道路建议&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;5–20km/h&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（精细化除雪），高速公路可提升至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;30km/h&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（快速清雪），兼顾效率与清扫效果，单次除雪率可达&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;95%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;左右摆角：&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;±30°&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;无级可调，可精准控制积雪抛射方向，避免二次影响交通，适配弯道、坡道等复杂路段作业。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;最大除雪厚度：&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥100mm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，可应对湿雪、干雪及压实积雪，极端场景下可清理&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≤30cm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;湿雪、&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≤50cm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;干雪，适配北方严寒多雪地区&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:等线;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;避障高度：&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥300mm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，支持整体翻转避让，可自动适配路面横坡坡度，保护路面标线、井盖等设施，减少设备与路面损耗。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;刷片材质：聚丙烯&lt;/span&gt;+&lt;span style=&quot;font-family:等线&quot;&gt;钢丝复合材质，单根刷毛抗拉强度&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥1000N&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，耐磨、耐&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;-30℃&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;低温，部分严寒地区可定制&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;-40℃&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;防冻液配置，不掉毛、不断毛，兼顾清扫效果与路面保护，使用寿命可达&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;500-800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;操作方式：驾驶室电控&lt;/span&gt;+&lt;span style=&quot;font-family:等线&quot;&gt;有线&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;无线遥控双模式，驾驶员可一键控制升降、摆角、转速，单人即可完成作业，操作便捷且安全可靠。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:20px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;2. &lt;span style=&quot;font-family:等线&quot;&gt;主力型号&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-XG3000&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（自带动力款）详细参数&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;该型号为豫工爆款，适配多数规模化除雪场景，现货充足，曾批量交付市政单位用于冬季清雪保障，核心参数如下：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;外形尺寸：&lt;/span&gt;3000×1100×1450mm&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;整机重量：约&lt;/span&gt;500–640kg&lt;span style=&quot;font-family:等线&quot;&gt;，采用&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3451&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;耐低温钢板一体折弯成型，表面烤漆处理，具备良好的防腐蚀性能。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;动力配置：&lt;/span&gt;37kW&lt;span style=&quot;font-family:等线&quot;&gt;柴油发动机（潍坊&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;云内），功率&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥30kW&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，低温启动性能优异，适配严寒环境。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;刷片数量：&lt;/span&gt;52&lt;span style=&quot;font-family:等线&quot;&gt;片（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2.5m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;规格）&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;按需定制（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;规格），钢丝含量高，韧性十足，低温环境下不易折断。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;连续作业时长：&lt;/span&gt;4&lt;span style=&quot;font-family:等线&quot;&gt;小时（自带动力油箱续航），燃油消耗约&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3-5&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;升&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时，兼顾续航与经济性。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;连接方式：快装挂板&lt;/span&gt;+&lt;span style=&quot;font-family:等线&quot;&gt;下压臂，&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;10–15&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;分钟即可完成换装，支持与除雪铲互换，可扩展融雪撒布功能，提升设备利用率。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font:9px Times New Roman&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;安全配置：配备&lt;/span&gt;LED&lt;span style=&quot;font-family:等线&quot;&gt;警示灯、防回雪装置、强制下压保护，夜间作业安全性更高。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:20px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;3. &lt;span style=&quot;font-family:等线&quot;&gt;招标常用款（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2.5m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;液压驱动）参数&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;适配市政、园区等批量采购场景，参数标准化，性价比突出，核心参数如下&lt;/span&gt;[&lt;span style=&quot;font-family:等线&quot;&gt;摘要&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;6]&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top:8px;margin-bottom:8px;margin-left:0;text-align:left;line-height:120