gin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）小型作业（单枪、局部处理）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font-variant-numeric: normal;font-variant-east-asian: normal;font-variant-alternates: normal;font-size-adjust: none;font-kerning: auto;font-optical-sizing: auto;font-feature-settings: normal;font-variation-settings: normal;font-variant-position: normal;font-variant-emoji: normal;font-stretch: normal;font-size: 9px;line-height: normal;font-family: &amp;#39;Times New Roman&amp;#39;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;适配场景：五金除锈、小型模具处理、局部除漆、小型构件表面处理。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;color:rgb(51,112,255);font-size:15px&quot;&gt;•&lt;span style=&quot;font-variant-numeric: normal;font-variant-east-asian: normal;font-variant-alternates: normal;font-size-adjust: none;font-kerning: auto;font-optical-sizing: auto;font-feature-settings: normal;font-variation-settings: normal;font-variant-position: normal;font-variant-emoji: normal;font-stretch: normal;font-size: 9px;line-height: normal;font-family: &amp;#39;Times New Roman&amp;#39;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;配套组合：喷砂机&lt;/span&gt;YG-600 + &lt;span style=&quot;font-family:等线&quot;&gt;空压机&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-7.5PM&lt;/span&gt;&lt;span style=