bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;滤板材质&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;不锈钢&lt;/span&gt;/&lt;span style=&quot;font-family:等线&quot;&gt;增强聚丙烯（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;PP&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;）高端定制，耐腐耐高压，抗冲击性强&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;操控方式&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能全自动（&lt;/span&gt;PLC&lt;span style=&quot;font-family:等线&quot;&gt;中控&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;远程操控&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;自动监测&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;故障预警），无需人工干预&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;核心配置&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能中控系统、高压液压系统、自动卸饼输送装置、滤布自动清洗烘干系统&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;应用案例&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;大型矿山尾矿处置、化工废水固液分离、市政污泥资源化利用&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;二、豫工板框压滤机核心结构特点（豫工专属设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工板框压滤机依托豫工专业研发团队技术积累，核心结构采用&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;高压过滤&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能控制&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;全方位密封&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;便捷运维&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四重设计，区别于普通板框压滤机，整体由滤板滤布模块、高压液压模块、智能控制模块、密封防护模块四大核心部分组成，所有部件均为豫工原厂定制适配，结构紧凑、运行稳定，耐腐耐磨，适配常规与复杂固液分离工况，不同型号结构核心一致，细节贴合其处理规模，核心豫工专属结构如下：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）滤板滤布模块（豫工核心过滤亮点）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;滤板滤布作为压滤机的核心过滤部件，豫工采用专属定制设计，兼顾过滤效率、耐用性与适配性，解决普通滤板易破损、滤布易堵塞、滤饼干度不足的难题：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;滤板设计：采用豫工自主研发的增强型滤板材质，涵盖聚丙烯（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;PP&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;）、铸铁、不锈钢三大类，可按需定制；滤板表面采用凹凸式流道设计，增大过滤面积，加快滤液流通速度，同时提升滤饼均匀度，滤饼含水率可低至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;60%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以下（高端型号可低至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;50%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以下）；滤板边缘采用加厚密封设计，耐高压、不易渗漏，使用寿命较普通滤板延长&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;30%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;滤布配置：标配豫工定制专用滤布，材质涵盖涤纶、丙纶、锦纶，可根据物料特性（腐蚀性、颗粒大小）定制孔径与厚度，过滤精度高，可有效拦截细小颗粒，同时具备易脱饼、不易堵塞、耐磨损的特点；滤布可快速拆卸更换，维护便捷，无需专业工具。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;模块优势：滤板与滤布精准适配，采用&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;板框交替排列&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;设计，形成独立过滤腔，高压过滤状态下不易变形、渗漏，过滤效率较普通板框压滤机提升&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;20-30%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，大幅缩短过滤周期，降低能耗成本。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（二）高压液压模块（豫工动力核心设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;全系标配豫工定制高压液压系统，是压滤机高效压紧、稳定运行的核心，采用豫工自主研发的液压控制技术，区别于普通第三方液压系统，适配方框压滤机高压过滤需求：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;系统配置：根据型号不同，配备对应功率的高压液压站，压力范围&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;0.6-3.0MPa&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;可调节，小型型号采用手动液压阀控制，中高端型号采用电磁换向阀控制，压力稳定、调节精准；液压泵采用优质齿轮泵&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;柱塞泵，噪音低、能耗低、使用寿命长，可连续长时间运行。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;技术优势：液压系统具备&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;保压功能&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，压紧后可自动维持压力，避免压力流失导致渗漏，同时具备过载保护功能，防止液压系统因负荷过大损坏；液压油缸采用无缝钢管精密加工，密封性能好，不易漏油，压紧力均匀，确保滤板滤布贴合紧密，提升过滤效果。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;耐用性保障：液压油采用专用抗磨液压油，配备液压油过滤器，可有效过滤杂质，防止液压系统堵塞；液压管路采用高压橡胶管，耐高压、抗老化，不易破损，适配长期连续运行需求，维护成本低。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（三）智能控制模块（豫工便捷化设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;采用豫工定制智能控制系统，兼顾便捷性、安全性与智能化，无需专业操作人员，适配不同规模固液分离作业需求，贴合板框压滤机自动化作业特点：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;操控方式：支持手动、半自动、全自动、智能远程四种操控模式，小型型号以手动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;半自动为主，中高端型号以全自动为主，高端型号兼容&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;PLC&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;中控与&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;5G&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;远程操控，操作人员可在安全区域完成设备启停、压力调节、滤板压紧、卸饼等全部操作，单人即可值守多台设备。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;实时监测：中高端型号配备高清智能中控屏，可实时展示设备运行状态，涵盖过滤压力、过滤时间、滤饼厚度、液压油温度等多参数，同时具备故障报警功能，设备出现渗漏、过载、滤布堵塞等异常时可快速提醒操作人员，便于及时排查维修；支持运行数据留存，便于后期核查与运维分析。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;安全防护：具备过载、过压、漏电自动保护功能，避免设备因负荷过大、操作失误损坏，同时配备紧急停止按钮，提升作业安全性；全自动型号配备&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;防夹手保护&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;装置，拉板、卸饼过程中可自动识别障碍物，避免安全事故；高压过滤状态下，设备锁定，防止误操作导致渗漏。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（四）密封防护模块（豫工耐用适配设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;结合固液分离作业特点，专属配置密封防护结构，提升设备耐用性与适配性，覆盖密封、防腐、运维等全场景需求：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;密封设计：滤板边缘配备豫工定制耐高温、耐高压密封垫，材质为橡胶&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;硅胶，密封性能好，不易老化、渗漏，适配不同温度与压力工况；设备整体采用密封式框架设计，防止滤液渗漏污染环境，同时保护内部电气设备与液压系统。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;防腐防护：设备框架采用碳钢喷漆&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;不锈钢材质，表面经过特殊防腐防锈处理，耐腐耐磨，适配市政污水、化工废水等腐蚀性较强的作业环境；核心部件（液压油缸、滤板）均经过防腐处理，延长设备使用寿命，可长期用于户外或潮湿环境作业。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;运维配套：配备滤布自动清洗系统（中高端型号标配），可快速清洗滤布表面残留物料，避免滤布堵塞，提升过滤效率；配备卸饼输送装置（高端型号标配），自动将滤饼输送至指定位置，减少人工干预；框架设计预留检修空间，便于设备日常维护与部件更换，降低运维成本。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;三、豫工板框压滤机适配场景及作业优势&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工板框压滤机凭借不同型号的规格差异，适配从小型实验到大型工程、从常规到高标准的多元固液分离场景，依托高效过滤、智能便捷、坚固耐用、适配广泛的核心优势，解决传统板框压滤机过滤效率低、滤饼干度不足、渗漏严重、运维繁琐的难题，适配市政、矿山、化工、食品、建筑等多领域，核心适配场景按型号分类如下，结合实际应用案例，增强参考性，贴合&lt;/span&gt;SEO&lt;span style=&quot;font-family:等线&quot;&gt;搜索需求：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）豫工&lt;/span&gt;YG-BK320&lt;span style=&quot;font-family:等线&quot;&gt;（小型实验款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;主打小型实验、小批量分离，核心场景包括：实验室固液分离实验、小型食品加工厂（豆制品、果汁）废水处理、小型养殖厂污泥脱水、科研机构样品脱水、小型作坊固液分离等；适配小批量、低压过滤需求，体积小巧、操作简单，无需大型安装基础，适配实验室、小型加工厂、科研机构等用户，用于实验研究与小批量生产作业，性价比高，移动便捷。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（二）豫工&lt;/span&gt;YG-BK500&lt;span style=&quot;font-family:等线&quot;&gt;（中型通用款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;适配中型通用固液分离场景，兼顾效率与实用性，核心场景包括：市政污水污泥脱水、小型矿山尾矿处理、化工企业小型废水处理、食品加工（淀粉、制糖）废水处理、建筑施工污泥脱水、小型印染废水处理等；可处理含泥沙、有机物、细小颗粒的物料，高压过滤、脱水效率高，适配市政环卫部门、小型矿山企业、中型食品加工厂、建筑工程队等用户，是日常固液分离与常规生产作业的主力机型，兼顾实用性与便捷性，适配多领域常规需求。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（三）豫工&lt;/span&gt;YG-BK800&lt;span style=&quot;font-family:等线&quot;&gt;（大型工程款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;主打大型工程、大规模分离，核心场景包括：大型矿山尾矿深度脱水、化工企业大规模废水处理、市政污泥集中处置、建筑污泥规模化处理、冶金废水固液分离、煤矿污泥脱水等；可处理含大量泥沙、重金属、腐蚀性物质的物料，超大处理量、超高压过滤，支持&lt;/span&gt;24&lt;span style=&quot;font-family:等线&quot;&gt;小时连续运行，适配大型矿山企业、大型化工企业、市政污泥处理厂、大型建筑集团等用户，一台设备可替代多台常规机型，大幅提升固液分离效率，缩短作业周期，降低人工与能耗成本。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（四）豫工&lt;/span&gt;YG-BK1250&lt;span style=&quot;font-family:等线&quot;&gt;（全自动智能款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;主打高端定制、高标准分离，核心场景包括：大型化工企业高标准废水处理、矿山尾矿资源化利用、市政污泥深度脱水（滤饼资源化）、大型冶金企业废水固液分离、高端食品加工废水处理、制药废水固液分离等；可处理腐蚀性强、颗粒细小、要求滤饼干度高的物料，智能全自动运行、无需人工干预，适配大型化工企业、大型矿山集团、市政污泥资源化处理厂、高端食品制药企业等用户，用于高标准、大规模生产作业，助力物料资源化利用，符合环保要求。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（五）豫工板框压滤机专属作业优势&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;高效过滤（豫工核心优势）：豫工定制滤板滤布&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;高压液压系统，过滤效率较传统机型提升&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;20-30%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，滤饼含水率低至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;60%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以下（高端型号可低至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;50%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以下），滤液清澈可循环利用，大幅提升固液分离效果，缩短过滤周期，降低污泥处置与水资源浪费成本。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能便捷：豫工定制智能控制系统，支持手动、半自动、全自动、远程操控多种模式，中高端型号全自动运行，单人即可值守，无需专业操作人员；实时监测与故障预警功能，便于及时排查维修，降低运维成本；滤板滤布拆卸更换便捷，维护简单。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;坚固耐用：核心部件采用豫工原厂定制材质，滤板耐腐耐高压、不易破损，液压系统稳定可靠，框架经过防腐处理，适配潮湿、腐蚀性强的作业环境；设备运行稳定，支持&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;24&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时连续运行，使用寿命长，可长期用于日常生产与应急分离作业。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;4. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;适配性强：型号齐全，涵盖小型至大型、手动至智能全自动款，可按需定制滤板材质、过滤压力、处理量、操控方式，适配市政、矿山、化工、食品、建筑等多领域；可处理清水、污水、污泥、尾矿、食品残渣等不同物料，通用性强，贴合国内各类固液分离工况。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;5. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;品质保障：豫工作为&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;年水利环保设备生产厂家，拥有完善的售后流程与专业售后团队，板框压滤机产品质保一年、终身维护，&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;24&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时远程技术支持，厂家直供、价格优惠、现货充足，可提供现场安装调试、技术培训服务，支持实地看厂，让用户买得放心、用得安心，多次获得权威部门与用户认可。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四、豫工板框压滤机选型核心参考&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;选型需结合&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;物料特性及固液分离要求&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;处理量及过滤面积需求&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;作业场景及安装条件&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;操控需求及预算&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四大核心因素，结合豫工不同型号的特点：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;小型实验、小批量分离（实验室、小型作坊，低压需求）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-BK320&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，侧重轻便灵活、操作简单，适配小批量、低压过滤，无需大型安装，贴合小型用户实验与小批量生产需求。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;中型通用、常规分离（市政、小型矿山、食品加工，中处理量需求）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-BK500&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，高压过滤、适配广泛，兼顾效率与实用性，可按需选择半自动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;全自动，是日常生产与常规分离的主力机型。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;大型工程、大规模分离（大型矿山、化工、市政污泥，大处理量需求）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-BK800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，超大处理量、超高压过滤，支持&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;24&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时连续运行，工程级品质，适配大规模、长时间固液分离需求。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;4. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;高端定制、高标准分离（大型化工、矿山资源化、高端食品，高标准需求）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-BK1250&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，智能全自动、高端定制，滤饼干度高、适配腐蚀性物料，参考矿山尾矿、市政污泥资源化应用案例选型。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;5. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;特殊需求：腐蚀性物料优先选择不锈钢&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;增强聚丙烯滤板型号；细颗粒物料优先选择高精度滤布定制款；无人工值守需求优先选择全自动智能款；户外作业优先选择防腐框架型号；预算有限可选择手动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;半自动中型款。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;综上，豫工板框压滤机是市政污水、矿山尾矿、化工废水、食品加工、建筑污泥等领域固液分离的优选设备，依托豫工&lt;/span&gt;20&lt;span style=&quot;font-family:等线&quot;&gt;年水利环保设备研发经验与定制化设计，兼具高效过滤、智能便捷、坚固耐用、适配广泛的核心优势，不同型号适配不同场景与需求，彻底解决传统板框压滤机的诸多痛点，适配国内各类固液分离工况，是实验室、小型加工厂、大型工程企业、市政部门、环保企业的核心选择，助力高效、环保、节能完成固液分离作业，实现物料资源化利用。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_shipinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(402, 1, 6, '&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;一、豫工路面抛丸机主流型号及核心参数&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工路面抛丸机型号以抛丸宽度、抛丸效率、适配路面类型为核心标定，结合国内市政、高速、桥梁、工业地面等各类路面处理工况需求，涵盖小型手推款、中型自行走款、大型牵引款，适配不同宽度、不同强度的路面处理需求，主流型号包括豫工&lt;/span&gt;YG-PW300&lt;span style=&quot;font-family:等线&quot;&gt;（小型手推款）、&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW550&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（中型自行走款）、&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（大型牵引款），可按需定制抛丸宽度、抛丸强度及配套除尘装置，所有参数均为豫工原厂标配，核心部件采用豫工定制抛丸轮及除尘系统，精准贴合路面抛丸&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;均匀高效、无尘环保、灵活适配&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;的核心需求，核心参数汇总如下（结合路面抛丸机行业特性及豫工产品优势标定）：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）豫工&lt;/span&gt;YG-PW300&lt;span style=&quot;font-family:等线&quot;&gt;（小型手推款，电动）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;核心定位&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;：小型手推式路面抛丸机，主打轻便灵活、操作简单、无尘环保，适配小型路面、狭窄区域抛丸处理，适配小型市政养护、车间地面、小型桥面、停车场等场景，体积小巧、移动便捷，单人即可操作，无需大型牵引设备，是豫工入门级路面抛丸设备，广泛应用于小型路面除锈、除污、防滑处理，也是目前国内适配狭窄区域路面抛丸工况的优质设备佼佼者。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;table cellspacing=&quot;0&quot;&gt;&lt;tbody&gt;&lt;tr class=&quot;firstRow&quot;&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;参数类别&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工&lt;/span&gt;YG-PW300&lt;span style=&quot;font-family:等线&quot;&gt;（小型手推款）&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;抛丸宽度&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;300mm&lt;span style=&quot;font-family:等线&quot;&gt;，可适配狭窄区域（如桥面边缘、车间角落）精准抛丸，灵活调节&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;抛丸效率&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;8-15&lt;span style=&quot;font-family:等线&quot;&gt;㎡&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/h&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，适配小型路面、局部修补抛丸作业，高效省力&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/t