px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;3000r/min&lt;span style=&quot;font-family:等线&quot;&gt;，豫工定制三抛丸轮，抛丸均匀度高，冲击力可调（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;0.1-0.5MPa&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），适配高强度抛丸需求&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;介质适配&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;钢丸（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;Φ1.0-2.0mm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;）、钢砂、合金钢丸可选，适配混凝土、沥青、厚钢板、机场跑道等复杂路面材质&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;整机重量&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;约&lt;/span&gt;4500-5000kg&lt;span style=&quot;font-family:等线&quot;&gt;，配专用牵引装置，重型卡车牵引转运，适配大型工程现场部署&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;核心配置&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能遥控操控系统、豫工定制三抛丸轮、高效脉冲除尘系统（除尘效率&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥99%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;）、钢丸自动循环回收系统、故障诊断系统、耐磨加厚护板，适配复杂路面高强度抛丸&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;text-align: center&quot;&gt;&lt;img src=&quot;https://www.hnyugong.com/uploadfile/ueditor/image/202603/177381723579dec1.jpg&quot; title=&quot;1 (2)&quot; alt=&quot;1 (2)&quot;/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;二、豫工路面抛丸机核心结构特点（豫工专属设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工路面抛丸机依托豫工专业工程设备研发团队技术积累，核心结构采用&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;耐磨抛丸&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;无尘除尘&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能操控&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;稳定行走&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四重设计，区别于普通路面抛丸机，整体由抛丸模块、除尘模块、动力模块、行走操控模块四大核心部分组成，所有部件均为豫工原厂定制适配，结构紧凑、运行稳定，抛丸均匀、无尘环保、耐磨耐用，适配户外复杂施工及室内车间多种路面处理工况，不同型号结构核心一致，细节贴合其路面处理规模与强度需求，核心豫工专属结构如下，突出豫工产品差异化优势：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）抛丸模块（豫工核心抛丸亮点，差异化优势）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;抛丸模块作为路面抛丸机的核心作业部件，豫工采用专属定制耐磨抛丸轮、精准抛射结构及耐磨防护设计，兼顾抛丸效率、均匀度与耐磨性，适配不同材质、不同强度的路面抛丸处理，解决普通路面抛丸机抛丸不均、抛丸轮磨损快、抛射力度不可调的难题，也是豫工路面抛丸机的核心竞争力：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;核心抛丸轮设计：全系配备豫工定制耐磨抛丸轮，采用高强度耐磨合金材质，经过淬火、耐磨处理，硬度高、耐磨性强，相较于普通抛丸轮，使用寿命延长&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;60%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上，可有效抵抗钢丸、钢砂的冲击磨损，避免抛丸轮磨损导致的抛丸不均、效率下降；小型型号采用单抛丸轮，中大型型号采用双抛丸轮&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;三抛丸轮设计，抛射角度经过精准校准，抛丸覆盖均匀，无死角，可实现路面表层均匀拉毛、除锈、除污，提升路面附着力；抛丸轮转速可灵活调节，适配不同强度的抛丸需求（如轻度除污、高强度除锈）。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;抛射结构设计：采用豫工自主研发的精准抛射系统，抛射角度可按需微调（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;0-15°&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），可根据路面材质（混凝土、沥青、钢板）灵活调整，避免过度抛射损坏路面基层；进料口采用精准控料设计，可精准控制钢丸输送量，实现抛丸强度的无级调节，贴合不同路面处理需求；抛丸腔采用密封式设计，减少钢丸飞溅，提升钢丸利用率，同时降低作业噪音。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;耐磨防护设计：抛丸腔内壁增设豫工定制耐磨衬板，采用耐磨合金材质，可快速拆卸更换，降低运维成本；抛丸出口配备耐磨护罩，避免钢丸飞溅伤人，同时保护设备本身，延长设备使用寿命；钢丸输送管路采用耐磨加厚设计，耐冲击、抗磨损，避免管路堵塞与磨损，保障钢丸循环顺畅。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（二）除尘模块（豫工无尘环保核心）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;除尘模块是路面抛丸机的&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;环保核心&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，豫工采用专属定制高效脉冲除尘系统，兼顾无尘作业、高效过滤、便捷清理的特点，解决普通路面抛丸机除尘效率低、粉尘泄漏、污染环境的难题，保障作业现场环保达标，适配市政、机场、室内车间等对环保要求高的场景：&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;1. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;除尘系统设计：采用豫工自主研发的高效脉冲除尘系统，小型型号配备内置式除尘装置，结构紧凑、占用空间小；中大型型号配备外置式脉冲除尘系统，过滤面积大、除尘效率高，除尘效率可达&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;99%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上，可有效过滤抛丸过程中产生的粉尘，实现无尘作业，避免粉尘污染环境与操作人员健康；除尘系统与抛丸腔无缝衔接，可快速收集抛丸过程中产生的粉尘与杂质，避免粉尘外泄。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;核心部件优势：除尘滤芯、除尘风机等核心部件均为豫工原厂定制，采用优质过滤材质，过滤精度高、透气性好，可有效过滤细小粉尘（粒径&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≤10μm&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），同时具备耐磨、耐腐蚀特性，使用寿命较普通除尘部件延长&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;40%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上；配备粉尘自动清理装置，可定时自动清理滤芯上的粉尘，避免滤芯堵塞，保障除尘系统稳定运行，减少人工清理工作量；除尘管道采用密封式设计，接口贴合紧密，无粉尘泄漏隐患。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;环保适配设计：除尘系统配备粉尘收集箱，可集中收集过滤后的粉尘，便于后续运输与处理，避免粉尘二次污染；中大型型号可定制移动式除尘装置，部署灵活，适配户外大型路面抛丸作业；设备运行过程中无废气排放，噪音控制在&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;85dB&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以下，符合国家环保施工标准，适配居民区周边、机场、室内车间等环保敏感场景。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（三）动力模块（豫工稳定驱动核心）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;动力模块作为路面抛丸机的核心驱动部件，豫工采用专属定制发动机&lt;/span&gt;/&lt;span style=&quot;font-family:等线&quot;&gt;电机，兼顾动力强劲、节能降噪、易启动的特点，解决普通动力系统功率不足、油耗过高、噪音过大、启动困难的难题，适配不同规模、不同场景的路面抛丸作业需求：&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;1. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;动力配置：全系采用豫工定制动力单元，小型型号采用电动电机（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;380V&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），适配室内、环保敏感场景，零排放、无噪音；中型型号可选电动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;柴油动力，适配户外无电源场景；大型型号采用大功率柴油发动机（四缸四冲程），动力强劲，适配大规模、长时间连续抛丸作业，同时配置自动调速系统，有效保护发动机&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;电机核心部件，避免路面不平、负载过大导致的设备损坏。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;动力优势：功率覆盖&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;7.5KW-45KW&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，可精准匹配抛丸模块、除尘模块与行走模块，实现抛丸效率、行走速度的灵活调节，快速驱动抛丸轮高速旋转，高效完成路面抛丸作业；采用节能降噪设计，柴油型号油耗较普通路面抛丸机降低&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;15-25%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，电动型号节能省电，运行成本低；动力输出稳定，无明显波动，保障抛丸均匀度与作业连续性。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;启动保障：小型电动型号采用一键启动，操作简单；中型柴油型号采用电动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;手动双启动模式，配备专用蓄电池，低温环境下也能快速启动（可适配&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;-20℃&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;60℃&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;环境）；大型柴油型号配备预热启动装置，解决户外低温、潮湿环境启动困难的痛点，保障路面抛丸作业进度不受影响。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（四）行走操控模块（豫工便捷化、智能化设计）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;采用豫工定制便捷行走操控系统，兼顾操作简单、移动灵活、安全可靠、智能监测，无需专业操作人员，适配户外复杂施工、室内车间路面处理等多种需求，降低人工操作难度，保障作业安全与抛丸效率：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;操控面板：配备简洁易懂的操控面板，标注清晰的启动开关、抛丸效率调节、行走速度调节、除尘系统控制等，可实时查看设备运行状态（电量&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;油量、抛丸强度、除尘状态），操作简单，新手也能快速上手；中大型型号配备智能监测仪表与故障诊断系统，可实时预警故障、精准定位故障位置（如抛丸轮故障、除尘堵塞、动力故障），便于及时排查，同时支持遥控操作，操作人员可远程调节作业参数，远离作业现场，提升作业安全性。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;行走设计：小型型号采用带万向轮的手推式设计，配备防滑扶手，移动灵活，可轻松穿梭于狭窄区域、小型作业现场，无需大型转运设备；中型型号采用自行走底盘，时速可灵活调节（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;0-5km/h&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），可实现直线、转向灵活行走，适配大面积路面连续抛丸；大型型号采用牵引式设计，配专用牵引装置，可与重型卡车对接，快速转运至不同施工现场，适配大范围、跨区域路面抛丸作业需求。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;安全防护：操控系统具备过载、过热、低油位（低电量）、除尘堵塞自动保护功能，设备过载、动力模块过热、燃油&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;电量不足或除尘系统堵塞时，可自动停机，避免设备损坏与安全事故；配备紧急停止按钮，应急情况下（如设备故障、人员靠近）可快速停机，提升作业安全性；行走底盘配备防滑轮胎，适配户外复杂路面（如泥泞、坡度路面），避免作业过程中打滑，保障作业稳定。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;三、豫工路面抛丸机适配场景及作业优势&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工路面抛丸机凭借不同型号的规格差异、均匀抛丸、无尘环保的核心优势，适配从小型局部路面抛丸到大型大面积高强度路面抛丸的多元场景，依托高效作业、灵活适配、耐磨耐用、无尘环保的核心优势，解决传统路面抛丸机抛丸不均、粉尘污染、效率低下、磨损快的难题，适配市政、路桥、机场、工业、停车场等多领域，核心适配场景按型号分类如下&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;;font-family:等线;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）豫工&lt;/span&gt;YG-PW300&lt;span style=&quot;font-family:等线&quot;&gt;（小型手推款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;主打小型路面、狭窄区域抛丸处理、局部修补抛丸，核心场景包括：小型市政道路局部养护抛丸、车间地面除锈除污、小型桥面（边缘区域）抛丸、停车场路面防滑处理、实验室地面拉毛、小型厂房地面翻新等；适配小范围、低强度路面抛丸需求，可精准完成局部路面除锈、除污、防滑处理，避免粉尘污染，操作灵活便捷，可快速对接小型路面修补作业；适配小型市政养护公司、小型加工厂、实验室、停车场管理方等用户，用于日常小型路面局部处理作业，高效省力，大幅减少人工劳动强度与设备运维成本，尤其适合受作业空间局限、狭窄区域的路面抛丸场景。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（二）豫工&lt;/span&gt;YG-PW550&lt;span style=&quot;font-family:等线&quot;&gt;（中型自行走款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;适配中型路面、大面积常规抛丸处理，核心场景包括：中型市政道路整体养护抛丸、桥面（整体）抛丸拉毛、工业园区路面除锈除污、机场跑道局部修补抛丸、收费站路面防滑处理、环氧地面表层处理等；可高效完成大面积路面均匀抛丸，无尘环保，自行走设计无需人工推送，作业速度快、效率高，可适配混凝土、沥青、钢板等多种路面材质，快速对接中型路面养护、翻新作业；适配中型市政养护公司、路桥工程企业、工业园区、机场运维部门等用户，是日常路面抛丸的主力机型，兼顾效率与经济性，可大幅提升路面抛丸效率，保证路面处理质量，减少粉尘污染与运维成本，适配多领域常规路面抛丸需求。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（三）豫工&lt;/span&gt;YG-PW800&lt;span style=&quot;font-family:等线&quot;&gt;（大型牵引款）适配场景&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;主打大型路面、高强度抛丸处理、大面积连续作业，核心场景包括：高速公路整体路面养护抛丸、大型桥梁桥面抛丸拉毛、机场跑道整体抛丸防滑、大型工业园区整体路面除锈、冶金厂区厚钢板路面抛丸、市政主干道大面积翻新抛丸等；超大流量、高强度抛丸，可快速完成大面积路面抛丸作业，支持&lt;/span&gt;24&lt;span style=&quot;font-family:等线&quot;&gt;小时连续运行，无尘环保，可适配复杂路面材质与高强度处理需求，快速对接大型路桥工程、机场运维等高标准作业；适配大型路桥工程企业、市政集团、机场运维公司、大型工业园区等用户，用于高标准、大规模路面抛丸作业，大幅提升路面处理效率，解决大面积高强度抛丸难题，保证路面处理质量，助力工程高效推进。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（四）豫工路面抛丸机专属作业优势&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;均匀高效（豫工核心优势）：豫工定制耐磨抛丸轮&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;+ &lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;精准抛射结构，抛丸均匀度高、无死角，抛丸效率较普通路面抛丸机提升&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;30%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上，可适配不同材质、不同强度的路面抛丸处理，实现路面表层均匀拉毛、除锈、除污，提升路面附着力，避免抛丸不均导致的路面损坏，大幅提升路面处理质量与效率。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;无尘环保更达标：豫工专属高效脉冲除尘系统，除尘效率&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≥99%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，可有效过滤抛丸过程中产生的粉尘，实现无尘作业，避免粉尘污染环境与操作人员健康，符合国家环保施工标准，尤其适配市政、机场、室内车间等对环保要求高的场景，同时减少粉尘二次污染。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;耐磨耐用寿命长：豫工定制耐磨抛丸轮、耐磨衬板及输送管路，耐磨性能优异，使用寿命较普通路面抛丸机延长&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;50%&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;以上，可有效抵抗钢丸、钢砂的冲击磨损，减少设备损坏与更换频率，降低运维成本，适配长时间连续作业需求。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;4. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;灵活适配性强：型号齐全，涵盖小型手推、中型自行走、大型牵引款，抛丸宽度、抛丸强度可灵活调节，动力类型可按需选择（电动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;柴油），适配不同宽度、不同材质、不同强度的路面处理需求，可快速对接市政、路桥、机场、工业等多领域路面作业，实现&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;多场景、多材质、多强度&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;一体化适配。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;5. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;智能便捷易操作：中大型型号标配智能操控、故障诊断、遥控操作功能，可实时监测设备运行状态，快速排查抛丸轮故障、除尘堵塞等问题，避免设备损坏；操控简单，无需专业操作人员，小型型号单人可操作，中大型型号可自行走、牵引转运，部署便捷，降低人工操作难度与施工成本，提升作业安全性。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;6. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;品质保障有保障：豫工作为&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;年水利市政设备生产厂家，拥有完善的售后流程与专业售后团队，路面抛丸机产品质保一年、终身维护，&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;24&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时远程技术支持，厂家直供、价格优惠、现货充足，可提供现场安装调试、技术培训服务，支持实地看厂，根据用户路面材质、处理面积定制专属型号，让用户买得放心、用得安心，多次获得市政、路桥、机场等领域用户认可。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四、豫工路面抛丸机选型核心参考&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;选型需结合&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;路面处理面积&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;路面材质及处理强度&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;作业场景（室内&lt;/span&gt;/&lt;span style=&quot;font-family:等线&quot;&gt;户外）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;环保要求&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;四大核心因素，结合豫工不同型号的特点，精准匹配需求，降低使用成本，提升路面抛丸效率：&lt;/span&gt;1. &amp;nbsp;&lt;span style=&quot;font-family:等线&quot;&gt;小型局部路面、狭窄区域、室内作业（处理面积&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;≤1000&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;㎡，轻度除污、防滑，混凝土&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;沥青材质）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW300&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，侧重轻便灵活、无尘环保，电动型号适配室内、环保敏感场景，贴合小型用户日常局部路面处理需求，是小型路面抛丸的优选设备。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;2. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;中型大面积路面、常规强度抛丸（处理面积&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;1000-10000&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;㎡，除锈、拉毛，多材质路面）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW550&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，电动&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;柴油可选，兼顾效率与灵活性，自行走设计提升作业效率，适配户外无电源场景，是日常路面抛丸的主力机型，适配多数常规路面养护需求。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;大型大面积路面、高强度抛丸（处理面积＞&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;10000&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;㎡，高强度除锈、机场&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;高速路面处理，复杂材质）：优先选择豫工&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;，大型牵引款，超大流量、高强度抛丸，支持&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;24&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;小时连续运行，适配复杂路面处理需求，可满足大型工程高标准路面抛丸需求，保障作业进度与质量。&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;4. &amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;特殊需求：室内路面处理、环保敏感场景，优先选择&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW300/YG-PW550&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;电动款（零排放、无噪音、无尘）；户外无电源、中型路面作业，优先选择&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW550&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;柴油款；大型工程、跨区域路面作业，优先选择&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;牵引款（部署便捷、效率高）；高强度除锈、厚钢板路面处理，优先选择&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW800&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（三抛丸轮、高强度抛射）；狭窄区域、局部修补，优先选择&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-PW300&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（灵活便捷、精准抛丸）。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;综上，豫工路面抛丸机是市政、路桥、机场、工业、停车场等领域路面处理的优选设备，依托豫工&lt;/span&gt;20&lt;span style=&quot;font-family:等线&quot;&gt;年水利市政设备研发经验与定制化设计，兼具均匀高效、无尘环保、耐磨耐用、灵活适配、智能便捷的核心优势，不同型号适配不同面积、不同材质、不同强度的路面处理需求，彻底解决传统路面抛丸方式的诸多痛点，适配国内各类路面作业工况，是市政养护公司、路桥工程企业、机场运维公司、工业园区等用户的核心选择，助力高效、高质量完成路面抛丸作业，提升路面附着力与使用寿命，降低施工成本。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Calibri;font-size:14px&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;');
INSERT INTO `dr_1_shipinguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(403, 1, 6, '&lt;p style=&quot;margin-top: 21px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:21px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;一、豫工激光超声波桥梁摊铺机主流型号及核心参数&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工激光超声波桥梁摊铺机型号以摊铺宽度、行走方式为核心标定，结合国内桥梁铺装工况，主打护栏行走式（主流款）与轮胎式两大类型，主流型号涵盖豫工&lt;/span&gt;YG-219&lt;span style=&quot;font-family:等线&quot;&gt;（三辊基础款）、&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-219D&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（双控智能款）、&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;YG-219F&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（全幅高效款），可按需定制摊铺宽度（&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;3-20m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;），所有参数均为豫工原厂标配，核心部件采用豫工定制配置，精准贴合不同桥梁铺装规模需求，核心参数汇总如下：&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 20px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:20px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;（一）豫工&lt;/span&gt;YG-219&lt;span style=&quot;font-family:等线&quot;&gt;（三辊基础款，护栏行走式）&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;核心定位&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;：基础型激光超声波桥梁摊铺机，依托桥面护栏铺设轨道行走，主打高性价比，适配中小型桥梁、乡村公路桥梁常规铺装，操作便捷、稳定性强，可减少人工二次处理接缝，是豫工入门级热门机型，广泛应用于基层桥梁铺装工程。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;table cellspacing=&quot;0&quot;&gt;&lt;tbody&gt;&lt;tr class=&quot;firstRow&quot;&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;参数类别&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-width: 1px; border-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;豫工&lt;/span&gt;YG-219&lt;span style=&quot;font-family:等线&quot;&gt;（三辊基础款）&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;摊铺宽度&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;3-6m&lt;span style=&quot;font-family:等线&quot;&gt;（可定制拼接，最大延伸至&lt;/span&gt;&lt;span style=&quot;font-family:Arial&quot;&gt;8m&lt;/span&gt;&lt;span style=&quot;font-family:等线&quot;&gt;）&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;&lt;span style=&quot;font-family:等线&quot;&gt;摊铺厚度&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: 120%&quot;&gt;&lt;span style=&quot;font-family:Arial;line-height:120%;font-size:15px&quot;&gt;10-30cm&lt;span style=&quot;font-family:等线&quot;&gt;（适配常规桥面铺装厚度）&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td width=&quot;200&quot; valign=&quot;top&quot; style=&quot;padding: 4px 8px 2px; border-left-width: 1px; border-left-color: rgb(222, 224, 227); border-right-width: 1px; border-right-color: rgb(222, 224, 227); border-top: none; border-bottom-width: 1px; border-bottom-color: rgb(222, 224, 227);&quot;&gt;&lt;p style=&quot;margin-top: 8px;margin-bottom: 8px;margin-left: 0;line-height: