(1, 0, 1, 6, '{\"content\":\"\",\"catid\":6,\"uid\":1,\"inputtime\":1770193242,\"updatetime\":1770193242,\"inputip\":\"123.160.243.73-57942\",\"displayorder\":0,\"hits\":1,\"title\":\"豫工喷砂机_空压机全型号参数 结构特点及适配场景详解\",\"thumb\":\"1121\",\"keywords\":\"空压机,喷砂机,豫工,除锈,表面处理\",\"description\":\"河南豫工作为工业机械实力制造商，专注表面处理与气源设备研发生产，其喷砂机与空压机主打高效耐用、适配性强、配套性佳，覆盖小型便携到大型工业级全规格，可精准匹配钢结构除锈、船舶桥梁翻新、矿山机械维护、石油管道处理、市政工程施工等多场景需求，形成“气源供给+表面处理”一体化解决方案。产品现货充足，河南郑州工厂直发，2天内快速发货，支持定制化参数与批量采购，兼顾性价比与实用性，是工业生产、工程施工中表面处\",\"author\":\"创始人\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\",\"status\":9,\"id\":0}', 1770193776);
