INSERT INTO `dr_1_shipinguanli_recycle` (`id`, `cid`, `uid`, `catid`, `content`, `result`, `inputtime`) VALUES
(1, 227, 1, 10, '{\"1_shipinguanli\":{\"id\":\"227\",\"catid\":\"10\",\"title\":\"\\r\\n        西安兴平食品工业钢板除锈\\r\\n       \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-227.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-40928\",\"inputtime\":\"1700812579\",\"updatetime\":\"1700812579\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"227\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n\\r\\n     &lt;div class=&quot;body_paragraph&quot;&gt;\\r\\n &lt;div class=&quot;body_paragraph_center&quot;&gt;\\r\\n  &lt;div class=&quot;body_paragraph_block&quot;&gt;\\r\\n   &lt;p&gt;\\r\\n     &lt;/p&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div class=&quot;body_match&quot;&gt;\\r\\n &lt;div class=&quot;body_match_center&quot;&gt;\\r\\n  &lt;div class=&quot;body_match_block&quot;&gt;\\r\\n   &lt;div class=&quot;body_match_block_title&quot;&gt;\\r\\n    &lt;div&gt;\\r\\n     &lt;h2&gt;\\r\\n      客户评价&lt;/h2&gt;\\r\\n    &lt;/div&gt;\\r\\n    &lt;div&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_match_title_img.png&quot;&gt;&lt;/div&gt;\\r\\n   &lt;/div&gt;\\r\\n   &lt;div class=&quot;body_match_block_content&quot;&gt;\\r\\n    &lt;div&gt;\\r\\n     钢板除锈施工，第一次用磨光机，有粉尘，环保局不通过，改用湿喷机，排出的污水污染下水道，村委会不让用，后选择豫工路面抛丸机，无尘环保，客户满意，甲方点赞&lt;/div&gt;\\r\\n   &lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div class=&quot;body_image&quot;&gt;\\r\\n &lt;div class=&quot;body_image_center&quot;&gt;\\r\\n  &lt;div class=&quot;body_image_block&quot;&gt;\\r\\n   &lt;div class=&quot;body_image_block_title&quot;&gt;\\r\\n    &lt;div&gt;\\r\\n     &lt;h2&gt;\\r\\n      图片展示&lt;/h2&gt;\\r\\n    &lt;/div&gt;\\r\\n    &lt;div&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;&gt;&lt;/div&gt;\\r\\n   &lt;/div&gt;\\r\\n   &lt;div class=&quot;body_image_block_content&quot;&gt;\\r\\n    &lt;div class=&quot;body_image_block_content_img1&quot;&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162620649.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162632Z0.jpg&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162642605.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210326/2-210326162AR48.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;&gt;&lt;/div&gt;\\r\\n   &lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n\\r\\n\\r\\n    \"},\"1_shipinguanli_category_data\":null}', '', 1700812795),
