 &lt;h2&gt;\\r\\n      施工现场&lt;/h2&gt;\\r\\n    &lt;/div&gt;\\r\\n    &lt;div&gt;\\r\\n     &lt;img alt src=&quot;https://yongjiu.hnyugong.com/skin/images/product_article/body_image_title_img.png&quot;&gt;&lt;/div&gt;\\r\\n   &lt;/div&gt;\\r\\n                        &lt;div class=&quot;body_image_block_content&quot;&gt;\\r\\n    &lt;div class=&quot;body_image_block_content_img1&quot;&gt;\\r\\n                             &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G604335G.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;\\r\\n                                    &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6045B06.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n                                    &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6051Gb.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n                                    &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G60530622.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n                                    &lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210427/2-21042G6061U38.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n                                    &lt;br&gt;\\r\\n                                &lt;/div&gt;\\r\\n                        &lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n\\r\\n\\r\\n\\r\\n    \"},\"1_shipinguanli_category_data\":null}', '', 1700812795),
