(12, 217, 1, 10, '{\"1_shipinguanli\":{\"id\":\"217\",\"catid\":\"10\",\"title\":\"\\r\\n        中建五局点赞豫工液压湿喷机\\r\\n       \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-217.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-40846\",\"inputtime\":\"1700812573\",\"updatetime\":\"1700812573\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"217\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n\\r\\n     &lt;h1&gt;\\r\\n 客户好评&lt;/h1&gt;\\r\\n&lt;p&gt;\\r\\n &lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;喷浆速度很快，操作很简单！这是设备给我最大的印象！&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;\\r\\n&lt;p&gt;\\r\\n &lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;感谢技术人员的辛勤付出，很专业也很有责任心，总是耐心指导工人操作步骤，听工人说他们现在可以熟练掌握设备的安装、拆卸、操作、保养步骤。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;\\r\\n&lt;p&gt;\\r\\n &lt;span style=&quot;font-family:arial,helvetica,sans-serif;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;选择豫工，我很放心。&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;\\r\\n&lt;h1&gt;\\r\\n 施工现场&lt;/h1&gt;\\r\\n&lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K544B2.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K61YG.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101K63K93.jpg&quot; style=&quot;width: 800px; height: 450px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101KF22a.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;&gt;&lt;br&gt;\\r\\n\\r\\n\\r\\n    \"},\"1_shipinguanli_category_data\":null}', '', 1700812800