(31, 277, 1, 0, '{\"1_shipinguanli\":{\"id\":\"277\",\"catid\":\"0\",\"title\":\"550路面抛丸机\",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/index.php?c=show&id=277\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-54448\",\"inputtime\":\"1701070813\",\"updatetime\":\"1701070813\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"277\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n     \\r\\n     &lt;p&gt;\\r\\n &lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;6532名客户一致选择它高效清理地面&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210402/2-210402145322316.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;/strong&gt;&lt;/span&gt;&lt;br&gt;\\r\\n  &lt;strong&gt;&lt;span style=&quot;font-size:18px;&quot;&gt;突出优势&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;\\r\\n&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;效率高 省人工：&lt;/strong&gt;一次性施工，即可得到干净整洁，粗糙度均匀的表面，工作效率高。&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-21032610360GX.png&quot; style=&quot;width: 691px; height: 462px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n混凝土地面打毛&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-210326103622451.png&quot;&gt;&lt;br&gt;\\r\\n&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;清理成本低&lt;/strong&gt;：钢丸损失小，易损件更换方便，有效降低施工成本&lt;br&gt;\\r\\n&lt;strong&gt;粗糙度可调&lt;/strong&gt;：地面清理粗糙度可调，深可抛3-4mm，符合不同的清理要求。&lt;/span&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-210326103632591.png&quot;&gt;&lt;br&gt;\\r\\n深度抛丸效果展示&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-21032610364M20.png&quot;&gt;&lt;br&gt;\\r\\n较浅抛丸效果展示&lt;br&gt;\\r\\n&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;strong&gt;暴露地面裂纹 防患于未然&lt;/strong&gt;：清理表面干净整洁，粗糙度均匀，没有损伤，同时将混凝土地面的裂纹充分暴露出来，防患于未然。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-210326103A9227.png&quot;&gt;&lt;br&gt;\\r\\n&lt;span style=&quot;font-size:14px;&quot;&gt;抛丸前地面展示&lt;/span&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210326/2-210326103G0392.png&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n     \\r\\n    \"},\"1_shipinguanli_category_data\":null}', '', 1701070933),
(32, 271, 1, 0, '{\"1_shipinguanli\":{\"id\":\"271\",\"catid\":\"0\",\"title\":\"沥青搅拌机\",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/index.php?c=show&id=271\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-53874\",\"inputtime\":\"1701070457\",\"updatetime\":\"1701070457\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"271\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n    &lt;div class=&quot;body_image_block_content_img3&quot;&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-210622120100321.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-210622122435Y4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-210622140244513.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-21062212024I21.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-210622120322939.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-210622120203D0.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210622/2-21062212022V54.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n   \"},\"1_shipinguanli_category_data\":null}', '', 1701070933),
