(37, 276, 1, 0, '{\"1_shipinguanli\":{\"id\":\"276\",\"catid\":\"0\",\"title\":\"300型自行走铣刨机\",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/index.php?c=show&id=276\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-53910\",\"inputtime\":\"1701070457\",\"updatetime\":\"1701070457\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"276\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n    &lt;div class=&quot;body_image_block_content_img3&quot;&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G4320V10.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G4322K24.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G43239B4.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G43251B9.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G43302533.jpg&quot; style=&quot;width: 691px; height: 319px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G43313626.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G433561L.jpg&quot; style=&quot;width: 691px; height: 371px;&quot;&gt;&lt;/div&gt;\\r\\n   \"},\"1_shipinguanli_category_data\":null}', '', 1701070933),
(38, 270, 1, 0, '{\"1_shipinguanli\":{\"id\":\"270\",\"catid\":\"0\",\"title\":\"乳化沥青撒布机\",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/index.php?c=show&id=270\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-53866\",\"inputtime\":\"1701070456\",\"updatetime\":\"1701070456\",\"displayorder\":\"0\",\"spxqysbzsp\":\"\",\"spxqyzbspjs\":\"\"},\"1_shipinguanli_data_0\":{\"id\":\"270\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n    &lt;div class=&quot;body_image_block_content_img3&quot;&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G4523Kb.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G45252M4.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G45324T8.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G4533O10.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n     &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032G4534TN.jpg&quot; style=&quot;width: 691px; height: 460px;&quot;&gt;&lt;/div&gt;\\r\\n   \"},\"1_shipinguanli_category_data\":null}', '', 1701070933);
