INSERT INTO `dr_1_xinwenguanli` (`id`, `catid`, `title`, `thumb`, `keywords`, `description`, `hits`, `uid`, `author`, `status`, `url`, `link_id`, `tableid`, `inputip`, `inputtime`, `updatetime`, `displayorder`) VALUES
(153, 8, '豫工机械秋日团建 连云港三日游        ', '941', '', '工作中乘风破浪，生活中多姿多彩，2023年8月18日，豫工机械2023秋季团建，三天两夜 欢乐启程。4辆豪华大巴满载我们的快乐奔赴美丽连云港，游山观海 不负时光，一起感受港城的秋天。  打卡羊山岛，渔村情调 潮声灌耳，感谢豫工的贴心安排，让我们一起，来一场诗和远方的浪漫。    敢问路在何方，路在脚下......，走进现实版的花果山，洞天福地 人间仙境，感受心中的桃花源。45°的侧脸很好看，45°', 1, 1, '创始人', 9, '/show-153.html', 0, 0, '39.96.59.7-60730', 1700798548, 1710555236, 0),
(154, 8, '豫工机械十八周年庆典隆重举行        ', '943', '', '春余夏首 微风习习,2023.6.21,豫工机械十八周年庆典隆重开启,索菲特国际酒店 五星级会议大厅,公司总部300多人盛装出席,共同见证豫工发展高光时刻!    辉煌大厅别具匠心,签名墙精心布置,留下了豫工人自信优雅的身影!一张张喜逐颜开的笑脸,一幅幅轻松融洽的合影,让豫工人的心更牢固地粘在一起!        在欢快动感的舞蹈中，庆典拉开序幕,豫工人活力四射 舞力全开，上演才艺大比拼。宫廷风', 1, 1, '创始人', 9, '/show-154.html', 0, 0, '39.96.59.7-60738', 1700798548, 1710555287, 0),
(155, 8, '豫工机械旺春大战火热启动        ', '944', '', '伴随着恢弘的音乐，豫工人满怀信心，火热开启，2023旺春大战启动会！作为一年一度的重头戏，豫工人最重要的日子，每个人精致妆容，盛装出席，大有与三月争春的劲头，只有额头上的红头巾，写着“赢战旺春”“舍我其谁”的宣言，时刻提醒我们，这是一场时间紧、任务重的百天大战（2023.3.1-6.15）。音乐停止，国内事业部成员入场就坐，200多位豫工人齐聚一堂，火热开启，2023旺春大战启动会。   本次大会', 1, 1, '创始人', 9, '/show-155.html', 0, 0, '39.96.59.7-60744', 1700798548, 1710555319, 0),
(156, 8, '2023新年庆典，豫工达人秀惊喜上线！        ', '945', '', '岁末将至，豫工机械2023新年庆典，欢乐上线。今天不谈工作，不谈业务，只谈“笑”“疯”声，红包、奖品、表彰，歌曲、小品、舞蹈，好事扎堆 快乐排队！优秀员工表彰，红包不停，礼品不断，荣誉感十足 幸福感爆棚......好嗨哟，感觉人生已经达到了巅峰！  看！这不就是努力的意义嘛！忙有所得 耕有所获，走路带风 眼神坚定，每根头发都散发着自信的光芒，内心富足 自律自强，有所忙有所爱有所期待！   才艺展示', 1, 1, '创始人', 9, '/show-156.html', 0, 0, '39.96.59.7-60750', 1700798548, 1710555438, 0),
(157, 8, '开工大吉！2023迎好运，启新章！        ', '948', '', '2023迎好运，启新章！开工红包惊喜派发中......公司董事长李总来到国内事业部和国际事业部，为员工一 一发放开工红包，666的大红包，寓意开工大吉，诸事顺利。   在一声声“新年好”“恭喜发财”的道贺声中，豫工人精神抖擞回到工作岗位，开心地从李总手里接过祝福红包，大大的红包，是豫工对员工一如既往的关爱。此刻，大家元气满满，再启征程！    2023致胜之年，豫工人卯足干劲，大展宏“兔”，一起加', 1, 1, '创始人', 9, '/show-157.html', 0, 0, '39.96.59.7-60756', 1700798548, 1710572921, 0),
(158, 8, '复工啦！豫工机械为全体员工发放高额福利！        ', '950', '', '秋高气爽、云开疫散，豫工机械全面复工复产，红包不断，为员工发放高额生活补贴，首批8万元复工红包已发放完毕。      适逢豫工金秋大战，叠加双11嗨购节，您的VIP专属红包已备好，超级钜惠，重磅加码，感谢广大新老客户一直以来的信任和支持，诚心相邀“，郑”等您来。  河南豫工机械是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施', 1, 1, '创始人', 9, '/show-158.html', 0, 0, '39.96.59.7-60762', 1700798548, 1710573018, 0),
(159, 8, '豫工机械2022团建欢乐启程        ', '937', '', '生活不止眼前的工作，还有静下来的诗意和远方，2022年8月13日，伴着动感的音乐，踏着欢快的节拍，豫工机械2022主题团建第一趴，快乐出发！  感谢公司的贴心安排，本次团建以部门为单位，自主规划活动路线，漂流、爬山、温泉、轰趴、划船......各赴人间惊鸿宴，一睹人间盛世颜！        打卡云上牧场，感受风的温柔，体验花的浪漫，听蝉鸣鸟叫，看蝴蝶纷飞，再和天空来一张合作！        生活中', 1, 1, '创始人', 9, '/show-159.html', 0, 0, '39.96.59.7-60768', 1700798549, 1710555087, 0),
(160, 8, '福利！豫工端午全家福新鲜出炉        ', '938', '', '美好恰逢其时，生活与“粽”不同，端午如期而至，豫工的福利也一如往昔，丰厚 健康 贴心！两箱粽子，一箱火龙果，一箱哈蜜瓜，沉甸甸的感觉，像极了豫工对家人的关爱，感谢大家为公司发展的辛勤付出！因为有你，所以出粽，2022是不平凡的一年，因为大家的不懈努力，豫工在充满机遇与挑战的市场竞争中，逆势而来 强势崛起！一粽传情，浓情端午，一盒盒精致的端午礼品，承载了公司对大家满满的关怀，代表着公司对全体员工的真', 1, 1, '创始人', 9, '/show-160.html', 0, 0, '39.96.59.7-60774', 1700798549, 1710555147, 0),
(161, 8, '豫工机械17周年庆典，巅峰时刻 群星闪耀        ', '939', '', '2022年6月18日 中都大酒店，豫工机械17周年庆典暨第二届女神节隆重举行，总部营销中心300多人参加活动，现场星光璀璨 精彩纷呈！董事长开幕式致辞李总表示：豫工17年高速发展与科学的规划密不可分，立足长远，计划落地。未来，公司还要继续练内功，强本领，做规划！做精、做深、做强主营业务，为客户提供不可替代的服务和价值!  2022旺春大战颁奖典礼柔肩担重任  巾帼绽芳华，旺春大战期间，豫工人执着于', 1, 1, '创始人', 9, '/show-161.html', 0, 0, '39.96.59.7-60780', 1700798549, 1710555171, 0),
(162, 8, '99公益日丨豫工邀您一起献爱心！        ', '940', '', '“99公益日”来临，豫工机械作为常年热心公益的爱心企业，特发起2022年度“99公益日”助力“困境儿童守护计划”公益募捐活动，携手助童 共护成长。即日起至9月9日，您的每一笔捐款，豫工机械将进行1：1金额的“陪捐”！也就是你捐多少，我公司会“陪捐”多少！“薅羊毛”式捐赠，为爱加油！积小善，成大爱 捐助10元，可以帮助一个孩子解决一天的生活补助； 捐助20元，可以帮助孩子买一本课外书； 捐助100元', 1, 1, '创始人', 9, '/show-162.html', 0, 0, '39.96.59.7-60786', 1700798549, 1710555201, 0),
(163, 8, '豫工机械发福利了，中秋快乐！        ', '934', '', '中秋节发福利了！红红火火的包装，至诚至爱的心意，节礼在手，温暖在心，感谢公司一如既往的厚爱！ 作为国人重要的传统佳节，每年中秋，公司都会精心准备节日贺礼，感谢大家一年来的努力与付出，希望每一位员工都能与家人，阖家团圆，把酒言欢，满满的仪式感，引来隔壁公司羡慕的眼光。   心怀感恩 所遇皆温柔，公司满满的关爱，不仅让豫工人找到归属感，也让背后的家庭对豫工好感度俱增，多年工作下来，他们都成了最合格的豫', 1, 1, '创始人', 9, '/show-163.html', 0, 0, '39.96.59.7-60832', 1700798564, 1710553871, 0),
(164, 8, '飒！豫工机械金秋大战燃情启动        ', '935', '', '2022年9月14日，豫工机械营销总部，金秋大战在国内事业部率先启动，近200名员工斗志昂扬，众志成城，正式打响金九银十决胜战！总结过去，赢战未来，表彰卓越，见证辉煌在热烈的掌声中，优秀代表纷纷登台，荣誉和鲜花，是对他们最大的鼓舞和肯定。在金九银十关键节点，豫工机械金秋大战也如期而至，作为公司2022年51工程（2022年销售额突破5个亿）的关键一战，本次启动会既要制定目标、分解过程，更要为营销团', 1, 1, '创始人', 9, '/show-164.html', 0, 0, '39.96.59.7-60840', 1700798564, 1710554995, 0),
(165, 8, '豫工旺春大战启动会燃情启动        ', '936', '', '2022年2月22日，豫工机械“如虎添亿，奋战51”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工200多人参加此次活动！2021，在豫工人的共同努力下，公司全年销售总额再破3亿元大关，品牌知名度、市场接受度、老客户返单率、生产总值、团队业绩再创新高。期间，公司涌现出了众多业绩精英、营销达人、优秀团队、百万英雄。她们8小时内求生存，8小时外求发展，每一天、每一分钟，都在', 1, 1, '创始人', 9, '/show-165.html', 0, 0, '39.96.59.7-60846', 1700798564, 1710555058, 0),
(166, 8, '豫工两台湿喷台车助力中铁隧道局开工大吉!        ', '927', '', '2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！它们将用于中铁隧道局宜兴铁路ZQ-3标隧道喷浆支护项目。作为3月的第49、50台喷浆支护系列设备，它的成功发车，意味着豫工机械喷浆支护设备3月销量再创新高。这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程', 1, 1, '创始人', 9, '/show-166.html', 0, 0, '39.96.59.7-60852', 1700798565, 1710552998, 0),
(167, 8, '豫工机械2021国庆放假通知        ', '928', '', '神州大地，举国欢庆！山河壮丽，岁月峥嵘！江山不老，祖国常青！豫工机械祝福我们的祖国繁荣昌盛十一国庆节来了，根据国家放假规定，结合公司实际情况，河南豫工机械有限公司2021年国庆放假安排如下： 注意事项 1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。2、各部门根据公司放假通知，安排好假期工作；工厂仓库', 1, 1, '创始人', 9, '/show-167.html', 0, 0, '39.96.59.7-60858', 1700798565, 1710553071, 0),
(168, 8, '豫工机械金秋大战燃情启动        ', '931', '', '2021年9月11日，豫工机械“2021金秋大战暨旺春优秀表彰” 燃情启动，郑州总部营销中心，全体员工180多人参加活动！国内事业部活动现场国际事业部活动现场旺春大战优秀表彰2个月前，公司旺春大战圆满收官，诞生了许多业绩标兵、百万英雄、服务之星、优秀团队，今天是见证荣誉的时刻！ 国内事业部旺春英雄奖 国内事业部捷报奖国际事业部旺春英雄奖国际事业部旺春达人奖国际事业部旺春捷报奖优秀个人表彰在豫工，从', 1, 1, '创始人', 9, '/show-168.html', 0, 0, '39.96.59.7-60864', 1700798565, 1710553443, 0),
(169, 8, '豫工机械2021中秋节放假通知        ', '930', '', '金秋九月，花好月圆，又是一年中秋时！河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：  放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班 温馨提示   1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。2、各部门根据公司放假通知，安排好假期工作；工厂', 1, 1, '创始人', 9, '/show-169.html', 0, 0, '39.96.59.7-60870', 1700798565, 1710553136, 0),
(170, 8, '您的中秋贺礼已发货！请注意查收！        ', '932', '', '金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!7月抗汛,赈灾义卖,!筹款30万捐向灾区8月抗疫，涝疫补贴,每人500元中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼', 1, 1, '创始人', 9, '/show-170.html', 0, 0, '39.96.59.7-60876', 1700798565, 1710553664, 0),
(171, 8, '豫工机械通过ISO9001-2016国际管理体系认证        ', '933', '', '河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目', 1, 1, '创始人', 9, '/show-171.html', 0, 0, '39.96.59.7-60882', 1700798565, 1710553844, 0),
(172, 8, '豫工机械通过企业AAA诚信认证        ', '926', '', '河南豫工机械是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目', 1, 1, '创始人', 9, '/show-172.html', 0, 0, '39.96.59.7-60888', 1700798566, 1710552977, 0),
(173, 8, '豫工机械为河南灾区捐赠的4车物资发车        ', '921', '', '7月23日，河南豫工机械有限公司通过郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。董事长李红旗先生第一时间捐款12万元用于抗洪救灾，并带领公司全体员工连', 1, 1, '创始人', 9, '/show-173.html', 0, 0, '39.96.59.7-60914', 1700798572, 1710552707, 0),
(174, 8, '豫工机械2021端午节放假通知        ', '922', '', '豫工机械五一放假通知根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。3、各部门根据公司放假通知，安排好假期', 1, 1, '创始人', 9, '/show-174.html', 0, 0, '39.96.59.7-60922', 1700798572, 1710552744, 0),
(175, 8, '赞！豫工端午福利多，老板实力宠员工！        ', '923', '', '端午来啦！老板实力宠员工2盒粽子，2箱水果啧啧......豪横，果然是中国好老板！  丰厚的节日福利是公司对中国文化的传承更体现了对豫工家人细致入微的关怀其实，每逢传统佳节公司都会为客户朋友和豫工家人精心准备节日贺礼这个习惯，豫工一干就是16年！    福利发放现场，欢声笑语！大家暂时放下手中繁忙的工作，聚在一起，享受节日的快乐！  国内事业部员工风采国际事业部员工风采今年端午，赶上公司16周年庆', 1, 1, '创始人', 9, '/show-175.html', 0, 0, '39.96.59.7-60928', 1700798572, 1710552810, 0),
(176, 8, '豫工机械16周年庆典暨第一届女神节        ', '924', '', '2021年5月21日，郑州禧逸酒店会议大厅，豫工机械“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。生日趴在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。    迎新环节16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备', 1, 1, '创始人', 9, '/show-176.html', 0, 0, '39.96.59.7-60934', 1700798572, 1710552827, 0),
(177, 8, '五一劳动节 ，豫工机械放假通知        ', '925', '', '在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！河南豫工机械五一放假通知根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：1、2021年劳动节', 1, 1, '创始人', 9, '/show-177.html', 0, 0, '39.96.59.7-60940', 1700798572, 1710552916, 0),
(178, 8, '热情服务获赞誉，客户感激送锦旗        ', '916', '', '客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。 客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙', 1, 1, '创始人', 9, '/show-178.html', 0, 0, '39.96.59.7-60946', 1700798573, 1710552423, 0),
(179, 8, '豫工收官启动，秒变大型跨年晚会现场        ', '917', '', '2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。迎新环节虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。  金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。 大', 1, 1, '创始人', 9, '/show-179.html', 0, 0, '39.96.59.7-60952', 1700798573, 1710552444, 0),
(180, 8, '一粽传情 快乐端午，豫工机械端午福利多        ', '918', '', '端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟', 1, 1, '创始人', 9, '/show-180.html', 0, 0, '39.96.59.7-60958', 1700798573, 1710552465, 0),
(181, 8, '豫工大型中秋福利现场，堪比红毯走秀        ', '919', '', '中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满', 1, 1, '创始人', 9, '/show-181.html', 0, 0, '39.96.59.7-60964', 1700798573, 1710552654, 0),
(182, 8, '燃！豫工液压湿喷机助战郑州地铁建设        ', '920', '', '2021年2月6日，豫工售后与技术支持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压', 1, 1, '创始人', 9, '/show-182.html', 0, 0, '39.96.59.7-60970', 1700798573, 1710552683, 0),
(183, 8, '豫工机械北京团建欢畅启程        ', '914', '', '战前OUTING豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！    豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比', 1, 1, '创始人', 9, '/show-183.html', 0, 0, '39.96.59.7-32768', 1700798583, 1710552236, 0),
(184, 8, '豫工特邀消防部门宣讲消防安全知识        ', '915', '', '安全生产 消防为先，8月4日下午4点，豫工机械开展消防安全讲座。公司特邀河南省护民防火中心祝教官，前往总部营销中心，为大家讲解消防安全知识，全体员工140多人参加。祝教官对近年发生的火灾以图片、视频的形式提高大家消防安全意识，从贴近生活，实用性强的单位、家庭用气、用电、夏季汽车自燃等方面入手，讲解消防知识，和火灾初期如何灭火的方法，提高大家防灾减灾能力！ 祝教官现场演示灭火器“一摇、二拔、三瞄、四', 1, 1, '创始人', 9, '/show-184.html', 0, 0, '39.96.59.7-32776', 1700798583, 1710552315, 0),
(185, 8, '豫工机械第八届司庆日暨表彰大会        ', '909', '', '2020年5月18日，河南豫工机械第八届司庆日暨表彰大会在郑州禧逸酒店隆重召开。首先豫工生日趴，小伙伴们和主持人一起齐声祝福“河南豫工，生日快乐”。这时灯光熄灭，伴随着生日快乐歌，我们的大蛋糕上场了，大家热情高涨的唱着生日歌，歌声刚落下，我们的小伙伴们就向着蛋糕蜂拥而上，蛋糕的香甜味道弥漫在会场的上空，整个大厅都沉浸在一片欢乐的海洋……分享完蛋糕，接下来是我们的年度表彰环节，首先是我们2019年度', 1, 1, '创始人', 9, '/show-185.html', 0, 0, '39.96.59.7-32782', 1700798584, 1710552187, 0),
(186, 8, '以色列客户考察豫工锚固钻车        ', '910', '', '经过邮件来往沟通，2020年4月29日，以色列客户来我司工厂参观考察 国外以色列客户来访，要目的是为了商讨豫工锚固钻机后续大批量订单交期及质量控制事宜。  经过多次的沟通，该客户对我司有了更深更好的了解。经过此次会谈，我们产品的技术和质量，价格优势，订单交期，服务方面得到了客户的认可，客户表示将与河南豫工机械长期订单合同，同时客户还表达豫工机械将成为自己核心的供用商。', 1, 1, '创始人', 9, '/show-186.html', 0, 0, '39.96.59.7-32788', 1700798584, 1710552195, 0),
(187, 8, ' 好嗨哟！豫工机械旺春大战盛大启动        ', '911', '', '2021年2月27日，豫工机械“春风十里，不如有你”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工180多人参加此次活动！      豫工小姐姐化身舞林高手，精彩演绎提神洗脑神曲，可可爱爱，奇奇怪怪，换个舞台，依旧是灯光下耀眼的小姑娘        2020年，在全体豫工人的共同努力下，全年销售总额突破亿元大关;品牌知名度、市场接受度、老客户返单率直线飙升，综合上升9.', 1, 1, '创始人', 9, '/show-187.html', 0, 0, '39.96.59.7-32794', 1700798584, 1710552204, 0),
(188, 8, '旅游团建｜豫工的小姐姐，你笑起来真好看        ', '912', '', '7月18日，河南豫工机械,“认真工作，快乐生活”主题团建欢畅启程!豫工的小伙伴们集合完毕,乘坐两辆舒适的大巴向云台山进发,这次我们不谈工作，不谈业务,只谈...笑风生!  大家一路欢声笑语,工作严谨认真，生活中却不乏开朗活泼,能干会玩，是我们的标签太行山把美的一段给了河南！焦作云台山，山美 水美 云美 泉美!还有豫工的小姐姐更美！美得不像话!!!大家来到小寨沟，这里被称为北方九寨沟!三步一泉，五步', 1, 1, '创始人', 9, '/show-188.html', 0, 0, '39.96.59.7-32800', 1700798584, 1710552211, 0),
(189, 9, '         智能张拉设备不可忽视的几点        ', '74', '', '智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。4、在移动设备的过程中，泵站、', 1, 1, '创始人', 9, '/show-189.html', 0, 0, '39.96.59.7-37094', 1700807659, 1708586385, 0),
(190, 9, '         什么是预应力机械？一分钟了解预应力        ', '75', '', '预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和', 1, 1, '创始人', 9, '/show-190.html', 0, 0, '39.96.59.7-37102', 1700807659, 1708586377, 0),
(191, 9, '         做防水，选对设备，不花冤枉钱！        ', '76', '', '防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。对于非固化设备的选购，许多人没有眉目。有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合', 1, 1, '创始人', 9, '/show-191.html', 0, 0, '39.96.59.7-37108', 1700807659, 1708586061, 0),
(192, 9, '         路面抛丸机对混凝土桥面的表面处理工艺        ', '77', '', '欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保', 1, 1, '创始人', 9, '/show-192.html', 0, 0, '39.96.59.7-37116', 1700807659, 1708586072, 0),
(193, 9, '         选购喷播机时都要注意哪些内容呢？        ', '78', '', '喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路）边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。一、选择合适的型号喷播机常按不同的喷播对象分为客土喷播机和液力喷播机。合适的型号才能发挥出喷播机效用。要选择合适的型号，我们需要从两个方面考虑：1、 根据边坡类型选择', 1, 1, '创始人', 9, '/show-193.html', 0, 0, '39.96.59.7-37122', 1700807659, 1708586176, 0),
(194, 9, '         超大雾化面非固化喷涂机多少钱一台？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401143303929.png', '', '近日，有客户找到豫工机械咨询关于超大雾化扇面非固化喷涂设备的型号及价格的问题。在充分了解了这位客户的施工场景、施工面积、工人数量、项目工期后，豫工产品经理为其推荐了以下几种机型，现将其列出，以供大家参考。客户需求信息项目介绍90000平方地库顶板防水施工喷涂物料非固化橡胶沥青防水涂料现场情况 客户第一次从事防水施工项目，工人无经验！其他需求工期紧，天气炎热，工人室外作业，希望设备高效作业，要求设备', 1, 1, '创始人', 9, '/show-194.html', 0, 0, '39.96.59.7-37288', 1700807830, 1700808043, 0),
(195, 9, '         桥面抛丸机防水打毛有那些优势？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153551501.jpg', '', '众所周知，路面清理打毛是防水喷涂施工前处理的重要环节，那么路面抛丸机在粗化打毛混凝土路面方面有那些优势呢？防水基层处理抛丸机路面抛丸机的抛丸工艺可以一次性将混凝土外表的浮浆，杂质清算洁净，同时对混凝土外表进行打毛处置，使其外表均匀粗糙，大大进步了防水层和混凝土基层的黏结强度。而且在此过程中，可以充沛暴露混凝土的裂纹等病害，以便提早采取弥补措施。所以在推系统时，有条件状况下，采用抛丸处置基面，可以更', 1, 1, '创始人', 9, '/show-195.html', 0, 0, '39.96.59.7-37296', 1700807830, 1700808051, 0),
(196, 9, '         三辊路面摊铺机有那些型号，多少钱一台？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153021911.jpg', '', '天气回温，路面施工市场的火热程度也在随之飙升，一众基建项目的开工使得路面摊铺设备出现了供不应求的状况。不少客户朋友蠢蠢欲动，来咨询豫工机械关于混凝土摊铺机的型号和情况，那么一台滚轴式摊铺机有哪些型号呢？买一台三辊的摊铺机需要多少钱呢？路面混凝土摊铺机的型号、摊铺效果摊铺排振一体机：混凝土摊铺机+排式振捣机设备参数辊子配置：两辊(2个行走轮)+1根绞龙（螺旋辊）动力：4KW-4极电机2台(两根行走轮', 1, 1, '创始人', 9, '/show-196.html', 0, 0, '39.96.59.7-37302', 1700807830, 1700808060, 0),
(197, 9, '         液压铣刨机价格，液压铣刨机有那些型号？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152344301.jpg', '', '目前，液压铣刨机型号比较多，其中，电机款统用18.5KW；300型也有15KW的，300型和350型适合2公分左右、3公分之内铣刨;500型适合半公分左右、1公分左右铣刨等，因施工要求、设备型号、配置差异加大，价格也不尽相同，大部分设备价格在3万-5万左右。液压铣刨机主要型号针对深度铣刨的施工要求，豫工机械热销机型是350型的电动和燃油款，4根轴、大刀片、直径110刀片、数量是76片。500型号的', 1, 1, '创始人', 9, '/show-197.html', 0, 0, '39.96.59.7-37308', 1700807830, 1700808073, 0),
(198, 9, '         高速公路车载式绿篱修剪机多少钱？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152015100.jpg', '', '车载绿篱修剪机的价格一直是每个客户关心的问题，但是，目前国内绿篱修剪机生产厂家众多，竞争激烈，各厂家会定期推出优惠政策，给出的报价不一！另外，市场平均价格水平，配置型号，安装调试，运送距离，发票等因素，都会影响产品最终报价！公路绿篱及边坡灌木修剪专用设备在没有绿篱修剪机之前，都是通过人工修建的方式，这种方式的缺点非常明显，不仅效率低下，而且也存在一定的安全问题，所以绿化带修剪机的出现，不仅解决了这', 1, 1, '创始人', 9, '/show-198.html', 0, 0, '39.96.59.7-37314', 1700807830, 1708586483, 0),
(199, 9, '         桥面抛丸机有那些型号？多少钱一台？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151321549.png', '', '近段时间，来到豫工机械询问路面抛丸机的客户不在少数，小编将其中问到较多的问题进行了汇总，包括路面抛丸机的工作效率、工作宽度、适用环境、性能特征、价格等要点，小编为大家统一汇总，以便大家参考。混凝土路面抛丸机能够一次将混凝土表面的浮浆、杂质清理和清除干净，最重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。而且在此过程中，抛丸工艺能够充分暴露混凝土的裂', 1, 1, '创始人', 9, '/show-199.html', 0, 0, '39.96.59.7-37320', 1700807830, 1708586455, 0),
(200, 9, '         22头机载凿毛机多少钱？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401150013529.jpg', '', '什么是混凝土凿毛机？混凝土凿毛机是一种把已经完成的主体结构面进行处理，使两个施工阶段的施工面粘结牢固的类似于&quot;斩斧&quot;的工具。通常凿毛机是应用在在现浇混凝土结构中，在现浇板浇注完毕后，要凿毛，进行下一层的浇注，让混凝土粘结牢固。  豫工机械22头机载凿毛机豫工机械机载凿毛机可对任何作业面做任意角度凿毛C50混凝土凿毛深度5mm，效率120㎡/hC40混凝土凿毛深度5mm，效率150㎡/h”相较于配套', 1, 1, '创始人', 9, '/show-200.html', 0, 0, '39.96.59.7-37326', 1700807830, 1708586421, 0),
(201, 9, '         智能张拉设备不可忽视的几点        ', 'https://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325161613320.jpg', '', '智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。4、在移动设备的过程中，泵站、', 1, 1, '创始人', 9, '/show-201.html', 0, 0, '39.96.59.7-37332', 1700807831, 1700808021, 0),
(202, 9, '         什么是预应力机械？一分钟了解预应力        ', 'https://yongjiu.hnyugong.com/uploads/allimg/210325/2-21032516102b54.jpg', '', '预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和', 1, 1, '创始人', 9, '/show-202.html', 0, 0, '39.96.59.7-37338', 1700807831, 1700808031, 0),
(203, 9, '做防水，选对设备，不花冤枉钱！        ', '947', '', '防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。对于非固化设备的选购，许多人没有眉目。有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合', 1, 1, '创始人', 9, '/show-203.html', 0, 0, '39.96.59.7-37364', 1700807840, 1710572823, 0),
(204, 9, '         路面抛丸机对混凝土桥面的表面处理工艺        ', 'https://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325153231941.jpg', '', '欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保', 1, 1, '创始人', 9, '/show-204.html', 0, 0, '39.96.59.7-37374', 1700807840, 1700808002, 0),
(205, 9, '         选购喷播机时都要注意哪些内容呢？        ', 'https://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325162444b9.jpg', '', '喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路）边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。一、选择合适的型号喷播机常按不同的喷播对象分为客土喷播机和液力喷播机。合适的型号才能发挥出喷播机效用。要选择合适的型号，我们需要从两个方面考虑：1、 根据边坡类型选择', 1, 1, '创始人', 9, '/show-205.html', 0, 0, '39.96.59.7-37380', 1700807840, 1700808013, 0),
(370, 8, '豫工机械2023收官大战燃情启动', '949', '', '这里是荣誉的殿堂，这里是梦想的舞台，这里是成功的摇篮。2023年12月12日，郑州豫工机械营销中心，200多名员工齐聚一堂，共同开启豫工金秋表彰暨丰年之战启动会。金色的王冠，丰厚的奖金，奋进的感言，豫工金秋大战优秀表彰，遇见豫工 誉见自己。', 1, 1, '创始人', 9, '/show-370.html', 0, 0, '39.96.59.7-34876', 1702535439, 1710572970, 0),
(387, 8, '豫工机械端午发福利啦', '970', '', '端午将至，豫工精心准备厚厚的礼品，送给最“粽”要的人，分享快乐，共迎端午，2箱粽子，两箱水果，甜甜蜜蜜 红红火火，仪式感满满，感谢豫工对我们的厚爱。每逢传统佳节，豫工家人都能收到一份甜甜的祝福，每个人脸上绽放的笑容，是身为豫工人的幸福，并肩作战的日子，平添了更多热爱和坚守！相信这个夏天，我们拼搏的汗水，将会闪耀整个盛夏，我们奋斗的脚步，必然让豫工更出“粽”，祝福豫工越来越好 ，未来宏图大展！为答谢', 1, 1, '创始人', 9, '/show-387.html', 0, 0, '39.96.59.7-40052', 1719912084, 1719912084, 0),
(388, 8, '豫工机械19周年庆典燃爆全场', '971', '', '2024年6月20日，河南豫工机械迎来19岁生日！全体员工欢聚一堂，共同见证这一辉煌的时刻！旺春优秀表彰，总结过去 赢战未来 表彰卓越 见证辉煌！刚刚过去的旺春大战，有热情 有汗水 有鲜花 有掌声，豫工人抵住压力 拼搏向上，踏实 努力 灵动 极致，成绩突飞猛进 信心与日俱增。领奖台上王冠耀眼夺目，领奖台下掌声持久不息，炽热如初 脚步如故，每一次平凡的坚守，在这一刻有了具体的意义！年度优秀表彰，豫工', 1, 1, '创始人', 9, '/show-388.html', 0, 0, '39.96.59.7-40062', 1719912085, 1719912085, 0),
(393, 8, '豫工机械2025供应商大会盛大启幕', '1058', '供应商大会,豫工机械,公司年会', '2025年2月19日，豫工机械隆重举办以“‘豫’见未来，‘工’谱新章”为主题的2025供应商大会。这次大会，旨在为豫工机械2025年达成6亿产值提供高品质配件供应，为豫工规模化发展保驾护航。100多个核心供应商厂家，豫工全体高管，相关职能部门负责人，齐聚一堂，共同探讨当前市场环境下，如何提升品质，如何以高质量产品和服务赢得市场，共建互利互信的可持续发展供应链体系，携手开创合作发展新局面。豫工机械董', 1, 2, '豫工机械', 9, '/show-393.html', 0, 0, '123.160.242.143-56610', 1740192150, 1740193718, 0);
INSERT INTO `dr_1_xinwenguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(153, 1, 8, '&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;工作中乘风破浪，生活中多姿多彩，2023年8月18日，豫工机械2023秋季团建，三天两夜 欢乐启程。4辆豪华大巴满载我们的快乐奔赴美丽连云港，游山观海 不负时光，一起感受港城的秋天。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3161JR56.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;\r\n 打卡羊山岛，渔村情调 潮声灌耳，感谢豫工的贴心安排，让我们一起，来一场诗和远方的浪漫。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3161U3956.jpg&quot; style=&quot;width: 900px; height: 692px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3161930516.jpg&quot; style=&quot;width: 900px; height: 736px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316194E95.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n 敢问路在何方，路在脚下......，走进现实版的花果山，洞天福地 人间仙境，感受心中的桃花源。45°的侧脸很好看，45°角的石梯很难攀，加油！豫工人，相互鼓励 一路高歌，我们终将抵达顶峰。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162024J6.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316214C95.jpg&quot; style=&quot;width: 900px; height: 540px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;畅游大海的怀抱，一揽连岛风貌，体验乘风破浪的壮阔，大家一路高歌，感受激情浪漫的美好，豫工机械，感谢有你！今天被好风景收买，剩下的都是好心情，漫步细沙浅滩，亲近自然 放空心情，遇见更好的自己。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162211J6.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R316222N24.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31623504E.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;云台铺海 群山环绕，畅游海上云台山，山海美景 尽收眼底，我爱这山色，就像对生活热烈的爱！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162649414.png&quot; style=&quot;width: 900px; height: 710px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162J0F8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162GM42.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; 你笑的真好看，像春天的花一样，美丽连云港，山美 海美 人更美。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R3162500Y4.png&quot; style=&quot;width: 897px; height: 433px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31625449A.jpg&quot; style=&quot;width: 900px; height: 453px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230823/2-230R31626305K.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3天的旅游圆满结束，大家收获满满，是前所未有的欢乐，是给予彼此的信任，未来，让我们一起 继续同行。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(154, 1, 8, '&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;春余夏首 微风习习,2023.6.21,豫工机械十八周年庆典隆重开启,索菲特国际酒店 五星级会议大厅,公司总部300多人盛装出席,共同见证豫工发展高光时刻!&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GA64B08.jpg&quot; style=&quot;width: 900px; height: 476px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF152K0.png&quot; style=&quot;width: 900px; height: 459px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF135233.png&quot; style=&quot;width: 900px; height: 464px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;辉煌大厅别具匠心,签名墙精心布置,留下了豫工人自信优雅的身影!一张张喜逐颜开的笑脸,一幅幅轻松融洽的合影,让豫工人的心更牢固地粘在一起!&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF41BF.jpg&quot; style=&quot;width: 900px; height: 512px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF43N49.jpg&quot; style=&quot;width: 900px; height: 1200px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GF5204O.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;在欢快动感的舞蹈中，庆典拉开序幕,豫工人活力四射 舞力全开，上演才艺大比拼。宫廷风 民国风 劲爆风 ，甜美风 波斯风 冷酷风，每个人用自己擅长的方式，表达对豫工的热爱，庆祝豫工18岁生日快乐，穿插的抽奖游戏和奖品，让大家同享欢乐时刻。&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFI5317.jpg&quot; style=&quot;width: 900px; height: 480px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFK9639.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GFS5Y9.jpg&quot; style=&quot;width: 900px; height: 554px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;遇见豫工 遇见自己，在激昂的音乐中，开启优秀表彰环节，金色皇冠见证王者归来，耀眼奖杯镌刻拼搏的力量，经久不息的掌声，是对家人们取得成功的由衷祝贺。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG054341.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG122B5.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG142b7.jpg&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;庆典重磅环节——股东分红，公司为2022年近百名股东发放分红，并宣读股东誓词，庄严的仪式感 字字铿锵，每句话都是股东们对豫工的责任与信心，未来，相信股东们必会齐心协力，再接再励，祝愿豫工明天会更好&lt;/span&gt;。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG254139.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG30VX.jpg&quot; style=&quot;width: 900px; height: 405px;&quot;/&gt;&lt;br/&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;庆典下半场，盛夏大战火热启动，大会现场气势磅礴，豫工人以飒爽英姿 亮剑出征，敢于挑战，敢闯敢拼，各团队精神抖擞，震撼有力的大战口号，喊出了团队的士气，也喊出豫工人赢战未来的信心。&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG459536.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG5124I.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG613551.jpg&quot; style=&quot;width: 900px; height: 613px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GGG94O.jpg&quot; style=&quot;width: 900px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GGK51U.jpg&quot; style=&quot;width: 900px; height: 618px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;火热的时刻 缤纷的舞台，未来因我们而在，豫工因我更精彩，斗志在这一瞬间迸发，激情在此时此刻绽放，热血、骄傲、拼搏、奔跑，汇成豫工盛夏大战的主旋律，愿我们努力的汗水，闪耀今年整个盛夏。&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GG95IX.jpg&quot; style=&quot;width: 900px; height: 605px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH015963.jpg&quot; style=&quot;width: 900px; height: 623px;&quot;/&gt;&lt;br/&gt; &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH12E63.jpg&quot; style=&quot;width: 900px; height: 632px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;除了精美的生日蛋糕，公司还贴心安排西式晚宴，开启惬意的悠闲时光，酒杯碰在一起，是我们梦想飞翔的声音！&lt;br/&gt; &amp;nbsp; &lt;br/&gt; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GJK5960.png&quot; style=&quot;width: 956px; height: 528px;&quot;/&gt;&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230627/2-23062GH5235F.png&quot; style=&quot;width: 797px; height: 471px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;豫工机械十八载正青春！回顾过去，感谢公司高瞻远瞩，感谢全体员工奋力拼搏，感谢支持豫工的客户朋友，未来，我们将不忘初心，砥砺前行，激情、拼搏、感恩，以高品质服务共赢美好明天。&lt;/span&gt;&lt;/div&gt;'),
(155, 1, 8, '&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;伴随着恢弘的音乐，豫工人满怀信心，火热开启，2023旺春大战启动会！作为一年一度的重头戏，豫工人最重要的日子，每个人精致妆容，盛装出席，大有与三月争春的劲头，只有额头上的红头巾，写着“赢战旺春”“舍我其谁”的宣言，时刻提醒我们，这是一场时间紧、任务重的百天大战（2023.3.1-6.15）。音乐停止，国内事业部成员入场就坐，200多位豫工人齐聚一堂，火热开启，2023旺春大战启动会。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324121352354.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324121523942.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;本次大会分为三个部分，团队风采、最美传帮带、百万英雄show，满满的仪式感，鼓励大家躬身入局，以强烈的责任感 使命感，珍惜每一个客户，坚守每一份荣誉，大干100天，拿下2个亿！&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122145I4.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;董事长致辞&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;李总强调：2023，豫工人要更懂换位思考，时刻站在客户的角度思考问题，将豫工服务做成一大特色、一个标杆、一面旗帜！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122240N4.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;团队风采展示&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;各团队小伙伴，自信满满，稳操胜券，在主管激情带领下，集结完毕 整装待发，正式出征！大家现场喊出大战目标，勇敢向最优秀者发起挑战，业绩PK&amp;nbsp; 勇往直前，逼迫自己更好更强，在优秀的路上永不止步&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122452562.jpg&quot; style=&quot;width: 900px; height: 493px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122505400.jpg&quot; style=&quot;width: 900px; height: 572px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-2303241225211M.jpg&quot; style=&quot;width: 900px; height: 638px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;最美传帮带&amp;nbsp;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;人才之兴 豫工之幸，豫工传帮带，作为公司人才输送站，培养了一批又一批 一代又一代，想干事、能干事的精英强将，助力豫工更高 更强 更大的发展！传帮带的导师们无私分享工作经验，让新人少走弯路 高效成长，星火相传 成功相继，此刻！致敬豫工最美园丁&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324122644253.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;百万英雄show，自信的女生会发光，参加百万英雄挑战的小伙伴，以巾帼英姿 必胜信念，用庄重响亮的誓言，展示自己力破百万的勇气！&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324142924631.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-2303241429443A.jpg&quot; style=&quot;width: 900px; height: 575px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230324/2-230324143001X1.jpg&quot; style=&quot;width: 900px; height: 571px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:14px;width: 110%;&quot;&gt;2023的豫工，是全力拼搏者的舞台，是孕育成功者的摇篮，期待豫工人，多一份坚持 多一点热情，以昂扬奋斗的姿态 脚踏实地的干劲，去创造、去突破、去提升！&lt;/span&gt;&lt;/div&gt;'),
(156, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;font-size:16px;&quot;&gt;岁末将至，豫工机械2023新年庆典，欢乐上线。今天不谈工作，不谈业务，只谈“笑”“疯”声，红包、奖品、表彰，歌曲、小品、舞蹈，好事扎堆 快乐排队！&lt;/span&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130143U4Y6.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会现场&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;优秀员工表彰，红包不停，礼品不断，荣誉感十足 幸福感爆棚......好嗨哟，感觉人生已经达到了巅峰！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144053I4.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会现场颁奖礼&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301441495S.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会颁奖现场&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144113D9.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023年会优秀表彰&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;看！这不就是努力的意义嘛！忙有所得 耕有所获，走路带风 眼神坚定，每根头发都散发着自信的光芒，内心富足 自律自强，有所忙有所爱有所期待！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013014425a24.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会优秀新人奖&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-2301301443262P.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会优秀进步奖&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;才艺展示环节，角色反转，曾经的职场精英，化身才艺明星，说、演、唱、跳，上演豫工达人秀，爆笑逗乐 嗨翻全场，欢欢喜喜迎新年！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144449338.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013014450S39.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144531J5.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会才艺展示&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;活动现场，歌声与鼓声共振，笑声与掌声齐飞，酣畅淋漓 开心尽兴！&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144645Q8.jpg&quot; style=&quot;width: 900px; height: 570px;&quot; title=&quot;豫工机械2023年会活动现场&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144J6222.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023年会活动现场&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130144FQb.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023新年庆典&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2022带着我们的热爱走进历史，我与旧事归于尽，来年依旧迎花开，感恩一路同行的小伙伴们，2023制胜之年，归零 更新 重启 向上，让我们继续加油！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130145022554.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械2023新年庆典&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(157, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2023迎好运，启新章！开工红包惊喜派发中......&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130162549B0.png&quot; style=&quot;width: 676px; height: 490px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;公司董事长李总来到国内事业部和国际事业部，为员工一 一发放开工红包，666的大红包，寓意开工大吉，诸事顺利。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130162HEV.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械董事长为员工发放红包&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130162JB28.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;豫工机械董事长为员工发放红包&quot;/&gt;&lt;br/&gt;\r\n 在一声声“新年好”“恭喜发财”的道贺声中，豫工人精神抖擞回到工作岗位，开心地从李总手里接过祝福红包，大大的红包，是豫工对员工一如既往的关爱。此刻，大家元气满满，再启征程！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130163140613.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023开工红包发放中&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013016315R52.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023开工红包发放中&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-230130163215406.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023开工红包发放中&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/230130/2-23013016322WT.jpg&quot; style=&quot;width: 900px; height: 900px;&quot; title=&quot;2023开工红包发放中&quot;/&gt;&lt;/div&gt;&lt;div&gt;2023致胜之年，豫工人卯足干劲，大展宏“兔”，一起加油‼冲冲冲。&lt;/div&gt;&lt;p&gt;河南豫工机械是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(158, 1, 8, '&lt;div&gt;秋高气爽、云开疫散，豫工机械全面复工复产，红包不断，为员工发放高额生活补贴，首批8万元复工红包已发放完毕。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94A2T8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94I5217.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94KM27.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94R5142.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P94SS15.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n 适逢豫工金秋大战，叠加双11嗨购节，您的VIP专属红包已备好，超级钜惠，重磅加码，感谢广大新老客户一直以来的信任和支持，诚心相邀“，郑”等您来。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221108/2-22110P95402428.jpg&quot; style=&quot;width: 900px; height: 649px;&quot;/&gt;&lt;br/&gt;\r\n 河南豫工机械是国内工程设备生产基地，拥有18年服务经验，公司规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;'),
(159, 1, 8, '&lt;div&gt;生活不止眼前的工作，还有静下来的诗意和远方，2022年8月13日，伴着动感的音乐，踏着欢快的节拍，豫工机械2022主题团建第一趴，快乐出发！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142052637.jpg&quot; style=&quot;width: 800px; height: 599px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;感谢公司的贴心安排，本次团建以部门为单位，自主规划活动路线，漂流、爬山、温泉、轰趴、划船......各赴人间惊鸿宴，一睹人间盛世颜！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142204911.jpg&quot; style=&quot;width: 800px; height: 599px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142231345.jpg&quot; style=&quot;width: 800px; height: 410px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101442405G.jpg&quot; style=&quot;width: 800px; height: 361px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-22101014430CE.jpg&quot; style=&quot;width: 800px; height: 1730px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;打卡云上牧场，感受风的温柔，体验花的浪漫，听蝉鸣鸟叫，看蝴蝶纷飞，再和天空来一张合作！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010142400236.jpg&quot; style=&quot;width: 800px; height: 802px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010143912603.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;生活中可能遇到的小情绪，在这天地间晒一晒，就好了，为明天的工作重拾心情，归来的我们，依旧元气满满。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-22101014410D43.jpg&quot; style=&quot;width: 800px; height: 1066px;&quot;/&gt;&lt;br/&gt;&lt;div&gt;选择自驾游的小伙伴，吃喝玩乐更加随性，春风十里，不如美食有你，今天的减肥事业，可以暂时放一放了，分享美食，快乐第一！&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010144213Z8.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-2210101443255O.jpg&quot; style=&quot;width: 800px; height: 1730px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;工作中乘风破浪，团建时激情绽放，打卡宝泉的小伙伴们，追逐清凉，趣味横生，在山水间撒个欢儿！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221010/2-221010144440D9.jpg&quot; style=&quot;width: 800px; height: 600px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;快乐的时光，小伙伴们乐在其中，增加了团队默契度，让大家彼此了解 并肩携手 ，一起创造豫工更好的明天！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(160, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 美好恰逢其时，生活与“粽”不同，端午如期而至，豫工的福利也一如往昔，丰厚 健康 贴心！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91030R6.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q9104O39.jpg&quot; style=&quot;width: 900px; height: 428px;&quot;/&gt;&lt;br/&gt;两箱粽子，一箱火龙果，一箱哈蜜瓜，沉甸甸的感觉，像极了豫工对家人的关爱，感谢大家为公司发展的辛勤付出！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91130595.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;因为有你，所以出粽，2022是不平凡的一年，因为大家的不懈努力，豫工在充满机遇与挑战的市场竞争中，逆势而来 强势崛起！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91224N1.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q9123Q35.jpg&quot; style=&quot;width: 900px; height: 451px;&quot;/&gt;&lt;br/&gt;一粽传情，浓情端午，一盒盒精致的端午礼品，承载了公司对大家满满的关怀，代表着公司对全体员工的真挚祝福，感谢公司每个节日的恩宠，很幸运在最美的年华相聚于此，一起奋斗一起成长！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91323R6.jpg&quot; style=&quot;width: 900px; height: 578px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100Q91334948.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;春风有信，花开有期，所有的美好都已经在路上了，值此端午佳节，豫工机械恭祝新老客户朋友，事业顺利 阖家幸福，粽享幸福 端午安康！\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(161, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年6月18日 中都大酒店，豫工机械17周年庆典暨第二届女神节隆重举行，总部营销中心300多人参加活动，现场星光璀璨 精彩纷呈！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QTQY23.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;董事长开幕式致辞&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;李总表示：豫工17年高速发展与科学的规划密不可分，立足长远，计划落地。未来，公司还要继续练内功，强本领，做规划！做精、做深、做强主营业务，为客户提供不可替代的服务和价值!&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QTZcB.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;2022旺春大战颁奖典礼&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;柔肩担重任&amp;nbsp; 巾帼绽芳华，旺春大战期间，豫工人执着于未来，奋斗于脚下，他们始于热爱，终于丰盈，立一个目标，守一份初心，今天他们是最亮的星，全力以赴，满载而归。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU14I53.jpg&quot; style=&quot;width: 900px; height: 544px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU202631.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU245N2.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;&lt;strong&gt;总经理总结致辞&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;国内事业部侯总和国际事业部赵总为本次颁奖环节总结致辞，回顾公司17年发展成果，侯总表示：豫工从桥梁设备生产起步，到形成八大产品系列，一百多款产品的庞大规模，用了17年！目前，豫工进入迅猛爆发期，生产总值连续5年持续翻番，客户遍布全球一百多个国家和地区，多款产品在国家大批重点建设项目中被广泛采用！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU319133.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;2022年度股东分红,不忘初心,方得始终,在公司领导的英明领导下,豫工人用务实浇灌硕果，用初心赢得绽放,取得丰硕成果!&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU41X04.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;2022盛夏大战启动仪式&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;梦想不设限 人生无极限，17年豫工正青春，引进新技术 吸纳新人才 规划新未来朝气蓬勃、积极向上 ，2022新征程&amp;nbsp; 亦有新发展。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU5302J.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU545P1.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QU610413.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;strong&gt;2022第二届女神节&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;文艺表演高潮迭起，载歌载舞展现豪情壮志，畅想未来图景，豫工人总是这样多才多艺，既有脚踏实地的努力，也有仰望星空的诗意，心如花木 向阳而生！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUGUG.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUHb32.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QUJQ25.jpg&quot; style=&quot;width: 900px; height: 483px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;时光奔流不息，初心历久弥坚，我们真诚期待，豫工未来波澜壮阔 绚丽多彩我们心怀感恩，诚邀广大客户朋友一起奋进新未来，逐梦星辰大海，成就互惠共赢！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(162, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS103295.jpg&quot; style=&quot;width: 900px; height: 381px;&quot;/&gt;&lt;br/&gt;“99公益日”来临，豫工机械作为常年热心公益的爱心企业，特发起2022年度“99公益日”助力“困境儿童守护计划”公益募捐活动，携手助童 共护成长。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS133351.png&quot; style=&quot;width: 900px; height: 552px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS151222.png&quot; style=&quot;width: 900px; height: 570px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS204496.jpg&quot; style=&quot;width: 900px; height: 497px;&quot;/&gt;&lt;br/&gt;即日起至9月9日，您的每一笔捐款，豫工机械将进行1：1金额的“陪捐”！也就是你捐多少，我公司会“陪捐”多少！“薅羊毛”式捐赠，为爱加油！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS24M13.jpg&quot; style=&quot;width: 900px; height: 500px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;积小善，成大爱&lt;/strong&gt;&lt;br/&gt;\r\n 捐助10元，可以帮助一个孩子解决一天的生活补助；&lt;br/&gt;\r\n 捐助20元，可以帮助孩子买一本课外书；&lt;br/&gt;\r\n 捐助100元，可以资助一名特困孩子1个月生活费；&lt;br/&gt;\r\n 捐助500元，可以帮助她们买够一学年的学习用品；&lt;br/&gt;\r\n 捐助1000元，可以捐助特困孩子一年的生活费&amp;nbsp;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS404324.png&quot; style=&quot;width: 900px; height: 569px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;希望您也能加入我们,让我们的队伍越来越强大，让更多困境儿童获益！&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;strong&gt;募捐活动时间&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;2022.9.7-9.9&lt;/div&gt;&lt;div&gt;&lt;strong&gt;获取配捐&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;腾讯基金会将拿出3亿元，向所有参与99公益日的公益项目进行配捐，每人每天配捐总额最高可达999元。&lt;/div&gt;&lt;div&gt;同时，豫工机械将对参与“困境儿童守护计划”的善款进行1：1的“陪捐”。&lt;/div&gt;&lt;div&gt;&lt;strong&gt;参与方式&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;（1）长按图片识别二维码；&lt;/div&gt;&lt;div&gt;（2）自定义或者选择捐款金额；&lt;/div&gt;&lt;div&gt;（3）点击确定，完成捐赠；&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QS524420.png&quot; style=&quot;width: 684px; height: 955px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;一起做好事&amp;nbsp; 让爱加倍，一份份捐助，一份份爱心，可以帮助困境中的孩子快乐成长，各位爱心人士可以在微信群、朋友圈 、发动家人、朋友一起捐，一起为爱翻倍，为爱加油！&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000cd;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(163, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 中秋节发福利了！红红火火的包装，至诚至爱的心意，节礼在手，温暖在心，感谢公司一如既往的厚爱！&lt;/p&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPG4N2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n 作为国人重要的传统佳节，每年中秋，公司都会精心准备节日贺礼，感谢大家一年来的努力与付出，希望每一位员工都能与家人，阖家团圆，把酒言欢，满满的仪式感，引来隔壁公司羡慕的眼光。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPRB91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QPT6225.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;/&gt;&lt;br/&gt;\r\n 心怀感恩 所遇皆温柔，公司满满的关爱，不仅让豫工人找到归属感，也让背后的家庭对豫工好感度俱增，多年工作下来，他们都成了最合格的豫工家属！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QP94G45.jpg&quot; style=&quot;width: 900px; height: 542px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QQ00R91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n 每逢生产旺季 客户来访，他们总是主动担待，让豫工人有更多精力苛求细节 圆满服务，因为他们的全力支持，豫工人有更多时间研发生产 优化产品，赢得一个又一个客户的信赖。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QQ303T8.jpg&quot; style=&quot;width: 900px; height: 505px;&quot;/&gt;&lt;br/&gt;\r\n 在这花好月圆的欢庆时刻，在这金九银十的施工旺季，我们特意为全国客户朋友准备了大大的中秋福利，满满的诚意，礼到、心到、实惠到！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QQ425158.jpg&quot; style=&quot;width: 900px; height: 370px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;9月8日-9月10日，豫工将送出30万中秋购机消费券，大到几十万的生产线，小到几百块的配件均可适用，爆款福利 限时派送 ，赶快联系你的业务经理领取吧！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(164, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年9月14日，豫工机械营销总部，金秋大战在国内事业部率先启动，近200名员工斗志昂扬，众志成城，正式打响金九银十决胜战！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI302X8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI222953.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI324337.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;总结过去，赢战未来，表彰卓越，见证辉煌&lt;br/&gt;&lt;/p&gt;&lt;div&gt;在热烈的掌声中，优秀代表纷纷登台，荣誉和鲜花，是对他们最大的鼓舞和肯定。&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI609157.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); font-family: system-ui, -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 0.544px; text-align: justify; background-color: rgba(246, 212, 218, 0.58);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QI645949.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;在金九银十关键节点，豫工机械金秋大战也如期而至，作为公司2022年51工程（2022年销售额突破5个亿）的关键一战，本次启动会既要制定目标、分解过程，更要为营销团队蓄势蓄力，增强信心！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIIX33.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIK9209.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QIQ5T2.jpg&quot; style=&quot;width: 900px; height: 703px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;启动会上，每个人都制定可行的金秋目标，分解目标，规划过程，最大程度保证方案的可行性，一鼓作气，赢战“51”！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKAW58.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKG4559.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;在团队主管的带领下，各部门纷纷签署金秋军令状，立下铿锵雄心，军令如山，一往无前，巅峰对决，闪耀金秋。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKQ5420.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/221008/2-22100QKS23B.jpg&quot; style=&quot;width: 900px; height: 551px;&quot;/&gt;&lt;br/&gt;战鼓声声，催人奋进，在公司各部门的大力支持下，营销中心全体人员枕戈待旦、鼓足干劲，金秋之战，志在必胜！豫工小伙伴，加油！\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(165, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年2月22日，豫工机械“如虎添亿，奋战51”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工200多人参加此次活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105116348.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-2204191051314T.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;2021，在豫工人的共同努力下，公司全年销售总额再破3亿元大关，品牌知名度、市场接受度、老客户返单率、生产总值、团队业绩再创新高。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105220O3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;期间，公司涌现出了众多业绩精英、营销达人、优秀团队、百万英雄。她们8小时内求生存，8小时外求发展，每一天、每一分钟，都在为成功全力以赴！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910530S45.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;3月，工程建设进入施工旺季，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号（3.1-5.31），各个部门与客户同频，大干100天，打好开局战。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105345Y3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;启动会上，豫工小伙伴胸有成竹梳理旺春目标，毫无保留分享工作方法，争取在接下来的100天，紧盯目标，协同向前，不达目的，绝不收兵。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105432b2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105444K3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105500934.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;有人说你相信什么，就会吸引什么！&lt;/div&gt;&lt;div&gt;公司股东作为豫工的中流砥柱，纷纷签订绩效责任承诺书，不畏艰难，身先士卒，同心协力，共战51！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105541391.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;戮力同心，勇于担当是我们的态度，团结协作、相互帮扶是我们的法宝&lt;/div&gt;&lt;div&gt;百天旺春，时间紧任务重，每一个豫工人都要同心协力，互助帮扶！心中无敌，奋战“51”！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105620Q5.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419105AMC.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;董事长赋能&amp;nbsp;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;作为公司的掌舵人，豫工的精神支柱，李总表示：2022，豫工的主旋律就一个字“干”，干他个虎虎生威，干他个红红火火。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419110415237.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;br/&gt;\r\n “豫工十六年发展，吸引越来越多的优秀人才加入这个大家庭，终成今日盛势！2022，豫工人还要继续互帮互助，团结协作，推动豫工这艘航船扬帆远航，再创辉煌！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419110523B8.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(166, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103610J7.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车发车现场&quot;/&gt;&lt;br/&gt;它们将用于中铁隧道局宜兴铁路ZQ-3标隧道喷浆支护项目。作为3月的第49、50台喷浆支护系列设备，它的成功发车，意味着豫工机械喷浆支护设备3月销量再创新高。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103645J2.jpg&quot; style=&quot;width: 900px; height: 405px;&quot; title=&quot;湿喷台车服务项目&quot;/&gt;&lt;br/&gt;这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程度高，遥控操作，全自动喷浆无盲区，广泛应用于高铁、隧道、边坡、地铁、基坑等喷浆支护项目。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103I3547.jpg&quot; style=&quot;width: 900px; height: 674px;&quot; title=&quot;湿喷台车生产现场&quot;/&gt;&lt;br/&gt;据豫工机械研发部门陈主任介绍，该款湿喷台车的机械臂、泵送系统、液压系统、电器系统等关键零部件优选知名品牌。机、电、液一体化控制系统，实现对发动机、液压系统、工作状态的检测和保护，保证设备的高可靠性。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103Q3140.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车调试现场&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;施工现场，操作人员使用无线遥控进行喷射作业，远离作业面，不仅操作方便，更增加了工人的安全性。&lt;/div&gt;&lt;div&gt;客户对设备高效的生产能力很满意，表示：根据工程需要，下次再上一台。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419103913G1.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;湿喷台车施工现场&quot;/&gt;&lt;br/&gt;\r\n 豫工机械作为17年喷浆支护设备生产厂家，型号齐全、品类完善，液压湿喷机、混凝土喷浆车，钢筋网片排焊机等设备深受欢迎，一站式采购，降低生产成本，提升施工效率！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104024U2.jpg&quot; style=&quot;width: 900px; height: 600px;&quot; title=&quot;液压湿喷机仓库&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910403R96.jpg&quot; style=&quot;width: 900px; height: 599px;&quot; title=&quot;喷浆支护设备仓库&quot;/&gt;&lt;br/&gt;\r\n 其实，豫工喷浆支护设备一直以“高效稳定”享誉市场，在高铁、地铁、隧道领域，发挥着举足轻重的作用，被国家大批重点建设项目广泛采用，累计服务工程项目30000+！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-22041910414V56.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104201Y2.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104211547.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220419/2-220419104230142.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;'),
(167, 1, 8, '&lt;div&gt;神州大地，举国欢庆！&lt;/div&gt;&lt;div&gt;山河壮丽，岁月峥嵘！&lt;/div&gt;&lt;div&gt;江山不老，祖国常青！&lt;/div&gt;&lt;div&gt;豫工机械祝福我们的祖国繁荣昌盛&lt;/div&gt;&lt;div&gt;十一国庆节来了，根据国家放假规定，结合公司实际情况，河南豫工机械有限公司2021年国庆放假安排如下：&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210930/2-210930151Ib36.jpg&quot; style=&quot;width: 850px; height: 1275px;&quot;/&gt;&lt;br/&gt;\r\n &lt;strong&gt;&lt;span style=&quot;color:#ff0000;&quot;&gt;注意事项&lt;/span&gt;&lt;/strong&gt;&lt;br/&gt;\r\n &lt;div&gt;1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;div&gt;3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(168, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年9月11日，豫工机械“2021金秋大战暨旺春优秀表彰” 燃情启动，郑州总部营销中心，全体员工180多人参加活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916104T33V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部活动现场&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916104ZO24.png&quot; style=&quot;width: 695px; height: 813px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部活动现场&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610500T94.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;旺春大战优秀表彰&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;2个月前，公司旺春大战圆满收官，诞生了许多业绩标兵、百万英雄、服务之星、优秀团队，今天是见证荣誉的时刻！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105423545.jpg&quot; style=&quot;width: 695px; height: 546px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div style=&quot;text-align: center;&quot;&gt;国内事业部旺春英雄奖&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105440121.jpg&quot; style=&quot;width: 695px; height: 474px;&quot;/&gt;\r\n &lt;div style=&quot;text-align: center;&quot;&gt;国内事业部捷报奖&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105614H5.jpg&quot; style=&quot;width: 695px; height: 739px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春英雄奖&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105630b7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春达人奖&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916105HK63.jpg&quot; style=&quot;width: 695px; height: 528px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部旺春捷报奖&lt;/div&gt;&lt;div&gt;&lt;strong&gt;优秀个人表彰&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;在豫工，从不缺工作上的拼命三郎，他们拼搏进取 所向披靡，他们是当之无愧的业务精英，是豫工人应该崇拜的旺春英雄！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161JGXM.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;国内事业部佳个人进步奖&lt;/span&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916110249236.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;/div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部佳个人进步奖&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;strong&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916110441H0.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;strong&gt;百万英雄表彰&lt;/strong&gt;&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;每一个不起眼的日子，都是逆风翻盘的机会，深夜办公室的灯火通明，陪伴豫工人日复一日的坚持，见证一个又一个百万大单的诞生！&lt;/div&gt;&lt;div style=&quot;text-align: left;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161110101F.jpg&quot; style=&quot;width: 695px; height: 537px;&quot;/&gt;&lt;br/&gt;\r\n &lt;strong&gt;金秋大战燃情启动&lt;/strong&gt;\r\n &lt;div&gt;金九银十，豫工人吹响金秋大战（9月15日-11月15日）集结号，各种促销政策感恩回馈，全员60天无休无假，及时发货，专业售后，为客户工程保驾护航！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611123E64.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111301G7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111325Y8.jpg&quot; style=&quot;width: 695px; height: 538px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111336309.jpg&quot; style=&quot;width: 695px; height: 541px;&quot;/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部团队风采&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611151N02.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611152R61.jpg&quot; style=&quot;width: 695px; height: 473px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111604527.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611162E59.jpg&quot; style=&quot;width: 695px; height: 487px;&quot;/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;国际事业部团队风采&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;奋斗不止的“军令状”&lt;/div&gt;&lt;div&gt;军令如山 使命必达！启动会上，各团队用热血誓言签下军令状，不找理由、不找借口，创新突破，勇于担当，全力以赴，目标必达！&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111QX07.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111SB03.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916111UH34.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div style=&quot;text-align: center;&quot;&gt;国内事业部员工风采&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611193M58.jpg&quot; style=&quot;width: 695px; height: 756px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611195Hb.jpg&quot; style=&quot;width: 695px; height: 769px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112010546.jpg&quot; style=&quot;width: 695px; height: 502px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;div style=&quot;text-align: center;&quot;&gt;国际事业部员工风采&lt;/div&gt;&lt;div&gt;&lt;strong&gt;实实在在豫工人&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;踏实独立，热爱上进，豫工女孩既爱红装也爱戎装，生活中追求仪式感，该努力时也绝不含糊，全力以赴，活出自己的色彩！&lt;/div&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112149E9.jpg&quot; style=&quot;width: 695px; height: 530px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091611215aD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916112215230.jpg&quot; style=&quot;width: 695px; height: 815px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161122251X.jpg&quot; style=&quot;width: 695px; height: 661px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;大好时光，奋斗正当时&lt;/div&gt;&lt;div&gt;豫工人天生勤奋、实干、永不服输&lt;/div&gt;&lt;div&gt;不抛弃不放弃，言出必行，使命必达&lt;/div&gt;&lt;div&gt;2021金秋大战&lt;/div&gt;&lt;div&gt;小伙伴们，加油！！！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(169, 1, 8, '&lt;div&gt;金秋九月，花好月圆，又是一年中秋时！&lt;/div&gt;&lt;div&gt;河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：&lt;br/&gt;\r\n &lt;br/&gt;\r\n &lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;&lt;strong&gt;放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916145453Q6.gif&quot; style=&quot;width: 640px; height: 440px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;background-color:#ffff00;&quot;&gt;温馨提示&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;div&gt;&lt;div&gt;1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;/div&gt;&lt;div&gt;3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;月圆人团圆&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;中秋合家欢&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;豫工机械恭祝新老客户朋友财源滚滚、事业顺利、阖家幸福、中秋安康！&lt;/span&gt;&lt;/strong&gt;&lt;br/&gt;\r\n &lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;'),
(170, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610215A62.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610221A35.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!&lt;br/&gt;&lt;strong&gt;7月抗汛,赈灾义卖,!筹款30万捐向灾区&lt;/strong&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-21091610345M33.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103512c7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103529218.jpg&quot; style=&quot;width: 695px; height: 312px;&quot;/&gt;&lt;br/&gt;&lt;strong&gt;8月抗疫，涝疫补贴,每人500元&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103J3A6.jpg&quot; style=&quot;width: 695px; height: 428px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103Q1R7.jpg&quot; style=&quot;width: 695px; height: 445px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-210916103S13A.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;/strong&gt;&lt;br/&gt;中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼，豫工人也吹响金秋大战（9月15日-11月15日）集结号，各种促销感恩让利，全体员工60天无休无假，及时发货，专业售后，为您的工程保驾护航。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210916/2-2109161042243V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;花好月圆，天涯共此良辰，豫工机械恭祝新老客户朋友，财源滚滚、事业顺利，家庭美满、中秋安康！&lt;br/&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械有限公司&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(171, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G0123D.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G033534.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G04M16.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G103H4.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G11RU.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G132129.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(172, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/210730/2-210I01G4319B.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G4463H.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G45H50.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G510N4.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G53bb.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G555950.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G606393.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G61L18.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GF2928.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GHT01.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GQ0R1.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GS4517.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GT4910.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GU5362.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01GZJX.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G924329.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01G93H11.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;h2 class=&quot;rich_media_title&quot; id=&quot;activity-name&quot; style=&quot;margin: 0px 0px 14px; padding: 0px; font-size: 22px; line-height: 1.4; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); text-decoration-line: none; font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/h2&gt;'),
(173, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;7月23日，河南豫工机械有限公司通过郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164G2436.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164H6492.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164R6355.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164Q31S.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;董事长李红旗先生第一时间捐款12万元用于抗洪救灾，并带领公司全体员工连续三天开展赈灾义卖，筹集救灾善款30余万元。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I0164U4624.jpg&quot; style=&quot;width: 695px; height: 1042px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;李总表示：尽管我们也受灾，厂区被淹，但在大是大非，大灾大难面前，我们还应当义不容辞地腾出余力，自救的同时，向同胞伸出援手，这是企业价值所在，也是企业回馈社会、反哺社会的责任所在，必须履行好。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I016493YE.jpg&quot; style=&quot;width: 695px; height: 584px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I016494X18.jpg&quot; style=&quot;width: 695px; height: 452px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;企业有担当 社会有能量！只要国家、社会有需要，豫工机械一定义不容辞，不忘初心，勇担使命，传递正能量！就如这次“720特大暴雨洪灾”，我们一定尽心竭力，自救救人，与灾区人民风“豫”同舟！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A113139.jpg&quot; style=&quot;width: 695px; height: 313px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A135291.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A212Z1.jpg&quot; style=&quot;width: 695px; height: 419px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;三天义卖结束后，全体员工同事一致意愿把每年的7月20日，设为公司的爱心慈善日（720爱心慈善日），成立专款专用的爱心慈善基金，每年720当天义卖 所得善款全部注入爱心慈善专项基金，用于慈善事业和爱心捐助。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210730/2-210I01A32X61.jpg&quot; style=&quot;width: 696px; height: 666px;&quot;/&gt;&lt;/span&gt;&lt;/p&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/div&gt;'),
(174, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611145944c8.jpg&quot; style=&quot;width: 695px; height: 1175px;&quot;/&gt;&lt;br/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;&lt;div&gt;根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：&lt;/div&gt;&lt;div&gt;1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。&lt;/div&gt;&lt;div&gt;2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;div&gt;祝愿大家过一个安全、惬意、有意义的端午节！&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;'),
(175, 1, 8, '&lt;div&gt;端午来啦！&lt;/div&gt;&lt;div&gt;老板实力宠员工&lt;/div&gt;&lt;div&gt;&lt;div&gt;2盒粽子，2箱水果&lt;/div&gt;&lt;div&gt;啧啧......豪横，果然是中国好老板！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111434414Z.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;丰厚的节日福利&lt;/div&gt;&lt;div&gt;是公司对中国文化的传承&lt;/div&gt;&lt;div&gt;更体现了对豫工家人细致入微的关怀&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143545919.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111436032W.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143F4611.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;其实，每逢传统佳节&lt;/div&gt;&lt;div&gt;公司都会为客户朋友和豫工家人精心准备节日贺礼&lt;/div&gt;&lt;div&gt;这个习惯，豫工一干就是16年！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143K4933.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143PSA.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143RDW.jpg&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;福利发放现场，&lt;/div&gt;&lt;div&gt;欢声笑语！&lt;/div&gt;&lt;div&gt;大家暂时放下手中繁忙的工作，&lt;/div&gt;&lt;div&gt;聚在一起，享受节日的快乐！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611143ZR25.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111439463V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-2106111439593L.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144029260.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144055K8.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;国内事业部员工风采&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144120103.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144136439.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144149318.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144200196.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;国际事业部员工风采&lt;br/&gt;今年端午，赶上公司16周年庆典 为回馈新老客户的关爱 老板特批优惠方案 推出年中大促活动（2021年6月6日-6月30日） 价格一降到底，还有定金翻倍抵货款 买的多，更省钱。 &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210611/2-210611144310146.jpg&quot; style=&quot;width: 695px; height: 350px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;心如糯米，越粘越紧，&lt;/div&gt;&lt;div&gt;情似粽叶，越煮越香。&lt;/div&gt;&lt;div&gt;端午佳节&lt;/div&gt;&lt;div&gt;我们向长期信任和支持豫工的客户朋友送上真诚的节日祝福&lt;/div&gt;&lt;div&gt;恭祝大家：事业顺利，生活安康，“粽”享幸福，端午安康！&lt;/div&gt;&lt;p&gt;&lt;br style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;/&gt;&lt;strong style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px; line-height: 32px; text-indent: 32px; display: inline-block; color: rgb(85, 85, 85);&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(176, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年5月21日，郑州禧逸酒店会议大厅，&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145129295.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052514514K22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;生日趴&lt;/div&gt;&lt;div&gt;在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145505a7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145532F2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145550E4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;迎新环节&lt;/div&gt;&lt;div&gt;16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！&lt;/div&gt;&lt;div&gt;公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家快速成长，融入团队。&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525145I11X.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515004R20.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;年度职级晋升&amp;nbsp;&lt;/div&gt;&lt;div&gt;迎光奔跑，保持热爱，每一个认真努力的现在，都有一个水到渠成的未来！&lt;/div&gt;&lt;div&gt;本次年度职级晋升表彰，让我们再次见证努力的意义！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251501563B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251502452a.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;2020年度表彰&lt;/div&gt;&lt;div&gt;知足上进，不负野心，各自努力，顶峰相见！&lt;/div&gt;&lt;div&gt;2020年度内外贸业绩冠军、亚军、季军表彰，高手过招，风景这边独好！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150510133.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251505325P.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;“积极向上，热爱生活，找差距，强弱项，认真对待每一件事，定有收获”&lt;/div&gt;&lt;div&gt;2020豫工年度销冠——国内事业部魏红岩、国际事业部刘建华分享工作方法，鼓励大家保持热爱，厚积薄发。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251506312B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150A2324.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;优秀团队表彰&lt;/div&gt;&lt;div&gt;有人说：千人同心，则得万人之力；万人异心，则无一人可用！&lt;/div&gt;&lt;div&gt;豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525150JKP.jpg&quot; style=&quot;width: 695px; height: 480px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515092S43.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151011624.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;百万英雄表彰&lt;/div&gt;&lt;div&gt;2020精彩纷呈，豫工人凭借历久弥坚的决心，勇闯百万的勇气，涌现出许多百万业绩精英!&lt;/div&gt;&lt;div&gt;今天是他们的高光时刻！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515111YR.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251511391G.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;优秀运营表彰&amp;nbsp;&lt;/div&gt;&lt;div&gt;成绩的取得，离不开市场人员辛勤付出，是他们凭借敏锐的市场感知力，深挖客户需求，助力研发部门优化设备功能，推出切实符合工程需求的设备！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151505458.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151520R3.jpg&quot; style=&quot;width: 695px; height: 383px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525151P9411.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;十大领军人物表彰&lt;/div&gt;&lt;div&gt;航海千里，成于罗盘！在公司有这么一群人，他们肩挑领跑者的责任，心怀冲锋者的闯劲，勤勉务实，敢为人先，他们是业务团队的领头羊！他们是豫工机械业务团队的领军者。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152004441.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152325135.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;明日之星表彰&lt;/div&gt;&lt;div&gt;2021，豫工涌现出了一批执行力超强的业务精英，他们的成绩有目共睹，工作中不讲如果，只讲结果！步履不停，奋斗不止，终于成长为公司的业绩担当，荣获豫工机械明日之星称号。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152503244.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152605205.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;未来之星表彰&lt;/div&gt;&lt;div&gt;奋斗的路上，没有奇迹，只有努力的轨迹；没有运气，只有坚持的勇气，每一滴汗水都是成功的积累！&lt;/div&gt;&lt;div&gt;2021，豫工很多小伙伴在工作中展现巨大爆发力，目标坚定，温柔上进，持续努力，未来可期，喜获未来之星荣誉称号！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515292G45.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525152944V5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;优秀表彰致辞&lt;/div&gt;&lt;div&gt;“分享、担当、感恩、自信、坚毅”，豫工总经理为活动致辞 ，再次分享公司企业文化，揭秘豫工机械16年保持高速发展的能量源泉！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153111320.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;风雨同舟者赢，上下同欲者胜&lt;/div&gt;&lt;div&gt;有人说你相信什么，就会吸引什么！你怀疑什么，就会失去什么，这就是相信的力量，这就是成功的秘籍！&lt;/div&gt;&lt;div&gt;年度股东分红，让我们再次见证相信的力量！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515324C15.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153300J3.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;豫工十六年发展，终成今日势，跨越式发展步伐，吸引众多优秀员工成为股东，风雨同舟，荣辱与共，推动豫工这艘航船稳步向前，再创新高！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515340J40.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153431Y9.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;女神篇&lt;/div&gt;&lt;div&gt;恰逢521全民表白日,豫工机械特设第一届女神节，鼓励大家怀揣公主梦，装着女王心，&lt;/div&gt;&lt;div&gt;勇敢展现自己的美，独立、优雅、自信、坚韧、洒脱、有底气、做自己，不负时光，活得漂亮！&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515353U03.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153552L6.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-21052515360S18.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251536203H.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-2105251536339A.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153Q3a5.jpg&quot; style=&quot;width: 695px; height: 451px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153P1V6.jpg&quot; style=&quot;width: 695px; height: 434px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210525/2-210525153RR22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;/&gt;&lt;br/&gt;\r\n 无论是女王节还是女神节，往后余生，祝愿豫工这群可爱且善良的女生，眼中有光，心中有爱，温柔中带着刚强，努力优秀，大方拥有，有所为，有所爱，有所期待！&lt;br/&gt;\r\n &lt;strong style=&quot;font-family: &amp;quot;microsoft yahei&amp;quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=&quot;color: rgb(85, 85, 85); font-family: &amp;quot;microsoft yahei&amp;quot;; font-size: 16px; text-indent: 32px;&quot;&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;'),
(177, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-210430145242945.png&quot; style=&quot;width: 695px; height: 295px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。&lt;br/&gt;&lt;/p&gt;&lt;div&gt;在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！&lt;/div&gt;&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210430/2-2104301453111a.jpg&quot; style=&quot;width: 695px; height: 1123px;&quot;/&gt;&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;&lt;div&gt;&lt;div&gt;根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：&lt;/div&gt;&lt;div&gt;1、2021年劳动节放假共3天，时间为2021年5月1日至5月3日，5月4日（星期二）正常上班。&lt;/div&gt;&lt;div&gt;2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;&lt;div&gt;3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;&lt;/div&gt;&lt;div&gt;祝愿大家过一个安全、惬意、有意义的劳动节！&lt;br/&gt;\r\n 　　&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;'),
(178, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-2105051111315F.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505111505c0.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505111515c3.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050511262HY.png&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-210505112F2928.png&quot; style=&quot;width: 695px; height: 395px;&quot;/&gt; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210505/2-21050511264T06.png&quot; style=&quot;width: 695px; height: 396px;&quot;/&gt;&lt;br/&gt;客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br/&gt;&lt;strong&gt;&lt;span style=&quot;font-size:14px;text-indent:0;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;拥有16年隧道喷浆设备研发生产经验，匠心质造，品质如一！规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(179, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113S1254.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;迎新环节&lt;/div&gt;&lt;div&gt;虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113TR63.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。&lt;br/&gt;\r\n 大战期间，豫工涌现出了许多业绩标兵，百万英雄，服务之星，优秀团队。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113U9143.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113913W8.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406113925592.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611395a28.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 有人说：千人同心，则得万人之力；万人异心，则无一人可用！豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611401Q94.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114039537.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040611405Q18.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114114634.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114154R1.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406114222230.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;/&gt;&lt;br/&gt;\r\n 一分耕耘未必有一分收获，但是九分耕耘，必定会有一分收获。金秋大战期间，小伙伴们用实际行动证明了，这世间，唯有努力和坚持不可被辜负。&lt;br/&gt;\r\n &amp;nbsp;&lt;/div&gt;'),
(180, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9202D57.png&quot;/&gt;&lt;br/&gt;豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F92049128.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9211T46.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F92132129.png&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F923212I.png&quot;/&gt;&lt;br/&gt;端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟邪消灾，平安健康！祝愿祖国繁荣昌盛，国泰民安！&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(181, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406115911564.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;/&gt;&lt;br/&gt;福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120013401.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120034I8.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040612004TB.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120102Q2.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061201224D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120135332.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120155449.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120229512.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120244545.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061203113D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406120334142.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;/&gt;&lt;br/&gt;报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满大街扬起的国旗和满街飘香的月饼,彰显祖国国泰民安 阖家团圆,国和家撞了个满怀,正如豫工和亲爱的客户朋友,坦诚相待 携手同行&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(182, 1, 8, '&lt;div&gt;2021年2月6日，豫工售后与技术支持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094355Y2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040609521Q58.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094411447.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094511R6.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;/&gt;&lt;br/&gt;试机中，在16/10空压机的配合下，液压湿喷机喷射距离达到100米，完全满足客户要求&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040609462a52.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;/&gt;&lt;br/&gt;客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406094FM63.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(183, 1, 8, '&lt;div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;战前OUTING&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！&lt;/span&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94K4227.jpg&quot; style=&quot;width: 691px; height: 405px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比的设备，及时发货和高效施工！&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94PS94.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94S0392.jpg&quot; style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; font-size: 12px; width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;来到北京，小伙伴们的每个细胞都充盈起来，所求皆所愿，所见皆所喜，祝福祖国，祝福豫工，祝福每一个追梦人&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94T4620.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F94U33Y.jpg&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;三天的美好时光,豫工的小伙伴们对工作按下暂停键,寄情山水，放空自己,争取以好的状态,迎接即将到来的金秋大战,努力工作，用心服务,用百分百的热情去朝着新的、更高的目标进发！&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(184, 1, 8, '&lt;div&gt;安全生产 消防为先，8月4日下午4点，豫工机械开展消防安全讲座。&lt;/div&gt;&lt;div&gt;公司特邀河南省护民防火中心祝教官，前往总部营销中心，为大家讲解消防安全知识，全体员工140多人参加。&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F95235R3.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;祝教官对近年发生的火灾以图片、视频的形式提高大家消防安全意识，从贴近生活，实用性强的单位、家庭用气、用电、夏季汽车自燃等方面入手，讲解消防知识，和火灾初期如何灭火的方法，提高大家防灾减灾能力！&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F953201T.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n 祝教官现场演示灭火器“一摇、二拔、三瞄、四压”的操作流程，介绍防火毯、防烟面具等消防器材的使用方法，火灾现场如何紧急疏散和逃生自救等知识，提高大家对突发事件的紧急处置能力。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F95333493.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9540MG.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;此次讲座豫工小伙伴再次感受中国消防官兵的美逆行，火灾面前，他们总是冲在一线，狭路相逢，火口夺人！&lt;/div&gt;&lt;div&gt;防患于未“燃”，是对他们好的致敬！大家纷纷表示要将学到的消防知识教给家人、朋友和身边的每个人，为提高社会整体消防意识尽自己的一份力。&lt;/div&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F95351S8.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt;\r\n &lt;span style=&quot;font-size: 15px;&quot;&gt;豫工机械作为工程机械类大型综合性企业，人员众多，设备沉重，消防安全重于泰山。此次培训，进一步增强了企业消防安全意识，为全面消除火灾隐患、创建稳定的工作环境打下坚实基础。&lt;/span&gt;&lt;/p&gt;'),
(185, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;2020年5月18日，河南豫工机械第八届司庆日暨表彰大会在郑州禧逸酒店隆重召开。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91455L0.png&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;首先豫工生日趴，小伙伴们和主持人一起齐声祝福“河南豫工，生日快乐”。这时灯光熄灭，伴随着生日快乐歌，我们的大蛋糕上场了，大家热情高涨的唱着生日歌，歌声刚落下，我们的小伙伴们就向着蛋糕蜂拥而上，蛋糕的香甜味道弥漫在会场的上空，整个大厅都沉浸在一片欢乐的海洋……&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91522193.png&quot;/&gt;&lt;br/&gt;分享完蛋糕，接下来是我们的年度表彰环节，首先是我们2019年度销售冠亚军，他们出类拔萃，一直是公司的骨干精英，分别获得5000、8000的现金奖励，董事长李红旗先生和冠亚军进行合影留念！ &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F9153Y55.png&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91556362.png&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91622350.png&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;下面开始我们的重头大戏，也是各位股东们期盼的环节，那就是我们的股东分红……&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032F91A2F2.png&quot;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;盛世谱华章、春秋铸辉煌，从星光点点到阳光璀璨，回首过去我们激情澎湃，把握现在我们豪情满怀，展望未来我们信心满满，让我们一起携手并肩，志存高远，实现河南豫工新跨越，共同再创辉煌！&lt;/span&gt;&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(186, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 经过邮件来往沟通，2020年4月29日，以色列客户来我司工厂参观考察 &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZS95I.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;/&gt;&lt;br/&gt;国外以色列客户来访，要目的是为了商讨豫工锚固钻机后续大批量订单交期及质量控制事宜。 &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZUO33.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZ9115P.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;/&gt;&lt;br/&gt;经过多次的沟通，该客户对我司有了更深更好的了解。经过此次会谈，我们产品的技术和质量，价格优势，订单交期，服务方面得到了客户的认可，客户表示将与河南豫工机械长期订单合同，同时客户还表达豫工机械将成为自己核心的供用商。 &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZ929C6.jpg&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210327/2-21032FZ94H11.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(187, 1, 8, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 2021年2月27日，豫工机械“春风十里，不如有你”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工180多人参加此次活动！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102345219.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102420S7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; 豫工小姐姐化身舞林高手，精彩演绎提神洗脑神曲，可可爱爱，奇奇怪怪，换个舞台，依旧是灯光下耀眼的小姑娘&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061025125H.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 2020年，在全体豫工人的共同努力下，全年销售总额突破亿元大关;品牌知名度、市场接受度、老客户返单率直线飙升，综合上升9.2个百分点，一举突破52%。&lt;br/&gt;收官大战期间，豫工涌现出了众多业绩标兵，百万英雄，服务之星，优秀团队。今天，他们是豫工人眼中的SUPERSTAR！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102A6264.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102G3G1.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102HS19.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;旺春大战启动仪式&lt;/div&gt;&lt;div&gt;工程建设旺季随春而至，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号，与客户同频，以“起跑即冲刺、开局即决战”的奋发姿态，大干100天，打好开局战。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102SCD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102TMS.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406102Z4511.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061029193A.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;/&gt;&lt;br/&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; 奋斗赋予时间意义，其实，每个人的好运气都藏自己的实力里，藏在那些不为人知的努力里，看似波澜不起的日复一日，会突然在某一天让我们看到坚持的意义，2021，豫工小伙伴，加油!\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(188, 1, 8, '&lt;div&gt;7月18日，河南豫工机械,“认真工作，快乐生活”主题团建欢畅启程!豫工的小伙伴们集合完毕,乘坐两辆舒适的大巴向云台山进发,这次我们不谈工作，不谈业务,只谈...笑风生!&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061214235H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;大家一路欢声笑语,工作严谨认真，生活中却不乏开朗活泼,能干会玩，是我们的标签&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-21040612161HR.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061216303b.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121A2G6.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;太行山把美的一段给了河南！焦作云台山，山美 水美 云美 泉美!还有豫工的小姐姐更美！美得不像话!!!&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121K4600.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121Q6223.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406121S1323.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;大家来到小寨沟，这里被称为北方九寨沟!三步一泉，五步一瀑，十步一潭,小伙伴结伴而行!瀑布 小溪 竹筏 猕猴谷，玩的不亦乐乎！&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061220045H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-2104061220204O.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406122044244.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;晚上，豫工机械2020旺春表彰，在云台山风景区会议大厅隆重举行百天旺春大战圆满收官，成绩引人注目，在过去100天，豫工产值突破3000万，国际事业部，更是以200%的业绩完成率超越了2019全年业绩之和，今晚注定是一个不眠之夜！&lt;/em&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406122233402.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/210406/2-210406122552226.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;em&gt;第二天，伴随着山间清凉的风和偶尔飘来的雨丝，经过15座山，19个洞，三千多个台阶，终于到达茱萸峰，登顶而立 云锁雾绕 人间仙境，呼吸着没有PM2.5的空气，感受风的自由，果然，越往上，风景越好！就像豫工的小伙伴，勇往直前，不负韶华！&lt;/em&gt;&lt;br/&gt;&lt;br/&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(189, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/a83e7b70d411899.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify; text-indent: 34px;&quot;&gt;智能张拉设备在进行张拉作业之前，除了要对张拉设备的构件进行检验，还有几个不能忽视的地方，一起来看一下吧。&lt;/span&gt;&lt;br/&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;1、开机后如果发现主从控制柜通讯不上的问题，需要先检查通讯线是否连接正常或有断线，如果没有需要重新启动系统。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;2、在张拉过程中油管和控制电缆要顺直，不得扭曲打卷，防止扯断油管和电缆。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;3、在张拉过程中如果出现问题应首先按下控制柜面板上“油泵停止“按钮，不能强行继续张拉。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;4、在移动设备的过程中，泵站、千斤顶和控制系统要搁置在专用小车上，注意油管和连接线不能扭曲和拉断。一般情况下千斤顶和泵站油管不准拆卸。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;5、千斤顶的磨阻会随着使用时间而改变，应按工艺要求对千斤顶进行周期校验。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;6、智能张拉系统张拉过程中，预应力钢绞线出现断丝现象，千斤顶严重漏洞，调换千斤顶时，均应重新使用标准力校正系统校核张拉机具。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;7、油泵运转有不正常情况时，必须立即停车检查。在有压情况下，严禁随意拧动油泵或千斤顶各部位的螺丝。&lt;/span&gt;&lt;/p&gt;&lt;p style=&quot;margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; overflow-wrap: break-word !important; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; font-size: 14px;&quot;&gt;8、电源连接线必须接零线并保证连接正确，否则损毁控制箱电路板，设备应可靠接地，并随时检查各处绝缘情况，避免触电。&lt;/span&gt;&lt;/p&gt;&lt;section style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; text-indent: 2em; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; font-size: 14px;&quot;&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; border-width: 0px; border-style: initial; border-color: initial; font-style: inherit; font-variant: inherit; font-weight: inherit; font-stretch: inherit; line-height: inherit; font-family: inherit; vertical-align: baseline; overflow-wrap: break-word !important;&quot;&gt;智能张拉设备作业时的注意就说到这里，更多的产品知识可以关注我们的网站或直接电话咨询。&lt;/span&gt;&lt;/span&gt;&lt;/section&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;'),
(190, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/1095bf2790d3ce0.jpg&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;预应力机械顾名思义就是强化产生预应力并进行施工的机械设备，这种机械通常必须要具备产生很大外力的能力，因为受力模块本身通常具有很强的刚度和硬度，普通机械很难起到作用，预应力机械便发挥了作用。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在各种工程结构构件承受外荷载之前,对受拉模块中的钢筋等受力模块，施加预拉应力，提高构件的刚度和硬度，推迟裂缝出现的时间，增加构件的耐久性。对于机械结构来看，其含义为预先使其产生应力，其好处是可以提高构造本身刚性和硬度，减少受拉模块的振动和弹性变形。这样做可以明显改善受拉模块的强度，使原本的抗性更强。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;在结构承受外荷载之前，预先对在外荷载作用下的受拉区施加压应力，以改善结构使用的性能的结构型式称之为预应力结构。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 0.544px; text-align: justify;&quot;&gt;举例：预应力是在混凝土凝结前用钢筋机械把混凝土中的钢筋适度拉伸着，在混凝土凝结后撤去外力，钢筋就会在混凝土里产生一个收缩的应力，使钢筋混凝土强度更大。因而可以减少钢筋用量，节约钢材。&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(191, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 1px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/55bad77d53d0.png&quot; style=&quot;width: 691px; height: 462px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;防水早已不再是一个新鲜的话题，不论是隧道、桥梁、堤坝、道路、建筑还是我们日常居住的房屋，防水都不容忽视。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;相对于老式的防水方式的笨重和繁琐，豫工推出非固化防水材料喷涂设备，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;对于非固化设备的选购，许多人没有眉目。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;有的人贪图便宜，去买一下低价位的产品，有的人只看外表，购买一些外表看起来很好的机器，其实这些做法都是不正确的，一个合格的非固化设备厂家应该具备优秀的产品，国家安全认证以及完善的服务体系，针对这些问题，今天非固化设备厂家就来教大家如何选择一套靠谱的非固化设备。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;众所周知，由于沥青涂料的特殊性，经常有施工人员不熟悉机器的使用或是因为机器安全性能低而被沥青灼伤。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;且由于沥青加热后会变为流体。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;如果机器内部构造不严密就有可能被沥青侵入，造成大面积损坏。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;更有喷溅，起火等等一系列让人头痛的安全问题。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;对于以上这些安全问题，专业的设备工程师知道解决设备使用问题。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;防护服，防护镜等一系列确保施工人员安全的物件。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;稳定的机器出料口防止沥青喷溅，科学严密的内部构造防止沥青渗漏。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;工程研发部门研发定制的发动机防止机器起火等等。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;一系列安全隐患问题得到了很好的解决。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;俗话说得好，时间就是金钱。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;当今社会。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;效率就代表着一切。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;就好像脱桶器的脱桶速度，熔胶机的熔胶速度和熔胶量无一不是施工效率的决定因素。豫工&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;非固化喷涂机一分钟脱桶，三分钟熔胶。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;相信很多施工队都遇到过这样的情况，购买了一套设备，付过款以后卖方就音信全无，要不就是推推拖拖，只能靠施工方自己摸索使用，费时费力。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;所以您在选购非固化设备的同时一定要着重看一下该公司是否有完善的售后服务体系，这样才能确保您以后的设备使用放心。&lt;br/&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; text-indent: 34px; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; max-width: 100%; text-indent: 34px; box-sizing: border-box !important; overflow-wrap: break-word !important;&quot;&gt;路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(192, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; &lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;欧美国家自20世纪70年代以来在混凝土桥面铺装中广泛使用防水层，大大减少了混凝土桥梁因为渗水的原因而造成的损坏，延长桥梁的使用寿命。但随着交通量的增加，同时出现了防水层和面层以及桥面黏结强度不足而产生推移的病害。在我国，混凝土桥梁也经常发生类似病害，以及由于渗水甚至造成的混凝土疏松、脱落，钢筋锈蚀。造成以上病害的原因之一是因为混凝土面层的处理没有能够完全去除表面残留物质，没有保留一定的粗糙表面来保证防水层和桥面底层的黏结强度。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;http://yongjiu.hnyugong.com/uploads/allimg/210325/2-21032515315R41.jpg&quot; style=&quot;width: 611px; height: 344px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;抛丸工艺能够一次将混凝土表面的浮浆、杂质清理和清除干净，最重要的是在同时对混凝土表面进行了打毛处理，使其表面均匀粗糙，大大提高防水层和混凝土基层的黏结强度。而且在此过程中，抛丸工艺能够充分暴露混凝土的裂纹等病害，以便提前采取补救措施。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/9294f17b53b24b7.jpg&quot; style=&quot;width: 611px; height: 458px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;让顾客用上放心的设备是豫工机械一直以来坚持的使命，我们的愿景是依中原为根基，服务全国，走向世界。路漫漫其修远兮，吾将上下而求索，企业发展之路永无止境，豫工机械将始终坚持以合法合规经营为基本原则，以过程管理为核心，以两化融合为手段，建立企业一体化管理体系，以支撑企业卓越发展。&lt;/span&gt;&lt;br/&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &amp;quot;Helvetica Neue&amp;quot;, &amp;quot;PingFang SC&amp;quot;, &amp;quot;Hiragino Sans GB&amp;quot;, &amp;quot;Microsoft YaHei UI&amp;quot;, &amp;quot;Microsoft YaHei&amp;quot;, Arial, sans-serif; font-size: 14px; letter-spacing: 2px; text-align: justify; background-color: rgb(244, 244, 244);&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;http://yongjiu.hnyugong.com/uploads/allimg/210325/2-210325153421E7.jpg&quot; style=&quot;width: 611px; height: 454px;&quot;/&gt;&lt;/span&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(193, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 喷播机是边坡绿化施工的机械设备，它质量的好坏直接影响喷播效率的高低。喷播机主要用于高速公路(铁路）边坡绿化、边坡防护、山体治理、矿山复绿、荒漠治理等工程。因此，用户在购买时，会有很多问题注意。下面我们来看选购喷播机时需要注意哪些事项。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;http://www.zzyugong.cn/uploadfile/202311/ff89000a3bdf.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;一、选择合适的型号&lt;/div&gt;&lt;div&gt;喷播机常按不同的喷播对象分为客土喷播机和液力喷播机。合适的型号才能发挥出喷播机效用。要选择合适的型号，我们需要从两个方面考虑：&lt;/div&gt;&lt;div&gt;1、 根据边坡类型选择型号：边坡的高度、坡度都是影响选型的重要因素，高度和坡度越大，相应选配的发动机功率就越大。&lt;/div&gt;&lt;div&gt;2、 根据喷播厚度进行选择：一般客土喷播要求5-10公分，就要选用客土喷播机；液压喷播或喷播1-2公分可选用液力喷播机（恒睿喷播机厂家的液力喷播机可以喷播大浓度的泥浆）。&lt;br/&gt;\r\n &lt;div&gt;二、选择合适的厂家&lt;/div&gt;&lt;div&gt;1、主要注意机器罐体钢板厚度，发动机，泥浆泵，柴油机功率以及耐磨件的耐磨性能。现在生产喷播机的厂家有很多，但真正能做出经济实用方便实用的客土喷播机的厂家并不是很多。&lt;/div&gt;&lt;div&gt;2、在购买机器设备时要先考察好市场。实地考察更适合。&lt;/div&gt;&lt;div&gt;3、在购买产品时要考察该公司实力，是否在现实中真实存在的，有很多网站是没有实体公司的，所以我们要擦亮眼睛认真考核，如果条件可以的话，可以去厂家看看。&lt;/div&gt;&lt;div&gt;&amp;nbsp; 4、看该公司产品外观设计、质量、试机效果如何。&lt;/div&gt;&lt;div&gt;&amp;nbsp; 5、看该公司售后服务怎样，信誉度如何。&lt;/div&gt;&lt;div&gt;&amp;nbsp; 6、再好的喷播机也要看设备自身的重量。外观相同的机器价格差很多时我们要注意看机器的内部构造，不能贪小便宜吃大亏。&lt;/div&gt;&lt;div&gt;选购喷播机就选豫工机械的喷播机，经济实用方便操作。&lt;/div&gt;&lt;div&gt;&amp;nbsp;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(194, 1, 9, '&lt;div&gt;近日，有客户找到豫工机械咨询关于超大雾化扇面非固化喷涂设备的型号及价格的问题。在充分了解了这位客户的施工场景、施工面积、工人数量、项目工期后，豫工产品经理为其推荐了以下几种机型，现将其列出，以供大家参考。&lt;/div&gt;&lt;p&gt;客户需求信息&lt;br/&gt;&lt;/p&gt;&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 500px&quot;&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td&gt;项目介绍&lt;/td&gt;&lt;td&gt;90000平方地库顶板防水施工&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;喷涂物料&lt;/td&gt;&lt;td&gt;&lt;div&gt;非固化橡胶沥青防水涂料&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;现场情况&amp;nbsp;&lt;/td&gt;&lt;td&gt;客户第一次从事防水施工项目，工人无经验！&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td&gt;其他需求&lt;/td&gt;&lt;td&gt;工期紧，天气炎热，工人室外作业，希望设备高效作业，要求设备操作简单，减轻工人的工作量，能够如期完工！&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;div&gt;每天喷涂2000平方米的非固化喷涂机&lt;/div&gt;&lt;div&gt;相对于老式的防水方式的笨重和繁琐，产品经理为客户推荐豫工经典非固化喷涂防水套装：非固化喷涂机、非固化溶胶机、非固化脱桶器！特别是非固化喷涂机，体积小、重量轻，全程加热免清理，适用于大面积顶板或平面施工，刮涂或喷涂施工。&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040114311b32.jpg&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;/p&gt;&lt;div&gt;非固化喷涂机一分钟脱桶，三分钟熔胶。&lt;br/&gt;\r\n 自主研发、生产加热喷涂软管，加热均匀速度快，隔热效果好，耐高温、耐高压、耐磨损，性能稳定。&lt;br/&gt;\r\n 整机轻便，体积小，适用各种负责工程项目。豫工非固化喷涂机在国内较先采用非固化定制钢泵，经久耐用，压力稳定，寿命是普通泵的三倍以上。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401143303929.png&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;br/&gt;\r\n 如果您有购置非固化喷涂机的打算，可以点击&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;&lt;strong&gt;立即咨询&lt;/strong&gt;&lt;/a&gt;按钮，豫工机械产品经理为您提供一对一选型指导并报价，心动不如行动，快快咨询选购吧！&amp;nbsp;&amp;nbsp;&lt;br/&gt;\r\n &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;'),
(195, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 众所周知，路面清理打毛是防水喷涂施工前处理的重要环节，那么路面抛丸机在粗化打毛混凝土路面方面有那些优势呢？&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153551501.jpg&quot; style=&quot;width: 838px; height: 558px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;防水基层处理抛丸机&lt;/div&gt;&lt;div&gt;路面抛丸机的抛丸工艺可以一次性将混凝土外表的浮浆，杂质清算洁净，同时对混凝土外表进行打毛处置，使其外表均匀粗糙，大大进步了防水层和混凝土基层的黏结强度。而且在此过程中，可以充沛暴露混凝土的裂纹等病害，以便提早采取弥补措施。所以在推系统时，有条件状况下，采用抛丸处置基面，可以更好的保证防水效果。&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;立即咨询&lt;/strong&gt;&lt;/span&gt;&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153643J2.jpg&quot; style=&quot;width: 838px; height: 628px;&quot;/&gt;&lt;/a&gt;&lt;br/&gt;\r\n &lt;div&gt;&lt;div&gt;路面抛丸机在去除水泥浮浆打毛地面方面与铣刨机相比优势明显，抛丸机效率高，操作过程干净整洁，无任何污染，不需要二次处理；抛铣机在去除浮浆时灰尘污染大、效率慢，路面打完后还需要进一步处理灰尘！&lt;/div&gt;&lt;div&gt;假如大面积施工，抛丸的效率很高！总包交过来的施工基面上，混凝土残渣，疙瘩，油渍，污染等，用人工清算，十分耗工，也清不洁净，而用抛丸机则能很快处理问题，效率高。 路面抛丸机主要应用于钢铁外表清算、机场划改线工程、铁路桥面防水施工、公路桥隧路面打毛、环氧地坪外表打毛等。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153J55Y.jpg&quot; style=&quot;width: 838px; height: 472px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;路面抛丸机生产厂家&lt;/div&gt;&lt;div&gt;豫工机械拥有17年路面清理设备生产经验，自营的路面抛丸机是混凝土和沥青地面清理打毛、钢板除锈专用环保设备，经过6次升级换代，品质稳定，故障率低，清理效率高，受到中铁建工、中交集团等重量级客户的欢迎，服务客户30000余家。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153R3634.jpg&quot; style=&quot;width: 838px; height: 471px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(196, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 天气回温，路面施工市场的火热程度也在随之飙升，一众基建项目的开工使得路面摊铺设备出现了供不应求的状况。不少客户朋友蠢蠢欲动，来咨询豫工机械关于混凝土摊铺机的型号和情况，那么一台滚轴式摊铺机有哪些型号呢？买一台三辊的摊铺机需要多少钱呢？&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401153021911.jpg&quot; style=&quot;width: 838px; height: 558px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;路面混凝土摊铺机的型号、摊铺效果&lt;/div&gt;&lt;div&gt;摊铺排振一体机：混凝土摊铺机+排式振捣机&lt;/div&gt;&lt;div&gt;设备参数&lt;/div&gt;&lt;div&gt;辊子配置：两辊(2个行走轮)+1根绞龙（螺旋辊）&lt;/div&gt;&lt;div&gt;动力：4KW-4极电机2台(两根行走轮，双向行走，可前进，可后退)&lt;/div&gt;&lt;div&gt;辊轴直径：219mm&lt;/div&gt;&lt;div&gt;工作效率：每分钟大概行走8-10米，每小时摊铺2600-3300平方&lt;/div&gt;&lt;div&gt;辊轮宽度8.5米(机器总长9m)排振一体机，重量约1.5吨。实际摊铺8米路面，配10根棒。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115311CG.jpg&quot; style=&quot;width: 838px; height: 558px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;常规混凝土路面摊铺机&lt;/div&gt;&lt;div&gt;用途和分类：常规混凝土路面摊铺机根据滚轴主要分为双辊（168型）和三辊（219型）两种。一条轴负责行走，一条轴负责整平，另一条负责提浆。也可多配一条螺旋轴（绞龙轴）称为四辊，该轴主要起到刮平分料作用及减轻几条轴的负担，使摊铺效果更为明显。&lt;/div&gt;&lt;div&gt;主要用途：用于高铁公路，桥梁，市政道路、乡村公路、机场跑道、水利斜坡等工程的混凝土面层摊铺整平。&lt;/div&gt;&lt;div&gt;主要作用：对各种公路基层和面层各种材料摊铺，整平、振实、提浆、找平，解决路面平整度、提高机械化摊铺能力、加快施工进度。&lt;/div&gt;&lt;div&gt;设备参数&lt;/div&gt;&lt;div&gt;摊铺厚度：300mm&amp;nbsp; &amp;nbsp; &amp;nbsp; 摊铺宽度:3-6m&amp;nbsp; &amp;nbsp; &amp;nbsp; 振动频率:32Hz&amp;nbsp; &amp;nbsp; &amp;nbsp;辊轴直径:168/219mm&lt;/div&gt;&lt;div&gt;激振力:5.5kn&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp; 行走速度:8-10m/min&amp;nbsp; &amp;nbsp; 功率:双辊 4kw +4kw ;三辊 5.5+7.5kw&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115321Jc.jpg&quot; style=&quot;width: 838px; height: 558px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;路面混凝土摊铺机价格&lt;/div&gt;&lt;div&gt;摊铺排振一体机属于定制款，型号不同，厂家的报价也不一样，跟随钢材价格变化。其中辊轮宽度8.5米(机器总长9m)排振一体机，重量约1.5吨。实际摊铺8米路面，配套10根震动棒的摊铺排振一体机价格在一万四左右。6米排振一体机总长7m，摊铺5.5米路面，配套10根震动棒，市场价格在一万左右，想要了解其他摊铺排振一体机规格的价格，可以点击咨询，产品经理向您推荐高性价比的设备。&lt;/div&gt;&lt;div&gt;对于常规款的混凝土路面摊铺机，两辊（168型）6米以下，市场价在四千左右，三辊（219型）6米以下市场价在七千左右，四辊 9米（10米）价格在一万左右。用户也可以根据施工的要求来定制不同长度的机器，豫工机械的混凝土摊铺机最长可以到12米。根据是否另外增加无缝管，价格差别比较大！大家可以&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;点击咨询&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;，让产品经理为您介绍不同型号的详细报价。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-2204011533152M.jpg&quot; style=&quot;width: 838px; height: 562px;&quot;/&gt;&lt;br/&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机、混凝土摊铺机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。\r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;'),
(197, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 目前，液压铣刨机型号比较多，其中，电机款统用18.5KW；300型也有15KW的，300型和350型适合2公分左右、3公分之内铣刨;500型适合半公分左右、1公分左右铣刨等，因施工要求、设备型号、配置差异加大，价格也不尽相同，大部分设备价格在3万-5万左右。&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152344301.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;液压铣刨机主要型号&lt;br/&gt;&lt;/p&gt;&lt;div&gt;针对深度铣刨的施工要求，豫工机械热销机型是350型的电动和燃油款，4根轴、大刀片、直径110刀片、数量是76片。500型号的电动/燃油铣刨机，主要用来拉毛，深度最好在1公分左右的，使用的是6根轴&amp;nbsp; 直径60刀片 数量210片。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152509122.png&quot; style=&quot;width: 838px; height: 603px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;设备特点&lt;/div&gt;&lt;div&gt;产品配置高，本机采用进口无极变速电机，使用寿命长，刀轴刀头为钨钢合金材质，每幅刀头使用寿命长达4000平方以上。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152553562.png&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;液压自行走 无级变速！&lt;/div&gt;&lt;div&gt;可快可慢 全进口液压系统！&lt;/div&gt;&lt;div&gt;配洒水箱，绿色环保！&lt;/div&gt;&lt;div&gt;进口刀头，行走速度跟深浅、地面硬度灵活控制！&lt;/div&gt;&lt;div&gt;设计合理，操作简单，施工效率高。维护简单，使用寿命长。&lt;/div&gt;&lt;div&gt;适用范围广&lt;/div&gt;&lt;div&gt;液压铣刨机广泛用于楼房、墙面、厂房、箱梁、高速公路、桥梁、铁路、水利、电力、机场、停车场及市政、建筑、建筑装饰、加固工程等的侧面立面狭窄空间各种混凝土表面处理拉毛，从而达到粗糙度用于二次铺装。&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152A9202.jpg&quot; style=&quot;width: 838px; height: 450px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;液压铣刨机价格&lt;/div&gt;&lt;div&gt;相较于进口全液压铣刨机而言，豫工机械生产的铣刨机十分优惠，大概在3-5万左右，之多以价格区间如此之大，主要在于影响设备价格的因素很多。不同型号，不同配置的设备价格也不尽相同。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152J6304.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;市场上生产的液压铣刨机厂家很多，我们向您推荐豫工液压铣刨机，因为他成立17年，经历了时间和市场的考验，除了设备质量可靠、设备型号齐全、服务流程完善，价格也是非常优惠，既可现货直发，也可按需定制。如果您目前有购置液压铣刨机的需求，可点击&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;咨询厂家&lt;/a&gt;了解详情，也可预约到厂进行考察！旺春施工旺季，豫工机械优惠多多，不要犹豫，快咨询选购吧！&lt;/div&gt;&lt;div&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是专业的路面施工机械设备生产商,主营路面抛丸机,桥面抛丸机,非固化喷涂机,路面铣刨机等，17年诚信经营企业，树立行业标杆形象，打造百年质量信得过品牌，买路面施工机械设备就找豫工机械，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！欢迎来厂咨询考察。&lt;/div&gt;&lt;/div&gt;&lt;p&gt;&lt;br/&gt; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp;&lt;/p&gt;');
INSERT INTO `dr_1_xinwenguanli_data_0` (`id`, `uid`, `catid`, `content`) VALUES
(198, 1, 9, '&lt;p&gt;&amp;nbsp; &amp;nbsp; &amp;nbsp; \r\n &amp;nbsp; &amp;nbsp; &amp;nbsp; 车载绿篱修剪机的价格一直是每个客户关心的问题，但是，目前国内绿篱修剪机生产厂家众多，竞争激烈，各厂家会定期推出优惠政策，给出的报价不一！另外，市场平均价格水平，配置型号，安装调试，运送距离，发票等因素，都会影响产品最终报价！&lt;br/&gt;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151S3440.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;&lt;/p&gt;&lt;div&gt;公路绿篱及边坡灌木修剪专用设备&lt;/div&gt;&lt;div&gt;在没有绿篱修剪机之前，都是通过人工修建的方式，这种方式的缺点非常明显，不仅效率低下，而且也存在一定的安全问题，所以绿化带修剪机的出现，不仅解决了这个问题，还提高工作效率，使有限的劳动力发挥更加的作用车载式绿篱修剪机定做。&lt;br/&gt;\r\n &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401151925431.jpg&quot; style=&quot;width: 838px; height: 838px;&quot;/&gt;&lt;br/&gt;\r\n &lt;div&gt;豫工机械研发生产的车载式树篱修剪机只需在车辆驾驶室内就可完成修剪操作，而且修剪高度高，速度快，修剪效果好。可实现平剪、立剪、斜剪等动作，完全替代了人工，保证了安全作业。&lt;/div&gt;&lt;div&gt;豫工机械车载绿篱修剪机臂长，1.5-2m&amp;nbsp; &amp;nbsp;修剪高度1.8米，臂长类型1米-8米，既能够修剪直径100mm的粗树，也能修剪通常的绿篱。&lt;br/&gt;\r\n &amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-220401152015100.jpg&quot; style=&quot;width: 838px; height: 1117px;&quot;/&gt;&lt;br/&gt;\r\n &amp;nbsp;&lt;div&gt;绿篱修剪机价格&lt;/div&gt;&lt;div&gt;车载式绿篱修剪机价格在6-8万、10-20万不等，之所以价格区间、跨度如此之大，主要原因在于各类设备型号多样、配置多样，运费、发票、售后服务不同，最终所呈现出的报价相差也就比较大。&lt;br/&gt;\r\n &amp;nbsp; &lt;img alt=&quot;&quot; src=&quot;https://yongjiu.hnyugong.com/uploads/allimg/220401/2-22040115205a32.jpg&quot; style=&quot;width: 838px; height: 791px;&quot;/&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;如果您有购置绿篱修剪机的打算，可以点击&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;strong&gt;&lt;a href=&quot;http://pwt.zoosnet.net/LR/Chatpre.aspx?id=PWT55787204&amp;lng=cn&quot;&gt;立即咨询&lt;/a&gt;&lt;/strong&gt;&lt;/span&gt;按钮，豫工机械产品经理为您提供一对一选型指导并报价，心动不如行动，快快咨询选购吧！&lt;/div&gt;&lt;div&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration:underline;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;