.hnyugong.com/uploads/allimg/210730/2-210I01GHT01.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01GQ0R1.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01GS4517.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01GT4910.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01GU5362.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01GZJX.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01G924329.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01G93H11.jpg&quot; style=&quot;width: 695px; height: 956px;&quot;&gt;&lt;br&gt;\\r\\n&lt;h2 class=&quot;rich_media_title&quot; id=&quot;activity-name&quot; style=\'margin: 0px 0px 14px; padding: 0px; font-size: 22px; line-height: 1.4; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; letter-spacing: 0.544px;\'&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com/&quot; style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); text-decoration-line: none; font-size: 16px;\'&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=\'color: rgb(85, 85, 85); font-family: &quot;microsoft yahei&quot;; font-size: 16px;\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/h2&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(3, 79, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"79\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械为河南灾区捐赠的4车物资发车\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-79.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52102\",\"inputtime\":\"1700634097\",\"updatetime\":\"1700634097\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"79\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;7月23日，河南豫工机械有限公司通过郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164G2436.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164H6492.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164R6355.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164Q31S.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;\'&gt;\\r\\n 董事长李红旗先生第一时间捐款12万元用于抗洪救灾，并带领公司全体员工连续三天开展赈灾义卖，筹集救灾善款30余万元。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164U4624.jpg&quot; style=&quot;width: 695px; height: 1042px;&quot;&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;李总表示：尽管我们也受灾，厂区被淹，但在大是大非，大灾大难面前，我们还应当义不容辞地腾出余力，自救的同时，向同胞伸出援手，这是企业价值所在，也是企业回馈社会、反哺社会的责任所在，必须履行好。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I016493YE.jpg&quot; style=&quot;width: 695px; height: 584px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I016494X18.jpg&quot; style=&quot;width: 695px; height: 452px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;企业有担当 社会有能量！只要国家、社会有需要，豫工机械一定义不容辞，不忘初心，勇担使命，传递正能量！就如这次“720特大暴雨洪灾”，我们一定尽心竭力，自救救人，与灾区人民风“豫”同舟！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A113139.jpg&quot; style=&quot;width: 695px; height: 313px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A135291.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A212Z1.jpg&quot; style=&quot;width: 695px; height: 419px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;三天义卖结束后，全体员工同事一致意愿把每年的7月20日，设为公司的爱心慈善日（720爱心慈善日），成立专款专用的爱心慈善基金，每年720当天义卖 所得善款全部注入爱心慈善专项基金，用于慈善事业和爱心捐助。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A32X61.jpg&quot; style=&quot;width: 696px; height: 666px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;\\r\\n&lt;div&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com/&quot; style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px;\'&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=\'color: rgb(85, 85, 85); font-family: &quot;microsoft yahei&quot;; font-size: 16px;\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(4, 80, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"80\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021端午节放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-80.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52108\",\"inputtime\":\"1700634097\",\"updatetime\":\"1700634097\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"80\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611145944c8.jpg&quot; style=&quot;width: 695px; height: 1175px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 祝愿大家过一个安全、惬意、有意义的端午节！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(5, 71, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"71\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工旺春大战启动会燃情启动\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-71.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52050\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"71\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2022年2月22日，豫工机械“如虎添亿，奋战51”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工200多人参加此次活动！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105116348.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-2204191051314T.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n2021，在豫工人的共同努力下，公司全年销售总额再破3亿元大关，品牌知名度、市场接受度、老客户返单率、生产总值、团队业绩再创新高。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105220O3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n期间，公司涌现出了众多业绩精英、营销达人、优秀团队、百万英雄。她们8小时内求生存，8小时外求发展，每一天、每一分钟，都在为成功全力以赴！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-22041910530S45.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n3月，工程建设进入施工旺季，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号（3.1-5.31），各个部门与客户同频，大干100天，打好开局战。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105345Y3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n启动会上，豫工小伙伴胸有成竹梳理旺春目标，毫无保留分享工作方法，争取在接下来的100天，紧盯目标，协同向前，不达目的，绝不收兵。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105432b2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105444K3.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105500934.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 有人说你相信什么，就会吸引什么！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 公司股东作为豫工的中流砥柱，纷纷签订绩效责任承诺书，不畏艰难，身先士卒，同心协力，共战51！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105541391.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  戮力同心，勇于担当是我们的态度，团结协作、相互帮扶是我们的法宝&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  百天旺春，时间紧任务重，每一个豫工人都要同心协力，互助帮扶！心中无敌，奋战“51”！&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105620Q5.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419105AMC.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;董事长赋能 &lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 作为公司的掌舵人，豫工的精神支柱，李总表示：2022，豫工的主旋律就一个字“干”，干他个虎虎生威，干他个红红火火。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419110415237.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n “豫工十六年发展，吸引越来越多的优秀人才加入这个大家庭，终成今日盛势！2022，豫工人还要继续互帮互助，团结协作，推动豫工这艘航船扬帆远航，再创辉煌！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419110523B8.jpg&quot; style=&quot;width: 900px; height: 900px;&quot;&gt;&lt;br&gt;\\r\\n &lt;u&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/u&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(6, 72, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"72\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工两台湿喷台车助力中铁隧道局开工大吉!\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-72.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52058\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"72\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2022年3月31日，在豫工机械生产车间，两台3017型湿喷台车完成最后的装配，成功下线，通过严格功能检测，即将发车！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419103610J7.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车发车现场&quot;&gt;&lt;br&gt;\\r\\n它们将用于中铁隧道局宜兴铁路ZQ-3标隧道喷浆支护项目。作为3月的第49、50台喷浆支护系列设备，它的成功发车，意味着豫工机械喷浆支护设备3月销量再创新高。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419103645J2.jpg&quot; style=&quot;width: 900px; height: 405px;&quot; title=&quot;湿喷台车服务项目&quot;&gt;&lt;br&gt;\\r\\n这台外形酷似机械手臂的升级版全机械化液压湿喷台车，与常规型液压湿喷机相比，工作效率提升2倍，轻松达到30㎥/h，而且，机械化程度高，遥控操作，全自动喷浆无盲区，广泛应用于高铁、隧道、边坡、地铁、基坑等喷浆支护项目。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419103I3547.jpg&quot; style=&quot;width: 900px; height: 674px;&quot; title=&quot;湿喷台车生产现场&quot;&gt;&lt;br&gt;\\r\\n据豫工机械研发部门陈主任介绍，该款湿喷台车的机械臂、泵送系统、液压系统、电器系统等关键零部件优选知名品牌。机、电、液一体化控制系统，实现对发动机、液压系统、工作状态的检测和保护，保证设备的高可靠性。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419103Q3140.jpg&quot; style=&quot;width: 900px; height: 505px;&quot; title=&quot;湿喷台车调试现场&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 施工现场，操作人员使用无线遥控进行喷射作业，远离作业面，不仅操作方便，更增加了工人的安全性。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 客户对设备高效的生产能力很满意，表示：根据工程需要，下次再上一台。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419103913G1.jpg&quot; style=&quot;width: 900px; height: 675px;&quot; title=&quot;湿喷台车施工现场&quot;&gt;&lt;br&gt;\\r\\n 豫工机械作为17年喷浆支护设备生产厂家，型号齐全、品类完善，液压湿喷机、混凝土喷浆车，钢筋网片排焊机等设备深受欢迎，一站式采购，降低生产成本，提升施工效率！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419104024U2.jpg&quot; style=&quot;width: 900px; height: 600px;&quot; title=&quot;液压湿喷机仓库&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-22041910403R96.jpg&quot; style=&quot;width: 900px; height: 599px;&quot; title=&quot;喷浆支护设备仓库&quot;&gt;&lt;br&gt;\\r\\n 其实，豫工喷浆支护设备一直以“高效稳定”享誉市场，在高铁、地铁、隧道领域，发挥着举足轻重的作用，被国家大批重点建设项目广泛采用，累计服务工程项目30000+！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-22041910414V56.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419104201Y2.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419104211547.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/220419/2-220419104230142.jpg&quot; style=&quot;width: 900px; height: 507px;&quot;&gt;&lt;br&gt;\\r\\n &lt;u&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;/u&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目!&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(7, 73, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"73\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021国庆放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-73.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52064\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"73\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 神州大地，举国欢庆！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 山河壮丽，岁月峥嵘！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 江山不老，祖国常青！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 豫工机械祝福我们的祖国繁荣昌盛&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 十一国庆节来了，根据国家放假规定，结合公司实际情况，河南豫工机械有限公司2021年国庆放假安排如下：&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210930/2-210930151Ib36.jpg&quot; style=&quot;width: 850px; height: 1275px;&quot;&gt;&lt;br&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#ff0000;&quot;&gt;注意事项&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(8, 74, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"74\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械金秋大战燃情启动\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-74.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52070\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"74\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2021年9月11日，豫工机械“2021金秋大战暨旺春优秀表彰” 燃情启动，郑州总部营销中心，全体员工180多人参加活动！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916104T33V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国内事业部活动现场&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916104ZO24.png&quot; style=&quot;width: 695px; height: 813px;&quot;&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国际事业部活动现场&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610500T94.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;旺春大战优秀表彰&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2个月前，公司旺春大战圆满收官，诞生了许多业绩标兵、百万英雄、服务之星、优秀团队，今天是见证荣誉的时刻！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916105423545.jpg&quot; style=&quot;width: 695px; height: 546px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n  国内事业部旺春英雄奖&lt;/div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916105440121.jpg&quot; style=&quot;width: 695px; height: 474px;&quot;&gt;\\r\\n &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n  国内事业部捷报奖&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916105614H5.jpg&quot; style=&quot;width: 695px; height: 739px;&quot;&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国际事业部旺春英雄奖&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916105630b7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国际事业部旺春达人奖&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916105HK63.jpg&quot; style=&quot;width: 695px; height: 528px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国际事业部旺春捷报奖&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;优秀个人表彰&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 在豫工，从不缺工作上的拼命三郎，他们拼搏进取 所向披靡，他们是当之无愧的业务精英，是豫工人应该崇拜的旺春英雄！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-2109161JGXM.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n &lt;span style=&quot;text-align: center;&quot;&gt;国内事业部佳个人进步奖&lt;/span&gt;&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: left;&quot;&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916110249236.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n 国际事业部佳个人进步奖&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: left;&quot;&gt;\\r\\n &lt;strong&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916110441H0.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: left;&quot;&gt;\\r\\n &lt;strong&gt;百万英雄表彰&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: left;&quot;&gt;\\r\\n 每一个不起眼的日子，都是逆风翻盘的机会，深夜办公室的灯火通明，陪伴豫工人日复一日的坚持，见证一个又一个百万大单的诞生！&lt;/div&gt;\\r\\n&lt;div style=&quot;text-align: left;&quot;&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-2109161110101F.jpg&quot; style=&quot;width: 695px; height: 537px;&quot;&gt;&lt;br&gt;\\r\\n &lt;strong&gt;金秋大战燃情启动&lt;/strong&gt;\\r\\n &lt;div&gt;\\r\\n  金九银十，豫工人吹响金秋大战（9月15日-11月15日）集结号，各种促销政策感恩回馈，全员60天无休无假，及时发货，专业售后，为客户工程保驾护航！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611123E64.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111301G7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111325Y8.jpg&quot; style=&quot;width: 695px; height: 538px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111336309.jpg&quot; style=&quot;width: 695px; height: 541px;&quot;&gt;\\r\\n  &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n   国内事业部团队风采&lt;/div&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611151N02.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611152R61.jpg&quot; style=&quot;width: 695px; height: 473px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111604527.jpg&quot; style=&quot;width: 695px; height: 605px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611162E59.jpg&quot; style=&quot;width: 695px; height: 487px;&quot;&gt;\\r\\n  &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n   &lt;strong&gt;国际事业部团队风采&lt;/strong&gt;&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   奋斗不止的“军令状”&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   军令如山 使命必达！启动会上，各团队用热血誓言签下军令状，不找理由、不找借口，创新突破，勇于担当，全力以赴，目标必达！&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111QX07.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111SB03.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916111UH34.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n    国内事业部员工风采&lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611193M58.jpg&quot; style=&quot;width: 695px; height: 756px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611195Hb.jpg&quot; style=&quot;width: 695px; height: 769px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916112010546.jpg&quot; style=&quot;width: 695px; height: 502px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;div style=&quot;text-align: center;&quot;&gt;\\r\\n   国际事业部员工风采&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   &lt;strong&gt;实实在在豫工人&lt;/strong&gt;&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   踏实独立，热爱上进，豫工女孩既爱红装也爱戎装，生活中追求仪式感，该努力时也绝不含糊，全力以赴，活出自己的色彩！&lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916112149E9.jpg&quot; style=&quot;width: 695px; height: 530px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091611215aD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916112215230.jpg&quot; style=&quot;width: 695px; height: 815px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-2109161122251X.jpg&quot; style=&quot;width: 695px; height: 661px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  大好时光，奋斗正当时&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  豫工人天生勤奋、实干、永不服输&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  不抛弃不放弃，言出必行，使命必达&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2021金秋大战&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  小伙伴们，加油！！！&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;&lt;strong&gt;&lt;u&gt;河南豫工机械&lt;/u&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(9, 75, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"75\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021中秋节放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-75.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52076\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"75\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 金秋九月，花好月圆，又是一年中秋时！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：&lt;br&gt;\\r\\n &lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;&lt;strong&gt;放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n   &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916145453Q6.gif&quot; style=&quot;width: 640px; height: 440px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;background-color:#ffff00;&quot;&gt;温馨提示 &lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n  &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n  &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;月圆人团圆&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;中秋合家欢&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;豫工机械恭祝新老客户朋友财源滚滚、事业顺利、阖家幸福、中秋安康！&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;\\r\\n &lt;u&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;&lt;/u&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(10, 76, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"76\",\"catid\":\"8\",\"title\":\"\\r\\n         您的中秋贺礼已发货！请注意查收！\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-76.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52082\",\"inputtime\":\"1700634096\",\"updatetime\":\"1700634096\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"76\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610215A62.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610221A35.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!&lt;br&gt;\\r\\n&lt;strong&gt;7月抗汛,赈灾义卖,!筹款30万捐向灾区&lt;/strong&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610345M33.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103512c7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103529218.jpg&quot; style=&quot;width: 695px; height: 312px;&quot;&gt;&lt;br&gt;\\r\\n&lt;strong&gt;8月抗疫，涝疫补贴,每人500元&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103J3A6.jpg&quot; style=&quot;width: 695px; height: 428px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103Q1R7.jpg&quot; style=&quot;width: 695px; height: 445px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103S13A.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;&gt;&lt;/strong&gt;&lt;br&gt;\\r\\n中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼，豫工人也吹响金秋大战（9月15日-11月15日）集结号，各种促销感恩让利，全体员工60天无休无假，及时发货，专业售后，为您的工程保驾护航。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-2109161042243V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n花好月圆，天涯共此良辰，豫工机械恭祝新老客户朋友，财源滚滚、事业顺利，家庭美满、中秋安康！&lt;br&gt;\\r\\n&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械有限公司&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634228),
(11, 70, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"70\",\"catid\":\"8\",\"title\":\"\\r\\n         飒！豫工机械金秋大战燃情启动\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-70.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-51998\",\"inputtime\":\"1700634071\",\"updatetime\":\"1700634071\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"70\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2022年9月14日，豫工机械营销总部，金秋大战在国内事业部率先启动，近200名员工斗志昂扬，众志成城，正式打响金九银十决胜战！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QI302X8.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QI222953.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QI324337.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n总结过去，赢战未来，表彰卓越，见证辉煌&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 在热烈的掌声中，优秀代表纷纷登台，荣誉和鲜花，是对他们最大的鼓舞和肯定。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QI609157.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;span style=\'color: rgb(0, 0, 0); font-family: system-ui, -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 0.544px; text-align: justify; background-color: rgba(246, 212, 218, 0.58);\'&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QI645949.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n在金九银十关键节点，豫工机械金秋大战也如期而至，作为公司2022年51工程（2022年销售额突破5个亿）的关键一战，本次启动会既要制定目标、分解过程，更要为营销团队蓄势蓄力，增强信心！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QIIX33.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QIK9209.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QIQ5T2.jpg&quot; style=&quot;width: 900px; height: 703px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n启动会上，每个人都制定可行的金秋目标，分解目标，规划过程，最大程度保证方案的可行性，一鼓作气，赢战“51”！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QKAW58.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QKG4559.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n在团队主管的带领下，各部门纷纷签署金秋军令状，立下铿锵雄心，军令如山，一往无前，巅峰对决，闪耀金秋。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QKQ5420.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QKS23B.jpg&quot; style=&quot;width: 900px; height: 551px;&quot;&gt;&lt;br&gt;\\r\\n战鼓声声，催人奋进，在公司各部门的大力支持下，营销中心全体人员枕戈待旦、鼓足干劲，金秋之战，志在必胜！豫工小伙伴，加油！\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(12, 69, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"69\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械发福利了，中秋快乐！\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-69.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-51868\",\"inputtime\":\"1700633879\",\"updatetime\":\"1700633879\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"69\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       中秋节发福利了！红红火火的包装，至诚至爱的心意，节礼在手，温暖在心，感谢公司一如既往的厚爱！\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QPG4N2.jpg&quot; style=&quot;width: 900px; height: 675px;&quot;&gt;&lt;br&gt;\\r\\n 作为国人重要的传统佳节，每年中秋，公司都会精心准备节日贺礼，感谢大家一年来的努力与付出，希望每一位员工都能与家人，阖家团圆，把酒言欢，满满的仪式感，引来隔壁公司羡慕的眼光。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QPRB91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QPT6225.jpg&quot; style=&quot;width: 900px; height: 409px;&quot;&gt;&lt;br&gt;\\r\\n 心怀感恩 所遇皆温柔，公司满满的关爱，不仅让豫工人找到归属感，也让背后的家庭对豫工好感度俱增，多年工作下来，他们都成了最合格的豫工家属！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QP94G45.jpg&quot; style=&quot;width: 900px; height: 542px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QQ00R91.jpg&quot; style=&quot;width: 900px; height: 506px;&quot;&gt;&lt;br&gt;\\r\\n 每逢生产旺季 客户来访，他们总是主动担待，让豫工人有更多精力苛求细节 圆满服务，因为他们的全力支持，豫工人有更多时间研发生产 优化产品，赢得一个又一个客户的信赖。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QQ303T8.jpg&quot; style=&quot;width: 900px; height: 505px;&quot;&gt;&lt;br&gt;\\r\\n 在这花好月圆的欢庆时刻，在这金九银十的施工旺季，我们特意为全国客户朋友准备了大大的中秋福利，满满的诚意，礼到、心到、实惠到！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/221008/2-22100QQ425158.jpg&quot; style=&quot;width: 900px; height: 370px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  9月8日-9月10日，豫工将送出30万中秋购机消费券，大到几十万的生产线，小到几百块的配件均可适用，爆款福利 限时派送 ，赶快联系你的业务经理领取吧！&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(13, 68, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"68\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械北京团建欢畅启程\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-68.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48814\",\"inputtime\":\"1700626951\",\"updatetime\":\"1700626951\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"68\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n &lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n  &lt;span style=&quot;font-size: 14px;&quot;&gt;战前OUTING&lt;/span&gt;&lt;/p&gt;\\r\\n &lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n  &lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！&lt;/span&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94K4227.jpg&quot; style=&quot;width: 691px; height: 405px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比的设备，及时发货和高效施工！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94PS94.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94S0392.jpg&quot; style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; font-size: 12px; width: 691px; height: 518px;&quot;&gt;&lt;/p&gt;\\r\\n &lt;div&gt;\\r\\n  来到北京，小伙伴们的每个细胞都充盈起来，所求皆所愿，所见皆所喜，祝福祖国，祝福豫工，祝福每一个追梦人&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94T4620.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94U33Y.jpg&quot;&gt;&lt;br&gt;\\r\\n  三天的美好时光,豫工的小伙伴们对工作按下暂停键,寄情山水，放空自己,争取以好的状态,迎接即将到来的金秋大战,努力工作，用心服务,用百分百的热情去朝着新的、更高的目标进发！&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232);
INSERT INTO `dr_1_xinwenguanli_recycle` (`id`, `cid`, `uid`, `catid`, `content`, `result`, `inputtime`) VALUES
(14, 61, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"61\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械16周年庆典暨第一届女神节\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-61.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48770\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"61\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2021年5月21日，郑州禧逸酒店会议大厅，&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145129295.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052514514K22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 生日趴&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145505a7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145532F2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145550E4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  迎新环节&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家快速成长，融入团队。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145I11X.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515004R20.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 年度职级晋升 &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 迎光奔跑，保持热爱，每一个认真努力的现在，都有一个水到渠成的未来！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 本次年度职级晋升表彰，让我们再次见证努力的意义！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251501563B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251502452a.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  2020年度表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  知足上进，不负野心，各自努力，顶峰相见！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2020年度内外贸业绩冠军、亚军、季军表彰，高手过招，风景这边独好！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150510133.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251505325P.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;div&gt;\\r\\n   “积极向上，热爱生活，找差距，强弱项，认真对待每一件事，定有收获”&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   2020豫工年度销冠——国内事业部魏红岩、国际事业部刘建华分享工作方法，鼓励大家保持热爱，厚积薄发。&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251506312B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150A2324.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;div&gt;\\r\\n    优秀团队表彰&lt;/div&gt;\\r\\n   &lt;div&gt;\\r\\n    有人说：千人同心，则得万人之力；万人异心，则无一人可用！&lt;/div&gt;\\r\\n   &lt;div&gt;\\r\\n    豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br&gt;\\r\\n    &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150JKP.jpg&quot; style=&quot;width: 695px; height: 480px;&quot;&gt;&lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515092S43.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151011624.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 百万英雄表彰&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2020精彩纷呈，豫工人凭借历久弥坚的决心，勇闯百万的勇气，涌现出许多百万业绩精英!&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 今天是他们的高光时刻！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515111YR.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251511391G.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  优秀运营表彰 &lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  成绩的取得，离不开市场人员辛勤付出，是他们凭借敏锐的市场感知力，深挖客户需求，助力研发部门优化设备功能，推出切实符合工程需求的设备！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151505458.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151520R3.jpg&quot; style=&quot;width: 695px; height: 383px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151P9411.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 十大领军人物表彰&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 航海千里，成于罗盘！在公司有这么一群人，他们肩挑领跑者的责任，心怀冲锋者的闯劲，勤勉务实，敢为人先，他们是业务团队的领头羊！他们是豫工机械业务团队的领军者。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152004441.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152325135.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  明日之星表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2021，豫工涌现出了一批执行力超强的业务精英，他们的成绩有目共睹，工作中不讲如果，只讲结果！步履不停，奋斗不止，终于成长为公司的业绩担当，荣获豫工机械明日之星称号。&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152503244.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152605205.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  未来之星表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  奋斗的路上，没有奇迹，只有努力的轨迹；没有运气，只有坚持的勇气，每一滴汗水都是成功的积累！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2021，豫工很多小伙伴在工作中展现巨大爆发力，目标坚定，温柔上进，持续努力，未来可期，喜获未来之星荣誉称号！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515292G45.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152944V5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 优秀表彰致辞&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n “分享、担当、感恩、自信、坚毅”，豫工总经理为活动致辞 ，再次分享公司企业文化，揭秘豫工机械16年保持高速发展的能量源泉！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153111320.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  风雨同舟者赢，上下同欲者胜&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  有人说你相信什么，就会吸引什么！你怀疑什么，就会失去什么，这就是相信的力量，这就是成功的秘籍！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  年度股东分红，让我们再次见证相信的力量！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515324C15.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153300J3.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n豫工十六年发展，终成今日势，跨越式发展步伐，吸引众多优秀员工成为股东，风雨同舟，荣辱与共，推动豫工这艘航船稳步向前，再创新高！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515340J40.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153431Y9.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 女神篇&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 恰逢521全民表白日,豫工机械特设第一届女神节，鼓励大家怀揣公主梦，装着女王心，&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 勇敢展现自己的美，独立、优雅、自信、坚韧、洒脱、有底气、做自己，不负时光，活得漂亮！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515353U03.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153552L6.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515360S18.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251536203H.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251536339A.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153Q3a5.jpg&quot; style=&quot;width: 695px; height: 451px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153P1V6.jpg&quot; style=&quot;width: 695px; height: 434px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153RR22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n 无论是女王节还是女神节，往后余生，祝愿豫工这群可爱且善良的女生，眼中有光，心中有爱，温柔中带着刚强，努力优秀，大方拥有，有所为，有所爱，有所期待！&lt;br&gt;\\r\\n &lt;strong style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=\'color: rgb(85, 85, 85); font-family: &quot;microsoft yahei&quot;; font-size: 16px; text-indent: 32px;\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(15, 62, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"62\",\"catid\":\"8\",\"title\":\"\\r\\n         五一劳动节 ，豫工机械放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-62.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48776\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"62\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210430/2-210430145242945.png&quot; style=&quot;width: 695px; height: 295px;&quot;&gt;&lt;br&gt;\\r\\n        在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210430/2-2104301453111a.jpg&quot; style=&quot;width: 695px; height: 1123px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  1、2021年劳动节放假共3天，时间为2021年5月1日至5月3日，5月4日（星期二）正常上班。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 祝愿大家过一个安全、惬意、有意义的劳动节！&lt;br&gt;\\r\\n 　　&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(16, 63, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"63\",\"catid\":\"8\",\"title\":\"\\r\\n         热情服务获赞誉，客户感激送锦旗\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-63.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48782\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"63\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-2105051111315F.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505111505c0.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505111515c3.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-21050511262HY.png&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505112F2928.png&quot; style=&quot;width: 695px; height: 395px;&quot;&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-21050511264T06.png&quot; style=&quot;width: 695px; height: 396px;&quot;&gt;&lt;br&gt;\\r\\n客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br&gt;\\r\\n&lt;strong&gt;&lt;span style=&quot;font-size:14px;text-indent:0;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;拥有16年隧道喷浆设备研发生产经验，匠心质造，品质如一！规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(17, 64, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"64\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工收官启动，秒变大型跨年晚会现场\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-64.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48788\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"64\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113S1254.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 迎新环节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113TR63.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。&lt;br&gt;\\r\\n 大战期间，豫工涌现出了许多业绩标兵，百万英雄，服务之星，优秀团队。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113U9143.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113913W8.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113925592.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611395a28.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 有人说：千人同心，则得万人之力；万人异心，则无一人可用！豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611401Q94.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114039537.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611405Q18.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114114634.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114154R1.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114222230.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 一分耕耘未必有一分收获，但是九分耕耘，必定会有一分收获。金秋大战期间，小伙伴们用实际行动证明了，这世间，唯有努力和坚持不可被辜负。&lt;br&gt;\\r\\n  &lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(18, 65, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"65\",\"catid\":\"8\",\"title\":\"\\r\\n         一粽传情 快乐端午，豫工机械端午福利多\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-65.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48794\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"65\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9202D57.png&quot;&gt;&lt;br&gt;\\r\\n豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F92049128.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9211T46.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F92132129.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F923212I.png&quot;&gt;&lt;br&gt;\\r\\n端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟邪消灾，平安健康！祝愿祖国繁荣昌盛，国泰民安！&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(19, 66, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"66\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工大型中秋福利现场，堪比红毯走秀\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-66.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48800\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"66\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406115911564.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;&gt;&lt;br&gt;\\r\\n福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120013401.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120034I8.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040612004TB.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120102Q2.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061201224D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120135332.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120155449.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120229512.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120244545.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061203113D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120334142.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满大街扬起的国旗和满街飘香的月饼,彰显祖国国泰民安 阖家团圆,国和家撞了个满怀,正如豫工和亲爱的客户朋友,坦诚相待 携手同行&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(20, 67, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"67\",\"catid\":\"8\",\"title\":\"\\r\\n         燃！豫工液压湿喷机助战郑州地铁建设\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-67.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48806\",\"inputtime\":\"1700626950\",\"updatetime\":\"1700626950\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"67\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 2021年2月6日，豫工售后与技术支​持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094355Y2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040609521Q58.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;/div&gt;\\r\\n订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094411447.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094511R6.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;&gt;&lt;br&gt;\\r\\n试机中，在16/10空压机的配合下，液压湿喷机喷射距离达到100米，完全满足客户要求&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040609462a52.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094FM63.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt; \\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634232),
(21, 59, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"59\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021端午节放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-59.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48756\",\"inputtime\":\"1700626949\",\"updatetime\":\"1700626949\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"59\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611145944c8.jpg&quot; style=&quot;width: 695px; height: 1175px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 祝愿大家过一个安全、惬意、有意义的端午节！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634236),
(22, 60, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"60\",\"catid\":\"8\",\"title\":\"\\r\\n         赞！豫工端午福利多，老板实力宠员工！\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-60.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-48764\",\"inputtime\":\"1700626949\",\"updatetime\":\"1700626949\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"60\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 端午来啦！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 老板实力宠员工&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  2盒粽子，2箱水果&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  啧啧......豪横，果然是中国好老板！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111434414Z.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;div&gt;\\r\\n   丰厚的节日福利&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   是公司对中国文化的传承&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   更体现了对豫工家人细致入微的关怀&lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143545919.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111436032W.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143F4611.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 其实，每逢传统佳节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 公司都会为客户朋友和豫工家人精心准备节日贺礼&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 这个习惯，豫工一干就是16年！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143K4933.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143PSA.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143RDW.jpg&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  福利发放现场，&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  欢声笑语！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  大家暂时放下手中繁忙的工作，&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  聚在一起，享受节日的快乐！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143ZR25.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111439463V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111439593L.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144029260.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144055K8.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n国内事业部员工风采&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144120103.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144136439.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144149318.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144200196.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n国际事业部员工风采&lt;br&gt;\\r\\n今年端午，赶上公司16周年庆典 为回馈新老客户的关爱 老板特批优惠方案 推出年中大促活动（2021年6月6日-6月30日） 价格一降到底，还有定金翻倍抵货款 买的多，更省钱。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144310146.jpg&quot; style=&quot;width: 695px; height: 350px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 心如糯米，越粘越紧，&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 情似粽叶，越煮越香。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 端午佳节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 我们向长期信任和支持豫工的客户朋友送上真诚的节日祝福&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 恭祝大家：事业顺利，生活安康，“粽”享幸福，端午安康！&lt;/div&gt;\\r\\n&lt;br style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;\\r\\n&lt;strong style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=\'font-family: &quot;microsoft yahei&quot;; font-size: 16px; line-height: 32px; text-indent: 32px; display: inline-block; color: rgb(85, 85, 85);\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700634236),
(23, 114, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"114\",\"catid\":\"8\",\"title\":\"\\r\\n         以色列客户考察豫工锚固钻车\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-114.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52920\",\"inputtime\":\"1700634845\",\"updatetime\":\"1700634845\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"114\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;span&gt;经过邮件来往沟通，2020年4月29日，以色列客户来我司工厂参观考察&lt;/span&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032FZS95I.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;&gt;&lt;br&gt;\\r\\n&lt;span&gt;国外以色列客户来访，要目的是为了商讨豫工锚固钻机后续大批量订单交期及质量控制事宜。 &lt;/span&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032FZUO33.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032FZ9115P.jpg&quot; style=&quot;width: 691px; height: 517px;&quot;&gt;&lt;br&gt;\\r\\n&lt;span&gt;经过多次的沟通，该客户对我司有了更深更好的了解。经过此次会谈，我们产品的技术和质量，价格优势，订单交期，服务方面得到了客户的认可，客户表示将与河南豫工机械长期订单合同，同时客户还表达豫工机械将成为自己核心的供用商。 &lt;/span&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032FZ929C6.jpg&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032FZ94H11.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(24, 115, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"115\",\"catid\":\"8\",\"title\":\"\\r\\n         好嗨哟！豫工机械旺春大战盛大启动\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-115.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52926\",\"inputtime\":\"1700634845\",\"updatetime\":\"1700634845\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"115\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2021年2月27日，豫工机械“春风十里，不如有你”旺春大战启动仪式在郑州营销中心——国内事业部和国际事业部依次举行，总部员工180多人参加此次活动！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102345219.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102420S7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n      豫工小姐姐化身舞林高手，精彩演绎提神洗脑神曲，可可爱爱，奇奇怪怪，换个舞台，依旧是灯光下耀眼的小姑娘&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061025125H.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n        2020年，在全体豫工人的共同努力下，全年销售总额突破亿元大关;品牌知名度、市场接受度、老客户返单率直线飙升，综合上升9.2个百分点，一举突破52%。&lt;br&gt;\\r\\n收官大战期间，豫工涌现出了众多业绩标兵，百万英雄，服务之星，优秀团队。今天，他们是豫工人眼中的SUPERSTAR！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102A6264.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102G3G1.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102HS19.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 旺春大战启动仪式&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 工程建设旺季随春而至，生产订单、设备售后、物流跟踪......等客户需求井喷式爆发，豫工特发起百天旺春大战冲锋号，与客户同频，以“起跑即冲刺、开局即决战”的奋发姿态，大干100天，打好开局战。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102SCD.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102TMS.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406102Z4511.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061029193A.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n      奋斗赋予时间意义，其实，每个人的好运气都藏自己的实力里，藏在那些不为人知的努力里，看似波澜不起的日复一日，会突然在某一天让我们看到坚持的意义，2021，豫工小伙伴，加油!\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(25, 116, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"116\",\"catid\":\"8\",\"title\":\"\\r\\n         旅游团建｜豫工的小姐姐，你笑起来真好看\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-116.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52932\",\"inputtime\":\"1700634845\",\"updatetime\":\"1700634845\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"116\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 7月18日，河南豫工机械,“认真工作，快乐生活”主题团建欢畅启程!豫工的小伙伴们集合完毕,乘坐两辆舒适的大巴向云台山进发,这次我们不谈工作，不谈业务,只谈...笑风生!&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061214235H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  大家一路欢声笑语,工作严谨认真，生活中却不乏开朗活泼,能干会玩，是我们的标签&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040612161HR.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061216303b.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406121A2G6.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;em&gt;太行山把美的一段给了河南！焦作云台山，山美 水美 云美 泉美!还有豫工的小姐姐更美！美得不像话!!!&lt;/em&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406121K4600.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406121Q6223.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406121S1323.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;em&gt;大家来到小寨沟，这里被称为北方九寨沟!三步一泉，五步一瀑，十步一潭,小伙伴结伴而行!瀑布 小溪 竹筏 猕猴谷，玩的不亦乐乎！&lt;/em&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061220045H.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061220204O.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406122044244.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;em&gt;晚上，豫工机械2020旺春表彰，在云台山风景区会议大厅隆重举行百天旺春大战圆满收官，成绩引人注目，在过去100天，豫工产值突破3000万，国际事业部，更是以200%的业绩完成率超越了2019全年业绩之和，今晚注定是一个不眠之夜！&lt;/em&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406122233402.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406122552226.jpg&quot; style=&quot;width: 695px; height: 472px;&quot;&gt;&lt;br&gt;\\r\\n&lt;em&gt;第二天，伴随着山间清凉的风和偶尔飘来的雨丝，经过15座山，19个洞，三千多个台阶，终于到达茱萸峰，登顶而立 云锁雾绕 人间仙境，呼吸着没有PM2.5的空气，感受风的自由，果然，越往上，风景越好！就像豫工的小伙伴，勇往直前，不负韶华！&lt;/em&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(26, 111, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"111\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械北京团建欢畅启程\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-111.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52900\",\"inputtime\":\"1700634844\",\"updatetime\":\"1700634844\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"111\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n &lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n  &lt;span style=&quot;font-size: 14px;&quot;&gt;战前OUTING&lt;/span&gt;&lt;/p&gt;\\r\\n &lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 15px; letter-spacing: 1.8px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n  &lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械一年一度的金秋大战即将拉开序幕，为了让大家以更好的状态决战金秋，公司组织小伙伴们畅游北京，三天两夜的行程，大家放空自己，调整状态，争取打出牛的战绩！&lt;/span&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94K4227.jpg&quot; style=&quot;width: 691px; height: 405px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;span style=&quot;font-size: 16px;&quot;&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;豫工机械金秋大战于每年9月15日-11月15日期间举行，与旺春大战（每年3月16日-6月30日）一样，公司将采取各种促销活动让利客户，有求必应做好售后服务，保证在金九银十的工程建设旺季，为广大客户朋友提供高品质、高性价比的设备，及时发货和高效施工！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94PS94.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94S0392.jpg&quot; style=&quot;color: rgb(34, 34, 34); font-family: Arial, Verdana, sans-serif; font-size: 12px; width: 691px; height: 518px;&quot;&gt;&lt;/p&gt;\\r\\n &lt;div&gt;\\r\\n  来到北京，小伙伴们的每个细胞都充盈起来，所求皆所愿，所见皆所喜，祝福祖国，祝福豫工，祝福每一个追梦人&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94T4620.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F94U33Y.jpg&quot;&gt;&lt;br&gt;\\r\\n  三天的美好时光,豫工的小伙伴们对工作按下暂停键,寄情山水，放空自己,争取以好的状态,迎接即将到来的金秋大战,努力工作，用心服务,用百分百的热情去朝着新的、更高的目标进发！&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(27, 112, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"112\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工特邀消防部门宣讲消防安全知识\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-112.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52908\",\"inputtime\":\"1700634844\",\"updatetime\":\"1700634844\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"112\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 安全生产 消防为先，8月4日下午4点，豫工机械开展消防安全讲座。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 公司特邀河南省护民防火中心祝教官，前往总部营销中心，为大家讲解消防安全知识，全体员工140多人参加。&lt;/div&gt;\\r\\n&lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F95235R3.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;/p&gt;\\r\\n&lt;div&gt;\\r\\n 祝教官对近年发生的火灾以图片、视频的形式提高大家消防安全意识，从贴近生活，实用性强的单位、家庭用气、用电、夏季汽车自燃等方面入手，讲解消防知识，和火灾初期如何灭火的方法，提高大家防灾减灾能力！&lt;/div&gt;\\r\\n&lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F953201T.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n 祝教官现场演示灭火器“一摇、二拔、三瞄、四压”的操作流程，介绍防火毯、防烟面具等消防器材的使用方法，火灾现场如何紧急疏散和逃生自救等知识，提高大家对突发事件的紧急处置能力。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F95333493.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9540MG.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;/p&gt;\\r\\n&lt;div&gt;\\r\\n 此次讲座豫工小伙伴再次感受中国消防官兵的美逆行，火灾面前，他们总是冲在一线，狭路相逢，火口夺人！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 防患于未“燃”，是对他们好的致敬！大家纷纷表示要将学到的消防知识教给家人、朋友和身边的每个人，为提高社会整体消防意识尽自己的一份力。&lt;/div&gt;\\r\\n&lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; box-sizing: border-box; clear: both; min-height: 1em; color: rgb(79, 79, 79); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 16px; letter-spacing: 1px; text-align: justify; overflow-wrap: break-word !important;\'&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F95351S8.jpg&quot; style=&quot;width: 691px; height: 518px;&quot;&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;font-size: 15px;&quot;&gt;豫工机械作为工程机械类大型综合性企业，人员众多，设备沉重，消防安全重于泰山。此次培训，进一步增强了企业消防安全意识，为全面消除火灾隐患、创建稳定的工作环境打下坚实基础。&lt;/span&gt;&lt;/p&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(28, 113, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"113\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械第八届司庆日暨表彰大会\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-113.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52914\",\"inputtime\":\"1700634844\",\"updatetime\":\"1700634844\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"113\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;2020年5月18日，河南豫工机械第八届司庆日暨表彰大会在郑州禧逸酒店隆重召开。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F91455L0.png&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;\'&gt;首先豫工生日趴，小伙伴们和主持人一起齐声祝福“河南豫工，生日快乐”。这时灯光熄灭，伴随着生日快乐歌，我们的大蛋糕上场了，大家热情高涨的唱着生日歌，歌声刚落下，我们的小伙伴们就向着蛋糕蜂拥而上，蛋糕的香甜味道弥漫在会场的上空，整个大厅都沉浸在一片欢乐的海洋……&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F91522193.png&quot;&gt;&lt;br&gt;\\r\\n&lt;span&gt;分享完蛋糕，接下来是我们的年度表彰环节，首先是我们2019年度销售冠亚军，他们出类拔萃，一直是公司的骨干精英，分别获得5000、8000的现金奖励，董事长李红旗先生和冠亚军进行合影留念！&lt;/span&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9153Y55.png&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F91556362.png&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F91622350.png&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;下面开始我们的重头大戏，也是各位股东们期盼的环节，那就是我们的股东分红……&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; letter-spacing: 0.544px; text-align: justify;\'&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F91A2F2.png&quot;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;盛世谱华章、春秋铸辉煌，从星光点点到阳光璀璨，回首过去我们激情澎湃，把握现在我们豪情满怀，展望未来我们信心满满，让我们一起携手并肩，志存高远，实现河南豫工新跨越，共同再创辉煌！&lt;/span&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496);
INSERT INTO `dr_1_xinwenguanli_recycle` (`id`, `cid`, `uid`, `catid`, `content`, `result`, `inputtime`) VALUES
(29, 104, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"104\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械16周年庆典暨第一届女神节\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-104.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52816\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"104\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2021年5月21日，郑州禧逸酒店会议大厅，&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;“保持热爱，共赴山海”16周年庆典暨第一届女神节欢乐开启，总部营销中心全体员工220多人参加了此次活动。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145129295.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052514514K22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 生日趴&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 在众人的生日祝福中，董事长李总为大家分切蛋糕，开启今天的活动庆典。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145505a7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145532F2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145550E4.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  迎新环节&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  16年开拓创新，争先、争勇、争光，创新、创业、创享,收获累累硕果！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  公司焕发的强大活力，不断吸引众多行业精英的加入！为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家快速成长，融入团队。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525145I11X.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515004R20.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 年度职级晋升 &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 迎光奔跑，保持热爱，每一个认真努力的现在，都有一个水到渠成的未来！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 本次年度职级晋升表彰，让我们再次见证努力的意义！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251501563B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251502452a.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  2020年度表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  知足上进，不负野心，各自努力，顶峰相见！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2020年度内外贸业绩冠军、亚军、季军表彰，高手过招，风景这边独好！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150510133.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251505325P.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;div&gt;\\r\\n   “积极向上，热爱生活，找差距，强弱项，认真对待每一件事，定有收获”&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   2020豫工年度销冠——国内事业部魏红岩、国际事业部刘建华分享工作方法，鼓励大家保持热爱，厚积薄发。&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251506312B.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150A2324.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n   &lt;div&gt;\\r\\n    优秀团队表彰&lt;/div&gt;\\r\\n   &lt;div&gt;\\r\\n    有人说：千人同心，则得万人之力；万人异心，则无一人可用！&lt;/div&gt;\\r\\n   &lt;div&gt;\\r\\n    豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br&gt;\\r\\n    &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525150JKP.jpg&quot; style=&quot;width: 695px; height: 480px;&quot;&gt;&lt;/div&gt;\\r\\n  &lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515092S43.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151011624.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 百万英雄表彰&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2020精彩纷呈，豫工人凭借历久弥坚的决心，勇闯百万的勇气，涌现出许多百万业绩精英!&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 今天是他们的高光时刻！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515111YR.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251511391G.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  优秀运营表彰 &lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  成绩的取得，离不开市场人员辛勤付出，是他们凭借敏锐的市场感知力，深挖客户需求，助力研发部门优化设备功能，推出切实符合工程需求的设备！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151505458.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151520R3.jpg&quot; style=&quot;width: 695px; height: 383px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525151P9411.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 十大领军人物表彰&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 航海千里，成于罗盘！在公司有这么一群人，他们肩挑领跑者的责任，心怀冲锋者的闯劲，勤勉务实，敢为人先，他们是业务团队的领头羊！他们是豫工机械业务团队的领军者。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152004441.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152325135.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  明日之星表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2021，豫工涌现出了一批执行力超强的业务精英，他们的成绩有目共睹，工作中不讲如果，只讲结果！步履不停，奋斗不止，终于成长为公司的业绩担当，荣获豫工机械明日之星称号。&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152503244.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152605205.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  未来之星表彰&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  奋斗的路上，没有奇迹，只有努力的轨迹；没有运气，只有坚持的勇气，每一滴汗水都是成功的积累！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2021，豫工很多小伙伴在工作中展现巨大爆发力，目标坚定，温柔上进，持续努力，未来可期，喜获未来之星荣誉称号！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515292G45.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525152944V5.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 优秀表彰致辞&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n “分享、担当、感恩、自信、坚毅”，豫工总经理为活动致辞 ，再次分享公司企业文化，揭秘豫工机械16年保持高速发展的能量源泉！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153111320.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  风雨同舟者赢，上下同欲者胜&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  有人说你相信什么，就会吸引什么！你怀疑什么，就会失去什么，这就是相信的力量，这就是成功的秘籍！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  年度股东分红，让我们再次见证相信的力量！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515324C15.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153300J3.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n豫工十六年发展，终成今日势，跨越式发展步伐，吸引众多优秀员工成为股东，风雨同舟，荣辱与共，推动豫工这艘航船稳步向前，再创新高！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515340J40.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153431Y9.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 女神篇&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 恰逢521全民表白日,豫工机械特设第一届女神节，鼓励大家怀揣公主梦，装着女王心，&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 勇敢展现自己的美，独立、优雅、自信、坚韧、洒脱、有底气、做自己，不负时光，活得漂亮！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515353U03.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153552L6.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-21052515360S18.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251536203H.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-2105251536339A.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153Q3a5.jpg&quot; style=&quot;width: 695px; height: 451px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153P1V6.jpg&quot; style=&quot;width: 695px; height: 434px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210525/2-210525153RR22.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;br&gt;\\r\\n 无论是女王节还是女神节，往后余生，祝愿豫工这群可爱且善良的女生，眼中有光，心中有爱，温柔中带着刚强，努力优秀，大方拥有，有所为，有所爱，有所期待！&lt;br&gt;\\r\\n &lt;strong style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=\'color: rgb(85, 85, 85); font-family: &quot;microsoft yahei&quot;; font-size: 16px; text-indent: 32px;\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(30, 105, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"105\",\"catid\":\"8\",\"title\":\"\\r\\n         五一劳动节 ，豫工机械放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-105.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52822\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"105\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210430/2-210430145242945.png&quot; style=&quot;width: 695px; height: 295px;&quot;&gt;&lt;br&gt;\\r\\n        在这个世界上，有这么一群人，他们不是叱咤风云的英雄，不是风光无限的明星，也不是天赋异禀的能人。他们只是热爱生活的普通人，是努力生活在平凡世界中的每一个人。&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 在即将到来的五一劳动节，豫工机械向所有平凡又非凡的劳动者致敬！愿你们都能以全力以赴的热忱，过梦寐以求的生活！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210430/2-2104301453111a.jpg&quot; style=&quot;width: 695px; height: 1123px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，劳动节放假安排如下：&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  1、2021年劳动节放假共3天，时间为2021年5月1日至5月3日，5月4日（星期二）正常上班。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 祝愿大家过一个安全、惬意、有意义的劳动节！&lt;br&gt;\\r\\n 　　&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(31, 106, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"106\",\"catid\":\"8\",\"title\":\"\\r\\n         热情服务获赞誉，客户感激送锦旗\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-106.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52828\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"106\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       客户服务无小事！江西武吉高速九岭山隧道，客户第一次使用液压湿喷机，售后人员耐心讲解，获客户由衷感谢。豫工机械致力于服务是公司核心竞争力的打造，客户至上，服务如一！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-2105051111315F.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505111505c0.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505111515c3.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n本次客户订购的是豫工单喷头液压湿喷机表现出色，生产能力7 m3/h ，搭配16立方空压机，输送距离可达100米，喷射混凝土密实、匀质、高强度，效果、效率远超客户预期。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-21050511262HY.png&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-210505112F2928.png&quot; style=&quot;width: 695px; height: 395px;&quot;&gt; &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210505/2-21050511264T06.png&quot; style=&quot;width: 695px; height: 396px;&quot;&gt;&lt;br&gt;\\r\\n客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br&gt;\\r\\n&lt;strong&gt;&lt;span style=&quot;font-size:14px;text-indent:0;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;拥有16年隧道喷浆设备研发生产经验，匠心质造，品质如一！规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(32, 107, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"107\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工收官启动，秒变大型跨年晚会现场\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-107.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52836\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"107\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       2020年12月21日，在郑州总部营销中心，豫工机械金秋表彰暨收官大战启动仪式火热开场，全体员工180多人参加活动。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113S1254.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 迎新环节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 虽历15年，豫工依然保持高速发展状态，员工队伍不断壮大。为让新入职小伙伴尽快融入集体，公司精心准备迎新活动，鼓励大家打开自己，融入团队。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113TR63.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 金秋大战60天，在豫工人的共同努力下，拿下了2020年同期棒的成绩，销售业绩突破3700万。其中，老客户返单率直线飙升，突破52%。&lt;br&gt;\\r\\n 大战期间，豫工涌现出了许多业绩标兵，百万英雄，服务之星，优秀团队。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113U9143.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113913W8.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406113925592.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611395a28.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 有人说：千人同心，则得万人之力；万人异心，则无一人可用！豫工一直注重团队向心力的打造，追求一群人、一条心、一个目标、一起奋斗，所向披靡，战无不胜。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611401Q94.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114039537.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040611405Q18.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114114634.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114154R1.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406114222230.jpg&quot; style=&quot;width: 695px; height: 595px;&quot;&gt;&lt;br&gt;\\r\\n 一分耕耘未必有一分收获，但是九分耕耘，必定会有一分收获。金秋大战期间，小伙伴们用实际行动证明了，这世间，唯有努力和坚持不可被辜负。&lt;br&gt;\\r\\n  &lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637496),
(33, 108, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"108\",\"catid\":\"8\",\"title\":\"\\r\\n         一粽传情 快乐端午，豫工机械端午福利多\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-108.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52842\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"108\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       端午粽飘香，欢乐事儿忙！为迎接端午佳节的到来，表达公司对员工的关爱，2020年6月22日，按照公司惯例，豫工机械提前为大家发放暖心福利，表达节日问候。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9202D57.png&quot;&gt;&lt;br&gt;\\r\\n豫工历来重视中华民族的传统节日，自公司成立至今十五年间，每年节假日都会给员工发放节日福利，更是把大家当家人看待，感谢大家一直以来的辛勤付出，共享企业发展的成果。&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F92049128.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F9211T46.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F92132129.png&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210327/2-21032F923212I.png&quot;&gt;&lt;br&gt;\\r\\n端午历来有消灾去病的习俗。在北京疫情依然严峻的形势下，豫工借五月端午，祝愿大家迎祥纳福，辟邪消灾，平安健康！祝愿祖国繁荣昌盛，国泰民安！&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(34, 109, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"109\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工大型中秋福利现场，堪比红毯走秀\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-109.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52848\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"109\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       中秋佳节，豫工的福利真是.......这是老板要向我们表白吗？&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406115911564.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;&gt;&lt;br&gt;\\r\\n福利发放现场，大家暂时放下手中繁忙的工作，聚在一起，享受节日快乐&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120013401.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120034I8.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040612004TB.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120102Q2.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061201224D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120135332.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120155449.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n一份中秋礼品代表一份美好的祝福，传递出豫工对大家浓浓的关爱，这里不仅是豫工人的发展平台，更是豫工小伙伴们相亲相爱的大家庭。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120229512.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120244545.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-2104061203113D.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406120334142.jpg&quot; style=&quot;width: 695px; height: 926px;&quot;&gt;&lt;br&gt;\\r\\n报道称,中秋圆月将出现在10月2日,国庆、中秋喜相逢,有人说：今年国庆和中秋是用来弥补春节遗憾的,国兴、家睦、月明,祖国快乐、月亮快乐、你我也快乐 满大街扬起的国旗和满街飘香的月饼,彰显祖国国泰民安 阖家团圆,国和家撞了个满怀,正如豫工和亲爱的客户朋友,坦诚相待 携手同行&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(35, 110, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"110\",\"catid\":\"8\",\"title\":\"\\r\\n         燃！豫工液压湿喷机助战郑州地铁建设\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-110.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52854\",\"inputtime\":\"1700634839\",\"updatetime\":\"1700634839\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"110\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 2021年2月6日，豫工售后与技术支​持部乔工来到水利七局项目工地——郑州地铁8号线五龙口地铁口，安装调试液压湿喷机。&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094355Y2.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040609521Q58.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;/div&gt;\\r\\n订购单位中国水电7局，隶属于中国电建，承建郑州地铁8号线建设项目。 客户对喷射距离、产品质量、售后服务非常看重，曾亲自到工厂考察，对工厂生产实力、产品品质很放心。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094411447.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n客户所选机型为90型单喷头液压湿喷机，具有泵送压力大、输送距离远、回弹率低、施工效率高等优势，生产能力7㎥/h,配合空压机正常施工，喷射距离100米，垂直扬尘60米。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094511R6.jpg&quot; style=&quot;width: 695px; height: 390px;&quot;&gt;&lt;br&gt;\\r\\n试机中，在16/10空压机的配合下，液压湿喷机喷射距离达到100米，完全满足客户要求&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-21040609462a52.jpg&quot; style=&quot;width: 695px; height: 391px;&quot;&gt;&lt;br&gt;\\r\\n客户表示：这次服务，让我看到豫工的专业、敬业！每次咨询，他们总是在百忙之后悉心指导，不管前期视频沟通，还是后期现场调试，都耐心细心、高效及时！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210406/2-210406094FM63.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt; \\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(36, 101, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"101\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械为河南灾区捐赠的4车物资发车\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-101.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52796\",\"inputtime\":\"1700634838\",\"updatetime\":\"1700634838\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"101\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;7月23日，河南豫工机械有限公司通过郑州西峡商会捐赠的12.8万元善款，已筹集4辆车的救灾物资，在河南红十字会的统一调配下，发往灾区！董事长李红旗先生携部分员工代表，义工一天，帮忙装车！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164G2436.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164H6492.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;span style=\'color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify;\'&gt;7月20日，台风“烟花”携带的强降雨席卷郑州，千年不遇的降雨量令河南1300万人民群众的生命和财产遭受巨大的损失，全国 各省市兄弟单位星夜驰援。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164R6355.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164Q31S.jpg&quot; style=&quot;width: 695px; height: 463px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n&lt;p style=\'margin: 0px; padding: 0px; max-width: 100%; clear: both; min-height: 1em; color: rgb(51, 51, 51); font-family: -apple-system, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 17px; letter-spacing: 0.544px; text-align: justify; box-sizing: border-box !important; overflow-wrap: break-word !important;\'&gt;\\r\\n 董事长李红旗先生第一时间捐款12万元用于抗洪救灾，并带领公司全体员工连续三天开展赈灾义卖，筹集救灾善款30余万元。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I0164U4624.jpg&quot; style=&quot;width: 695px; height: 1042px;&quot;&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;李总表示：尽管我们也受灾，厂区被淹，但在大是大非，大灾大难面前，我们还应当义不容辞地腾出余力，自救的同时，向同胞伸出援手，这是企业价值所在，也是企业回馈社会、反哺社会的责任所在，必须履行好。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I016493YE.jpg&quot; style=&quot;width: 695px; height: 584px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I016494X18.jpg&quot; style=&quot;width: 695px; height: 452px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;企业有担当 社会有能量！只要国家、社会有需要，豫工机械一定义不容辞，不忘初心，勇担使命，传递正能量！就如这次“720特大暴雨洪灾”，我们一定尽心竭力，自救救人，与灾区人民风“豫”同舟！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A113139.jpg&quot; style=&quot;width: 695px; height: 313px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A135291.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A212Z1.jpg&quot; style=&quot;width: 695px; height: 419px;&quot;&gt;&lt;/span&gt;&lt;br&gt;\\r\\n &lt;span style=&quot;letter-spacing: 0.544px;&quot;&gt;三天义卖结束后，全体员工同事一致意愿把每年的7月20日，设为公司的爱心慈善日（720爱心慈善日），成立专款专用的爱心慈善基金，每年720当天义卖 所得善款全部注入爱心慈善专项基金，用于慈善事业和爱心捐助。&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210730/2-210I01A32X61.jpg&quot; style=&quot;width: 696px; height: 666px;&quot;&gt;&lt;/span&gt;&lt;/p&gt;\\r\\n&lt;div&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com/&quot; style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px;\'&gt;&lt;strong&gt;&lt;span style=&quot;line-height: 32px; text-indent: 2em; display: inline-block;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;span style=\'color: rgb(85, 85, 85); font-family: &quot;microsoft yahei&quot;; font-size: 16px;\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/span&gt;&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(37, 102, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"102\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021端午节放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-102.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52804\",\"inputtime\":\"1700634838\",\"updatetime\":\"1700634838\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"102\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611145944c8.jpg&quot; style=&quot;width: 695px; height: 1175px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;豫工机械&lt;/a&gt;&lt;/span&gt;&lt;/strong&gt;五一放假通知&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 根据《国务院办公厅关于2021年部分节假日安排的通知》，结合公司实际情况，端午节放假安排如下：&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 1、2021年端午节放假共3天，时间为2021年6月12日至6月14日，6月15日（星期二）正常上班。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 2、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 3、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 祝愿大家过一个安全、惬意、有意义的端午节！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(38, 103, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"103\",\"catid\":\"8\",\"title\":\"\\r\\n         赞！豫工端午福利多，老板实力宠员工！\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-103.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52810\",\"inputtime\":\"1700634838\",\"updatetime\":\"1700634838\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"103\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 端午来啦！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 老板实力宠员工&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  2盒粽子，2箱水果&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  啧啧......豪横，果然是中国好老板！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111434414Z.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n  &lt;div&gt;\\r\\n   丰厚的节日福利&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   是公司对中国文化的传承&lt;/div&gt;\\r\\n  &lt;div&gt;\\r\\n   更体现了对豫工家人细致入微的关怀&lt;/div&gt;\\r\\n &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143545919.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111436032W.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143F4611.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 其实，每逢传统佳节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 公司都会为客户朋友和豫工家人精心准备节日贺礼&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 这个习惯，豫工一干就是16年！&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143K4933.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143PSA.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143RDW.jpg&quot;&gt;&lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  福利发放现场，&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  欢声笑语！&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  大家暂时放下手中繁忙的工作，&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  聚在一起，享受节日的快乐！&lt;br&gt;\\r\\n  &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611143ZR25.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111439463V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-2106111439593L.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144029260.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144055K8.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n国内事业部员工风采&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144120103.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144136439.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144149318.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144200196.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n国际事业部员工风采&lt;br&gt;\\r\\n今年端午，赶上公司16周年庆典 为回馈新老客户的关爱 老板特批优惠方案 推出年中大促活动（2021年6月6日-6月30日） 价格一降到底，还有定金翻倍抵货款 买的多，更省钱。 &lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210611/2-210611144310146.jpg&quot; style=&quot;width: 695px; height: 350px;&quot;&gt;&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n 心如糯米，越粘越紧，&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 情似粽叶，越煮越香。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 端午佳节&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 我们向长期信任和支持豫工的客户朋友送上真诚的节日祝福&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 恭祝大家：事业顺利，生活安康，“粽”享幸福，端午安康！&lt;/div&gt;\\r\\n&lt;br style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;\\r\\n&lt;strong style=\'font-family: &quot;microsoft yahei&quot;; color: rgb(85, 85, 85); font-size: 16px; text-indent: 32px;\'&gt;&lt;a href=&quot;http://www.hnyugong.com/&quot; style=&quot;color: rgb(85, 85, 85); text-decoration-line: none;&quot;&gt;河南豫工机械&lt;/a&gt;&lt;/strong&gt;&lt;span style=\'font-family: &quot;microsoft yahei&quot;; font-size: 16px; line-height: 32px; text-indent: 32px; display: inline-block; color: rgb(85, 85, 85);\'&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目。&lt;/span&gt;\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(39, 97, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"97\",\"catid\":\"8\",\"title\":\"\\r\\n         豫工机械2021中秋节放假通知\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-97.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52744\",\"inputtime\":\"1700634831\",\"updatetime\":\"1700634831\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"97\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       &lt;div&gt;\\r\\n 金秋九月，花好月圆，又是一年中秋时！&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 河南豫工机械有限公司根据国假办放假规定，结合公司实际情况，中秋节放假安排如下：&lt;br&gt;\\r\\n &lt;br&gt;\\r\\n &lt;div&gt;\\r\\n  &lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;&lt;strong&gt;放假时间：2021年9月19-21日，共三天。9月22日（周三）正式上班&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n   &lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916145453Q6.gif&quot; style=&quot;width: 640px; height: 440px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&lt;span style=&quot;background-color:#ffff00;&quot;&gt;温馨提示 &lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n  &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n  &lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;div&gt;\\r\\n  1、放假期间，公司正常接单，工厂正常发货；如果您在假期期间有技术问题，可以电话咨询售后人员，或者在官方网站留言，节后我们第一时间安排人员为您处理。&lt;/div&gt;\\r\\n &lt;div&gt;\\r\\n  2、各部门根据公司放假通知，安排好假期工作；工厂仓库需全面检查电源门窗，排除安全隐患；仓库值班人员提前安排，做好假期正常发货工作。&lt;/div&gt;\\r\\n&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n 3、假期期间出行要佩戴好口罩，尽量避免乘坐公共交通，如需乘坐务必防护到位。外出游玩过程中注意保持人际距离，不去中高风险地区，保持良好卫生习惯。&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;月圆人团圆&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;中秋合家欢&lt;/span&gt;&lt;/strong&gt;&lt;/div&gt;\\r\\n&lt;div&gt;\\r\\n &lt;strong&gt;&lt;span style=&quot;color:#b22222;&quot;&gt;豫工机械恭祝新老客户朋友财源滚滚、事业顺利、阖家幸福、中秋安康！&lt;/span&gt;&lt;/strong&gt;&lt;br&gt;\\r\\n &lt;u&gt;&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;&lt;/u&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目&lt;/div&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
(40, 98, 1, 8, '{\"1_xinwenguanli\":{\"id\":\"98\",\"catid\":\"8\",\"title\":\"\\r\\n         您的中秋贺礼已发货！请注意查收！\\r\\n        \",\"thumb\":null,\"keywords\":\"\",\"description\":\"\",\"hits\":\"1\",\"uid\":\"1\",\"author\":\"创始人\",\"status\":\"9\",\"url\":\"/show-98.html\",\"link_id\":\"0\",\"tableid\":\"0\",\"inputip\":\"39.96.59.7-52750\",\"inputtime\":\"1700634831\",\"updatetime\":\"1700634831\",\"displayorder\":\"0\"},\"1_xinwenguanli_data_0\":{\"id\":\"98\",\"uid\":\"0\",\"catid\":\"0\",\"content\":\"\\r\\n       \\r\\n       金色九月，喜迎中秋!豫工机械为答谢新老客户的支持和厚爱，精心定制中秋贺礼800份,已包装完毕，即将发货！&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610215A62.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610221A35.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n刚刚过去的两个月，郑州人过得极不容易,先抗洪灾、又战疫情,幸运的是，有像您这样一群老朋友新伙伴的一路相伴,豫工人才能凭借勇敢无畏的干劲，排除万难，顺利闯关!&lt;br&gt;\\r\\n&lt;strong&gt;7月抗汛,赈灾义卖,!筹款30万捐向灾区&lt;/strong&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-21091610345M33.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103512c7.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103529218.jpg&quot; style=&quot;width: 695px; height: 312px;&quot;&gt;&lt;br&gt;\\r\\n&lt;strong&gt;8月抗疫，涝疫补贴,每人500元&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103J3A6.jpg&quot; style=&quot;width: 695px; height: 428px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103Q1R7.jpg&quot; style=&quot;width: 695px; height: 445px;&quot;&gt;&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-210916103S13A.jpg&quot; style=&quot;width: 695px; height: 695px;&quot;&gt;&lt;/strong&gt;&lt;br&gt;\\r\\n中秋佳节将至，金九银十已来，为答谢您一如既往的信任和支持，除中秋贺礼，豫工人也吹响金秋大战（9月15日-11月15日）集结号，各种促销感恩让利，全体员工60天无休无假，及时发货，专业售后，为您的工程保驾护航。&lt;br&gt;\\r\\n&lt;img alt src=&quot;https://www.hnyugong.com/uploads/allimg/210916/2-2109161042243V.jpg&quot; style=&quot;width: 695px; height: 521px;&quot;&gt;&lt;br&gt;\\r\\n花好月圆，天涯共此良辰，豫工机械恭祝新老客户朋友，财源滚滚、事业顺利，家庭美满、中秋安康！&lt;br&gt;\\r\\n&lt;strong&gt;&lt;a href=&quot;http://www.hnyugong.com&quot;&gt;&lt;span style=&quot;color:#0000ff;&quot;&gt;河南豫工机械有限公司&lt;/span&gt;&lt;/a&gt;&lt;/strong&gt;是国内工程设备生产基地，规格多，设备全，一站式采购，成本低！长期供货于中铁局、中交局等桥梁预应力施工项目！&lt;br&gt;\\r\\n&lt;br&gt;\\r\\n\\r\\n       \\r\\n       \\r\\n      \"},\"1_xinwenguanli_category_data\":null}', '', 1700637500),
