(1, '河南豫工机械官网', 'www.hnyugong.com', '{\"webpath\":null,\"config\":{\"SITE_NAME\":\"河南豫工机械官网\",\"SITE_DOMAIN\":\"www.hnyugong.com\",\"SITE_TEMPLATE\":\"newdaguanwang\",\"SITE_INDEX_HTML\":\"1\",\"SITE_CLOSE\":\"0\",\"SITE_CLOSE_MSG\":\"网站升级中....\",\"SITE_LANGUAGE\":\"zh-cn\",\"SITE_TIMEZONE\":\"8\",\"SITE_TIME_FORMAT\":\"\",\"SITE_THEME\":\"default\"},\"seo\":{\"SITE_SEOJOIN\":\"_\",\"SITE_TITLE\":\"豫工机械_豫工机械设备_豫工机械厂家_豫工机械官网-河南豫工机械设备有限公司\",\"SITE_KEYWORDS\":\"豫工机械,河南豫工机械,豫工机械设备,豫工机械产品,豫工机械厂家,豫工机械官网,豫工机械有限公司,豫工机械怎么样\",\"SITE_DESCRIPTION\":\"豫工机械技术力量雄厚，加工设备齐全，检测手段完备，专注于路面机械、隧道喷浆支护设备、桥梁设备、工程注浆泵、防汛除雪应急设备等的研发制造，历经千百次改进，精工品质，稳定可靠。拥有8大产品系列，100多款产品，提供售前-售中-售后一站式服务，扎根市场，服务全球。是工程设备研发、生产、销售于一体的大型综合性企业。\\r\\n\",\"SITE_URLRULE\":\"1\",\"list_pagesize\":\"10\",\"list_mpagesize\":\"10\"}}', 0, 0);
